window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["cotTruyen"]=[{"chuong":635,"tieuDe":"Pháp Bảo Đặc Thù Của Liễu Mi","tomTat":"Vương Lâm nhìn vào ánh mắt trong màn sương đen và chấn động vì cảm giác máu huyết tương dung, lập tức thu chiêu rồi gọi Tiên vệ khôi lỗi bao phủ màn sương để khống chế oán ảnh. Liễu Mi tiết lộ nàng đã luyện hóa đứa nhỏ trăm năm thành oán ảnh, gieo vào ý thức nó rằng phụ thân đã vứt bỏ nó, và người phụ thân ấy chính là Vương Lâm. Sau cơn trầm mặc, Vương Lâm không sụp đổ mà cảm ơn Liễu Mi vì đã đưa đứa nhỏ trở lại, đồng thời khẳng định dù mất ngàn năm cũng sẽ khiến nó hồi phục. Sát khí của hắn bùng lên dữ dội, dùng Hoàng tuyền chỉ, Thất Tinh kiếm trận, Tịch Diệt chỉ và Định để áp đảo Liễu Mi, trong khi nàng chống đỡ bằng Cổ kính Hạ phẩm Tiên bảo và hắc châm Hồn thứ tư. Khi Liễu Mi gọi Lệ nhi khiến oán ảnh phát tiếng thê lương làm Vương Lâm đau đớn, hắn vẫn không dừng tay. Đúng lúc Liễu Mi lâm nguy, Huyễn gia Lão Tổ mở lốc xoáy cứu nàng, đưa cánh tay khô héo ra đối chưởng khiến Vương Lâm phun máu lùi lại. Vương Lâm tuyên bố Huyễn gia sẽ bị diệt tộc nếu cứu Liễu Mi, rồi phóng kiếm khí Lăng Thiên Hầu vào lốc xoáy truy kích. Kiếm khí làm lốc xoáy sụp đổ, chấn thương Huyễn gia Lão Tổ ở Nhà Tổ trên Thiên Huyễn Tinh, nhưng Liễu Mi vẫn được bạch quang cuốn về mật thất."},{"chuong":636,"tieuDe":"Vương Bình","tomTat":"Huyễn gia Lão Tổ dùng nguyên thần vượt tinh không cứu Liễu Mi, nhưng nhanh chóng nhận ra Vương Lâm không phải tiểu bối dễ giết vì nguyên thần đối phương có thể đánh tan một chỉ của lão và bên cạnh còn có Tiên vệ khôi lỗi cảnh giới Âm Dương hư thật. Kiếm khí của Lăng Thiên Hầu do Vương Lâm phóng ra phá sập lốc xoáy, truy vào nguyên thần lão với khí tức Tịnh Niết, buộc lão hoảng hốt chạy về mật thất Huyễn gia. Dù lão đánh tan thông đạo, kim mang vẫn lao ra làm mật thất nổ tung, chấn động Thiên Huyễn Tinh; Huyễn gia Lão Tổ phải vận Vạn Huyễn Vô Tướng đạo đối kháng nhưng vẫn bị kiếm khí xâm nhập thân thể. Lão nhớ lại lời uy hiếp diệt Huyễn gia của Vương Lâm, suy đoán sau lưng hắn có cao thủ Tịnh Niết, nhưng cuối cùng vẫn không giao Liễu Mi vì kế hoạch trên người nàng có thể giúp lão tiến thêm về tu vi. Sau khi tự trấn an rằng Vương Lâm đến từ Liên Minh Tinh Vực và khó có cao thủ vượt sang La Thiên, lão truyền thần thức cầu viện Thiên gia cùng Hứa gia. Trên Nhiễm Vân Tinh, Vương Lâm quay lại đối diện màn sương đen bị Tiên vệ vây quanh, nghe tiếng oán anh non nớt và đau đớn nhận ra đó là huyết mạch của mình. Dù đứa bé cắn hút máu và truyền oán khí âm hàn vào cơ thể, hắn vẫn dịu dàng đặt lại tên từ Lệ Nhi thành Vương Bình, mong con được bình an."},{"chuong":637,"tieuDe":"Đạo Nghĩa","tomTat":"Oán anh Bình nhi vẫn cắn đầu ngón tay Vương Lâm và truyền oán khí vào người hắn, nhưng lôi uy nguyên thần khiến oán khí không thể gây hại. Vương Lâm dùng cấm chế phong ấn đứa nhỏ, đưa vào Thiên nghịch không gian và để lại một phần nguyên thần để về sau xua oán khí cho con. Sau đó hắn thu hồi đệ tử hồn của Tôn Hồn Phiên, gặp Tôn Tích và nghe Tôn Tích thú nhận chuyện ba người từng giấu giếm để kéo hắn vào Hồn thủy làm người thế tội. Vương Lâm không truy cứu, vì đã nhận ba Tiên ngọc nên hứa bảo đảm hậu nhân ba nhà bình yên trăm năm, đồng thời tuyên bố Huyễn gia sẽ không còn tồn tại nếu bảo vệ Liễu Mi. Hắn phân tích cho Tôn Tích con đường khôi phục tu vi, rồi dùng Đạo hóa Hoàng Tuyền, Hoàng Tuyền lực và một viên Bát phẩm đan dược giúp Tôn Tích đạt lại Anh Biến trung kỳ, nhưng cũng khiến con đường tiến thêm của Tôn Tích bị khóa. Trước khi rời đi, Vương Lâm giao việc dàn xếp hậu nhân ba nhà cho Tôn Tích, sau đó xuyên qua Tỏa Tinh đại trận, dùng Tinh La bàn theo vị trí trong ngọc giản lao tới Thiên Huyễn Tinh. Trên đường, hắn suy đoán Huyễn gia thế lực phức tạp và Huyễn gia Lão Tổ có thể mời viện thủ nếu quyết bảo vệ Liễu Mi."},{"chuong":638,"tieuDe":"Kinh Thối Thiên Quỳ Tử","tomTat":"Huyễn Vô Tình triệu hồi trực hệ Huyễn gia về phía Nam Thiên Huyễn Tinh, mở hộ tộc đại trận và chuẩn bị cố thủ trong Nhà Tổ. Chương đồng thời xác lập thế cục ba đại gia tộc trên Thiên Huyễn Tinh: Thiên gia mạnh nhất, Huyễn gia đứng thứ hai nhờ truyền thừa tiên nhân, còn Hứa gia thần bí vì bị nghi có liên hệ với Đông Lâm Tinh. Thiên Quỳ Tử, một trong ba lão tổ Thiên gia, lấy tư cách cá nhân ra ngoài tinh không chặn Vương Lâm để đổi lấy bảo vật từ Huyễn gia. Vương Lâm cưỡi Tinh La bàn tới với sát ý, gọi Tiên vệ khôi lỗi giao chiến khiến Thiên Quỳ Tử vừa kiêng kị vừa nảy lòng tham. Khi Vương Lâm phóng Xạ Thần xa hóa thành Lôi Thú nuốt lôi phù văn, Thiên Quỳ Tử lầm tưởng hắn là người Lôi Tiên Điện, lập tức xin lỗi, bồi thường Tiên ngọc và tuyên bố Thiên gia không tham dự việc Huyễn gia. Sau đó Vương Lâm tiến vào Thiên Huyễn Tinh, tới phía trên Nhà Tổ Huyễn gia đòi giao Liễu Mi, trong khi Liễu Mi né tránh ánh mắt hắn và Huyễn Vô Tình thách hắn phá đại trận. Vương Lâm dùng Lôi Thú dẫn lôi công kích, rồi nhỏ máu mở phong ấn, khiến lôi uy bùng phát thành lốc và lưới lôi đình bên ngoài thân Lôi Thú."},{"chuong":639,"tieuDe":"Huyễn Gia Phân Liệt !","tomTat":"Vương Lâm ra lệnh phá trận, thúc Lôi Thú dồn lôi điện tới cực hạn công kích Huyễn gia đại trận, khiến tộc nhân Huyễn gia nhận ra biểu tượng Lôi Thú và liên hệ tới Lôi Tiên Điện nên hoảng sợ. Bên trong đại trận, bất mãn bị dồn nén vì việc Lão Tổ bảo hộ Liễu Mi bùng phát, nhiều tộc nhân cho rằng không đáng vì một ngoại nhân mà dẫn họa tới gia tộc. Huyễn Vô Tình quát mắng trấn áp phản đối, đồng thời âm thầm chờ Vương Lâm tiêu hao kiếm khí để tìm cơ hội ra tay. Lôi Thú và Tiên vệ khôi lỗi liên thủ ép đại trận nổi sóng dữ, làm trận pháp dần suy yếu. Huyễn Phong Thần, Tộc trưởng Huyễn gia, công khai chất vấn Lão Tổ, chỉ ra Vương Lâm có Lôi Thú và khôi lỗi mạnh nên đáng cân nhắc kết giao hơn là kết tử thù, rồi tuyên bố nếu trận bị phá sẽ thối lui để bảo toàn Huyễn gia. Khi đại trận bị ép tới cực hạn, Vương Lâm lấy Vũ Kiếm tiên do Chu Dật phân ly truyền thừa và thi triển Trảm La Quyết, khiến thiên địa như rơi vào hư ảo và làm Huyễn gia Lão Tổ chấn động nhận ra dấu hiệu quy tắc."},{"chuong":640,"tieuDe":"Trảm La Quyết !","tomTat":"Vương Lâm thi triển Trảm La Quyết, một kiếm ẩn chứa quy tắc khiến Huyễn Phong Thần, trực hệ Huyễn gia và các tu sĩ quan sát từ xa đều chấn động. Thiên Quỳ Tử nhận ra quy tắc trong kiếm thức, nghi ngờ Vương Lâm có liên quan Lôi Tiên Điện, còn lão già Hứa gia vốn định tương trợ Huyễn gia cũng dừng lại vì kiêng dè hậu thủ của hắn. Huyễn gia đại trận sụp đổ trước khi thực sự va chạm với công kích, nhưng Vương Lâm cũng tái nhợt vì Trảm La Quyết tiêu hao sự dung hợp giữa nguyên khí thân thể và nguyên thần. Huyễn Vô Tình không chịu lùi, mời Phúc Trạch ngọc giản, chí bảo Huyễn gia do tổ tiên ở Lôi chi Tiên giới để lại, đồng thời nghĩ tới di bảo tổ tiên đã mất tích cùng Huyễn Vô Tướng. Trước cục diện ấy, Huyễn Phong Thần dùng thân phận Tộc trưởng tuyên bố Huyễn gia không tham dự ân oán cá nhân giữa Vương Lâm và Huyễn Vô Tình, khiến nội bộ Huyễn gia tách khỏi lão tổ. Phúc Trạch ngọc giản hóa thành bóng người tỏa tiên lực áp chế toàn Thiên Huyễn Tinh và bước về phía Vương Lâm; Tiên vệ khôi lỗi cùng Lôi Thú lập tức hộ bên hắn, Liễu Mi do dự chạm túi trữ vật rồi buông tay. Ở thời khắc quyết định, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian, gọi một tồn tại trong nguyên thần và hứa sau trận sẽ thả tự do."},{"chuong":641,"tieuDe":"Tán Ma Xuất Hiện","tomTat":"Trong lúc tiên khí của hư ảnh Tiên nhân đối trọng với ma khí, Vương Lâm gọi ra Tán Ma từ thiên linh cái, để lộ con bài mà hắn đã khắc lạc ấn khống chế hơn trăm năm nhưng chưa luyện hóa hoàn toàn. Sự xuất hiện của Tán Ma khiến Huyễn gia Lão Tổ tái mặt, Huyễn Phong Thần và tộc nhân Huyễn gia kinh sợ, Thiên Quỳ Tử run rẩy, còn lão già Hứa gia nhận ra lai lịch Cổ Ma của nó. Tán Ma đòi Vương Lâm thực hiện giao ước thả tự do sau trận, và Vương Lâm đồng ý dùng điều kiện ấy để đổi lấy chiến lực nhằm phá thế bảo hộ Liễu Mi. Tán Ma hóa sương mù nhập vào thất khiếu Vương Lâm, ma giáp bao phủ thân thể, tiên lực trong người hắn chuyển thành ma lực và dung hợp với ma hồn Tán Ma. Khi Tán Ma tung quyền hóa hắc long, hư ảnh Tiên nhân dùng tiên lực ngưng tụ thành lốc xoáy hóa giải, rồi thi triển Hoá Tiên Thuật rút linh lực toàn Thiên Huyễn Tinh, chuyển thành tiên lực và ngưng tụ thành vụ cầu màu trắng ngà. Tán Ma nhận ra thủ đoạn ấy thuộc một chi nhánh Cổ Yêu bộ tộc, bèn dùng ngôn ngữ Cổ Tộc gọi Cổ Ma, hóa ma trảo rút tinh hồn Thiên Huyễn Tinh để đối lại. Dù thân thể bị khống chế, Vương Lâm vẫn trực tiếp cảm nhận quá trình Cổ Ma rút tinh hồn và sinh ra cảm ngộ."},{"chuong":642,"tieuDe":"Cắn Nuốt","tomTat":"Tán Ma khống chế thân thể Vương Lâm thi triển Trừu hồn, rút tinh hồn Thiên Huyễn Tinh với quy mô khiến Vương Lâm nhớ đến Tham Lang từng rút Sơn hồn ở Yêu Linh chi địa nhưng hoàn toàn không thể so sánh. Tinh hồn tinh cầu va chạm với tiên lực của Tiên nhân hư ảnh, khiến linh mạch khô héo, mặt đất chấn động và tộc nhân Huyễn gia phải lui lại tự bảo vệ. Sau va chạm, Tiên nhân hư ảnh sụp đổ, Phúc Trạch ngọc giản hiện ra rồi vỡ vụn, chỉ còn lại một đạo phòng ngự cuối bao phủ mười dặm. Vương Lâm nhờ trực tiếp cảm nhận trận chiến này mà hiểu sâu hơn về thần thông, tiên lực và khoảng cách với tầng thứ bước thứ hai tu đạo. Khi Tán Ma tiếp tục công kích quầng sáng, Huyễn Phong Thần khuyên giao Liễu Mi để giữ mạng cho Huyễn gia, còn Liễu Mi van xin vì biết ra ngoài là chết. Huyễn Vô Tình cuối cùng lộ rõ ý đồ thật: muốn Liễu Mi giao ý cảnh để hắn đạt tới Vô Tướng Thiên Ma đạo, đồng thời chương hé lộ việc hắn thu nàng làm đệ tử vốn là để nuôi dưỡng rồi cắn nuốt Vạn Huyễn Thiên Ma đạo của nàng."},{"chuong":643,"tieuDe":"Cát Bụi Trở Về Với Cát Bụi","tomTat":"Huyễn Vô Tình vốn định chờ Liễu Mi đạt tới Âm Dương hư thật để ý cảnh lột xác hoàn chỉnh rồi mới cắn nuốt, nhưng vì Vương Lâm phá cục nên lão quyết định ra tay sớm. Liễu Mi hiểu rõ số phận của mình, đồng ý giao ý cảnh nhưng buộc Huyễn Vô Tình phải giết Vương Lâm, nếu không thì giao túi trữ vật của nàng cho hắn. Tán Ma khống chế thân thể Vương Lâm phá vỡ quầng sáng tiên lực cuối cùng của Huyễn gia, rồi nuốt sạch tia Vô Tướng Thiên Ma mà Huyễn Vô Tình cưỡng ép tạo ra và tiêu diệt luôn Huyễn Vô Tình. Liễu Mi mất sinh cơ vì ý cảnh cùng nguyên thần bị cắn nuốt, thân thể dần hóa thành những mảnh nhỏ bay đi. Vương Lâm nhận túi trữ vật nàng để lại, bên trong có một viên đan dược và một khối ngọc giản, nhưng hắn không diệt toàn tộc Huyễn gia mà rời đi trong mỏi mệt. Ở một tuyến khác, Tham Lang bôn tẩu trong tinh không La Thiên vì các lạc ấn trên thân đe dọa tính mạng. Nhiều ngày sau, Vương Lâm sống ẩn tại Lạc Nguyệt thôn trên Nhiễm Vân Tinh cùng đứa trẻ yếu bệnh tên Vương Bình, bắt đầu một quãng đời phàm tục giữa dân thôn."},{"chuong":644,"tieuDe":"Cả Đời Không Cần Tu Đạo","tomTat":"Vương Lâm sống tại thôn Lạc Nguyệt như một thợ mộc phàm tục, chăm sóc Vương Bình và bắt cậu uống thuốc đắng hằng ngày để trị oán khí. Đêm xuống, hắn dùng thần thông Lôi hệ ép hắc khí ra khỏi thân thể đứa trẻ, cho thấy Vương Bình vốn là Oán Anh, đã dùng đan dược do Liễu Mi lưu lại và bị Vương Lâm hủy ký ức cũ để bắt đầu một đời mới. Chương cũng kể lại việc Vương Lâm trở về Nhiễm Vân Tinh, chọn thôn Lạc Nguyệt vì nơi này giống quê cũ, rồi sống bằng nghề thợ mộc như mong muốn năm xưa của cha mình. Tôn Thái đã đến sống gần Vương Lâm từ năm thứ ba, nay già nua và tử khí nặng, rất yêu quý Vương Bình nhưng phải nghe Vương Lâm khẳng định sẽ không cho đứa trẻ tu đạo. Vương Lâm muốn bầu bạn với Vương Bình trọn một kiếp luân hồi, để con làm phàm nhân, cưới vợ sinh con rồi bình an trải qua sinh tử. Năm năm nữa trôi qua, thôn Lạc Nguyệt có người mất và trẻ nhỏ ra đời, Vương Bình mười tuổi nhưng vẫn nhỏ yếu, còn Vương Lâm cố ý để dung mạo già đi như người trung niên để hòa vào đời sống thôn xóm."},{"chuong":645,"tieuDe":"Tháo Giáp","tomTat":"Ở thôn Lạc Nguyệt, bà mối khuyên Vương Lâm tái hôn với nữ nhi Triệu gia vì Vương Bình đã mười tuổi và thiếu mẫu thân, nhưng Vương Lâm khéo léo từ chối. Vương Bình sợ có mẹ kế nên phản ứng mạnh, sau đó được cha hứa sẽ không tìm mẹ kế cho hắn; hắn uống thuốc và bộc lộ mong muốn ở bên phụ thân đến già. Đời sống phàm tục kéo dài khiến Vương Lâm gần như không dùng thần thông, chỉ âm thầm xua oán khí cho Vương Bình vào ban đêm. Qua việc nhìn con trưởng thành, đạo tâm của hắn dần thoát khỏi mệt mỏi, cảm ngộ sinh tử luân hồi sâu thêm và xuất hiện dấu hiệu thăng hoa về nhân quả tuần hoàn. Chương cũng dùng Liễu Mi và Huyễn Gia Lão Tổ để giải thích giá trị hiếm có của thăng hoa ý cảnh trong tu đạo. Sáu năm sau, khi Vương Bình mười sáu tuổi, Tôn Thái đại nạn, nghe Vương Lâm nhắc lời hứa năm xưa rồi an tường qua đời; lão được chôn sau núi cạnh thôn Lạc Nguyệt, mộ bia do Vương Bình khắc với thân phận nghĩa tôn."},{"chuong":646,"tieuDe":"Rời Đi","tomTat":"Sau khi Tôn Thái qua đời, thi thể lão hóa thành tro cốt và được Vương Lâm giữ trong túi trữ vật theo lời hứa. Thời gian trôi qua, Vương Bình trưởng thành trong Lạc Nguyệt thôn, học điêu khắc bên cha và được Vương Lâm dạy rằng mỗi nhát đao phải gắn với tâm ý cùng ký ức. Vương Bình hỏi về pháp thuật do Tôn Thái để lại, khiến Vương Lâm biết rõ chuyện Tôn Thái từng âm thầm truyền khẩu quyết tu đạo cho con mình, nhưng Vương Bình nói chưa từng tu luyện. Vương Lâm dứt khoát cấm Vương Bình bước vào tu đạo, khẳng định có thể cho con mọi thứ trên thế gian ngoại trừ con đường ấy. Ba năm sau, Vương Bình mười chín tuổi, dung mạo càng giống Liễu Mi, còn Vương Lâm quyết định thu dọn nhà cửa, dẫn con rời Lạc Nguyệt thôn sau mười chín năm. Người trong thôn đến tiễn biệt, Chu gia đại hán cảm khái năm tháng đã qua, còn Chu Nhược Đồng hỏi Vương Bình có trở về không và bật khóc khi nghe hắn nói có lẽ sẽ không."},{"chuong":647,"tieuDe":"Thăng Hoa","tomTat":"Trên Nhiễm Vân tinh, Vương Lâm không truyền đạo thuật cho Vương Bình mà dẫn con trai dùng thân phàm đi qua danh sơn, sông lớn và biển rộng để trực tiếp cảm nhận thiên địa. Ba năm leo núi khiến Vương Bình dần cứng cỏi, sau đó hành trình trên sông và ngoài biển tiếp tục mở rộng tâm linh hắn bằng sự liên miên, bao dung và mênh mông của tự nhiên. Tám năm sau, Vương Bình hai mươi bảy tuổi, dáng vẻ yêu dị tan đi, tâm cảnh đã đủ chứa núi sông biển trời dù vẫn là phàm nhân. Vương Lâm nhận ra oán khí trong linh hồn con chỉ còn một chút cuối cùng, nhưng phần này không còn pháp thuật hay đan dược nào khu trừ được, chỉ có thể chờ luân hồi hủy diệt. Khi trở lại gần Lạc Nguyệt thôn, Vương Bình không muốn vào thôn mà theo phụ thân lên Kỳ Liên phong, nơi họ chứng kiến dông tố tan đi và cầu vồng hiện ra. Một tu sĩ trung niên cưỡi phi kiếm màu xanh bay qua, tán thưởng nghị lực của phàm nhân leo núi rồi rời đi, khiến Vương Bình lần đầu thấy cảnh tượng tu tiên. Hắn hỏi phụ thân có thật sự không thể cho mình tu đạo hay không; Vương Lâm bi thương nhưng chỉ lắc đầu, khiến Vương Bình lặng im suốt đường xuống núi."},{"chuong":648,"tieuDe":"Thanh Nghi","tomTat":"Trên đường tới Kỳ Thủy thành, Vương Bình lần thứ hai xin phụ thân cho tu đạo, nhưng Vương Lâm vẫn từ chối vì một căn nguyên chỉ mình hắn biết, có liên hệ tới bản thân Vương Bình và cái chết của Liễu Mi. Hai cha con vào Kỳ Thủy thành, một phó đô phồn hoa của Đại Tần quốc trên Nhiễm Vân tinh, và Vương Lâm quyết định sẽ định cư tại đây. Tại tửu quán Tĩnh Nhã Hiên, dung mạo của Vương Bình khiến Thanh nhi sư muội chú ý, làm thanh niên tử y đi cùng nàng sinh ghen tức và nhiều lần nhục mạ hắn. Vương Bình bình tĩnh đáp trả, khiến lão nhân cẩm y bên cạnh mượn cớ giáo huấn thay gia trưởng, phóng đôi đũa nhằm phế hai tay hắn. Vương Lâm chỉ liếc một cái đã khiến đôi đũa mất lực, đồng thời làm lão nhân Kết Đan tâm thần tan rã, kim đan nứt và đan khí lẫn máu trào ra. Sau khi uống đan dược và bóp nát ngọc giản đưa tin, lão nhân ngã gục trước sự kinh hãi của mọi người; Vương Lâm lạnh lùng tuyên bố con trai mình không cần người khác giáo huấn rồi tiếp tục uống rượu."},{"chuong":649,"tieuDe":"Chỉ Một Lần Thôi","tomTat":"Trong tửu lâu Kỳ Thủy thành, lão nhân Kết Đan bị Vương Lâm làm đan khí tán loạn, còn thanh niên tử y của Tôn gia vừa định uy hiếp đã bị phất tay đánh ngã nhưng được tha mạng. Vương Bình chứng kiến uy thế của phụ thân nên bắt đầu hiểu rằng Vương Lâm không phải tu sĩ bình thường; đồng thời hắn trò chuyện với Thanh Nghi và biết sư tôn nàng đã bóp nát ngọc giản đưa tin. Ba lão nhân Tôn gia kéo tới, Tôn sư tổ nhìn ra Vương Bình có thiên tư đặc biệt rồi dùng linh quyết tạm khóa đan khí cho lão nhân Kết Đan. Khi nhóm Tôn gia ngăn đường, Vương Lâm chỉ tiến một bước đã khiến hai lão nhân Nguyên Anh trung kỳ lùi lại, ngay cả Tôn sư tổ Nguyên Anh viên mãn cũng tái mặt. Rời tửu lâu, Vương Lâm cảnh cáo Tôn gia rằng đây chỉ là một lần được tha, rồi nói với Vương Bình rằng mình từng có uyên nguyên và từng hứa che chở Tôn gia một trăm năm bình an. Sau đó hai cha con mua một đại viện ở phía bắc Kỳ Thủy thành để định cư, trong khi chi nhánh Tôn gia vì lời cảnh cáo ấy mà nổi lên biến động lớn."},{"chuong":650,"tieuDe":"Yêu Cầu Của Vương Bình","tomTat":"Sau hơn hai mươi năm, Tôn gia nhờ nguyên do Tôn Tích đã thay thế địa vị Nhiễm gia tại Nhiễm Vân tinh, trở thành thế lực độc tôn và dần sinh ngạo khí. Tại chi nhánh Tôn gia ở Kỳ Thủy thành, ba trưởng lão Hóa Thần thẩm vấn những người liên quan vụ tửu lâu, nghe lại lời cảnh cáo của Vương Lâm và phán đoán đối phương ít nhất có thể là Anh Biến kỳ; Thanh Nghi dù run sợ vẫn che giấu họ tên Vương Lâm. Ở đại viện phía bắc Kỳ Thủy, Vương Lâm thay biển thành Vương Phủ, giữ lại người hầu cũ rồi nói với Vương Bình rằng sau đời thường và mạo hiểm, hắn sẽ cho con ba mươi năm phú quý. Vương Bình hiểu đó là sự bù đắp vì mình không được tu đạo, nhưng yêu cầu nếu phải đi đường phàm nhân thì muốn tự mình trở thành chí tôn trong phàm nhân. Vương Lâm chấp thuận, trao hư ảnh bảo hộ dung nhập sau lưng Vương Bình và nói ở Nhiễm Vân tinh hắn có thể làm được hết thảy. Đêm ấy hai cha con đều giấu nỗi đau: Vương Lâm biết con không thể tu đạo, còn Vương Bình chỉ muốn tu đạo để mãi ở bên phụ thân. Ba ngày sau, Tôn Khải Minh với thân phận phó gia chủ Tôn gia và tu vi Anh Biến hậu kỳ tới Kỳ Thủy, được chi nhánh nghênh đón và bắt đầu nghi ngờ người gây chuyện có thể là Vấn Đỉnh lão quái."},{"chuong":651,"tieuDe":"Chia Lìa","tomTat":"Tôn gia ở Kỳ Thủy Thành tìm tới Vương phủ sau chuyện Vương Bình, nhưng Tôn Khải Minh quở trách tộc nhân vì không biết tốt xấu và có thể dẫn đại địch tới gia tộc. Trước Vương phủ, lão nhân mặt đỏ xông vào liền bị lực lượng vô hình chấn thương, khiến Tôn Khải Tinh nhận ra khí tức Vấn Đỉnh và lập tức cung kính rút lui; sau đó ông cấm toàn tộc bước vào phạm vi một ngàn trượng quanh nơi ở của vị tiền bối. Chương cũng xác lập Vân Vô Phong là tộc nhân Vân gia trên Vân Hải tinh, ở lại Nhiễm Vân tinh vì Thanh Nghi, rồi hoảng sợ khi nhớ lời cảnh báo rằng Hứa Mộc từng quét sạch Huyễn gia. Khi Thanh Nghi bị phong tu vi và đưa tới phòng Vân Vô Phong, Vương Lâm xuất hiện từ bóng đêm, đánh ngã hắn, chọn Thanh Nghi đi theo giúp Vương Bình và hứa đưa nàng tới đạo hạnh Nguyên Anh. Ba ngày sau, Vương Bình rời Kỳ Thủy Thành cùng Thanh Nghi để theo đuổi lý tưởng không muốn sống bình thản. Vương Lâm ở lại một mình, uống say lần đầu sau tám trăm năm trong đêm chia lìa và giữ lời không dùng thần thức truy tìm con trai. Ba năm sau, Bắc bộ Nhiễm Vân tinh xuất hiện Thiên Hành phái trong phàm nhân, phát triển mạnh với lời đồn về một thủ lĩnh như tiên nhân luôn có nữ nhân bên cạnh; thêm bảy năm nữa, Vương Lâm ngày càng già nua."},{"chuong":652,"tieuDe":"Năm Tháng","tomTat":"Thiên Hành phái phát triển nhanh trong dân gian, lan tới Kỳ Thủy thành và hơn nửa Nhiễm Vân Tinh, còn Vương Lâm già nua vẫn sống lặng lẽ như một phàm nhân, ngày ngày tới tửu quán uống rượu nghe chuyện thế sự. Ở đô thành Đế Sơn quốc, Vương Bình đã gần bốn mươi tuổi, ngồi trước bản đồ trong điện phủ xa hoa, nhớ tới phụ thân và được Thanh Nghi chăm sóc bên cạnh. Năm tháng trôi qua, Thiên Hành phái bao phủ ba đại đế quốc; khi Đế Sơn quốc toàn lực chèn ép, Thiên Hành phái dựa vào mạng lưới giáo chúng trong triều đình và quân đội để phản kích, nhanh chóng đoạt binh quyền. Đế Sơn quốc bị thay thế bởi Thiên Hành đế quốc, Vương Bình mặc long bào trở thành quân chủ, còn Thanh Nghi đứng bên cạnh hắn. Sau đó Đại Tần và Trần Vân xé bỏ minh ước, chiến tranh ba nước bùng lên, tu sĩ cũng nhúng tay nhưng đều bại lui khi Vương Bình thân chinh, lại thêm mệnh lệnh từ ba gia tộc Triệu, Nhiễm, Tôn khiến tu sĩ dần rời khỏi chiến tranh phàm nhân. Vương Lâm trở về Vương phủ trong tuổi già phàm tục, lặng nghĩ Bình nhi đã bốn mươi bảy tuổi và có thể đã nhận ra manh mối. Trong doanh trướng, Vương Bình dù đứng trên đỉnh quyền lực vẫn không khoái hoạt, mệt mỏi nhớ về thời thiếu niên ở sơn thôn, còn Thanh Nghi dịu dàng hỏi hắn có muốn trở lại nơi thơ ấu ấy hay không."},{"chuong":653,"tieuDe":"Mẫu Thân","tomTat":"Vương Bình cùng Thanh Nghi và quân sĩ trở lại thôn Lạc Nguyệt sau nhiều năm, nhìn cảnh cũ đổi thay và gặp lại Chu Nhược Đồng, người nay đã có chồng con. Con gái Chu Nhược Đồng tên Hứa Niệm Bình khiến hắn xúc động, nhưng hắn không quay lại mà lên hậu sơn tế bái mộ Tôn Thái rồi tiếp tục đi theo đại quân. Ở La Thiên Bắc Vực, Tham Lang cảm ứng được bảo vật trên một tinh cầu quỷ dị bị sương mù và mây tía che phủ, lấy đại đỉnh màu đen tiến vào tìm kiếm. Nhiều năm sau, Đại Tần và Trần Vân thuần phục, Thiên Hành trở thành quốc gia duy nhất trên Nhiễm Vân Tinh, hoàn thành chí nguyện thế tục của Vương Bình. Mười năm làm chí tôn khiến Vương Bình mỏi mệt; hắn nhường giang sơn cho thần tử thân tín rồi cùng Thanh Nghi trở về Vương phủ, nơi Vương Lâm đã chờ và chuẩn bị bữa cơm. Khi Vương Bình hỏi về mẫu thân, Vương Lâm kể lại quá khứ từ Chu Tước Tinh, Liễu Mi đến nguồn gốc của đứa nhỏ, khiến Vương Bình đau đớn nhận ra mình là oán anh bị mẫu thân luyện hóa. Sáng hôm sau, Vương Bình rời cha không nói lời nào và cùng Thanh Nghi quy ẩn ở một sơn thôn biên thùy, trở lại với điêu khắc tượng gỗ. Vương Lâm tiếp tục sống bình lặng thêm mười năm, từ cây cối sinh diệt, hoa tàn nở và mây tan tụ mà hiểu sâu hơn về sinh tử luân hồi, cân bằng và nhân quả."},{"chuong":654,"tieuDe":"Sứ Giả Lôi Tiên Điện Chân Chính","tomTat":"Vương Lâm sống lặng lẽ trong căn phòng lớn ở Vương phủ, để trẻ nhỏ chung quanh lui tới chơi đùa, lòng dần yên tĩnh vì cho rằng những điều cần nói với Vương Bình đã nói xong. Vương Bình tuổi già vẫn khắc tượng phụ thân, bộc bạch với Thanh Nghi rằng nếu có kiếp sau chỉ muốn cùng Vương Lâm sống như người thường trong một sơn thôn nhỏ, đồng thời thừa nhận còn một nghi vấn không dám hỏi về việc phụ thân không cho mình tu đạo. Thanh Nghi ở bên hắn đến cuối đời, dù có tu vi Nguyên Anh hậu kỳ đại viên mãn và ý cảnh tình yêu không hối hận vẫn chọn tình cảm phàm nhân hơn con đường thần tiên vô tình. Trong tinh không, Lôi Đạo Tử cưỡi Lôi Thú, lấy thân phận sứ giả Lôi Tiên Điện chân chính tiến về Nhiễm Vân tinh để điều tra nghi án giả mạo sứ giả sau biến cố Thiên Huyễn Tinh bảy mươi năm trước. Đêm tuyết dữ dội, Vương Bình cảm nhận sinh mệnh sắp hết, tiếp tục khắc pho tượng cuối cùng, dặn sau khi mình chết hãy đốt các tượng và nói đã sớm tha thứ cho phụ thân. Khi Lôi Đạo Tử giáng lâm, lôi uy làm trời đất Nhiễm Vân tinh biến đổi, toàn bộ tu sĩ cảm nhận khí tức khổng lồ; Tôn Tích rời bế quan lên không trung, còn Tôn Khải Tinh nhận định người đến không có ý tốt."},{"chuong":655,"tieuDe":"Kinh Biến","tomTat":"Nhiễm gia và Triệu gia được nhắc là không còn bằng Tôn gia vì nhiều cao thủ đã rời đi từ lâu. Tại Kỳ Thủy thành, Vương Lâm đang sống lặng lẽ trong Vương gia đại viện như một lão nhân thì Lôi Đạo Tử cưỡi lôi thú xuất hiện trên Nhiễm Vân tinh, dùng thần thức mang lôi uy quét khắp tinh cầu khiến tu sĩ kinh động, yêu vật run rẩy và phàm nhân hôn mê. Ban đầu Lôi Đạo Tử không chú ý tới Vương Lâm và định rời đi, nhưng hắn bất ngờ phát hiện Vương Bình trong một thôn nhỏ không bị thần thức làm ngất. Thanh Nghi bị uy áp làm phun máu nhưng vẫn vận linh lực chắn trước Vương Bình, còn Vương Bình bình tĩnh đối diện Lôi Đạo Tử và hỏi thân phận đối phương. Khi Lôi Đạo Tử nhìn ra Vương Bình không phải người, Vương Lâm ở xa lập tức cảm ứng nguy cơ, bóp tan bầu rượu và ánh mắt bùng hàn quang. Tiên vệ khôi lỗi từ bóng Vương Bình hiện thân, tung quyền đánh xuyên lôi quang khiến Lôi Đạo Tử lùi lại và nhận ra phẩm cấp cực cao của khôi lỗi. Lôi Đạo Tử sau đó gom điện quang vào chân giẫm xuống, phá tan căn phòng và để lôi quang lan rộng, đe dọa trực tiếp Vương Bình cùng Thanh Nghi. Trước nguy cơ ấy, Thanh Nghi nắm tay Vương Bình, còn Vương Bình vẫn không hoảng loạn vì tin phụ thân mình nhất định sẽ tới và là tồn tại mạnh nhất dưới vòm trời."},{"chuong":656,"tieuDe":"Tu Vi","tomTat":"Lôi quang của Lôi Đạo Tử áp sát Vương Bình thì một giọng nói tang thương vang lên chữ Định, khiến điện quang đông cứng; Vương Lâm từ lốc xoáy bước ra, phá tan lôi quang và cứu con trai. Nhận ra thôn dân đã bị thần thức quét qua làm bất tỉnh, Vương Lâm dùng ánh sáng dịu dàng bao lấy Vương Bình và Thanh Nghi, đưa hai người rời khỏi thôn tới bình nguyên phía tây Nhiễm Vân tinh. Lôi Đạo Tử đuổi theo, đòi Vương Lâm giao tiên vệ khôi lỗi để đổi lấy đường sống, nhưng Vương Lâm tuyên bố đối phương suýt giết con trai mình nên hôm nay phải chết. Tiên vệ khôi lỗi lao vào tấn công Lôi Đạo Tử nhưng bị lôi võng vây khốn, còn Lôi Đạo Tử tự xưng sứ giả Lôi Tiên Điện và tin rằng Vương Lâm không dám giết mình. Vương Lâm nuốt trọn lôi quang của đối thủ, tạo lôi cầu hút lôi lực thiên địa, khiến Lôi Đạo Tử phải dùng thiết côn khắc phù thu lôi nhưng pháp bảo này không chịu nổi, nứt vỡ rồi sụp đổ, kéo theo lôi võng tan rã. Sau khi pháp bảo bị phá, Lôi Đạo Tử nhận ra Vương Lâm chính là Hứa Mộc từng giả mạo sứ giả Lôi Tiên Điện, rồi kinh hãi khi thấy tiên lực và ý cảnh của Vương Lâm lần lượt dâng lên tới Vấn Đỉnh hậu kỳ trước khi tạm ngừng."},{"chuong":657,"tieuDe":"Im Mồm","tomTat":"Trên không trung Nhiễm Vân tinh, ý cảnh luân hồi của Vương Lâm hiện thành tranh sơn thủy và hoàng tuyền rồi thu vào thiên linh, khiến Lôi Đạo Tử nhận ra ý cảnh ấy đã chạm tới Vấn Đỉnh hậu kỳ đỉnh nhưng chưa vượt bước đầu tiên. Lôi Đạo Tử ngoài mặt mỉa mai Vương Lâm giả mạo sứ giả Lôi Tiên Điện, song trong lòng vẫn nghi ngờ vì lôi hệ thần thông và lớp che giấu tu vi do ý cảnh nhân quả tuần hoàn tạo ra. Khi Vương Lâm nâng tu vi, thân hình Vương Bình dao động từ linh hồn, còn Thanh Nghi nắm tay trấn an rằng nàng sẽ ở cạnh hắn bất luận thế nào. Lôi Đạo Tử thi triển Lôi chi tiên thú, gọi ra lôi thú của Lôi Tiên Điện để chứng minh thân phận, nhưng Vương Lâm đáp lại bằng Xạ Thần Xa hóa thành Ngân Giác lôi thú có lôi uy áp đảo. Hai lôi thú lao vào tử đấu, khiến Lôi Đạo Tử nổi tham niệm muốn giết Vương Lâm để đoạt thú vô chủ. Hắn dùng phi kiếm bạc và Lôi tiên kiếp tấn công, nhưng Vương Lâm lấy tiên bút vẽ bảy phù văn lôi, dung nhập nguyên thần mang thiên lôi thái cổ, phá tan tử lôi và khiến Lôi Đạo Tử lần đầu thua trên phương diện lôi điện thần thông. Sau khi khôi phục nhờ tiên lực cùng nguyên lực thiên địa, Lôi Đạo Tử uy hiếp sẽ thi triển nguyên lực pháp thuật bước thứ hai nếu Vương Lâm không giao Ngân Giác lôi thú và khôi lỗi. Vương Lâm rút đại kiếm muốn trực diện trải nghiệm nguyên lực thần thông của Âm Hư tu sĩ, nhưng khi Lôi Đạo Tử nhìn sang Vương Bình và nhắc tới một người chết, hắn bùng sát ý đỏ mắt, lạnh lùng quát im mồm."},{"chuong":658,"tieuDe":"Thần Thông Bước Thứ Hai","tomTat":"Lôi Đạo Tử vận dụng thần thông ở hai mắt để nhìn người đứng sau Vương Lâm và phát hiện Vương Bình là oán anh. Khi thấy trong thân thể Vương Bình có hai đạo kiếm khí cực kỳ đáng sợ, hắn lập tức bỏ ý định giao chiến trực diện và quay đầu chạy về phía lôi thú. Vương Lâm nổi giận, nâng đại kiếm thi triển Trảm La quyết bằng nguyên thần phối hợp nguyên lực, khiến Lôi Đạo Tử cảm nhận nguy cơ sinh tử. Bị ép đến đường cùng, Lôi Đạo Tử dùng nguyên lực lôi đỉnh, biến thiên địa thành cự đỉnh màu lam để luyện hóa đối thủ bằng lôi điện và đạo niệm. Trong lôi đỉnh, Vương Lâm chịu đạo niệm thần lôi liên tục oanh kích nhưng vẫn dùng Trảm La quyết chém vào quy tắc thiên địa, khiến cấu trúc đại đỉnh sụp đổ. Tiên vệ khôi lỗi và lôi thú của Vương Lâm cũng cùng công kích, làm đại đỉnh rung chuyển dữ dội và buộc Lôi Đạo Tử tiếp tục tiêu hao nguyên lực để duy trì."},{"chuong":659,"tieuDe":"Một Đời Luân Hồi, Chấm Dứt…","tomTat":"Trong đại đỉnh của Lôi Đạo Tử, thần lôi và lửa tím hợp thành thế lôi hỏa khiến Vương Lâm chịu áp lực nặng nề. Vương Lâm dùng máu vẽ phù văn, mở đạo phong ấn thứ ba trên lôi thú, khiến lôi quang hóa đen và khí tức viễn cổ áp đảo lôi thú của Lôi Tiên Điện. Tiên vệ bộc phát kim quang pha hồng quang, cùng lôi thú và Trảm La của Vương Lâm hợp lực phá nát đại đỉnh, khiến Lôi Đạo Tử trọng thương bỏ chạy. Sau trận chiến, Vương Bình hỏi cha về chân tướng, tự nhận ra mình đã chết từ sớm và chỉ là một tia hồn phách oán anh được kiếm khí cùng pháp thuật duy trì suốt hơn bảy mươi năm. Vương Bình từ biệt Vương Lâm và Thanh Nghi rồi tan thành kiếm khí, chỉ còn dải sáng trắng mang tia oán khí cuối cùng. Vương Lâm xóa sạch tia oán khí ấy, đưa hồn tức Vương Bình vào Thiên Nghịch bên cạnh nguyên anh Lý Mộ Uyển và nhận Uyển Nhi là mẫu thân của con. Thanh Nghi xin được đi theo Vương Bình bằng linh hồn, khẳng định không hối hận, còn Vương Lâm rời đi khi dáng vẻ già nua tan biến, khép lại một đời luân hồi bảy mươi năm."},{"chuong":660,"tieuDe":"Tiên Vệ Thứ Hai","tomTat":"Sau một đời luân hồi gắn với Vương Bình và chính bản thân mình, Vương Lâm nhận ra tu vi đã đột phá tới Vấn Đỉnh trung kỳ, ý cảnh đạt Vấn Đỉnh hậu kỳ, nhưng muốn thật sự phát huy cảnh giới cao hơn vẫn cần tiên ngọc và thiên địa nguyên lực. Hắn tự xét nếu gặp tu sĩ Âm Hư thì có thể chiến nhưng rất gian nan, còn Dương Thực thì không thể địch, nên càng xác định phải tăng tích lũy. Vương Lâm dùng Tinh La bàn truy theo tiên vệ và lôi thú, phát hiện Lôi Đạo Tử đang bị tiên vệ khôi lỗi cùng lôi thú đã giải phong ấn thứ ba vây ép đến nguyên lực gần cạn. Để tránh hậu hoạn từ Lôi Tiên Điện, hắn triển khai sát cục bằng Thất Tinh kiếm trận, Tôn Hồn Phiên, ba chung cực chủ hồn, tiên vệ và lôi thú công phá lôi mạc của Lôi Đạo Tử. Lôi Đạo Tử ngoài mặt xin tha và chấp nhận để Vương Lâm lưu dấu vết, nhưng trong lòng vẫn tính khôi phục nguyên lực rồi phá cấm báo thù. Vương Lâm dùng Cấm Phiên hạ võng cấm chế vào nguyên thần hắn, sau đó đưa hắn tới một tinh cầu xám hoang phế và mở động phủ tạm. Tại đây Vương Lâm lộ mục đích thật là luyện Lôi Đạo Tử thành tiên vệ thứ hai, rồi dùng nguyên thần khí và Côn Cực Tiên rút nguyên thần đối phương khỏi thân thể, mở màn quá trình luyện chế."},{"chuong":661,"tieuDe":"Tham Lang Đáng Thương","tomTat":"Khi Lôi Đạo Tử vừa muốn phản kháng, Vương Lâm lập tức vận dụng tiên vệ khôi lỗi, lôi thú, ba chung cực chủ hồn, Thất Tinh kiếm trận và cấm chế điện quang để khóa chặt nguyên thần hắn, không cho trở về thân thể. Vương Lâm nhân lúc Lôi Đạo Tử trọng thương, nguyên lực gần cạn, dùng nguyên thần khí và cấm chế tế luyện thân thể hắn, khiến Lôi Đạo Tử dần nhận ra mình đang bị luyện thành tiên vệ khôi lỗi. Sau đó Vương Lâm triệu Hoàng Tuyền lực trên tinh cầu bỏ hoang, hút khoáng thạch kim loại từ lòng đất luyện thành ba dịch cầu màu vàng, rồi đặt một dịch cầu vào mi tâm thân thể Lôi Đạo Tử, đẩy thân thể khôi lỗi tới ngân cấp. Trước sự phản kháng của Lôi Đạo Tử, Vương Lâm dùng hai đạo kiếm khí trấn áp và đưa ra điều kiện làm khôi lỗi ba ngàn năm thì sẽ được tự do. Ở Vân Hà tinh thuộc La Thiên Tinh Vực, Tham Lang quần áo rách nát, chật vật thử trốn khỏi tử địa lần thứ tám trong bảy mươi năm cùng một cái đỉnh lớn. Hắn vừa lao khỏi sương mù thì bị xúc tu từ trong tinh cầu quấn lấy kéo trở xuống, tuyệt vọng oán trách Vương Lâm khiến mình lưu lạc tới nơi đáng sợ này."},{"chuong":662,"tieuDe":"Bản Tiên Thuật Thiếu Của Vương Lâm","tomTat":"Nửa năm sau, tại động phủ trên tinh cầu bỏ hoang, Vương Lâm bước ra sau khi tế luyện tiên vệ thứ hai từ Lôi Đạo Tử và đầu lôi thú nhưng thất bại ở bước cuối. Tuy không luyện thành trung phẩm tiên vệ, hắn vẫn giữ được một thân thể ngân cực đỉnh phong, chỉ có thể làm động tác đơn giản dưới thần thức hiện tại. Sau thất bại, Vương Lâm ổn định đạo tâm, thu hai tiên vệ và xác định việc trọng yếu là nâng tu vi bản thân lên ngang bằng ý cảnh. Lôi thú sau khi mở phong ấn thứ ba không chịu trở lại Xạ Thần Xa hay túi trữ vật, tỏ ra linh động như có linh hồn riêng nên hắn tạm để nó tự do. Vương Lâm mở túi trữ vật vô chủ của Lôi Đạo Tử, chú ý ngọc giản khắc lôi thú, lôi kiếm, khoáng thạch bạc và tiên ngọc. Nhờ lôi uy Thái Cổ trong nguyên thần, hắn phá lôi quang trong ngọc giản và phát hiện Đỉnh Hóa Thiên Địa cùng Lôi Nguyên Thuật, trong đó Lôi Nguyên Thuật là bản thiếu hạ phẩm tiên thuật cực kỳ phù hợp với cơ duyên nguyên thần lôi của hắn. Sau đó hắn thu lôi kiếm, thử khoáng thạch bạc khiến lôi đình nhập thể sinh ra chút nguyên lực thiên địa, rồi cất lại để tính toán về sau."},{"chuong":663,"tieuDe":"Bản Tôn, Thác Sâm, Chu Như","tomTat":"Vương Lâm kiểm kê túi trữ vật của Lôi Đạo Tử, phát hiện lượng tiên ngọc cực lớn và từ đó nhận ra nội tình Lôi Tiên Điện vượt xa tưởng tượng. Hắn rời động phủ trên tinh cầu bỏ hoang, san phẳng phạm vi ngàn dặm, bố trí tiên ngọc, Tôn Hồn Phiên, ba chủ hồn và tiên vệ khôi lỗi để bế quan thôn phệ tiên khí tăng tu vi. Ở Liên Minh Tinh Vực, Tử Tâm cùng hai huyết nô Vấn Đỉnh tới điều tra một tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ, nhưng khi thần thức dò sâu thì bị tiếng quát uy nghiêm trong lòng tinh cầu đánh bật và buộc phải rút lui. Tinh cầu sau đó tan vỡ, hai huyết nô tự bạo nguyên thần để giúp Tử Tâm kích hoạt ngọc giản huyết sắc, còn trung tâm tinh cầu lộ ra bản tôn Vương Lâm với tóc đỏ và bốn tinh điểm chưa hoàn chỉnh. Bản tôn thử Trừu Hồn nhưng chưa thành thục, nghĩ tới cổ thần chi khí, Chu Tước Tinh và Thác Sâm, rồi vài tháng sau chọn một tinh cầu có tầng lôi quang tự nhiên để tiếp tục tu luyện. Tại Cổ Thần Chi Địa trong Tu Ma Hải, Thác Sâm khắc đầy tên Vương Lâm trên cột đá, tuyên bố sắp thoát khốn và phái sứ giả rời đi; người này chính là Thiên Ma Tán Nhân vốn đã chết từ lâu. Trên đỉnh Chu Tước Sơn, Chu Như mở túi trữ vật Vương Lâm lưu lại, nhận bạch quang nhập mi tâm, khôi phục ký ức phong ấn và bật khóc khi hiểu Vương Lâm vẫn không muốn nàng đi tìm hắn."},{"chuong":664,"tieuDe":"Tu Đạo Bước Thứ Bốn…","tomTat":"Vương Lâm bế quan hấp thu lượng lớn tiên ngọc trong gần một năm, nhờ nguyên thần biến dị mà đột phá từ Vấn Đỉnh trung kỳ lên Vấn Đỉnh hậu kỳ. Sau khi xuất quan, hắn cưỡi lôi thú ngân sừng đi trong tinh không, khí thế và lôi quang khiến dáng vẻ rất giống sứ giả Lôi Tiên Điện. Trên đường, hắn hồi tưởng hơn chín trăm năm tu đạo, nhớ ân cứu mạng của Chu Dật, suy ngẫm về ba bước tu đạo và tự hỏi liệu sau bước thứ ba còn có bước thứ tư hay không. Vì cần nhiều Thăng Tiên quả và không muốn trở lại ký ức đau buồn ở Nhiễm Vân Tinh, hắn quyết định tới Thiên Huyễn Tinh tìm Huyễn Gia; đồng thời nghĩ tới Vọng Nguyệt trên Vân Hà tinh, Cổ Thần Khí và thần điêu đầu tinh của sứ giả Tu Chân Liên Minh. Lôi thú giáng lâm Thiên Huyễn Tinh tạo lôi vân, lôi đình và uy áp khiến tu sĩ chấn động, buộc Huyễn Phong Thần dẫn Huyễn Gia ra nghênh tiếp. Trước thân phận sứ giả Lôi Tiên Điện mà Vương Lâm thể hiện, Huyễn Phong Thần chấp nhận giao toàn bộ Thăng Tiên quả, dù như vậy là bỏ cơ hội vào Lôi Chi tiên giới sau trăm năm. Khi nhận ra số Thăng Tiên quả ấy vẫn chưa đủ, Vương Lâm nảy ý mượn danh Lôi Tiên Điện để tới La Thiên Bắc Vực chiếm đoạt thêm."},{"chuong":665,"tieuDe":"Phụ Thuộc","tomTat":"Vương Lâm sau khi lấy Thăng Tiên quả của Huyễn gia liền cưỡi Lôi Thú tới Thiên gia trên Thiên Huyễn Tinh. Thiên Quỳ Tử vừa kiêng dè uy danh Sứ giả Lôi Tiên Điện vừa cân nhắc vận mệnh gia tộc, nên yêu cầu xem Lôi Tiên lệnh bài trước khi quyết định. Vương Lâm lấy ngọc giản của Lôi Đạo Tử ra, lôi uy trên đó khiến Thiên Quỳ Tử tin thân phận sứ giả của hắn. Thiên gia giao một nửa Thăng Tiên quả nhưng chỉ hứa sẽ phụ thuộc khi Vương Lâm đạt Âm Dương Hư Thực, khiến Thiên Quỳ Tử sau đó sinh lòng hối hận. Rời Thiên Huyễn Tinh, Vương Lâm tiếp tục dùng danh nghĩa Sứ giả Lôi Tiên Điện quét qua La Thiên bắc vực để thu gom Thăng Tiên quả."},{"chuong":666,"tieuDe":"Bài Tiết","tomTat":"Vương Lâm dùng thân phận Sứ giả Lôi Tiên Điện thu gom lượng lớn Thăng Tiên quả nhưng từ chối nhận gia tộc phụ thuộc. Sau nửa năm, hắn cưỡi Lôi Thú tới Vân Hà Tinh, trên đường tra xét hồn phách lão giả trong Tôn Hồn Phiên để ghi nhớ thần thông chạy trốn. Khi xuyên qua sương mù, hắn bị xúc tu Vọng Nguyệt tập kích, mất Thất Tinh kiếm trận và nhận ra Vọng Nguyệt đang chuyển sang trạng thái công kích. Vương Lâm luyện Thăng Tiên quả thành hồng vụ để gây tê xúc tu, cấy lạc ấn vào phần lớn gốc xúc tu, đồng thời cứu Lôi Thú khỏi vòng vây rồi thu nó lại thành Xạ Thần Xa. Bên trong Vân Hà Tinh, Tham Lang xuất hiện trong nơi bài tiết của Vọng Nguyệt, bị đại đỉnh và xúc tu vây khốn. Khi Thăng Tiên quả đã cạn, Vương Lâm không rời đi mà xuống lòng đất tìm Kim Viêm quáng mạch, nhưng phát hiện tiên lực bất thường nên tạm dừng hấp thu xương để truy xét nguy cơ."},{"chuong":667,"tieuDe":"Tiểu Bảo Vật Của Tham Lang","tomTat":"Vương Lâm men theo xương của Vọng Nguyệt và phát hiện một khe lớn gần chặt đứt bộ xương, dấu vết mà trước kia không tồn tại. Tại khe này, hắn tìm thấy khối sơn thạch cực lớn của Tham Lang đã bị Kim Viêm quáng mạch đồng hóa, nên dùng một tia kiếm khí của Lăng Thiên Hậu để cắt lấy phần có thể tách ra. Khi sắp thành công, một con Vọng Nguyệt nhỏ phục kích từ bùn đất, buộc Vương Lâm dùng Định thân thuật rồi nhanh chóng bỏ chạy. Từ biến hóa bất thường của thân thể Vọng Nguyệt, hắn suy đoán Tham Lang có thể đã động tới thứ nguy hiểm hơn, đặc biệt là Nguyệt Hoa mang kịch độc và nguy cơ tự bạo. Sau khi tìm kiếm mà không gặp thêm cá thể nào, Vương Lâm chuyển hướng tới nơi bài tiết hấp thu để lần theo vật hoặc người bị nuốt vào."},{"chuong":668,"tieuDe":"Rút Xương Cốt Của Vọng Nguyệt","tomTat":"Vương Lâm thận trọng tới gần nơi bài tiết hấp thu của Vọng Nguyệt và phát hiện thần niệm cầu cứu của Tham Lang. Chương hé lộ Tham Lang vì cảm ứng trọng bảo mà lẻn vào Vân Hà Tinh, đào Kim Viêm quáng mạch rồi chạm tới Nguyệt Hoa, cuối cùng bị nuốt vào nơi bài tiết và mắc kẹt gần trăm năm nhờ đại đỉnh thần bí. Vương Lâm nhận ra cứu Tham Lang là tự đưa mình vào hiểm cảnh nên dứt khoát bỏ đi, không tham pháp bảo. Hắn quay lại chỗ xương bị sơn thạch kẹt, gọi Tiên Vệ hộ vệ rồi phá toàn bộ lạc ấn trong chất lỏng Thăng Tiên quả đã cấy vào xúc tu. Lực lượng kỳ dị lan khắp Vân Hà Tinh, khiến xúc tu mất tính công kích trong trạng thái hưng phấn. Nắm thời cơ, Vương Lâm thi triển Đạo hóa Hoàng Tuyền đệ tam thức, dùng Hoàng Tuyền lực rút xương cốt Vọng Nguyệt khiến toàn bộ tinh cầu rung chuyển và vang lên tiếng rống tang thương."},{"chuong":669,"tieuDe":"Vọng Nguyệt Thức Tỉnh","tomTat":"Trong lòng Vân Hà Tinh, Vương Lâm dùng Hoàng Tuyền lực tác động lên hai đầu xương cốt Vọng Nguyệt, khiến bộ xương rung động như vật sống và làm toàn bộ tinh cầu chấn động. Do đã hấp thu nhiều Thăng Tiên quả, đau đớn của Vọng Nguyệt bị biến thành hưng phấn kỳ dị, nhưng thân thể nó vẫn bắt đầu thức tỉnh: xúc tu phun hồng vụ, bùn đất nứt vỡ và khí tức hung thú cổ xưa lan ra. Cảm nhận nguy cơ tăng nhanh, Vương Lâm liều mạng kéo nửa đoạn xương sống bên trái ra khỏi lòng đất bằng toàn bộ tiên lực và thân thể. Hắn triệu Tiên Vệ cảnh giới Âm Hư kéo nửa đoạn xương sống còn lại, khiến hai nửa xương khổng lồ lần lượt được rút lên mặt đất. Vì xương sống quá lớn không thể cất vào túi trữ vật, Vương Lâm phải kéo đi trực tiếp trong lúc xúc tu Vọng Nguyệt quấn giữ. Để phá thế cản, hắn cắn răng lấy Cấm Phiên, pháp bảo đã theo mình hơn chín trăm năm và có chút linh trí."},{"chuong":670,"tieuDe":"Trốn Trốn Trốn!","tomTat":"Cấm Phiên tan vỡ, linh tính vì Vương Lâm mà sinh cũng vì hắn mà diệt, hóa thành cấm chế đánh vào xúc tu của Vọng Nguyệt để mở ra một khoảnh khắc thoát thân. Vọng Nguyệt thức tỉnh khiến Vân Hà Tinh rung chuyển, mặt đất nứt như miệng khổng lồ, tiên lực của Vương Lâm tán loạn nhưng hắn vẫn cùng Tiên Vệ khiêng xương cốt lao vào tầng sương mù. Khi khe nứt truy tới, Vương Lâm gọi Thất Tinh Kiếm Trận trở về rồi lần lượt cho Tử Thử kiếm và sáu kiếm còn lại cùng tà hồn tự bạo, không làm Vọng Nguyệt bị thương đáng kể nhưng khiến nó chậm lại đúng lúc. Sự tan vỡ của Vân Hà Tinh được hé lộ không phải tinh cầu nổ tung từ bên trong, mà là thân thể Vọng Nguyệt xoay mình ngẩng đầu khiến các lục địa bám trên người nó vỡ thành bụi phấn. Vọng Nguyệt phát ra tiếng nói Cổ Thần và thi triển kỹ thuật phá nát của Bát Tinh Cổ Thần, làm bầu trời nứt vỡ, khiến Vương Lâm nghi hoặc vì ký ức Đồ Ti chưa từng ghi nhận khả năng này. Trong sát cơ, Vương Lâm dùng tiếng nói Cổ Thần truyền thừa từ Đồ Ti đáp lại, làm khe nứt tạm ngừng rồi tiếp tục bỏ chạy. Cùng lúc đó, Tham Lang nhân biến động thoát khỏi chỗ bài tiết và hấp thu của Vọng Nguyệt, mang theo Cự Đỉnh, vừa sợ hãi vừa hưng phấn vì cuối cùng nhìn thấy cơ hội rời khỏi nơi tanh tưởi sau trăm năm."},{"chuong":671,"tieuDe":"Trốn Trốn Trốn!","tomTat":"Cấm Phiên của Vương Lâm tự hủy, hóa thành cấm chế màu đen có linh tính để làm các xúc tu của Vọng Nguyệt chậm lại, giúp hắn và Tiên Vệ mang xương cốt Vọng Nguyệt lao về phía tầng sương mù. Vọng Nguyệt thức tỉnh dữ dội, mặt đất Vân Hà Tinh lộ rõ là thân thể của nó, lục địa bám trên thân vỡ vụn còn tiếng rống khiến Vương Lâm và Tiên Vệ bị chấn động. Khi khe nứt truy sát áp sát, Vương Lâm gọi Thất Tinh Kiếm Trận trở về rồi cho Tử Thử kiếm cùng sáu kiếm thể còn lại và tà hồn tự bạo, đổi lấy khoảnh khắc đủ để tiếp tục thoát thân. Sau đó Vọng Nguyệt phát ra tiếng nói Cổ Thần bất thường, khiến Vương Lâm nhận ra nguy cơ từ kỹ thuật phá nát cấp Bát Tinh Cổ Thần và phải dùng tiếng nói Cổ Thần truyền thừa từ Đồ Ti để tạm ngăn khe nứt lan rộng. Trong lúc biến động toàn thân Vọng Nguyệt diễn ra, khu vực bài tiết và hấp thu xuất hiện vết nứt, Tham Lang mang Cự Đỉnh phóng ra với hy vọng thoát khỏi nơi tanh tưởi đã giam giữ hắn lâu ngày."},{"chuong":672,"tieuDe":"Vọng Nguyệt Phẫn Nộ Như Một Chỉ Của Cổ Thần","tomTat":"Tham Lang sau trăm năm bị nhốt trong bộ phận bài tiết của Vọng Nguyệt dốc sức lao tới khe nứt để thoát, nhưng Vương Lâm ném trả nửa đoạn xương Vọng Nguyệt khiến đường thoát của hắn lại bị cản. Khi hiệu lực Thăng Tiên Quả tiêu tán, Vọng Nguyệt nhận ra đó là xương của mình, cơn đau và phẫn nộ bùng phát đúng như ký ức Cổ Thần Đồ Ti từng mô tả. Vương Lâm cùng Tiên Vệ mang nửa xương còn lại lao vào tinh không bằng Tinh La Bàn, đồng thời thử để Thiên Nghịch hấp thụ xương nhưng chưa thành. Vọng Nguyệt truy sát, phun ra ngôn ngữ Cổ Thần và thả đàn Vọng Nguyệt nhỏ; Vương Lâm uống hai giọt tiên tửu để thi triển Định Thân Thuật, tạm khóa đám hung thú nhỏ và ngăn Tham Lang đổi vị trí với mình. Tham Lang kích phát Cự Đỉnh đổi vị trí, hi sinh thọ nguyên để phóng lớn pháp bảo rồi đau lòng bỏ lại khi Vọng Nguyệt bị khí tức của đỉnh hấp dẫn. Cuối cùng Tham Lang lấy bình phong Sơn Hà Đồ chống đỡ, nhưng Vọng Nguyệt huyễn hóa một chỉ Cổ Thần phá tan bình phong, khiến hắn phun máu nguyên thần và tiếp tục bị uy năng ấy ép tới."},{"chuong":673,"tieuDe":"Chạy Đằng Trời!","tomTat":"Vương Lâm nhận ra bình phong trong tinh không mang thần thông Sơn Hà Đồ, liền lợi dụng lúc Cổ Thần Chỉ đang truy đuổi Tham Lang để lao tới đoạt bảo. Hắn thi triển Định Thân Thuật lên Tham Lang, khiến đối phương khựng lại và kéo sự chú ý của ngón tay Cổ Thần, rồi thu bình phong vào túi trữ vật. Tham Lang đội Tôn Tiên Đế Quan, dùng vương miện kim quang có năm hạt châu ngũ hành và linh hồn đế vương để chịu một chỉ, nhưng vẫn bị đánh bay mất tung tích, còn vương miện rơi vào tinh không. Cổ Thần Chỉ sau đó chuyển mục tiêu sang Vương Lâm; Sinh Mệnh Lạc Ấn, Đệ Nhị Tiên Vệ và kiếm khí Lăng Thiên Hậu lần lượt bị phá, cuối cùng nhục thân Vương Lâm tan thành bụi. Một chỉ vô tình phá lớp màng giam nguyên thần, khiến nguyên thần hắn hóa thành thái cổ Lôi Long, phóng lôi cầu cản địch rồi cuốn túi trữ vật, Tiên Vệ và xương Vọng Nguyệt bỏ chạy. Trên đường đào thoát, Vương Lâm dùng thần thức thu thêm vương miện của Tham Lang, tự tổng kết mình mất Thất Tinh Kiếm Trận, Cấm Phiên, kiếm khí và nhục thân nhưng đổi lại đoạt được nhiều bảo vật. Khi Cổ Thần Chỉ tiêu tán, Vọng Nguyệt vẫn do dự nhìn cự đỉnh trên xúc tua rồi tiếp tục truy sát, buộc nguyên thần Vương Lâm dung hợp vào Tinh La Bàn để điên cuồng bỏ chạy."},{"chuong":674,"tieuDe":"Lôi Ngục","tomTat":"Vương Lâm nhập nguyên thần vào Tinh La Bàn, liều mạng chạy khỏi La Thiên Bắc Vực trong tình trạng bị trọng thương, cuối cùng thoát chết khi Vọng Nguyệt dừng lại trước ranh giới Nam-Bắc Vực vì một nỗi kiêng kỵ mơ hồ. Dị thú khổng lồ sau đó quay về gần Ngũ Đại Chủ Tinh, thu cự đỉnh và xúc tua vào thân thể rồi chìm vào giấc ngủ, khiến tu sĩ Bắc Vực hoảng sợ vì khoảng cách quá gần. Cùng lúc, Tham Lang rơi xuống một tinh cầu nguyên thủy, thân thể gần như tan nát nhưng vẫn sống sót; hắn phát hiện phần lớn lạc ấn khống chế trong cơ thể đã bị một chỉ Cổ Thần phá hủy, chỉ còn lạc ấn của Thiên Vận Tử, nên lẩn xuống lòng đất chờ ngày phục hồi. Ở La Thiên Nam Vực, bản năng nguyên thần Lôi Long dẫn Vương Lâm tới một tiểu tinh cầu bị tầng đá che giấu, nơi tràn ngập lôi điện tiên thiên và sinh cơ nồng đậm, rất thích hợp để hắn chữa thương. Tiên Vệ e dè trước thiên lôi nên được để lại bên ngoài hộ pháp, còn Vương Lâm đặt nửa khúc xương Vọng Nguyệt xuống mặt đất rồi ngồi giữa Lôi Ngục hấp thu lôi lực suốt mười năm. Khi nguyên thần hoàn toàn khôi phục, hắn phá vỡ lôi cầu bao quanh, hút lôi pháp vào cơ thể, toàn thân như khoác giáp sấm. Sau đó Vương Lâm vận dụng bí thuật trong Cổ Thần Quyết từ ký ức Đồ Ti, dẫn lôi điện trong Lôi Trì ngưng tụ xương tay, khung xương rồi rút lôi lực toàn tinh cầu để tiếp tục tái tạo thân thể mới."},{"chuong":675,"tieuDe":"Thiên Nghịch Hấp Thu Và Bảo Vật Của Tham Lang!","tomTat":"Sau một giáp hấp thu lôi quang và sinh cơ trên tinh cầu lôi quang, Vương Lâm phá kén bước ra với thân thể mới, máu thịt ẩn chứa sức mạnh sấm sét tương hỗ với nguyên thần lôi quang. Hắn bố trí hộ pháp bằng Tôn Hồn Phiên, ba chủ hồn và Đệ Tứ Hồn rồi cẩn thận lấy Thiên Nghịch Châu từ mi tâm ra, đặt lên dãy núi do xương Vọng Nguyệt hóa thành để hấp thu Kim Viên Quáng. Trong lúc chờ Thiên Nghịch hấp thu chậm, Vương Lâm kiểm tra những bảo vật đoạt từ Tham Lang, dùng núi đá tiên giới để rút Sơn Hồn và hiểu thêm giá trị cảm ngộ thần thông rút linh hồn linh vật của Đệ Nhị Bộ. Hắn tiếp tục xem xét bình phong Sơn Hà Đồ, nhận ra đó chỉ là bản in lại của Sơn Hà Thiên Đạo Đồ, bèn lưu lạc ấn và đưa vào nguyên thần tế luyện. Với Vương Miện, hắn phát hiện năm hạt châu ngũ hành có linh tính, nhớ tới Hồng Điệp rồi thử dùng đóa hồng lam, khiến đóa hồng tan thành lam quang dung nhập vào pháp bảo và để lại bóng người múa kiếm mơ hồ. Ba tháng sau, Kim Viên Quáng bị hấp thu hết, thuộc tính kim của Thiên Nghịch viên mãn; Vương Lâm nhỏ máu dung hợp thần thức lạc ấn lên hạt châu, khiến một phù văn cổ xưa tang thương hiện ra trong tâm thần và được hắn vẽ ra trước người."},{"chuong":676,"tieuDe":"Thiên Nghịch Viên Mãn","tomTat":"Khi khí tức tang thương tràn ngập tinh cầu lôi quang, Vương Lâm đưa phù văn vào Hạt Châu Thiên Nghịch, khiến tử quang mục nát bùng phát và ăn mòn mọi thứ xung quanh. Tiên Vệ cùng tam đại chủ hồn trong Tôn Hồn Phiên cũng bị tử quang ảnh hưởng, buộc hắn phải lập tức thu hồi để tránh chúng tan rã. Tử quang lan khắp tinh cầu, phá hủy mặt đất và tầng đá ngoài, đồng thời hình thành cấm chế mạnh đến mức sinh linh không thể tiến vào, như cắt đứt khu vực này khỏi La Thiên Tinh Vực. Sau khi lực ngũ hành tích lũy trong Thiên Nghịch bị phóng xuất hơn phân nửa, một cánh cửa màu tím khổng lồ hiện ra giữa thiên địa, khiến Vương Lâm sinh nỗi sợ từ linh hồn. Hắn nhớ tới thời thiếu niên ở Hằng Nhạc Phái nhưng vẫn dùng đạo niệm bất khuất để chống lại nỗi sợ, vì phải bảo vệ hồn phách của mình và Uyển Nhi trong Thiên Nghịch. Khi tử quang ngoài cửa hóa thành cánh tay khổng lồ vẫy gọi, Vương Lâm không bước vào mà ném xương Vọng Nguyệt để thử; cánh tay chỉ sờ nhẹ đã làm xương tan vỡ và khiến trời đất, tinh không cùng khu vực quanh tinh cầu bị xé nát."},{"chuong":677,"tieuDe":"Thiên Nghịch Triệu Tập","tomTat":"Cánh tay khổng lồ sau cánh cửa thiên địa tiếp tục vẫy gọi Vương Lâm, khiến hắn nhận ra cái sờ nhẹ của nó là một loại quy tắc cực mạnh, vượt xa cảm nhận thông thường của hắn. Sau khi cánh tay và cánh cửa biến mất, tử quang co lại thành Thiên Nghịch Châu rơi về tay Vương Lâm, nhưng bề mặt hạt châu đã không còn ngũ hành lực. Hắn dùng thần thức kiểm tra, thấy nguyên anh Lý Mộ Uyển, Vương Bình và hồn phách Thanh Nghi vẫn còn trong châu, thậm chí linh động hơn trước, rồi suy đoán về những chủ nhân Thiên Nghịch từng khiến ngũ hành viên mãn và có thể đã tiến vào cánh cửa. Vì Lôi Quang tinh cầu đã thành phế tích, Vương Lâm quyết định đi sâu vào tầng đá vụn tìm nguồn lôi quang để tu luyện Lôi Nguyên Thuật. Hắn lấy Xạ Thần Xa hóa thành Lôi Thú; Lôi Thú cảm nhận hắn như một đạo sấm sét nên vừa kinh ngạc vừa thân thiết, chở hắn xuyên qua khu vực đá vụn ngày càng dày. Cuối cùng Vương Lâm phát hiện phía trước không phải tinh cầu mà là vùng không gian đầy vô số Lôi Trì khổng lồ, sấm sét cuồng bạo như địa ngục lôi điện. Hắn thả khôi lỗi Tiên Vệ hộ pháp, bước vào rìa Lôi Trì tới cực hạn rồi khoanh chân thổ nạp, trong khi Lôi Thú cũng hấp thu lôi điện bên ngoài."},{"chuong":678,"tieuDe":"Thiên Nghịch Kinh Biến","tomTat":"Một người đàn ông tóc đen cưỡi Lôi Thú khoác giáp đen bay trong tinh không về phía tầng đá vụn Nam Vực La Thiên, định vào Lôi Ngục hấp thụ nguyên lực trước khi Lôi Tiên Giới mở ra. Hắn nhắc tới truyền thuyết hạt châu Thiên Nghịch lần đầu xuất hiện tại tầng đá vụn này, từ đó sinh ra dị biến Lôi Đình và biến nơi đây thành Lôi Ngục. Trong Lôi Trì, Vương Lâm đọc hiểu Lôi Nguyên Thuật, dùng thủ ấn dẫn Lôi Đình nhập thể và chuyển hóa được một tia nguyên lực pha tạp. Khi hắn định đưa tia nguyên lực vào nguyên thần luyện hóa, nó mất khống chế lao tới mi tâm nguyên thần và dung nhập vào Thiên Nghịch, khiến nguyên thần cùng thân thể chấn động mạnh. Thiên Nghịch sau đó tự bay ra khỏi mi tâm Vương Lâm, làm Lôi Trì bạo loạn, khiến Tiên Vệ và Lôi Thú phải lùi xa, đồng thời hút vô số Lôi Long từ bốn phương tám hướng. Khi hạt châu hấp thu lôi điện, tử quang, cấm chế kỳ dị và cánh cửa lớn từng xuất hiện trước đó lại hiện ra giữa trời đất. Chương khép lại bằng việc xác lập rằng Vương Lâm vô ý đưa Thiên Nghịch trở về nơi nó từng lần đầu xuất hiện, và cảm giác dẫn hắn tới đây có liên quan sâu tới chính Thiên Nghịch."},{"chuong":679,"tieuDe":"Tầm Đạo Giả, Vong Sinh Tri Tử, Hám Nhĩ…","tomTat":"Sau khi ngũ hành viên mãn, Thiên Nghịch biến hóa, nhận chủ Vương Lâm và được hắn hấp thu vào nguyên thần. Cánh cửa Thiên Địa lại hiện ra giữa Lôi Trì, tử quang phủ khắp, còn cánh tay khổng lồ bên ngoài cửa bị vô số lôi điện màu tím quấn lấy trấn áp. Vương Lâm nhận ra đây là cơ hội hiếm có nên giữ sẵn đường lui rồi mạo hiểm lao tới khe cửa; khi cửa mở, thân thể hắn dừng ngoài khe hở còn tâm thần bị hút vào không gian Thiên Nghịch. Trong không gian ấy, hắn chứng kiến vật sáng bành trướng thành tinh cầu có đại lục, sông biển và linh khí, rồi lại thoái hóa về vật sáng như thời gian đảo ngược, khiến tâm thần dần chìm vào trạng thái quên hết. Hắn tiếp tục quan sát sinh diệt, theo bản năng truy tìm nguồn lực lượng thần bí và dấu chân của Đạo. Sau đó, Vương Lâm gặp một tinh cầu ấm áp cùng hai tinh cầu nhỏ mang khí tức quyến luyến; khi hắn chạm vào hư vô, ba tinh cầu hóa thành ba luồng hào quang nhập vào đầu hắn. Từ đó hắn dừng truy tìm, bản thân hóa thành vật sáng rồi bành trướng thành một tinh cầu có núi sông, biển cả và sinh hoạt phàm tục. Trên tinh cầu này có một nam một nữ ở phía bắc và một cô gái áo trắng ở phía nam; qua vô số năm tháng, tinh cầu biến đổi nhưng ba người ấy là điều duy nhất không biến mất."},{"chuong":680,"tieuDe":"Thấy Được Bước Thứ Ba","tomTat":"Vương Lâm tỉnh khỏi cảnh giới kỳ dị trong Thiên Nghịch sau khi chứng kiến biến hóa sinh tử, nhân quả và tự hỏi đó có phải là Đạo. Qua hình ảnh Lý Mộ Uyển, Vương Bình và Thanh Nghi, hắn nhận ra đạo sinh tử luân hồi cùng đạo nhân quả của mình, rồi bị một lực lượng mạnh đẩy nguyên thần trở lại bên ngoài cánh cửa lớn giữa lôi đình và tử quang. Khi cánh cửa khép lại, tử quang co rút thành Thiên Nghịch Châu, lạc ấn ngũ hành trên châu biến mất và thay bằng âm dương ngày đêm chia đôi trước khi dung nhập mi tâm hắn. Vương Lâm hiểu cơ duyên lần này không trực tiếp tăng tu vi nhưng làm tâm cảnh thăng hoa, quý đến mức ngay cả Thiên Vận Tử cũng có thể đánh đổi tất cả để cầu được; hắn đã nhìn thấy khí tức bước thứ ba. Sau đó, một người đàn ông tóc đen cưỡi Lôi Thú mặc áo giáp tiến vào tầng đá vụn, nhận ra lôi quang và khí tức nơi Lôi Ngục biến động khác thường. Người này vốn có tu vi Dương Thực, quen đến Lôi Trì tu luyện Lôi Nguyên Thuật, nhưng khi thấy Vương Lâm lơ lửng bên trên Lôi Trì đã rút nhỏ gần một nửa, hắn lập tức kinh hãi. Vương Lâm mở mắt, ánh mắt còn lưu tàn ảnh cảm ngộ bước thứ ba khiến đối phương bị chấn nhiếp, tim máu và nguyên lực đều rối loạn như sắp sụp đổ."},{"chuong":681,"tieuDe":"Người Thứ Nhất Dựa Vào","tomTat":"Vương Lâm tỉnh khỏi cảnh mộng tầm đạo do Thiên Nghịch mở khe hở, nhưng dư uy trong ánh mắt vẫn khiến người đàn ông tóc đen và tọa kỵ Lôi Thú bị áp chế đến mức sinh tử mong manh. Sau khi thoát khỏi áp lực ấy, người đàn ông tóc đen nhận định cảnh tượng vừa rồi giống Đạo Yểm trong truyền thuyết La Thiên, từ sợ hãi chuyển sang sùng kính. Vương Lâm tự nhận cơ duyên lần này đã cho hắn thấy con đường tới bước thứ ba Tu Đạo, khiến tâm tính, linh hồn và ý cảnh có biến hóa lớn. Người đàn ông tóc đen tự xưng là Thân Công Hổ, Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên, tu sĩ Dương Thật, rồi quỳ xin dựa vào Vương Lâm. Khi bị từ chối, hắn rút Đạo Hồn chứa ý cảnh và đạo niệm để làm bảo chứng nương tựa ngàn năm, và Vương Lâm cuối cùng thu Đạo Hồn vào nguyên thần. Thân Công Hổ sau đó giải thích mình đến Lôi Trì để tu luyện trước khi Lôi Tiên Giới mở ra sau mười năm, đồng thời nói về Lôi Đỉnh, giới hạn tu vi vào giới và bí pháp Lôi Tiên Điện. Vương Lâm bộc lộ mình không phải người La Thiên Tinh Vực, nắm được giá trị của Lôi Tiên Giới đối với việc tìm tiên ngọc tu luyện, rồi cho phép Thân Công Hổ ở lại Lôi Trì nhưng không được quấy rầy mình."},{"chuong":682,"tieuDe":"Lôi Nguyên Ngưng Tụ","tomTat":"Thân Công Hổ được Vương Lâm cho ở lại Lôi Trì, bề ngoài cảm kích nhưng thực chất đạo tâm đã bị ánh mắt của Vương Lâm làm cho khiếp sợ, lại vì đã giao đạo hồn nên trong tiềm thức chịu khuất phục. Vương Lâm tiến sâu khoảng trăm bước vào Lôi Trì rồi khoanh chân tu luyện, khiến Thân Công Hổ càng sùng kính vì bản thân hắn khó chịu nổi khoảng cách ấy. Lôi Thú của Thân Công Hổ bị Lôi Thú sừng bạc của Vương Lâm áp chế, còn Tiên Vệ ngồi trên đá vụn canh chừng. Vương Lâm dùng Lôi Nguyên Thuật hấp thụ lôi đình, rút nguyên lực pha tạp để luyện hóa vào nguyên thần, đồng thời chương giải thích nguyên lực của hắn đã xuống rất thấp sau trận với Lôi Đạo Tử do chưa có Vấn Đỉnh Chi Tinh. Trong hai năm tu luyện, hắn tăng dần lượng lôi đình hấp thụ, còn Thân Công Hổ cũng chăm chỉ chữa thương và quan sát. Vương Lâm nhận ra công pháp của Thân Công Hổ tuy giống Lôi Nguyên Thuật nhưng hiệu suất chuyển hóa cao hơn nhiều, từ đó hiểu thêm khác biệt giữa các cảnh giới bước tu đạo thứ hai. Sau khi ghi nhớ cảm ngộ bước thứ ba và có chút thu hoạch, hắn đứng dậy, xác định lôi đình gần trung tâm Lôi Trì chứa nguyên lực vượt xa vùng ngoài, rồi cẩn thận bước sâu hơn, dẫn động vô số lôi đình lao tới."},{"chuong":683,"tieuDe":"Quy Luật Của Sấm Sét","tomTat":"Vương Lâm dùng thân thể do lôi đình biến thành và nguyên thần mang lôi uy để thử tiến vào Lôi Trì, nhưng chỉ đi được mười bước thì cảm thấy nguyên thần không thể chịu nổi uy thế nơi đây. Thân Công Hổ chứng kiến cảnh đó thì thất vọng, cho rằng tiền bối mà mình sùng kính cũng chỉ đạt mức hắn có thể chạm tới khi vào Khuy Niết sơ kỳ. Vương Lâm không tiếp tục cưỡng ép mà nhìn sâu vào Lôi Trì, dần quên hết ngoại giới và tiến vào trạng thái cảm ngộ tương tự khi từng nhìn vào không gian Nghịch Thiên. Từ trong vô số lôi đình, hắn nhận ra các tia sáng ẩn hiện và mỗi bước tiếp theo đều hạ đúng nơi lôi quang xuất hiện, khiến Thân Công Hổ kinh hãi rồi cuồng nhiệt trở lại. Lôi Thú mặc giáp của Thân Công Hổ cảm nhận sâu hơn rằng Vương Lâm không được Lôi Trì nghênh đón, mà như đang đạp lên chính Lôi Trì, nên sinh ra kính sợ từ linh hồn. Lôi Thú sừng bạc của Vương Lâm cũng đứng bật dậy vì chấn động. Khi tỉnh khỏi cảm ngộ, Vương Lâm hiểu rằng nhận thức mới về sấm sét có liên hệ tới bước thứ ba và còn quan trọng hơn tiên thuật, pháp bảo đối với hắn."},{"chuong":684,"tieuDe":"Nghi Ngờ Bên Tai","tomTat":"Vương Lâm tỉnh lại ở vòng trong Lôi Trì, phát hiện nơi này có lôi đình dày đặc và thiên địa nguyên lực mạnh hơn hẳn bên ngoài, nhưng mỗi lần thổ nạp đều khiến thân thể cùng nguyên thần bị tê liệt, vận chuyển chậm chạp. Trong lúc Thân Công Hổ còn đang kích động vì những gì đã chứng kiến, Chiến Không Liệt thuộc Chiến gia cưỡi kiếm gỗ màu tím tiến vào, lập tức khiến bầu không khí trở nên căng thẳng. Chiến Không Liệt nhìn thấy Vương Lâm ở vị trí sâu trong Lôi Trì, lại thấy Lôi Thú sừng bạc và Tiên Vệ con rối bên cạnh, nên nghi ngờ Vương Lâm có pháp bảo cực mạnh, ẩn giấu tu vi hoặc liên quan tới Lôi Tiên Điện. Thân Công Hổ dựa vào sự hiện diện của Vương Lâm để uy hiếp Chiến Không Liệt rời đi trong ba nhịp thở, còn Chiến Không Liệt vừa thăm dò vừa chuẩn bị lôi pháp và kiếm khí để giao chiến. Vương Lâm hiểu mình chưa đủ sức trực tiếp đối đầu với hai người, nên dùng lời nói biến trận chiến thành khảo nghiệm dành cho Thân Công Hổ, đồng thời tuyên bố nếu Thân Công Hổ thất bại sẽ trả lại đạo hồn. Thân Công Hổ vì thế chiến ý bừng lên và công khai gọi Vương Lâm là Tôn chủ, khiến Chiến Không Liệt chấn động mạnh trước quan hệ thần phục bất ngờ này."},{"chuong":685,"tieuDe":"Lão Tử Rất Lợi Hại Đấy","tomTat":"Trong Lôi Trì, Chiến Không Liệt suy xét cách Thân Công Hổ gọi Vương Lâm là Tôn Chủ và dần nghi rằng Vương Lâm không đơn giản dựa vào pháp bảo, mà có thể là tiền bối ẩn tu che giấu tu vi. Thân Công Hổ vì muốn thể hiện trước mặt Vương Lâm đã nuốt đan dược phát hồng quang, cưỡng ép áp chế thương thế rồi dùng Dẫn lôi thuật giao chiến với Chiến Không Liệt. Hai tu sĩ bước thứ hai va chạm bằng lôi quang và kiếm khí, tạo chấn động lớn khiến cả hai đều bị đẩy lui. Vương Lâm quan sát trận đấu, dựa vào kinh nghiệm từng thấy cấp độ bước thứ ba và cảm nhận quy luật sấm sét trong Lôi Trì để chỉ ra Dẫn lôi thuật có lôi uy nhưng thiếu lôi hồn. Hắn thu một đạo lôi quang vào lòng bàn tay, khiến nó tiêu tán chỉ còn ánh sáng thoáng qua, mượn đó gợi ý cho Thân Công Hổ về căn nguyên của sấm sét. Thân Công Hổ nhờ vậy như phá được tầng ngăn cách trong nhận thức và càng sùng bái Vương Lâm. Chiến Không Liệt cũng càng tin Vương Lâm là cao nhân, cung kính nhận lỗi rồi nói mình đã nhận thư triệu tập của Lôi Tiên Điện, sau này sẽ cùng Thân Công Hổ làm sứ giả, rồi rời khỏi nơi này."},{"chuong":686,"tieuDe":"Lão Tử Rất Lợi Hại Đấy","tomTat":"Chiến Không Liệt từ cách Thân Công Hổ gọi Vương Lâm là Tôn Chủ mà sinh nghi, cho rằng Vương Lâm có thể là tiền bối ẩn tu chứ không chỉ dựa pháp bảo để vào vòng trong Lôi Trì. Thân Công Hổ nuốt đan dược của Lôi Tiên Điện, cưỡng ép khôi phục khí tức rồi dùng Dẫn lôi thuật giao thủ với Chiến Không Liệt, nhưng bị Vương Lâm nhìn ra thần thông có lôi uy mà thiếu lôi hồn và căn nguyên. Vương Lâm biểu diễn lôi quang quy về căn nguyên khiến Thân Công Hổ ngộ đạo, còn Chiến Không Liệt cúi đầu nhận hắn là tiền bối, nói rõ chuyện thư triệu tập và cơ chế sứ giả Lôi Tiên Điện rồi rời đi. Sau tổng cộng mười năm tu luyện trong Lôi Trì, Vương Lâm nhờ Lôi nguyên thuật đạt mức nguyên lực ổn định, nguyên thần bão hòa nhưng không thể hấp thụ thêm vì tu vi chưa đủ, nên cưỡi Lôi Thú sừng bạc rời đi cùng Tiên Vệ. Trên đường, hắn xác định hai mươi năm sau phải tới Lôi Tiên Giới, trước đó cần nâng tu vi, tìm hiểu Thiên Nghịch Châu, chỉnh lý thần thông và kiếm một tu chân tinh thuộc về mình tại La Thiên Tinh Vực. Khi tới một tinh cầu gợi nhớ Chu Tước Tinh, Hứa Lập Quốc trong tiên kiếm khoe đã nuốt kiếm ý viễn cổ nhưng lập tức bị Vương Lâm trấn áp. Vương Lâm đặt chân lên Thanh Linh Tinh, chọn Hoành Vân Phong làm nơi dừng chân, đúng lúc gia chủ Trương gia là Trương Tân Hải lên núi chuẩn bị tọa hóa và kinh sợ vì thấy hắn bằng mắt thường trong khi thần thức không phát hiện được."},{"chuong":687,"tieuDe":"Tu Chân Tinh Của Ta","tomTat":"Vương Lâm hiện thân trên Hoành Vân Sơn Phong và chỉ bằng khí tức đã khiến Trương Tân Hải nhận ra chênh lệch lớn giữa hai người. Hắn xua tan tử khí tích tụ qua vô số năm trên ngọn núi, dùng linh quyết thiêu đốt linh lực để kéo dài tuổi thọ cho Trương Tân Hải thêm mười năm, đồng thời nhớ tới tiếc nuối về Lý Mộ Uyển trong Thiên Nghịch Châu. Sau đó Vương Lâm giao Trương Tân Hải nhiệm vụ trong mười năm phải thu thập oán khí phàm nhân càng nhiều càng tốt, đổi lại bảo đảm hương hỏa Trương gia khi hắn còn ở Thanh Linh Tinh. Vương Lâm cắm Tôn Hồn Phiên, thả hồn phách và ba đại chủ hồn bao phủ Hoành Vân Sơn Phong, mở động phủ rồi truyền thần niệm khắp tinh cầu tuyên bố Thanh Linh Tinh là tu chân tinh của mình và ngọn núi là cấm địa. Trong năm năm sau, Trương gia cùng các gia tộc tu chân bôn ba thu oán khí nhưng mới đạt chưa đến bốn phần. Còn Vương Lâm ở trên đỉnh núi tế luyện Sơn Hà Đồ, sơn thạch tiên giới, nghiên cứu vương miện hoa hồng màu lam của Hồng Điệp và nhận ra Côn Cực Tiên là pháp bảo duy nhất của hắn ẩn chứa phương hướng bước thứ ba."},{"chuong":688,"tieuDe":"Pháp Khí Đại Diện Cho Nhân Quả Ý Cảnh","tomTat":"Vương Lâm suy xét Côn Cực Tiên và đạo nhân quả, nhận ra bản thể có thể xem là nhân, nguyên thần là quả, từ đó tìm được cách dùng pháp bảo này làm vật đại diện cho nhân quả ý cảnh. Ý cảnh của hắn đang chuyển từ sinh tử luân hồi sang nhân quả, chưa thể thực chất hóa hoàn toàn như trước kia nhưng đã mở ra phương hướng cho bước thứ ba. Vì chuẩn bị tiến vào Lôi Chi Tiên Giới, hắn ở lại Hoành Vân Phong tế luyện Côn Cực Tiên suốt ba năm, trong khi danh hiệu lão tổ Thanh Linh Tinh ngày càng lan rộng và màn sương đen quanh núi trở thành vùng cấm. Hứa Lập Quốc phá được phong ấn túi trữ vật, liên tục kêu gào đòi đổi vai chủ tớ với Vương Lâm, rồi khi được thả ra liền hóa thành đại kiếm mang viễn cổ kiếm ý lao tới. Vương Lâm không tự động thủ, chỉ để Côn Cực Tiên bay lên, tỏa khí tức quỷ dị và hóa thành vòng tròn nhân quả khiến đại kiếm tan rã. Hắn tuyên bố viễn cổ kiếm ý của Hứa Lập Quốc có nhân là do mình, nên quả phải thuộc về mình, khiến Hứa Lập Quốc hoảng sợ cầu xin và cố dùng chính lý nhân quả để phản biện nhưng không lay chuyển được Vương Lâm."},{"chuong":689,"tieuDe":"Đại Viên Mãn Và Ác Thú Hứa Lập Quốc","tomTat":"Côn Cực Tiên dung nhập vào hư vô của ý cảnh, khiến Hứa Lập Quốc hoảng sợ khuất phục và vội nịnh nọt Vương Lâm. Vương Lâm cho hắn tạm hoạt động trong phạm vi quanh Hoành Vân Phong để lĩnh ngộ viễn cổ kiếm ý, đồng thời thả Văn Thú, Lôi Oa và Xạ Thần Xa, khiến Xạ Thần Xa hóa thành Lôi Thú rồi đối địch với Lôi Oa. Sau đó, Vương Lâm chuyển trọng tâm từ tế luyện pháp bảo sang rà soát thần thông, nhận ra Trảm La Quyết, Định Thân Thuật, ba chỉ pháp Tịch Diệt, Hóa Ma, Hoàng Tuyền và tam thức đạo niệm Hoàng Tuyền cần được điều chỉnh theo cảm nhận về bước thứ ba. Trong hai năm hắn suy luận không ngừng, Hứa Lập Quốc lén dùng ảo thuật lừa tu sĩ quanh vùng, rồi khi Trương Tân Hải dẫn con tới giao oán khí, hắn còn định tạm dung nhập thân thể người con nên bị Vương Lâm cấm túc. Vương Lâm chấp nhận con trai Trương Tân Hải làm sứ giả kế nhiệm, ban đan dược, giao nhiệm vụ thu oán khí định kỳ và đưa hạt giống Thăng Tiên Quả cho Trương gia gieo trồng trong mười năm. Oán khí phàm nhân được hấp thu vào Hoàng Tuyền, khiến thần thông này có bóng dáng Tuyền Hồn, còn sinh tử luân hồi ý cảnh của Vương Lâm đến năm thứ mười tám ở Thanh Linh Tinh thì hoàn toàn viên mãn. Cuối cùng, Vương Lâm bày trận tiên ngọc ở hoang mạc tây bắc Thanh Linh Tinh, dùng hết tiên ngọc rồi uống tiên dịch, đạt Vấn Đỉnh viên mãn sau mười chín năm tám tháng. Khi cảnh giới đã viên mãn, hắn lấy tiên bút kim quang vẽ liền tám nét ký hiệu, vượt cực hạn bảy nét trước kia và nhận ra uy lực tăng thêm một bậc."},{"chuong":690,"tieuDe":"Đoạt Lôi Đỉnh","tomTat":"Sau khi kết thúc việc ở Thanh Linh Tinh, Vương Lâm cưỡi Lôi Thú rời đi, mang theo Thăng Tiên Quả và ngọc giản chứa oán khí. Biết muốn vào Lôi Tiên Giới cần có Lôi Đỉnh, hắn không muốn dựa nhiều vào Thân Công Hổ nên quyết định tự đoạt một chiếc. Dựa vào ngọc giản của Thân Công Hổ, hắn chọn Thánh Đàn Tinh, nơi có hai gia tộc thường nhận nhiều Lôi Đỉnh, rồi ngồi chờ trong tinh không. Khi đội tu sĩ trở về, lão già Trương gia vừa đạt Âm Hư nghi hắn giả mạo sứ giả Lôi Tiên Điện và cự tuyệt yêu cầu giao đỉnh. Vương Lâm gọi khôi lỗi Tiên Vệ giao chiến, phá khiên lửa của đối phương, rồi lấy Tiên Sơn thi triển Trừu Linh Chi Lai khiến lão già kinh hãi. Chương kết khi Vương Lâm tiếp tục ngưng tụ lôi điện thực chất hóa trong tay phải, đẩy áp lực của trận đoạt đỉnh lên cao."},{"chuong":691,"tieuDe":"Có Lợi Hơn Rất Nhiều","tomTat":"Vương Lâm áp đảo lão già Âm Hư, đoạt lấy Lôi Đỉnh rồi không rời đi ngay mà muốn đổi lấy thần thông Đệ Tam Nhãn. Ban đầu lão già chê Tịch Diệt Chỉ và Hóa Ma Chỉ, nhưng khi Vương Lâm dùng khôi lỗi Tiên Vệ bắt mãnh thú và thi triển Sát Lục Tiên Quyết, lão nhận ra giá trị công thủ của thuật này. Sau khi Vương Lâm giả vờ bỏ đi, lão già đồng ý đổi Đệ Tam Nhãn lấy ba thuật, nhưng cố ý ghi sai vài chỗ trong ngọc giản. Vương Lâm nhìn ra mưu tính đó, cảnh báo giới hạn Sát Lục Chi Khí rồi rời đi, trong lòng cho rằng mình lời lớn vì Đệ Tam Nhãn ẩn chứa phương hướng bước thứ ba. Trở lại Hoành Vân Phong, hắn tu chỉnh Đệ Tam Nhãn hơn nửa tháng. Khi Lôi Đỉnh dẫn Tiên Lôi chuẩn bị đưa hắn vào Lôi Tiên Giới, Vương Lâm cố ý thu đỉnh và nuốt hai đạo Tiên Lôi để hấp thụ nguyên lực."},{"chuong":692,"tieuDe":"Chưa Ai Từng Làm","tomTat":"Trên Thanh Linh Tinh, mây sấm không tan sau hai đạo Tiên Lôi mà tiếp tục ngưng tụ thành đạo thứ ba mạnh hơn rất nhiều. Vương Lâm để nguyên thần mang Lôi Đỉnh bay lên, hóa hình có vài phần giống Thái Cổ Lôi Long và nuốt một nửa đạo lôi. Phần lôi đình còn lại bị Lôi Đỉnh tiếp nhận, khiến chiếc đỉnh hút trọn cơn lốc sấm sét rồi nứt vỡ hoàn toàn. Sự kiện này tạo tiền lệ chưa từng có, làm Lôi Tiên Giới mất vĩnh viễn một Lôi Đỉnh và một chỉ tiêu tiến vào. Cuồng lôi từ Lôi Đỉnh vỡ cuốn lấy Vương Lâm, phá nát hư không và kéo hắn tới cửa Lôi Tiên Giới với tốc độ dữ dội. Trên đường, nhiều tu sĩ La Thiên Tinh Vực đang được lôi quang dẫn dắt kinh hãi khi thấy luồng sao băng lôi đình lao vụt qua."},{"chuong":693,"tieuDe":"Lôi Tiên Giới","tomTat":"Trước cửa Lôi Tiên Giới, các tu sĩ nhìn thấy lối vào không phải cánh cửa bình thường mà là đạo sấm sét đỏ sậm khổng lồ, theo truyền thuyết do tiên hồn sau khi tiên giới sụp đổ hóa thành. Nhiều sứ giả Lôi Tiên Điện và độc tu La Thiên Tinh Vực khoanh chân chờ cửa mở, trong đó có Thân Công Hổ. Đường Ngôn Phong mỉa mai Thân Công Hổ vì phụ thuộc Tôn Chủ và đạo hồn không đầy đủ, nhưng Thân Công Hổ không hối hận dù từng chịu áp lực từ gia tộc và Lôi Tiên Điện. Đúng lúc đó, sao băng lôi đình của Vương Lâm lao tới với tốc độ khiến thần thức mọi người không kịp bắt, va thẳng vào sấm sét đỏ sậm và biến mất vào trong trước khi cửa mở. Một tu sĩ Âm Hư dùng phân thân thử cửa liền bị tia chớp truy diệt cả thân thể, nguyên thần và túi trữ vật. Thân Công Hổ nhờ đạo hồn cảm nhận khí tức Tôn Chủ trong sao băng, còn bên trong Lôi Tiên Giới, một lão già tóc bạc trên lôi sơn đen cảm ứng dị biến rồi hóa thành tinh điểm biến mất."},{"chuong":694,"tieuDe":"Người Có Duyên","tomTat":"Lưu tinh lôi đình kéo Vương Lâm xuyên vào tia chớp đỏ sậm của Lôi Tiên Giới, lôi lực tăng mạnh khóa chặt thân thể và nguyên thần rồi nện hắn xuống một vùng đại lục. Vương Lâm trọng thương dưới đáy hố, trong khi lão giả tóc bạc xuất hiện bên miệng hố, nhận ra nguyên thần và thân thể hắn đều liên quan lôi điện, còn cảnh báo con đường này có thể khiến hắn thành lôi linh. Thấy vị trí Vương Lâm rơi xuống có chút thú vị, lão xem là có duyên và dùng thần thông tác động vào mặt đất trước khi biến mất. Vương Lâm tỉnh lại trong thạch thất sụp đổ dưới lòng đất, phát hiện một tia lôi lực không hòa hợp trong nguyên thần nên thổ nạp bảy ngày để khu trừ, có khôi lỗi Tiên Vệ hộ pháp. Khi thử thoát ra, hắn bị bùn đất chứa thiên địa nguyên lực bắn ngược, nhận ra có người cố ý giam cầm các hướng. Không còn lựa chọn, hắn lấy tiên bút, dùng tiên lực mở đường vào thông đạo phía trước, nhưng các cửa ra liên tục lóe sáng rồi biến mất trước khi hắn tiếp cận."},{"chuong":695,"tieuDe":"Muốn Giết Người !","tomTat":"Vương Lâm nhiều lần vồ hụt cửa ra trong thông đạo dưới lòng đất, từ đó nhận ra cánh cửa có người điều khiển và mình đang bị một loại thần thông trêu chọc, giam khốn. Ở một nơi trong Lôi Tiên Giới, một lão giả tóc bạc quan sát hắn, gọi hắn là tiểu bối có duyên và đặt hạn bảy ngày để xem hắn có thể thoát ra hay không. Vương Lâm không tiếp tục đuổi theo từng cửa ra mà dùng ba ngày đi hết hệ thống thông đạo, ghi nhớ địa hình thành bản đồ trong đầu rồi chọn điểm trung tâm để phá cục. Hắn gọi Xạ Thần Xa hóa thành Lôi Thú, để con rối Tiên Vệ và tiên kiếm có Hứa Lập Quốc cùng công kích tầng bùn đất, sau đó tự vận tiên lực và lôi uy trong nguyên thần đánh tiếp, khiến các thông đạo sụp đổ dây chuyền. Tuy vậy, mạng thiên địa nguyên lực tạo cửa ra vẫn không tan, chứng tỏ thần thông của đối phương vượt ngoài cấu trúc đất đá. Nhờ bùn đất không còn ngăn trở, khi cửa tiếp theo hiện ra, Vương Lâm lập tức lao qua cùng Tiên Vệ và Lôi Thú, thoát ra hư không. Sau khi rời khỏi khu vực bị nhốt, hắn suy đoán nơi này là Lôi Tiên Giới và hệ thống hóa các cơ duyên khiến tu sĩ khao khát tiến vào, gồm tiên đan, tiên bảo, tiên thuật hoàn chỉnh, thi thể tiên nhân, vũng nguyên lực và nguyên khí."},{"chuong":696,"tieuDe":"Đông Lâm Hứa Gia","tomTat":"Sau khi thoát khỏi nơi bị nhốt và suy ngẫm về bí mật của Lôi tiên giới, Vương Lâm phát hiện dưới lớp bùn đất một mảnh vỡ màu xám trắng to bằng nắm tay, phát ra dao động tiên lực như một phần của cái bình. Ở một mảnh đại lục nhỏ khác, lão giả tóc trắng nhận ra Vương Lâm đã dùng mánh khóe thoát sớm nhưng tạm bỏ qua, tiếp tục kế hoạch thu hồn tiên sơn và bố trí La Thiên đại trận. Ông bộc lộ dã tâm sau khi kế hoạch hoàn thành sẽ trở thành đệ nhất La Thiên tinh vực, quét ngang Liên Minh Tinh Vực và giết Trọng Huyền Tử. Khi Vương Lâm thu mảnh vỡ vào túi trữ vật, một thanh niên áo tím đứng trên ma ảnh đầu một sừng xuất hiện, dùng ma khí uy hiếp hắn giao vật. Hai bên giao chiến; đối phương dùng mưa tên, ma ảnh thôn lôi cầu và trường thương nước ma khí, còn Vương Lâm mượn lôi lực Lôi tiên giới để phản kích. Trước màn nước ma khí, Vương Lâm lấy đá núi tiên giới, rút hồn phách tiên thạch thành sương mù tiên khí, xuyên thủng phòng tuyến và lao tới tiếp tục tấn công."},{"chuong":697,"tieuDe":"Tuyệt Luân, Đạo Niệm Chi Chiến","tomTat":"Đám sương do hồn phách tiên thạch biến thành bao vây trường thương, trong khi Vương Lâm kích nổ lôi cầu từng bị ma ảnh nuốt để phá tan ma ảnh từ bên trong. Hắn lập tức điều Tiên Vệ lao ra tung một quyền đỉnh phong, ép Hứa Phong Hàn phải phun nguyên thần tinh huyết và thi triển Đông Lâm chi mạc để giữ mạng. Va chạm làm đại lục chấn động, Tiên Vệ bị suy yếu rõ rệt, còn Hứa Phong Hàn lộ tên trong trạng thái chật vật và nổi sát ý. Vương Lâm nhận ra tu sĩ Âm Hư khó giết, tranh thủ thu các mảnh vỡ pháp bảo lộ ra dưới bùn đất vào túi trữ vật. Hứa Phong Hàn chuyển sang đạo niệm hóa ma, thi triển Đạo hóa Ma Liên, đệ nhất chuyển, khiến ma diễm phủ trời và áp lực như thiên địa cùng vận động. Vương Lâm dùng Hoàng Tuyền hiện giữa không trung để vây Ma Liên, hóa giải cảm giác thiên địa xoay chuyển. Hứa Phong Hàn vì thấy Vương Lâm có đạo niệm ngưng thật, nhiều pháp bảo và thủ đoạn rút hồn phách đá núi nên suy đoán hắn là tu sĩ bước thứ hai bị tụt tu vi. Trận chiến tiếp tục khi Hứa Phong Hàn thúc ma diễm lao tới, còn Vương Lâm đáp bằng Thức thứ hai, ngưng tụ tuyền hồn."},{"chuong":698,"tieuDe":"Cưu Chiếm Thước Sào","tomTat":"Oán niệm phàm nhân trên Thanh Linh tinh do Vương Lâm ngưng tụ tràn ra từ Hoàng Tuyền, hóa thành vô số hư ảnh rồi hợp nhất thành một oan hồn đối kháng ma diễm của Hứa Phong Hàn. Va chạm làm Hoàng Tuyền tan nát, đạo niệm Vương Lâm bị tổn thương và khiến hắn phun máu, nhưng hắn dùng ý chí bất khuất tái ngưng tụ Hoàng Tuyền. Hứa Phong Hàn cũng bị oán niệm ăn mòn tâm trí, phải áp chế các ý niệm hỗn tạp và bắt đầu xem Vương Lâm là đối thủ ngang hàng. Khi Ma Liên bách chuyển ép Vương Lâm lùi lại, Hoàng Tuyền lực tạo lực hút làm chậm liên hoa, rồi Roi nhân quả đánh trúng sơ hở tâm thần Hứa Phong Hàn. Vương Lâm không đánh thẳng đối phương mà đạp lên, rồi khoanh chân ngồi trên Ma Liên, khiến Hứa Phong Hàn thừa nhận đã bại trong chiến đạo niệm. Không chịu dừng lại, Hứa Phong Hàn thi triển Nguyên Hóa Ma Thần bằng thiên địa nguyên lực; Vương Lâm mở con mắt thứ ba chuẩn bị ứng đối, nhưng ma vật một sừng vừa hiện ra đã quay lại cắn và nuốt chính Hứa Phong Hàn."},{"chuong":699,"tieuDe":"Ma Liên","tomTat":"Vương Lâm đối mặt ma vật đang bao lấy Hứa Phong Hàn, mở con mắt thứ ba để soi rõ bên trong rồi dùng Định thân thuật phối hợp Trảm La Quyết chém đứt thần thông, khiến ma vật tan rã và Hứa Phong Hàn tuyệt khí. Hắn thu mảnh vỡ pháp bảo, rời xa chiến trường tới Lôi Sơn mở động phủ, luyện hóa hai đạo tiên lôi để bù nguyên lực hao tổn. Trong lúc nghiên cứu Ma Liên, Vương Lâm phát hiện nó là không gian trữ vật do đạo niệm tạo thành, nuốt ma hồn bên trong để hồi phục và tinh tiến nguyên lực. Hắn lấy được dược bình khắc chữ Hứa chứa đan dược tiên khí nồng đậm cùng một lá bùa có ký hiệu mực đỏ, sau đó Ma Liên héo rũ tiêu tan. Ở La Thiên Tinh Vực, Diêu Không trở về Diêu gia xin nhận tổ quy tông để cầu cứu cho Diêu Tích Huyết; tổ phụ Diêu gia tính ra nàng ở Lôi Tiên Giới và giao lệnh bài để hắn tới Lôi Tiên Điện. Vương Lâm rời động phủ tiếp tục thăm dò Lôi Tiên Giới, nhận ra nơi này không thể dựa vào truyền tống trận, rồi gặp hai tu sĩ Vấn Đỉnh đại viên mãn nhưng đôi bên tránh xung đột."},{"chuong":700,"tieuDe":"Lý Nguyên!","tomTat":"Sau một tháng tìm kiếm trên đại lục vỡ trong Lôi Tiên Giới mà không có manh mối, Vương Lâm quay về đường cũ và phát hiện một trận pháp cấm chế mới xuất hiện. Hắn nhìn ra tiên lực trong cấm chế có sơ hở nhưng lập tức nghi đây là bố cục cố ý, nên giả vờ rời đi để quan sát. Khi hắn biến mất, Lý Nguyên và nữ tu Vấn Đỉnh đại viên mãn lộ diện; qua đối thoại, Lý Nguyên cho biết mệnh hồn của mình nằm trong tay gia tộc nữ tu và từng được tổ phụ nàng ban đan dược cứu mạng. Một tu sĩ trung niên sau đó dùng hình nhân mộc linh phá cấm chế, làm lộ cửa động, nhưng vừa xông vào đã bị tồn tại bên trong nuốt cả thân thể lẫn nguyên thần. Nữ tu tỏ ra hưng phấn với thú cưng trong hang và muốn tiếp tục cho nó ăn no tại Lôi Tiên Giới. Vương Lâm lúc này hiện thân, chứng tỏ hắn chưa hề mắc bẫy; nữ tu dùng quạt lông công kích còn Lý Nguyên thi triển mười tám cấm chế liên hoàn. Vương Lâm phóng lôi đình từ ngón trỏ phá tan lông chim khiến nữ tu thổ huyết, rồi ngưng lôi quang thành chưởng ấn hư ảo để đối diện hệ cấm chế quỷ dị của Lý Nguyên."},{"chuong":701,"tieuDe":"Mũi Kiếm","tomTat":"Vương Lâm phá tan mười tám cấm chế trong hang, đánh Lý Nguyên thổ huyết rồi dùng Nhân Quả Chi Tiên bắt Thiên Quỷ đang hóa đầu lâu xanh lục, ném nó vào Tôn Hồn Phiên để phục vụ luyện chế Tiên Vệ thứ hai. Trước uy thế ấy, Lý Nguyên nhận sai và dùng tin tức về một bí địa có cấm chế trong Lôi Tiên Giới để cầu hòa, đồng thời giao ngọc giản chứa phương pháp cấm chế ẩn giấu thân hình. Vương Lâm không lấy hồn Lý Nguyên mà rút một phần hồn nữ tử họ Cát làm tín vật, khiến hai người bị ràng buộc phải dẫn đường. Trên đường, Lý Nguyên dùng cấm chế bao bọc thần thức để trấn an nữ tử họ Cát, còn Vương Lâm vẫn nghi lời hắn nửa thật nửa giả và chuẩn bị sát ý nếu phát hiện bất lợi. Ba người tới rìa đại lục Lôi Tiên Giới, nơi các mảnh đại lục vỡ được vô số xích lôi nối trong hư vô, khiến Vương Lâm liên tưởng tới sự sụp đổ của tiên giới. Nữ tử họ Cát lấy thiết kiếm đen gia truyền, dùng máu kích hoạt quầng sáng để chở Lý Nguyên vượt xích lôi; phản ứng của Lý Nguyên với thanh kiếm khiến Vương Lâm nhận ra quan hệ giữa hắn và kiếm không bình thường. Vương Lâm tự bước trên sợi xích lôi quang như đi trên đất bằng, hấp thu lôi đình rồi dần khống chế hiện tượng lôi quang bùng sáng, đồng thời suy đoán việc Lý Nguyên phục vụ Cát gia có thể là một kế hoạch liên quan tới thanh thiết kiếm."},{"chuong":702,"tieuDe":"Rất Tốt, Rất Tốt","tomTat":"Vương Lâm cùng Lý Nguyên và Cát Hồng tiếp tục đi sâu trong hư vô Lôi Tiên Giới bằng thanh thiết kiếm, nhận ra vật này chống chịu lôi quang rất mạnh. Hành trình kéo dài gần hai tháng không gặp tu sĩ nào, trong lúc đó Cát Hồng vừa sợ Vương Lâm vì hồn mình bị hắn nắm giữ, vừa nhiều lần cảm thấy bóng dáng Lý Nguyên quen thuộc khó hiểu. Khi lôi quang càng nồng đậm, sợi xích lôi đình bắt đầu chấn động dữ dội, khiến Vương Lâm cảm thấy phía trước có tồn tại đáng sợ. Lý Nguyên cảnh báo hiện tượng sợi xích lay động có thể làm các mảnh vỡ đại lục sụp đổ, nhưng Vương Lâm vẫn quyết định tiến tới để tìm câu trả lời. Phía trước, họ gặp đám sương mù tiên khí vô biên chắn đường; Lý Nguyên dùng la bàn tính toán cấm chế nhưng la bàn nổ tung. Hắn xác định đó là cấm chế thiên cấp trung phẩm, lấy Lôi Tiên Giới làm nền và hình thành đại trận có thể luyện hóa vạn vật. Cuối chương, một lão già bí ẩn cầm sợi xích lôi quang bước ra từ trong sương mù, nói rằng có duyên và đang muốn tìm đối phương."},{"chuong":703,"tieuDe":"Bao Nhiêu Thành","tomTat":"Vương Lâm cùng Lý Nguyên, Cát Hồng gặp một lão già thần bí cầm Lôi quang thiết liên trong Lôi tiên giới. Lão chỉ thẳng Vương Lâm là người hữu duyên vì đã thoát khỏi thông đạo trong bảy ngày, đồng thời để lộ chính mình là người bố trí thông đạo ấy. Khi lão chộp tay định bắt, Vương Lâm dùng thần thông máu huyết học ở mảnh đất Yêu Linh để thuấn di thoát thân, nhưng lão lập tức thi triển Đảo ngược khiến phương hướng đảo lộn và kéo hắn trở lại trước mặt. Lão phát hiện Lôi thú sừng bạc trong túi trữ vật của Vương Lâm, cưỡng ép mượn đi và tuyên bố lôi thú của người tiến vào Lôi tiên giới đều tạm thuộc về mình. Sau đó lão ngưng tụ vô số hạt bụi thành quả cầu sáng, bắn vào ngực Vương Lâm để giúp hắn tu luyện lôi nguyên thần và lôi thể. Cuối cùng lão phất tay dùng nguồn lực cực mạnh cuốn Vương Lâm, Lý Nguyên và Cát Hồng xuyên qua sương mù, rồi tự lẩm bẩm không biết mình vừa dùng bao nhiêu thành lực."},{"chuong":704,"tieuDe":"Thiêu Đốt","tomTat":"Vương Lâm, Lý Nguyên và Cát Hồng đáp xuống một đại lục trong Lôi tiên giới sau lần di chuyển cực nhanh; Lý Nguyên tái nhợt, Cát Hồng nôn mửa, còn Vương Lâm lập tức bị cơn đau dữ dội từ quả cầu ánh sáng trong lồng ngực lan khắp thân thể. Thấy hắn bất ổn, Cát Hồng lấy chủy thủ màu đen truyền thừa gia tộc định ám toán, nhưng bị ánh mắt và lời uy hiếp của hắn làm hoảng sợ, ném chủy thủ xuống đất để hắn thu lấy. Quả cầu ánh sáng do lão già ngưng tụ vừa thiêu đốt đau đớn vừa không làm hại tu vi, ngược lại còn thúc đẩy tu vi Vương Lâm tiến gần Vấn Đỉnh đại viên mãn. Vương Lâm nhận ra thân thể mình đang nghịch chuyển từ trạng thái lôi điện về máu thịt, hiểu rằng khi quá trình hoàn tất thì cơn đau sẽ biến mất và tu vi sẽ vượt qua cánh cửa tu đạo đầu tiên, nên chủ động hít sâu để tăng đau nhằm tăng tốc tiến cảnh. Hắn không giết Cát Hồng vì suy đoán việc nàng vào được Lôi tiên giới và việc Lý Nguyên chưa đoạt thanh thiết kiếm đều ẩn chứa nguyên nhân. Lý Nguyên âm thầm dùng cấm chế trên mi tâm quan sát Vương Lâm, cho rằng tu vi hắn càng cao càng có lợi nhưng không thể để đạt Âm Dương hư thực trước khi tới nơi cần tìm. Sau một tháng tới trung tâm đại lục, Lý Nguyên xác định cấm chế nằm về phía đông; ba người tiếp tục xuyên qua Lôi quang Thiên liên trong hư vô, ba tháng sau tới trước một ngọn núi cao vút trong mây mà Lý Nguyên kích động xác nhận chính là địa điểm cần tìm."},{"chuong":705,"tieuDe":"Gây Khó Dễ","tomTat":"Vương Lâm, Lý Nguyên và Cát Hồng tới một ngọn núi cực cao trong Lôi tiên giới, nơi sấm sét dày đặc và cấm chế bao phủ. Khi nhìn bóng lưng Lý Nguyên và ngọn núi, Cát Hồng nhận ra bí mật của Cát gia: từng có tộc nhân vào Lôi tiên giới mấy vạn năm trước không trở về, còn việc nàng được truyền pháp bảo và đưa vào đây có liên quan tới chuộc tội cùng hiến tế hồn phách. Vương Lâm quan sát phản ứng của nàng và suy ra Lý Nguyên đã sớm chú ý tới mình, dùng cấm chế dẫn hắn xuất hiện và đưa mọi việc vào kế hoạch. Lý Nguyên thừa nhận việc gặp Vương Lâm nằm trong bố cục, tiết lộ sâu trong núi có chủ nhân của mình và cảnh báo Vương Lâm không thể rời đi nếu không được cho phép. Vương Lâm lập tức gọi Tiên Vệ khôi lỗi đánh mở dòng chảy thông ra ngoài, rồi phóng kiếm khí của Lăng Thiên Hậu dừng trước mi tâm Lý Nguyên để phá thế uy hiếp. Sau đó hắn nói rõ mục tiêu thật sự không phải Nguyên khí mơ hồ mà là Mai hoa thuật, cấm chế cổ đã thất truyền mà hắn nghi Lý Nguyên đang nắm giữ."},{"chuong":706,"tieuDe":"Chuôi Kiếm Và Mũi Kiếm","tomTat":"Khi đã tới ngọn núi mục tiêu, Vương Lâm ép Lý Nguyên giao trước phần đầu Mai Hoa thuật, khiến Lý Nguyên phải đưa ngọc giản chứa Mai hoa thập tam cấm và hẹn giao thêm năm loại sau khi vào núi. Trên đường lên núi, Lý Nguyên giải thích nguồn gốc cấm chế, bốn cấp Thiên, Địa, Huyền, Hoàng và cấp Hư gồm tứ đại cấm thuật, đồng thời nói ngọn núi này do tứ đại cấm thuật tan vỡ tạo nên nên không có điểm cuối nếu không biết hóa giải. Hắn nhiều lần thi triển cấm chế làm ngọn núi chấn động và thu nhỏ, trong lúc Cát Hồng hoảng sợ cầu cứu Vương Lâm rồi tố Lý Nguyên tới Cát gia có mục đích. Để cầu sống, Cát Hồng giao họa trục, thiết kiếm và la bàn; Lý Nguyên nhận ba vật, đặc biệt trân trọng họa trục vẽ ngọn núi, phi kiếm, người trên chuôi kiếm và bóng người trên mũi kiếm giống hắn, rồi để nàng bỏ chạy. Sau nhiều lần phá cấm, Lý Nguyên đưa Vương Lâm tới đỉnh núi, nơi có tượng đá trung niên nam tử, thanh phi kiếm và người đứng trên mũi kiếm. Khi Vương Lâm nhìn ấn quyết trên cánh tay tượng đá, tâm thần hắn bị hút vào huyễn cảnh Tiên giới, thấy các tiên nhân lôi điện giao chiến và một thanh bảo kiếm tím xuất hiện. Trong huyễn cảnh, nam tử đứng trên chuôi kiếm tuyên bố linh hồn bất diệt rồi tan rã, còn người hầu trên mũi kiếm đau thương lao theo lên trời, khép lại bằng ý niệm chủ chết thì đầy tớ đi theo."},{"chuong":707,"tieuDe":"Nô Ấn","tomTat":"Vương Lâm cùng Lý Nguyên chứng kiến cảnh tượng như ký ức về một người đứng trên phi kiếm tan thành mảnh vụn, thanh kiếm cắm xuống đỉnh núi rồi đá vụn ngưng tụ thành tượng tiên nhân, chủ nhân và người hầu. Thủ ấn trên tượng đá hút toàn bộ tâm thần Vương Lâm, khiến âm thanh truyền thừa khắc sâu vào đầu hắn, nhưng nhờ đau đớn thân thể và lực lượng đang thiêu đốt, hắn tỉnh lại và nhận ra đó không phải truyền thừa lực lượng mà là nô ấn. Lý Nguyên giải thích tổ tiên Lý gia từng mở đường qua cấm chế lên đỉnh núi này rồi trở thành đầy tớ của tiên nhân, khiến hậu nhân nhiều đời bị ấn ký nô lệ làm suy kiệt. Hắn kể Lý gia vốn là một trong sáu gia tộc cổ ở La Thiên tinh vực, nổi danh phá cấm chế, nhưng sau lần Lôi tiên giới mở ra đầu tiên thì không ai vượt qua Vấn Đỉnh đại viên mãn, tuổi thọ cũng giảm mạnh. Khoảng vạn năm trước, một tổ tiên thiên tài của Lý gia tìm cách phá nô ấn, đổi được họa trục và la bàn, rồi để một nửa tộc nhân hiến linh hồn tế luyện thiết kiếm mang vào Lôi tiên giới, nhưng từ đó bặt vô âm tín. Một ngàn năm trước, cha Lý Nguyên nhặt được thiết kiếm và nhận ra oán khí tộc nhân Lý gia trong đó, từ đó dẫn tới mối thù với Cát gia. Cuối chương, Lý Nguyên dùng cấm chế kéo Cát Hồng ra khỏi dòng xoáy dưới tượng đá, tuyên bố sẽ dùng máu nàng đền cho linh hồn tuyệt vọng của tộc nhân Lý gia."},{"chuong":708,"tieuDe":"Huyết Tổ Tới","tomTat":"Lý Nguyên khống chế Cát Hồng trước tượng đá, dùng tiên lực giết nàng để tế linh khiến thân thể hóa thành sương máu, nguyên thần bị tượng đá hấp thu và hồn phách tiêu tán. Vương Lâm bình tĩnh quan sát, không can thiệp vào ân oán Lý gia và Cát gia, nhưng nhận ra Lý Nguyên che giấu rất sâu, nhất là qua phản ứng kỳ lạ của Cát Hồng trước khi chết. Lý Nguyên muốn mượn Định Thân thuật của Vương Lâm để xử lý linh hồn bất diệt trong tượng đá, giao trước phần còn lại của Mai Hoa thuật và hứa trao Phá Diệt cấm sau khi xong việc. Hắn tiếp tục dùng thiết kiếm, la bàn, bình ngọc, họa trục cùng oán khí tế luyện, khiến tượng đá nứt vỡ và khí tức bên trong thức tỉnh mạnh dần. Khi bị yêu cầu ra tay, Vương Lâm lùi lại, vạch ra rằng mục đích thật của Lý Nguyên không phải giải thoát Lý gia mà là muốn tiên nhân trong tượng đá sống lại. Lý Nguyên lộ thực lực cấm chế, trói chặt tiên vệ khôi lỗi, rồi dùng cấm chế từ mi tâm ép Vương Lâm đang thuấn di phải hiện thân. Cùng lúc đó, trên một đại lục nhỏ trong Lôi Tiên giới, Huyết Tổ xuất hiện trong trận pháp khổng lồ trước bốn lão nhân canh giữ và tuyên bố đã tới tìm Vương Lâm."},{"chuong":709,"tieuDe":"Nhân Quả","tomTat":"Khi Lý Nguyên quay đầu, ngọn lửa quanh tượng đá bị hút vào, các vết nứt phát huyết quang mang mùi máu Cát Hồng và một luồng hơi thở mạnh lan về phía họa trục. Vương Lâm quan sát toàn bộ biến hóa, từ nô ấn trong người Lý Nguyên suy ra quan hệ nhân quả giữa Lý gia, Cát gia và tiên nhân bị phong ấn trong tượng đá. Hắn nhận ra việc giải khai nô ấn thực chất là làm sống lại chủ nhân của nô ấn, còn thất bại của lần luân hồi trước là vì tiên nhân không muốn hồi sinh bằng cách đoạn tuyệt huyết mạch. Vương Lâm cũng hiểu trong linh hồn Lý Nguyên có hai suy nghĩ cùng tồn tại, khiến cấm chế Lý gia như Mai Hoa thuật và Phá Diệt cấm bị ảnh hưởng. Lý Nguyên đau đớn quỳ trước tượng đá gọi chủ nhân, thừa nhận mình sai và vẫn cố chấp mong chủ nhân thức tỉnh. Cuối cùng họa trục hút hết huyết quang khiến tượng đá mất linh động, rồi bức họa cháy thành tro, khói xanh tụ thành hình người mơ hồ đứng trên chuôi kiếm."},{"chuong":710,"tieuDe":"Bộ Giáp Bằng Da Cổ Thần","tomTat":"Người đứng trên chuôi kiếm khói xanh vẫy tay, khiến nô ấn trên mi tâm Lý Nguyên hiện ra, tách khỏi trán hắn rồi hóa thành tàn hồn bay lên mũi kiếm. Vương Lâm nhìn pho tượng đá, ấn quyết và cảnh tượng viễn cổ lặp lại, hiểu tiên nhân năm xưa đã chết và mọi trải nghiệm giống như giấc mộng của tàn hồn người đầy tớ, nhưng vẫn không giải hết nghi vấn. Từ đó trong Lôi tiên giới lưu lại một thanh kiếm do khói xanh hóa thành, trên mũi kiếm có thân ảnh đứng như vĩnh hằng, còn Lý Nguyên tỉnh lại trong ngơ ngác. Nửa tháng sau, Vương Lâm và Lý Nguyên đi qua các đại lục nhỏ để tìm động phủ, di tích và cấm chế; Lý Nguyên truyền dạy sở học, chỉ cách nhận biết tiên cấm và khuyên thu bùn đất để sau này chế tạo cấm chế la bàn. Vì cảm kích đại ân cứu mạng và giải nô ấn, Lý Nguyên hứa đưa Vương Lâm về từ đường Lý gia học Phá Diệt cấm và chia một nửa tâm cấm. Khi Lý Nguyên phá tiên cấm trên một mảnh đại lục đất đen, bùn đất sụp xuống, lộ ra tiên sơn cùng cung điện rách nát đã bị khai phá. Vương Lâm phát hiện cây sau cung điện chỉ chuyển động một nửa, rồi cùng Lý Nguyên tới gần và nhìn thấy hai bộ hài cốt trắng, trong đó một bộ mặc giáp da có đường nét khiến hắn kinh ngạc."},{"chuong":711,"tieuDe":"Kinh Biến","tomTat":"Vương Lâm nhìn bộ giáp trên hài cốt và nhận ra đó là da Cổ Thần chế thành, nhưng trước mặt Lý Nguyên chỉ nói giống một vật cũ để che giấu liên hệ với bổn tôn. Lý Nguyên thi triển cấm chế hoa mai, phá huyễn cảnh quanh cái cây, khiến cây cối và hài cốt tan biến, để lộ một truyền tống trận phát sáng. Hai người phân tích cấm chế này thuộc pháp thứ ba trong bát pháp của tiên cấm, có thể là bẫy dùng hài cốt và giáp da để dụ người tới rồi giết. Khi truyền tống trận vừa lộ ra, nó bắt đầu bất ổn vì tiếp xúc ngoại giới và tiên khí, mép trận sinh ra những dòng xoáy nhỏ kèm ảo ảnh kiến trúc cổ cùng thi thể. Đúng lúc đó, một đạo thần thức cực mạnh từ xa tràn tới, làm mây đen tản đi, ép Lý Nguyên phun máu, còn Vương Lâm nhận ra cảm giác quen thuộc nên lập tức ôm Lý Nguyên lao vào truyền tống trận. Chủ nhân thần thức tiếp tục biến sương đỏ thành vô số âm hồn truy kích, còn Lý Nguyên cố dùng cấm chế ngăn cản. Khi chỉ còn vài bước nữa là tới trận, thần thông Ngưng huyết khóa chặt không gian trong phạm vi trăm trượng, khiến hai người gần như đứng im. Cuối chương, một tia sáng hồng lao tới, bên trong dần hiện ra bóng người màu hồng tràn đầy căm hận và sát khí."},{"chuong":712,"tieuDe":"Cạm Bẫy","tomTat":"Trong lúc bị Huyết Tổ áp sát, Vương Lâm dùng mắt thứ ba phóng hồng quang về phía Lý Nguyên để làm lỏng lực trói buộc, còn Lý Nguyên thi triển Phá diệt tâm cấm tạo cơ hội cho cả hai lao vào truyền tống trận sắp sụp đổ. Huyết Tổ để mất mục tiêu thì giẫm sụp một mảnh vỡ Lôi chi tiên giới, khiến tu sĩ La Thiên Tinh vực trên đó hoảng loạn bỏ chạy, đồng thời chương xác nhận hắn vào đây chỉ để tìm con gái Diêu Tích Tuyết. Vương Lâm và Lý Nguyên xuất hiện trên một tế đàn trong vùng không gian u ám đầy khe nứt, rồi Vương Lâm lấy Diêu Tích Tuyết ra đối thoại nhưng nàng khẳng định dù thả, giết hay phong ấn nàng thì hắn vẫn khó thoát Huyết Tổ. Lý Nguyên sau khi hồi phục đánh giá Huyết Tổ có thể đã tới Tịnh Niết kỳ, rồi quan sát bùn đất, cây cối và không gian xung quanh để kết luận nơi này là không gian trữ vật của một tiên nhân đã chết. Biết không gian này đã suy yếu và có thể sụp đổ nếu bị quấy nhiễu, Vương Lâm nảy ý biến nó thành cạm bẫy đối phó Huyết Tổ, còn Lý Nguyên vì ân cứu mạng và ý tưởng thí Tiên mà đồng ý trợ giúp. Hai người bắt đầu khảo sát thung lũng đầu tiên; Lý Nguyên phá lớp sương mù bề ngoài nhưng Vương Lâm vẫn sai Tiên vệ dò đường, khiến cấm chế ẩn lập tức hóa thành mũi tên sương mù đánh bật Tiên vệ ra ngoài."},{"chuong":713,"tieuDe":"Thú Cốt","tomTat":"Lý Nguyên nhận ra cấm chế thung lũng thứ nhất có hai tầng sáng tối, còn Vương Lâm gọi Tiên vệ tạo lốc xoáy và dùng lôi điện Nguyên thần ổn định để gom sương mù. Hai người phá mắt cấm Đông, Nam, làm lộ đoản kiếm đen và tám đầu lâu mãnh thú; Vương Lâm nhường kiếm cho Lý Nguyên, tự thu đầu lâu. Trước thung lũng thứ hai, vùng khe nứt dày đặc khiến Lý Nguyên không thể đi tiếp, nên Vương Lâm tự dùng Sơn Hà Đồ, lực ném của Tiên vệ và huyết quang độn để vượt qua. Ở lối vào, hắn phát hiện quầng sáng vô hình cùng bóng ma nuốt cấm chế, rồi dùng kiếm khí Lăng Thiên Hậu mở lỗ thủng xông vào. Bên trong thung lũng đầy hài cốt, sâu bọ gặm xương, tám đoản kiếm cùng bộ với thanh kiếm trước đó và một đầu thú lớn bốn gai xương âm trầm."},{"chuong":714,"tieuDe":"Tiên Nhân Di Vật","tomTat":"Vương Lâm xông vào thung lũng thứ hai, dùng Định thân thuật giữ đoản kiếm, chờ ma ảnh vô hình áp sát rồi phản kích bằng Nhân quả Côn Cực Tiên để đoạt đầu thú. Sau khi đầu thú bị lấy, tám kiếm, sương mù từ hài cốt, sâu bọ và ma ảnh vô hình cùng vây sát, khiến hắn gần như không còn đường thoát. Hắn suy ra dãy núi trong không gian trữ vật được dời từ ngoài vào, liền đánh vách đá và phối hợp Tiên vệ nâng cả dãy núi, làm thế cấm chế hỗn loạn để thoát thân. Tới thung lũng thứ ba, Vương Lâm thấy miếu cổ và hai bộ xương, thu được giáp da Cổ Thần từ một bộ xương bị ngón tay kim quang của bộ xương khác đâm vào đầu. Trong miếu, Vương Lâm và Lý Nguyên nhìn thấy chín bức tranh vẽ người khổng lồ trán tám chấm bị vô số Tiên nhân vây công."},{"chuong":715,"tieuDe":"Sắp Xếp Chuẩn Xác","tomTat":"Vương Lâm lên tầng hai miếu thờ, đọc di bút của Tiên nhân vô danh về trận Cổ Thần thắng chư tiên, pháp bảo bị tổn hại, cái chết kỳ dị của Tiên đế và cảnh tượng trên trời khiến người viết kinh hãi. Hắn mô phỏng nét bút để cảm nhận tâm cảnh của chủ nhân cũ, rồi đốt trang giấy và thu quỹ thước. Xuống tầng một, Vương Lâm cảnh báo Lý Nguyên phải giữ kín tranh, đồng thời xác định xương đầu thú là pháp bảo quan trọng nhất trong không gian này. Trong một tháng, Lý Nguyên bố trí một ngàn bốn trăm sáu mươi lăm điểm sụp đổ bằng Phá Thiên cấm, giao cầu cấm chế và ngọc giản Phá Diệt cấm cho Vương Lâm rồi rời đi bằng truyền tống trận dùng được ba lần. Vương Lâm phong ấn túi trữ vật của Diêu Tích Tuyết, ném quả cầu giam nàng sâu vào dãy núi và rời khỏi trữ vật không gian, quyết định dùng sự sụp đổ của nơi này để đánh cược với Huyết Tổ."},{"chuong":716,"tieuDe":"Rốt Cục Đến Đây","tomTat":"Vương Lâm rời truyền tống trận tới một mảnh vỡ xa lạ trong Lôi chi Tiên giới, thu nhỏ trận pháp rồi chôn giấu túi trữ vật của Diêu Tích Tuyết sâu dưới dãy núi để tránh lộ khí tức. Sau một tháng di chuyển theo xích sắt hư vô, hắn chọn một mảnh vỡ khác để giấu bản thể, dùng cấm chế học từ ngọc giản của Lý Nguyên tạo quả cầu che giấu khí tức. Hắn phân một luồng nguyên thần vào Tiên vệ, để con rối nuốt tinh thể truyền tống trận và ra ngoài phóng thần thức, sát khí nhằm dụ Huyết Tổ. Trong nhiều tháng, thân Tiên vệ gây uy danh trong Lôi chi Tiên giới nhưng vẫn chỉ tuần hoàn quanh nơi bản thể ẩn nấp. Huyết Tổ vì Diêu Tích Tuyết mà phá lời thề không vào La Thiên Tinh vực, lần theo khí tức Vương Lâm và sát ý bùng lên khiến núi sụp. Khi thiên địa biến sắc và các tu sĩ run rẩy, Vương Lâm biết Huyết Tổ cuối cùng đã tới."},{"chuong":717,"tieuDe":"Thí Tiên","tomTat":"Huyết Tổ giáng lâm trên mảnh vỡ đại lục bằng mây máu và thần thức bước thứ hai, hiện thân rồi lập tức điểm một chỉ về phía Vương Lâm trong thân Tiên vệ. Vương Lâm dùng sinh tử Diêu Tích Tuyết để buộc Huyết Tổ thu bớt sát chiêu, dù thân Tiên vệ vẫn bị đánh trọng thương. Hắn phun tinh thể hóa thành truyền tống trận, nói Diêu Tích Tuyết ở trong trận rồi bỏ chạy, biến cạm bẫy thành dương mưu. Huyết Tổ xác nhận khí tức con gái nhưng vẫn thu tinh thể và truy sát vì oán hận chuyện Diêu Tích Tuyết bị giam mấy trăm năm. Trong hư vô, Huyết Tổ cắt đứt xích sắt lôi quang, dùng biển máu luyện hóa Tiên vệ và phát huyết quang truy tìm bản thể Vương Lâm. Bản thể Vương Lâm bị hồng châm truy sát liền dùng quả cầu cấm chế kích hoạt một nửa cấm chế trong trữ vật không gian sụp đổ, lấy an nguy của Diêu Tích Tuyết trong hư vô sụp đổ làm lời đe dọa cuối cùng trước khi nguyên thần phân trong Tiên vệ tan vỡ."},{"chuong":718,"tieuDe":"Cơ Duyên","tomTat":"Huyết Tổ tiến vào trữ vật không gian do Tiên nhân mở ra để cứu Diêu Tích Tuyết, nhưng Vương Lâm lập tức dẫn động toàn bộ cấm chế khiến nơi này sụp đổ. Vương Lâm còn dùng liên hệ với Tiên vệ khiến con rối Âm hư tự bạo, phá nát truyền tống trận và cắt đường lui của Huyết Tổ. Trong nguy cấp, Huyết Tổ bóp vỡ quả cầu cấm chế để Diêu Tích Tuyết hồi sinh ở vùng đất Yêu Linh, rồi bóp nát ba viên Huyết Hồn đan cuối cùng để thi triển Dong thần hóa huyết. Vương Lâm nhận ra Huyết Tổ chưa chết qua hồng châm, phong ấn nó và dùng làm dấu vết truy sát. Trong hư vô Lôi Tiên Giới, lão già thần bí cưỡi lôi thú phát hiện Huyết Tổ, cưỡng ép dung hợp khiến hắn tụt xuống Khuy Niết hậu kỳ rồi xé mất nửa nguyên thần và nửa huyết thân. Huyết Tổ rơi vào ngủ say còn Vương Lâm tiếp tục lần theo hồng châm tới phía trước."},{"chuong":719,"tieuDe":"Thức Tỉnh","tomTat":"Trong hư vô Lôi Tiên Giới, hơn mười huyết cầu của Huyết Tổ bắt đầu dung hợp sau khi hồng châm nhập vào một huyết cầu. Vương Lâm nhận ra nguy cơ Huyết Tổ thức tỉnh, liên tiếp dùng Hồn núi đá, Kiếm tiên, Trảm La quyết, lôi uy nguyên thần và Định thân thuật để phá quá trình hợp nhất. Huyết cầu sụp đổ, một phần huyết thân cuốn nguyên thần Huyết Tổ chạy trốn, phần khác xâm nhập cơ thể Vương Lâm khiến hắn hôn mê và rơi vào mảnh vỡ đại lục. Nguyên lực trong giọt máu Huyết Tổ trở thành sát cơ nhưng cũng thúc đẩy Vương Lâm hướng tới cảnh giới Âm hư. Huyết Tổ thức tỉnh trong trạng thái suy yếu cực độ, phát cuồng quay lại truy sát. Hứa Lập Quốc khống chế Kiếm tiên đuổi theo hộ chủ, còn bản tôn Vương Lâm ở Liên minh Tinh vực mở mắt và xuất quan vì phân thân gặp nạn."},{"chuong":720,"tieuDe":"Huyết Tinh","tomTat":"Bản tôn Vương Lâm từ tinh cầu bỏ đi lao ra, buông áp chế thân thể Cổ Thần bốn sao và hóa thành người khổng lồ trăm trượng trong tinh không. Vì phân thân bị Huyết Tổ đánh hôn mê, hắn chấp nhận nguy cơ lộ thân phận, dùng Cổ Thần thuật che điểm sao rồi theo tinh đồ Thiên Vận tử để tới Huyết Tinh. Trên đường, hắn thu gom các khối đá vụn trăm trượng làm vũ khí. Tại Huyết Tinh, Huyết nô và Huyết vệ chết quá bảy phần vì biến cố của Huyết Tổ, bốn lão già áo đỏ công khai rời bỏ, kéo theo thế lực Huyết Tinh tan rã. Vương Lâm ném đá vụn phá sập màn máu phòng hộ, còn Tử Tâm cố trốn vào Huyết các nhưng bị con đường đỏ ăn mòn đến chết. Cuối cùng Vương Lâm nhổ cả Huyết các mang đi, tàn phá Huyết Tinh rồi rời khỏi; những Huyết nô còn sống được giải phóng khỏi gông xiềng vô hình và tản về quê nhà."},{"chuong":721,"tieuDe":"Bảo Vật Thiên Luyện","tomTat":"Sau khi Huyết Tinh bị tiêu diệt, vì nơi này hẻo lánh trong Liên Minh Tinh Vực nên chưa gây chấn động lớn. Bản tôn Vương Lâm mang Huyết Các rời đi, phong ấn thu nhỏ rồi nuốt vào miệng để dùng linh lực bao bọc, sau đó ẩn vào một lục cấp Tu Chân Tinh. Trong Lôi Tiên Giới thuộc La Thiên Tinh Vực, phân thân Vương Lâm vẫn hôn mê trong mảnh lục địa bị mây sét bao phủ. Huyết Tổ cảm nhận Huyết thân của mình bị hấp thu nhưng không dám xông vào vì nhận ra đây là Thiên Kiếp, chỉ đứng ngoài chờ Vương Lâm chết. Suốt một tháng, thiên lôi truyền vào cơ thể Vương Lâm, khiến Huyết thân Huyết Tổ và khí tức lão già thần bí dung hợp, triệt tiêu và làm nguyên lực hắn tăng nhanh. Mảnh lục địa dưới thiên lôi dần hóa thành phôi pháp bảo thiên luyện, khiến Huyết Tổ nảy lòng tham. Khi hắc lôi xuất hiện, Vương Lâm mở mắt trong khe sâu và bị sét đánh trúng, nhưng lực lượng trong cơ thể hắn lập tức đánh tan sấm sét xâm nhập."},{"chuong":722,"tieuDe":"Âm Hư","tomTat":"Ba luồng lực lượng trong cơ thể Vương Lâm va chạm dữ dội, nhưng Thiên Kiếp đến đúng lúc giúp hắn biến nguy thành cơ. Hắn thu tiên kiếm chứa Hứa Lập Quốc và ngọn núi tiên giới vào túi trữ vật rồi trực diện kiếp lôi. Sấm sét màu đen kích phát nửa Huyết Thân cùng khí tức lão già thần bí, sinh ra nguyên lực để nguyên thần hắn thôn phệ, giúp hắn đột phá từ Vấn Đỉnh hậu kỳ đại viên mãn lên Âm Hư. Huyết Tổ ở ngoài nhận ra nửa Huyết Thân của mình lại thành nguồn trợ lực cho Vương Lâm nên vừa kinh hãi vừa không cam lòng. Khi tám đạo kiếp lôi đen hạ xuống, nguyên thần Vương Lâm hóa thành Thái Cổ Lôi Long nuốt chửng toàn bộ, khiến cảnh giới Âm Hư ổn định rồi tiến tới đỉnh phong. Cuối chương, sấm sét bảy màu ngưng tụ kèm ma âm câu hồn, mở ra tầng Thiên Kiếp nguy hiểm hơn."},{"chuong":723,"tieuDe":"Phản Kích","tomTat":"Sấm sét bảy màu liên tục giáng xuống, đánh tan nửa Huyết Thân trong cơ thể Vương Lâm thành nguyên lực và đẩy tu vi hắn từ Âm Hư ổn định tới Âm Hư đỉnh phong. Nhận ra khí tức lão già thần bí trong thân cần được thanh trừ, Vương Lâm không còn bị động chịu kiếp mà chủ động lao vào tầng mây thôn phệ lôi lực và mây kiếp. Huyết Tổ thấy vậy kinh hãi, lao vào ngăn cản nhưng bị Thiên Kiếp áp chế vì không có lôi nguyên thần. Trong tầng mây, Vương Lâm dùng Trảm La Quyết giao chiến, còn Huyết Tổ vận dụng huyết ảnh, huyết quang ký hiệu và huyết cầu để cố tốc chiến tốc thắng. Khi khí tức lão già thần bí hoàn toàn tiêu tán, nguyên lực khổng lồ giúp Vương Lâm đột phá tới Dương Thực. Cuối chương, nguyên thần hắn rời thân hóa thành Thái Cổ Lôi Long dài trăm trượng, chuẩn bị ép Huyết Tổ thành cơ duyên tiếp theo."},{"chuong":724,"tieuDe":"Lòng Tin","tomTat":"Nguyên thần Vương Lâm hóa Thái Cổ Lôi Long trong tầng mây Thiên Kiếp, dẫn sấm sét truy kích Huyết Tổ. Huyết Tổ dùng huyết cầu thi triển Huyết bạo đánh tan hình thái Lôi Long, nhưng Vương Lâm phân tán thành mưa lôi và tiếp tục dụ Thiên Kiếp đánh vào lão. Vương Lâm công kích tâm thần Huyết Tổ bằng việc nhắc Huyết Tinh bị phá, Tử Tâm đã chết và Diêu Tích Tuyết có thể gặp nguy, khiến huyết quang của lão dao động. Nhân cơ hội đó, nguyên thần Vương Lâm chui vào Huyết Thân, không nhằm đoạt xá mà kiềm chế nguyên thần Huyết Tổ để giữ lão trong Thiên Kiếp. Trước luồng sét cuối cùng, Huyết Tổ thi triển Huyết Phong, bỏ lại Huyết Thân để nguyên thần chạy thoát. Thiên Kiếp phá tan phong ấn, Vương Lâm thoát ra, thu Huyết Thân, nuốt mảnh đất Lôi Tiên Giới thành hạt cát rồi tiếp tục truy sát Huyết Tổ với lòng tin mới của một tu sĩ nghịch tu."},{"chuong":725,"tieuDe":"Diêu Gia","tomTat":"Sau khi bức Huyết Tổ rơi vào trạng thái suy yếu, Vương Lâm nhận ra những cường giả như Huyết Tổ, Thiên Vận Tử hay Lăng Thiên Hậu cũng không phải không thể chiến thắng, đồng thời vẫn nghi ngờ có người âm thầm giúp mình phát hiện sơ hở của Huyết Tổ. Trong lúc thích ứng với cảnh giới Dương Thực, hắn cảm ứng được sự hòa nhập với thiên địa và thi triển Súc Địa Thành Thốn, nhờ đó liên tiếp đuổi kịp Huyết Tổ đang chạy trốn để tìm cơ hội đoạt xá khôi phục tu vi. Vương Lâm dùng Hoàng tuyền nguyên lực vây khốn, biến oán khí thành vô số hình bóng Diêu Tích Tuyết để đánh vào điểm yếu tinh thần của Huyết Tổ, rồi dùng Tôn Hồn Phiên, ba đại chủ hồn, Côn Cực Tiên và mảnh vỡ Tiên giới hóa đại ấn để trấn áp lão. Khi Huyết Tổ định tự bạo, Vương Lâm lấy khả năng còn được gặp lại Diêu Tích Tuyết để khiến lão dao động, cuối cùng phong ấn lão vào Tôn Hồn Phiên thay vì giết chết. Sau trận chiến, Vương Lâm không hề đắc ý mà chỉ thấy nặng nề, bởi giữa hắn và Huyết Tổ vốn không có thâm cừu tất yếu, nhưng sát niệm của đối phương đã buộc hắn phải phản kháng. Hắn xác lập mục tiêu tiếp theo trong Lôi chi Tiên giới là tranh đoạt Tiên thuật và tiếp tục tìm mọi cách khiến Lý Mộ Uyển thức tỉnh, đặc biệt là hướng tới Đông Lâm Tinh. Cùng lúc đó, Lý Nguyên trên một mảnh vỡ đại lục đã bị ba người Diêu gia truy sát và tra tấn suốt nhiều ngày, mất nhiều tiên kiếm, bị Bát diện Phệ hồn trùng ký sinh và gần như dầu hết đèn tắt nhưng vẫn day dứt vì chưa truyền Tâm Cấm cho Hứa Mộc. Khi Vương Lâm tới gần mảnh vỡ đại lục và dùng thần thức quét qua, hắn lập tức phát hiện tình cảnh của Lý Nguyên, sắc mặt trở nên âm trầm và sát khí bùng lên dữ dội."},{"chuong":726,"tieuDe":"Mười Ba Ngày!","tomTat":"Sau khi nghe hận ý của Lý Nguyên, Vương Lâm bước tới trước mặt nữ tử đang cầm kiếm tiên; nữ tử vốn đã kinh hoàng vì chứng kiến thanh niên họ Diêu bị một chỉ đánh nát nên chỉ muốn bỏ chạy. Vương Lâm điểm một chỉ vào mi tâm nàng, nguyên lực phá hủy cơ thể, nguyên thần hóa quang cầu bị hắn bắt lấy rồi ném vào thân thể Lý Nguyên để dịu nguyên thần và chữa bớt thương thế, thân nữ tử tiêu tán. Lão già cảnh giới Âm Hư không cứu đồng bọn mà bỏ chạy, nhưng Vương Lâm dung hợp thiên địa xuất hiện chặn đường, dùng lôi đình màu tím phá tấm chắn hỏa diễm của lão. Bị đánh bị thương, lão khai việc truy sát Lý Nguyên đã kéo dài mười ba ngày và do Thiếu chủ Diêu gia gây nên, càng khiến sát khí Vương Lâm bùng mạnh. Vương Lâm dùng Định Thân thuật khống chế lão, lần lượt đánh nát tay trái, chân trái, chân phải, tay phải rồi điểm nát ngực theo từng mốc “ngày”, biến việc hành hạ thành sự trả lại mười ba ngày Lý Nguyên chịu khổ. Sau khi tuyên bố ngày cuối cùng, hắn biến tay phải thành chưởng, mang theo cỗ vô tình lạnh như băng vỗ lên người lão già đã đứt đoạn xương cốt."},{"chuong":727,"tieuDe":"Tử Mẫu Đạo Khô","tomTat":"Sau khi phá hủy thân thể Sửu thúc, Vương Lâm dùng Tôn Hồn Phiên hiện hình Huyết Tổ để dò xét, từ phản ứng của nguyên thần lão xác nhận Huyết Tổ có liên hệ sâu với Diêu gia. Hắn thi triển Sưu hồn thuật lấy ký ức, hủy thần thức lão rồi luyện nguyên thần thành nguyên lực cầu, dùng để tẩm bổ Lý Nguyên và trao cho hắn cơ hội bước vào Âm Hư. Từ ký ức thu được, Vương Lâm biết Diêu gia rất mạnh, Diêu gia Lão Tổ là Huyết Thần Tử, nhưng vẫn không hối hận vì đã cứu Lý Nguyên. Sau đó hắn bày chín thanh phi kiếm và chín thú cốt, dùng nguyên thần Thái Cổ Lôi Long phá cấm chế kiếm khí bên trong, nhận chủ pháp bảo Tiên gia Tử Mẫu Đạo Khô và thu thành đồ án trên tay phải. Khi kiểm tra túi trữ vật của ba người Diêu gia, hắn lấy tiên ngọc, phát hiện thêm một tờ Chỉ phù có dao động nguyên lực và biết Diêu gia vào Lôi chi Tiên giới để tới Tàng Quyết Các thu hoạch Tiên thuật. Lý Nguyên tỉnh lại, tuy chưa lập tức đạt Âm Hư nhưng được Vương Lâm khẳng định sau khi hấp thu hết nguyên lực nhất định sẽ phá cảnh; hắn nhận lại phi kiếm, tặng Phá cấm Cổ kính cho Vương Lâm và đồng ý đồng hành phá cấm. Cuối chương, Lý Nguyên dùng cấm chế gia truyền mở lớp che giấu trên bình nguyên, để lộ thành trì hoang tàn và bia đá Dẫn Tiên Khí, đồng thời nói Tâm Cấm thuật của Lý gia có thể đảo nghịch dấu tích Tiên thuật dù phương hại bản thân."},{"chuong":728,"tieuDe":"Hắc Động","tomTat":"Vương Lâm và Lý Nguyên đi vào khu phế tích có bia đá tàn phá, nơi Lý Nguyên nhận ra là Dẫn Cơ phủ, một phủ giao dịch của Tiên nhân thời Lôi chi Tiên giới chưa sụp đổ. Sau khi khảo sát mà chưa thấy chỗ bất thường, Lý Nguyên suy đoán cửa hàng lớn nhất nằm ở phía đông và chỉ cho Vương Lâm dùng lôi điện tím phá vách đổ, làm lộ đồ án tiên trận đã mất sinh cơ. Lý Nguyên nhận định đây là tử trận dẫn tới mật thất cửa hàng Tiên nhân, rồi dùng máu và hắc tuyến cấm chế để cưỡng ép khôi phục dao động của trận pháp. Biến cố xảy ra khi trận phun cột sáng sáng ngời xông thẳng lên trời, tạo hiện tượng tiết linh vì lần đầu bị mở bằng phương pháp khác. Cột sáng khiến tu sĩ trên mảnh vỡ đại lục tưởng có bảo vật xuất thế và kéo tới, nhưng Vương Lâm lập ranh giới nghìn trượng, cảnh cáo ai tiến vào thì chết, khiến cả hai tu sĩ Triệu gia lẫn những người tới sau đều không dám vượt qua. Khi cột sáng tiêu tan, vị trí trận pháp lộ ra một hắc động tỏa dao động tiên lực mạnh đến mức người ở ngoài nghìn trượng cũng cảm nhận được."},{"chuong":729,"tieuDe":"Cấm Địa Nghìn Trượng, Người Vào - Chết!","tomTat":"Hắc động trong Lôi chi Tiên giới khiến quần tu ngoài phạm vi nghìn trượng thèm muốn, nhưng uy thế của Vương Lâm khiến không ai dám tự ý lao vào. Đường Ngôn Vân, tu sĩ áo vàng Âm Hư đỉnh của Đường gia, ngự kiếm quang tới nơi và bất chấp vòng bụi đất do Vương Lâm lập ra. Vương Lâm truyền âm để Lý Nguyên xuống hắc động trước, còn mình ở lại ngăn Đường Ngôn Vân; hai bên giao thủ, Đường Ngôn Vân dùng năm hắc long nuốt lôi quang tím nhưng bị Vương Lâm làm lôi điện bộc phát từ bên trong. Khi Đường Ngôn Vân nêu thân phận Đường gia và muốn cùng tìm di động Tiên nhân để lại, Vương Lâm lạnh lùng nói hắn không đủ tư cách rồi chủ động truy sát. Đường Ngôn Vân thi triển Nguyên long thôn, hóa ra hắc long nghìn trượng, nhưng Thú cốt từ tay Vương Lâm hiện ra, phóng sát khí và u hỏa hóa đá hắc long, khiến quần tu khiếp sợ. Đường Ngôn Vân định thuấn di chạy trốn nhưng bị Vương Lâm dùng nguyên lực ép kín trăm trượng chặn lại; dù từ xa có tiếng quát uy hiếp, Vương Lâm vẫn giết hắn cả thân thể lẫn nguyên thần. Sau trận, Vương Lâm tuyên bố trong nghìn trượng này kẻ nào tiến vào thì chết, chính thức biến khu vực quanh hắc động thành cấm địa trước mắt quần tu."},{"chuong":730,"tieuDe":"Hứa Mộc!","tomTat":"Sau khi Vương Lâm tuyên bố phạm vi nghìn trượng quanh mình là cấm địa, Lý Nguyên từ hắc động lao ra báo đã đoạt được bảo vật phía dưới và còn phát hiện một thông đạo bí mật. Bốn tu sĩ do Đường Ngôn Phong hiện diện hạ xuống gần khu vực này, trong đó nam tử trung niên và thanh niên Âm Hư lần lượt thử bước vào phạm vi cấm địa. Lý Nguyên tự biết tu vi khó trực tiếp trợ chiến nên lui về cửa hắc động, dùng hắc tuyến từ mi tâm bố trí cấm chế để giữ đường lui. Vương Lâm chỉ bằng ánh mắt và từng bước chân đã khiến nam tử trung niên hoảng loạn, tim sụp đổ và nguyên thần bị xé nát tại chỗ. Thanh niên Âm Hư thấy vậy lập tức lui ra ngoài nghìn trượng, nhận sai và tự nổ ngón út để cầu tha. Đường Ngôn Phong nhận ra cách vận dụng nguyên lực của Vương Lâm cực kỳ nguy hiểm, hỏi danh tính nhưng không dám ra tay. Vương Lâm chỉ lưu lại tên Hứa Mộc rồi cùng Lý Nguyên tiến vào hắc động, để cấm chế phong kín lối vào phía sau."},{"chuong":731,"tieuDe":"Kịch Biến !","tomTat":"Sau khi chứng kiến thực lực của Hứa Mộc, các tu sĩ quanh khu vực đều kiêng sợ, còn nhóm Đường Ngôn Phong cũng ghi nhớ cái tên này. Nữ tử bên cạnh Đường Ngôn Phong suy đoán Hứa Mộc có thể liên quan Hứa gia Đông Lâm Tinh, nhưng Đường Ngôn Phong cho rằng người này quá mạnh, quyết định Đường gia không nên tùy tiện trêu chọc và lập tức rút đi. Các tu sĩ ngoài phạm vi nghìn trượng lần lượt rời khỏi, khiến danh Hứa Mộc bắt đầu truyền ra, trong khi cấm chế phong ấn hang động dần ảm đạm rồi hóa thành tử trận. Bên dưới cấm chế, Vương Lâm và Lý Nguyên đi vào một hang động nối với thông đạo tối; Lý Nguyên nhận định nơi này vẫn còn dư âm tiên lực và có thể họ là nhóm đầu tiên tiến vào sau khi Tiên giới sụp đổ. Càng xuống sâu, Vương Lâm càng cảm thấy mi tâm đau như có ngón tay vô hình đặt vào, sau đó yêu cầu Lý Nguyên tản Tâm Cấm để kiểm chứng hiện tượng. Vương Lâm dùng thần thức phác họa đường đi trong thông đạo thành một ký hiệu kỳ dị, khiến Lý Nguyên nhận ra đó là một loại Tiên Cấm hiếm gặp. Ở tận cùng thông đạo, hai người nhìn thấy lốc xoáy ngũ sắc, và Lý Nguyên suy đoán chín ký hiệu tương tự có thể hợp thành một đại trận chữa thương khổng lồ trong Lôi Tiên Giới."},{"chuong":732,"tieuDe":"Cực Cảnh Lại Xuất Hiện","tomTat":"Vương Lâm và Lý Nguyên tiếp tục quan sát đại trận chữa thương, suy đoán cơn lốc xoáy dẫn tới trận nhãn và có thể che giấu một tiên nhân đang chữa thương qua vô số năm. Lý Nguyên đột nhiên bị lực kỳ dị dẫn dụ, định đánh ra tiên cấm để mở cơn lốc, nhưng Vương Lâm kịp phát hiện, bóp nát cấm chế rồi dùng tiên lực khiến hắn hôn mê và kéo lui. Khi hai người rời đi, trung tâm lốc xoáy hiện ra một con mắt, truyền âm dụ Vương Lâm để Lý Nguyên đánh tiên cấm đổi lấy tiên thuật; Vương Lâm vì cảnh giác và vì bài học Sát Lục Tiên Quyết nên từ chối. Con mắt bèn phóng hồng quang truy kích qua thông đạo, xuyên phá lôi quang của Vương Lâm, khiến hắn nhận ra đó chính là Cực Cảnh. Hồng quang nhập thể, Vương Lâm lập tức kéo Lý Nguyên thuấn di vạn dặm, dùng đại ấn đất cát và thú cốt hộ thân, nhờ Lý Nguyên hộ pháp rồi vận nguyên lực vào thần thức để chống lại tia chớp đỏ đang tàn phá nguyên thần. Nhờ từng sở hữu Cực Cảnh và nguyên thần đã dung hợp Thái Cổ Lôi Long, hắn không bị xóa bỏ ngay mà có cơ hội chống cự. Sau đó, một tu sĩ vô danh vì tham lợi lẻn vào hang động tìm bảo vật sót lại, bị con mắt trong lốc xoáy mê hoặc, dẫn nguyên thần tới gần và tự nổ."},{"chuong":733,"tieuDe":"Chiến Không Liệt","tomTat":"Sau khi huyết nhục của kẻ trong thông đạo bị cơn lốc xoáy hút sạch, thêm một tầng phong ấn bị phá, khiến tồn tại bí ẩn bên trong tuyên bố chín phong ấn đã phá được năm và mở hé bốn phong ấn còn lại để dẫn dụ người tới. Cùng lúc, bốn mảnh vỡ đại lục trong Lôi Tiên Giới phát ra dao động tiên lực mạnh, kéo tu sĩ khắp nơi đổ về. Vương Lâm tỉnh lại, có thể bức tia Cực Cảnh ra khỏi thân thể nhưng quyết định giữ nó trong nguyên thần làm thủ đoạn bảo mệnh, rồi cùng Lý Nguyên rời mảnh vỡ, chuyển hướng tới Tàng Phẩm Các trong ký ức lão già Diêu gia để tìm tiên thuật. Trên đường đi, hắn nhớ tới Nạp Đa từng có Cực Cảnh và nghi ngờ Cực Cảnh có thể tồn tại phương pháp thăng cấp. Hai người gặp ngày càng nhiều tu sĩ trong hư vô, rồi Chiến Không Liệt từ một nhóm kiếm quang quay lại, cung kính bái kiến Vương Lâm là tiền bối trước sự kinh ngạc của mọi người. Chiến Không Liệt báo tin các mảnh vỡ có trọng bảo sau phong ấn và nhắc đã hẹn Thân Công Hổ ở mảnh vỡ mạn trái để liên thủ đoạt bảo, nhưng Vương Lâm ưu tiên Tàng Phẩm Các. Sau mấy tháng, Vương Lâm và Lý Nguyên tới trung tâm phần lớn mảnh vỡ Lôi Tiên Giới; Lý Nguyên dùng tâm cấm dò ra cấm chế, khiến hư ảnh đại lục và lầu các hiện ra rồi tiếp tục phá giải trong khi Vương Lâm quan sát."},{"chuong":734,"tieuDe":"Tư Cách","tomTat":"Trước mảnh vỡ đại lục bị cấm chế che phủ, Lý Nguyên cho biết giải trừ hoàn toàn cấm chế sẽ mất vài tháng nhưng chỉ đưa Vương Lâm vào thì có tám phần nắm chắc; Vương Lâm quyết định tiến vào lấy tiên thuật rồi rời đi, dặn Lý Nguyên ẩn mình cẩn thận. Lý Nguyên thi triển Tâm cấm tiêu tan, kết dấu ấn hắc quang mở một thông đạo hình tròn bất ổn để Vương Lâm lao vào; sau đó thông đạo sụp đổ, mảnh vỡ đại lục biến mất khỏi hư vô, còn Vương Lâm xuất hiện trên đại lục bị quầng sáng cấm chế tách khỏi Lôi Tiên Giới. Một tu sĩ áo đen cảnh giới Dương Thực chặn hắn, dùng Tiên Lôi và thủ ấn công kích nhưng bị nguyên thần Vương Lâm nuốt lôi, rồi bị mảnh vỡ đại ấn ép phải dùng huyết quang thoát thân. Tu sĩ áo đen gọi ba thủ vệ Dương Thực còn lại ra tay, cả bốn tuyên bố ngoài tu sĩ Khuy Niết thì không ai có tư cách vào Tàng Phẩm Các. Chúng hợp kích bằng phi kiếm đỏ, cuồng phong lốc xoáy và đồ hình âm dương; Vương Lâm dùng mảnh vỡ đại ấn kiềm chế hai người, thả Thú Cốt chặn kẻ tạo lốc xoáy, rồi thi triển Định Thân Thuật khiến tu sĩ áo đen và phi kiếm ngừng lại, đánh sụp nhục thân hắn. Nguyên thần tu sĩ áo đen bị Côn Cực Tiên quấn thất thoát nguyên khí rồi bị Tôn Hồn Phiên nuốt lấy; nguyên thần Huyết Tổ hiện ra trong màn sương đen khiến hắn chấn động vì diện mạo quen thuộc và bị bao phủ."},{"chuong":735,"tieuDe":"Tư Cách Cửu Phẩm Tiên Quân","tomTat":"Sau khi thu nguyên thần người áo đen, Vương Lâm dùng sương đen bao phủ khu vực trước Tàng Phẩm Các và buộc các tu sĩ còn lại phải cho hắn vào. Thú Cốt bộc phát sát khí, khiến thần thông lốc xoáy của tu sĩ họ Lữ hóa đá, thân thể ông ta cũng bị hủy đến mức chỉ còn nguyên thần thoát ra. Ba người Trần, Lữ, Tống thừa nhận Hứa Mộc có tư cách vào Tàng Phẩm Các; lão Trần còn mời hắn làm trưởng lão khác họ của Trần gia, đồng thời chương mở rộng bối cảnh về các cấp gia tộc tu chân trong La Thiên Tinh Vực. Sau khi Tàng Phẩm Các được mở, Vương Lâm bước vào không gian sương mù và được phán là Bát Phẩm Thượng Tiên, chỉ có thể vào tầng bốn. Trước khi kiểm tra kết thúc, hắn lấy bảo tháp thả nữ thi áo trắng, điều khiển nàng chạm vào người sương mù, khiến kết quả biến thành Cửu phẩm tiên quân và mở quyền lên tầng chín. Bên ngoài, ba lão kinh hãi khi hào quang Tàng Phẩm Các tăng đến chín đạo, vượt cả giới hạn tầng tám của các lão tổ trước kia. Ở tầng chín, Vương Lâm thấy tiên ngọc, bức họa cây và đồng tử cùng câu thơ nhắc Hô phong hoán vũ, Tát đậu thành binh, Địa liệt sơn băng và Âm nguyệt hữu tình, trong đó cụm cuối vẫn khiến hắn khó hiểu."},{"chuong":736,"tieuDe":"Thần Thông Của Tiên Đế","tomTat":"Vương Lâm kiểm tra tầng chín Tàng Phẩm Các, phát hiện bồ đoàn đá và tiên ngọc trong các ô vuông đều là hư ảnh, chỉ có thể nhìn mà không thể lấy. Không cam lòng rời đi tay trắng, hắn dồn tâm thần quan sát bức họa trong phòng và phát hiện đồng tử dưới tán cây trong tranh âm thầm biến hóa thủ ấn. Sau bảy ngày ghi nhớ, Vương Lâm thi triển lại thủ ấn vào ngày thứ tám, khiến lầu các chấn động và nguyên thần bị kéo vào không gian trong tranh. Trong cảnh giới ấy, câu thơ hóa thành mưa mực, hội chúng mờ ảo hiện ra, rồi một người mờ ảo mang uy áp xuất hiện giảng đạo và nhắc tới bức tranh của Tiêu Dao Tử cùng đề tựa của Tiên Quân. Người này thi triển Hô phong, gọi gió đen hóa chín hắc long, uy năng khiến nguyên thần Vương Lâm tan vỡ. Sau đó thanh âm Tiên Quân cuốn nguyên thần tan vỡ của hắn như mực viết thành hai chữ Hô phong, giúp hắn nhận được tiên thuật rồi đẩy khỏi bức tranh. Vương Lâm tỉnh lại, hiểu cơ duyên này quý hơn toàn bộ tiên ngọc hư ảnh tầng chín, sau đó rời Tàng Phẩm Các. Bên ngoài, Trần, Tống và Lữ từ khiếp sợ chuyển sang ghen tị dữ dội, ý nghĩ ấy dần lấn át lý trí."},{"chuong":737,"tieuDe":"Thu Tàng Phẩm Các","tomTat":"Sau khi rời quang môn Tàng Phẩm Các trong trạng thái còn hoảng hốt vì cảm ngộ tiên thuật tầng chín, Vương Lâm bị ba tu sĩ họ Trần, họ Tống và họ Lữ nổi sát tâm đánh úp để đoạt ý niệm tiên thuật trong đầu. Giữa lúc pháp bảo và thần thông áp sát, hắn gần như bản năng thi triển Hô Phong, gọi hắc phong khiến trời đất biến sắc, phá nát ngân châm, âm dương đồ, hư ảnh tiên khí và hỏa long của đối phương. Tu sĩ họ Trần bị hắc phong thổi tắt nguyên thần; tu sĩ họ Tống và họ Lữ lần lượt mất thân thể, nguyên thần bị đại ấn, Nhân Quả Côn Cực Tiên và Tôn Hồn Phiên chế phục rồi bị Vương Lâm bóp nát nuốt lấy nguyên lực. Vì Hô Phong tiêu hao quá lớn, Vương Lâm còn luyện hóa nguyên thần người áo đen trong Tôn Hồn Phiên và nhận ra về sau muốn dùng thuật này phải chuẩn bị nguyên thần Âm Hư, Dương Thực để bổ sung. Hắn nhớ lại lời liên quan Tiêu Dao Tử và thủ ấn của đồng tử trong bức tranh, bèn thi triển ấn quyết khiến Tàng Phẩm Các thu nhỏ bằng lòng bàn tay và thu vào tay. Sau đó, vì đã kết thù với tứ đại gia tộc, Vương Lâm dùng gần mười ngày bày cấm chế nham hiểm trên mảnh vỡ đại lục rồi rời đi; nửa tháng sau, hắn cùng Lý Nguyên bay nhanh trong hư vô."},{"chuong":738,"tieuDe":"Sống Lại","tomTat":"Lý Nguyên theo yêu cầu của Vương Lâm bố trí hơn mười vạn cấm chế quanh mảnh vỡ đại lục có Tàng Phẩm Các, đồng thời không dùng Phá Thiên Cấm của gia tộc để tránh lộ dấu vết. Vương Lâm giữ kín việc mình đã đoạt được Tàng Phẩm Các, cảm thấy biến động tiên lực trong Lôi Tiên Giới không lành nên quyết định đi thẳng tới đại môn để dùng Lôi Đỉnh rời khỏi nơi này. Trong khi đó, bốn mảnh vỡ đại lục ở đông, tây, nam, bắc đồng loạt xuất hiện tiên lực nồng đậm và trận pháp cấm chế cổ xưa, thu hút rất nhiều tu sĩ cùng cao thủ cấm chế tụ tập phá giải. Ở mảnh vỡ phía tây, Thân Công Hổ nhận ra trận pháp trên bình nguyên xuất hiện quá bất thường, còn Chiến Không Liệt tới báo đã gặp vị tiền bối sẽ đến, khiến cả hai càng thêm cảnh giác. Các thông đạo sau trận pháp lần lượt biến thành bẫy chết: phía bắc bị hồng quang quét sụp, phía đông khiến tu sĩ tự nổ khi thấy lốc xoáy ngũ sắc, phía nam tái diễn thảm kịch, còn phía tây sụp đổ sau tiếng kêu thảm. Khi bốn thông đạo đều tan rã, tiên lực khổng lồ tràn ngập toàn Lôi Tiên Giới, chín mảnh vỡ đại lục cùng hiện dấu ấn trận pháp đỏ. Một mảnh vỡ bị khí tức vượt xa Khuy Niết phá nát từ bên trong, để lộ một cánh tay cụt bị phong ấn vô số năm; sau khi thoát ra, cánh tay ấy bay thẳng về trung tâm Lôi Tiên Giới."},{"chuong":739,"tieuDe":"Ai Cũng Không Thể Rời Khỏi!","tomTat":"Sau khi cánh tay cụt xuất hiện, bảy mảnh vỡ đại lục còn lại sụp đổ, phóng ra hai tay, hai chân, đầu lâu một mắt và các phần thân thể khác; những tàn chi này nuốt tu sĩ trên đường rồi bay về trung tâm Lôi Tiên Giới. Vương Lâm và Lý Nguyên đang lao về cực tây thì gặp cánh tay đỏ đầy sát khí, khiến tử lôi và mảnh vỡ đại ấn của Vương Lâm đều bị áp chế; hắn phải dùng con mắt thứ ba, Định và thú cốt để hóa đá ba giọt máu, rồi thu chúng và dùng Trảm La Quyết truy kích. Cánh tay cụt chuyển sang giết sạch một đội gia tộc tu chân để hấp thu nguyên thần hồi phục, sau đó có thêm tàn chi khác bay tới khiến Vương Lâm lập tức rút đi. Tám đạo hồng quang hội tụ ở trung tâm Lôi Tiên Giới, hợp thành quái nhân tóc bạc thân thể tàn phá, thiếu mắt phải; hắn nhắc tới Thanh Thủy Tiên Quân, lốc xoáy phong ấn và việc mình sống sót sau khi tiên giới sụp đổ. Quái nhân phá phong ấn thứ chín trên mảnh vỡ đại lục từng có thông đạo, lấy lại mắt phải chứa Cực Cảnh rồi quyết định đóng cửa Tiên Giới để nhốt toàn bộ tu sĩ làm thức ăn khôi phục tiên nguyên. Khi Vương Lâm, Lý Nguyên và nhiều tu sĩ chạy tới cửa Lôi giới, quái nhân xuất hiện trong sương đỏ, giết nuốt người và thi pháp khiến tia chớp đỏ của cánh cửa thu nhỏ. Một nam tử kim bào Âm Hư kêu gọi mọi người ngăn hắn đóng đại môn nhưng bị giết; quái nhân tiếp tục dùng Tiên thuật hóa thân tạo ba mươi hai phân thân phong tỏa phạm vi ngàn trượng, khiến mọi tu sĩ lao vào đường sống duy nhất đều bị diệt thân và nuốt nguyên thần."},{"chuong":740,"tieuDe":"Tôn Chủ, Ra Tay Đi","tomTat":"Quái nhân tóc bạc dùng ba mươi hai phân thân phong tỏa khu vực quanh đại môn Tiên giới, còn bản thể xử lý những tu sĩ Âm Hư lọt vào gần hơn và thôn phệ nguyên lực từ họ để mạnh lên. Chiến Không Liệt, Đường Ngôn Phong, Thân Công Hổ cùng nhiều tu sĩ Dương Thực và Âm Hư hợp lực vây công, nhưng màn sáng đỏ của quái nhân phản chấn pháp bảo thần thông khiến họ bị thương. Vương Lâm vì ân tình của Lý Nguyên quyết định mạo hiểm dùng trạng thái dung nhập thiên địa chưa hoàn toàn nắm giữ để đưa Lý Nguyên tới đại môn. Quái nhân tóc bạc nhận ra đạo dung thiên địa, tự dung nhập thiên địa truy bắt và ép Vương Lâm hiện thân cách đại môn hơn năm mươi trượng. Vương Lâm đẩy Lý Nguyên vào cửa, tự bạo dòng chảy nguyên lực để cản quái nhân, giúp Lý Nguyên dùng Lôi Đỉnh thoát khỏi Lôi tiên giới. Ngay sau đó quái nhân tóc bạc khiến đại môn tiêu tan, Vương Lâm bị kẹt lại và trở thành tiêu điểm của toàn trường. Khi Thân Công Hổ chờ mong gọi Tôn chủ ra tay, Vương Lâm bị phong kín đường lui, liền thi triển Phong gọi hắc phong hóa thành hắc long phun gió về phía quái nhân tóc bạc."},{"chuong":741,"tieuDe":"Ra Tay","tomTat":"Quái nhân tóc bạc nhận ra thần thông Hô Phong của Vương Lâm và lập tức hỏi hắn có quan hệ gì với tiên đế Bạch Phàm, nhưng Vương Lâm không đáp mà tiếp tục điều khiển hắc phong công kích. Trước tốc độ và lực lượng áp đảo của đối thủ, Vương Lâm lần lượt tung tia chớp đỏ, mảnh đại ấn, Thú Cốt, tiên kiếm cùng Trảm La Quyết, song đều bị nhận ra hoặc phá giải. Không còn cách nào khác, hắn hút nguyên lực từ nửa huyết thân, bất chấp thân thể khó chịu nổi, cưỡng ép làm Hô Phong tăng mạnh và hóa thành nhiều hắc long vây công. Sau đó Vương Lâm ném nửa huyết thân về phía quái nhân tóc bạc và kích nổ, khiến ba hắc long tan nát, không gian chấn động dữ dội và xuất hiện dấu hiệu sụp đổ. Những tu sĩ quan chiến đều bị trận chiến làm rung động; Thân Công Hổ, Chiến Không Liệt sùng kính hoặc chăm chú, còn Đường Ngôn Phong kinh hãi và muốn mau lui. Khi Vương Lâm định dung nhập thiên địa để rút khỏi chiến trường, lão giả thần bí từng lấy Lôi Thú truyền lực lượng từ hư vô tới, cắt đứt liên hệ của hắn với nhục thân, ép nguyên thần hắn lại rồi mượn thân thể hắn hoàn toàn."},{"chuong":742,"tieuDe":"Hỏa, Viêm, Diễm","tomTat":"Sau vụ sụp đổ không gian, một pho tượng đen nứt mi tâm, để Thanh Thủy tiên quân trong hình dạng nam tử trung niên tóc đen bước ra mà không hề bị thương. Hắn nhận ra nhiều thủ đoạn bên phía Vương Lâm như Bạch Phàm tiên thuật, Thanh Sương tiên kiếm và pháp bảo của Tiêu Dao Tử, rồi biến pho tượng thành trường thương màu đen để giao chiến. Lão giả đang điều khiển thân thể Vương Lâm thu lực lượng thiên địa thành bạch cầu, va chạm với hồng mang trường thương khiến khe không gian lan rộng và nuốt mất một số tu sĩ. Sau đó lão giả thi triển Phần Tiên Hỏa, tiếp tục gọi Viêm và Diễm, khiến biển lửa hóa viêm long rồi co thành hỏa cầu thiêu đốt cả hữu hình lẫn hư vô. Thanh Thủy dùng Cực Cảnh xuyên phá hỏa cầu, đánh vào thân thể Vương Lâm và liên tục đánh tan nguyên thần lão giả; Vương Lâm buộc phải trợ lực, cuối cùng cùng lão giả áp chế và phong ấn Cực Cảnh trong nguyên thần. Bên ngoài, Thân Công Hổ, Chiến Không Liệt và Đường Ngôn Phong đều hiểu lầm uy thế này là thực lực thật của Vương Lâm, khiến Đường Ngôn Phong hoảng sợ về thân phận của hắn. Khi hỏa cầu tan nát, Thanh Thủy lại xuất hiện từ một pho tượng trong hỏa quang dưới hình dạng thanh niên anh tuấn đầy tà khí."},{"chuong":743,"tieuDe":"Mục Đích","tomTat":"Quái nhân tóc bạc sau nhiều lần thoát nguy bằng pho tượng đã trẻ hóa thành thanh niên, biến tượng vỡ thành trường thương rồi tiếp tục thôn phệ tu sĩ để bổ sung bản thân. Lão giả thần bí điều khiển thân thể Vương Lâm dùng tử quang đẩy toàn bộ tu sĩ trong phạm vi mười dặm ra xa, cố cô lập chiến trường, nhưng thanh niên tà khí tránh giao chiến trực diện và tiếp tục truy sát người bỏ chạy. Khi bị gọi là Thanh Thủy tiên quân, hắn phủ nhận danh tính này, khiến thân phận thật vẫn chưa được xác nhận. Thân Công Hổ lâm nguy, bộc lộ đạo lôi điện đỏ sậm do nhiều năm ngưng luyện từ chỉ điểm của Vương Lâm, nhưng bị đối phương bóp nát; Vương Lâm lập tức truyền thần niệm yêu cầu lão giả cứu hắn. Thanh niên tà khí phân ra ba mươi hai phân thân truy sát tu sĩ, buộc lão giả thi triển tiên thuật “tiêu” và “tán” để đưa toàn bộ tu sĩ rời khỏi chiến trường, khiến nguyên thần lão suy yếu gần tiêu tán. Cuối chương, trong lúc truy đuổi qua nhiều mảnh đại lục, thanh niên nói đã biết lão giả muốn dụ hắn tới chỗ bản thể, nhưng vẫn thuận theo vì nơi đó có vô số luyện khí sĩ có thể giúp hắn khôi phục tu vi."},{"chuong":744,"tieuDe":"Vùng Đất Gần Viễn Cổ Tiên Vực Nhất","tomTat":"Lão giả thần bí tiếp tục điều khiển thân thể Vương Lâm, dùng cách di chuyển gần như dung nhập thiên địa để lao đi cực nhanh, đổi lại nguyên thần của lão tiêu tán dữ dội. Trong quá trình bị điều khiển, Vương Lâm chịu đau đớn nhưng thu được cảm ngộ sâu hơn về Súc địa thành thốn, dung hợp thiên địa, nguyên thần, ý cảnh nhân quả và thân thể. Khi cả hai hiện ra trên một đại lục phía bắc Lôi tiên giới, nguyên thần lão giả hoàn toàn biến mất, còn Vương Lâm lập tức tự bạo dòng nguyên lực quanh thân để tránh cú tập kích của thanh niên đầy tà khí. Hắn dùng tiên kiếm chém tám đạo Trảm La Quyết phá lực giam cầm rồi tiếp tục bỏ chạy, trong khi đối phương nhận ra nơi này là Triều Tiên Đài, trung tâm Lôi tiên giới năm xưa và là vùng đất gần viễn cổ tiên vực nhất. Bị quang cầu đỏ đánh tới, Vương Lâm không còn huyết thân Huyết Tổ để thoát thân nên dùng mảnh vỡ đại ấn chống đỡ, tuy đại ấn không vỡ nhưng phản lực khiến hắn trọng thương. Sau đó hắn triển khai tấm bình phong chứa Sơn Hà Đồ, mượn cảnh non nước triệt tiêu công kích, nhưng thanh niên tà khí xé rách cảnh tượng và bức hắn hiện thân trong tình trạng suy yếu."},{"chuong":745,"tieuDe":"Viêm Lôi Tử","tomTat":"Thanh niên đầy tà khí tuyên bố từng nghiên cứu Sơn Hà Đồ nhiều năm và có thể phá đồ thật, nhưng chưa kịp tiếp tục truy kích thì toàn bộ Lôi Tiên Giới chấn động dữ dội. Bốn mươi chín mảnh vỡ đại lục bị Lôi Thú kéo lên, lấy mảnh vỡ nơi Vương Lâm và thanh niên đầy tà khí làm trung tâm, xoay thành đại trận hình hoa mai khiến hư không nứt rách và Lôi Tiên Giới sụp đổ lần thứ hai trên phạm vi lớn. Lão già thần bí hiện thân, tự xưng Viêm Lôi Tử, nói đã chuẩn bị hàng vạn năm để luyện hóa một nửa Lôi Tiên Giới thành pháp bảo, dùng nó mở vách ngăn không gian cho tu sĩ La Thiên Tinh Vực tiến vào Liên Minh Tinh Vực mà không cần La Thiên Thạch. Hắn cũng nhắc mối thù với Trọng Huyền Tử và dã tâm dẫn La Thiên san bằng Liên Minh Tinh Vực. Sau đó Viêm Lôi Tử thúc nguyên lực xuống mặt đất, tuyên bố Lôi Tiên Đại Trận tái hiện, còn thanh niên đầy tà khí nhận ra hiện thân của hắn chỉ là phân thân hư ảo và cho rằng luyện hóa tiên giới cần pháp linh. Viêm Lôi Tử phun khí xám chứa mảnh kính cũ, để mặt kính phóng ra các nguyên thần Âm Hư dung nhập vào mảnh vỡ đại lục; đến cuối chương, mười tám mảnh vỡ đã có pháp bảo chi linh và một nguyên thần Dương Thực mạnh hơn xuất hiện."},{"chuong":746,"tieuDe":"Tiên Quân Thanh Thủy","tomTat":"Sau nguyên thần Dương Thực, Viêm Lôi Tử tiếp tục đưa thêm mười ba nguyên thần vào bốn mươi chín mảnh vỡ đại lục, khiến Tiên Giới Đại Trận tăng linh tính và uy lực. Hắn dùng cổ kính cùng pháp quyết Tái hiện để gọi ra những nguyên thần cấp cao hơn, từ Khuy Niết tu sĩ tam phẩm thiên tiên, cửu phẩm thiên tiên sát khí, lão già nhị phẩm tiên vương cho đến hai nguyên thần nhất phẩm Tiên Quân. Huyết Tổ cũng bị đưa vào trận làm đệ tứ thần, cho thấy Viêm Lôi Tử tạm thay đổi bố trí ban đầu sau khi đoạt được nguyên thần này. Khi cổ kính vỡ nát, Sát Lục Tiên Quân lục phẩm của Vũ Tiên Giới xuất hiện, sát khí ép Vương Lâm phun máu rồi nhập vào mảnh vỡ trung tâm làm đệ nhất thần. Viêm Lôi Tử thu bốn mươi chín mảnh vỡ đại lục thành các mảnh nhỏ quanh mình, hợp nhất thần thức phân tán để ngưng tụ lại bản thể. Sau đó hắn nói thẳng với thanh niên tà khí rằng mình muốn Cực Cảnh của Thanh Thủy Tiên Quân, dù đối phương phủ nhận mình là Thanh Thủy. Viêm Lôi Tử kể rằng Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, phi thăng đến Lôi Tiên Giới thành Tiên Quân, rồi trước khi tiên giới bị phá đã nhập ma gây sát kiếp. Cuối cùng Tiên Đế Bạch Phàm ra tay đánh bại Thanh Thủy nhưng không nỡ giết hắn."},{"chuong":747,"tieuDe":"Hiệp Định","tomTat":"Viêm Lôi Tử kể lại bi kịch của Thanh Thủy: sau khi tỉnh khỏi cơn mất thần trí, Thanh Thủy biết mình đã giết rất nhiều tiên nhân thân cận nên tự sát và dùng pháp bảo lốc xoáy phong ấn nguyên thần, thân thể thành chín phần để ngăn Cực Cảnh khiến mình sống lại. Bạch Phàm vì xem Thanh Thủy là đệ tử duy nhất và hy vọng duy nhất của Lôi Tiên Giới nên bố trí trận pháp trị thương trên chín phong ấn, đồng thời để lại tiên giản cũ. Viêm Lôi Tử đưa tiên giản ấy cho Thanh Thủy, nhưng vật này lại kích phát huyết quang và sát ý, khiến Thanh Thủy nuốt tiên giản rồi tấn công ông. Hai bên giao chiến dữ dội: Viêm Lôi Tử dùng bốn mươi chín mảnh vỡ, tiên trận và Đồ Tiên Thứ vây công, còn Thanh Thủy phá trận bằng Hô Phong, tiếp tục dùng Hoán Vũ và Băng Ấn tạo thế áp chế. Vương Lâm rút khỏi vùng nguy hiểm, bị dư chấn làm thất khiếu chảy máu nhưng vẫn quan sát và nhận ra uy lực chân chính của Hô Phong. Khi xung đột sắp leo thang, Viêm Lôi Tử nêu nghi vấn rằng không chỉ Thanh Thủy mà Tiên Quân ở ba tiên giới khác cũng từng mất thần trí, đồng thời gợi ý Tu Chân Liên Minh cùng Phong, Điện hai đại tiên giới có thể liên quan đến đáp án. Thanh Thủy tạm nén sát khí và yêu cầu Viêm Lôi Tử đưa ra một lý do để hắn giao Cực Cảnh."},{"chuong":748,"tieuDe":"Sư Huynh?","tomTat":"Viêm Lôi Tử thuyết phục Thanh Thủy tới Liên Minh Tinh Vực ở Vũ tiên giới để thôn phệ tu sĩ đại thần thông khôi phục tu vi, đưa ra manh mối về quyển trục Tu Chân Liên Minh mang khí tức viễn cổ tiên vực được đồn ghi nguyên nhân thật sự khiến tứ đại tiên giới sụp đổ, liên quan tới kinh biến năm xưa của Thanh Thủy. Thanh Thủy không hoàn toàn tin nhưng chấp nhận đi cùng, cảnh cáo sẽ dẫn bạo Cực Cảnh nếu bị lừa; bốn mươi chín tia Cực Cảnh màu đỏ của hắn dung nhập vào các mảnh nhỏ pháp bảo tiên trận, khiến pháp bảo mang khí tức âm hàn và thần thông Cực Cảnh. Viêm Lôi Tử mở hắc động, cùng Thanh Thủy rời Lôi tiên giới để gặp đạo hữu La Thiên rồi mở thông đạo. Vương Lâm đòi trả Lôi Thú vì tiên trận đã thành hình, nhưng Viêm Lôi Tử hẹn dùng thêm vài ngày, đồng thời trao đoạn sừng tử kim làm tín vật, hứa nếu Vương Lâm tự rời Lôi tiên giới và trong một năm tới Lôi Tiên Điện thì có cơ hội cùng đi Liên Minh Tinh Vực. Trước khi biến mất, Thanh Thủy truyền thần niệm nói Vương Lâm đã học Hô Phong thuật nên xem như truyền nhân của sư tôn mình, một trong sáu đại thần thông cả đời của sư tôn. Sau khi mất bốn mươi chín mảnh đại lục, Lôi tiên giới càng sụp đổ dữ dội, khe nứt không gian dày đặc; Vương Lâm nhớ lời Thân Công Hổ và cảm ứng đạo hồn trong nguyên thần hắn để đổi hướng đi tìm. Thân Công Hổ biết một truyền tống trận duy nhất do Lôi Tiên Điện bố trí trong Lôi tiên giới, buộc phải chọn hướng đó khi đại môn đã đóng, đồng thời vẫn tin tôn chủ Vương Lâm sẽ không thua."},{"chuong":749,"tieuDe":"Lao Ra!","tomTat":"Trong lúc Lôi Tiên Giới sụp đổ dữ dội, Chiến Không Liệt dựa vào thân phận tân sứ giả Lôi Tiên Điện để bay thẳng về truyền tống trận, đồng thời vẫn tin Vương Lâm sẽ không thua sau trận chiến ngoài đại môn tiên giới. Vương Lâm lần theo Thân Công Hổ bằng đạo hồn trong nguyên thần, nhưng các khe nứt không gian dày đặc khiến tốc độ truy đuổi bị hạn chế. Để phá thế bế tắc, hắn phun đất cát từ mi tâm, hóa thành mảnh đại lục hơn trăm trượng, dùng độ bền từng chịu thiên kiếp và một kích của Thanh Thủy để ép qua khe nứt rồi truyền nguyên lực tăng tốc. Trên đường, hắn gặp Chiến Vân sắp bị khe nứt nuốt, đổi hướng cứu nàng sau khi nghe nàng nói Chiến Không Liệt là tộc huynh. Sau khi lên mảnh đại lục, Chiến Vân bị Vương Lâm đòi tiên ngọc cho ơn cứu mạng và thời gian trú lại, cuối cùng giao túi có khoảng năm vạn tiên ngọc dù trong lòng khinh miệt. Nàng sau đó nhận ra Tây Tử Phượng cùng hai tu sĩ khác đang đuổi theo, xin Vương Lâm dừng lại không được nên tự lấy dây tơ tằm màu hồng phóng về phía ba người."},{"chuong":750,"tieuDe":"Lao Ra!","tomTat":"Tây Tử Phượng cùng hai nam tử đuổi kịp mảnh nhỏ trăm trượng trong Lôi Tiên Giới, nhận ra Vương Lâm và cung kính cảm tạ hai lần cứu mạng. Chiến Vân thay Vương Lâm đặt quy củ thu tiên ngọc: mười vạn để trả ơn cứu mạng, thêm mười vạn để lưu lại một canh giờ, khiến nhiều tu sĩ lần lượt bám lên mảnh nhỏ hoặc đi theo phía sau. Uy danh Vương Lâm sau trận ngoài cánh cửa tiên giới khiến không ít tu sĩ kiêng nể, trong khi hắn cũng cảm nhận Thân Công Hổ đã không còn xa. Một tảng đá ngàn trượng chở ba tu sĩ Dương Thực và gần trăm người xuất hiện, vì tảng đá liên tục vỡ vụn nên nhóm này muốn cướp mảnh nhỏ của Vương Lâm. Vương Lâm dùng Thú cốt làm thân thể nam tử kim bào xám hóa rồi gọi Tôn Hồn Phiên truy nguyên thần; tiếp đó hắn nuốt Tiên thuật lôi trảm của lão giả bạch y, thi triển Định thân tiên thuật đánh nát thân thể lão và bắt nguyên thần. Văn sĩ áo lam phóng kiếm hư ảo cứu viện nhưng bị con mắt thứ ba của Vương Lâm phá hủy. Khi đối phương muốn thoái lui, Vương Lâm trở lại mảnh nhỏ, thi triển Hô Phong và ép văn sĩ áo lam lùi vào khe không gian rồi biến mất."},{"chuong":751,"tieuDe":"Lao Ra!","tomTat":"Sau khi giết ba tu sĩ Dương Thực, uy danh của Vương Lâm khiến các tu sĩ quanh mảnh nhỏ trăm trượng kính sợ, không ai dám có ý cướp đoạt. Hắn gặp lại Thân Công Hổ, người này cung kính bái kiến gọi là tôn chủ rồi dẫn hắn tới truyền tống trận của Lôi Tiên Điện, cách không tới mười dặm. Lôi Tiên Giới sụp đổ nghiêm trọng, hư không đầy khe nứt chết người, một khe gần hai trăm trượng nuốt mất một bộ phận tu sĩ theo sau. Tới nơi, Vương Lâm thấy mảnh đại lục có truyền tống trận được màn sáng ngàn trượng bao bọc, người trong màn sáng vận nguyên lực tạo hào khe nứt chặn lối vào. Trước thần niệm lạnh lùng bảo lui, hắn thúc mảnh nhỏ tăng tốc, chém chín đường Trảm La Quyết dung hợp làm một mở lỗ hổng, đánh vào màn sáng khiến nó nứt vỡ. Một sứ giả Lôi Tiên Điện lao ra ngăn cản nhưng bị các tu sĩ trên mảnh nhỏ vây công. Cuối cùng Vương Lâm dẫn nguyên lực đông đảo tu sĩ hợp vào mảnh nhỏ, đánh sập màn sáng và đưa cả ngàn người tràn vào mảnh đại lục chứa truyền tống trận tìm đường sống."},{"chuong":752,"tieuDe":"Lực Lượng Cầu Sinh","tomTat":"Sau khi màn sáng tan nát, đám tu sĩ đi theo mảnh nhỏ trăm trượng lao vào khu truyền tống trong trạng thái điên cuồng vì sinh tồn, không còn e dè uy áp cảnh giới hay thân phận sứ giả Lôi Tiên Điện. Bảy sứ giả bên ngoài truyền tống trận biến sắc trước thế công của hơn trăm tu sĩ, đặc biệt là sát khí và uy thế mà Vương Lâm tạo ra trong đám đông. Vương Lâm dùng Trảm La Quyết công kích một sứ giả, đúng lúc nam tử trung niên gầy gò cảnh giới Dương Thực hóa ngân quang xuyên ngực đối phương, rồi hắn phóng cuồng lôi màu tím diệt nguyên thần sứ giả này. Cái chết của một sứ giả khiến khí thế phe tu sĩ dâng cao; Vương Lâm liên tiếp quát “Nhường đường”, kéo theo tiếng hưởng ứng của đám tu sĩ và ép sáu sứ giả còn lại phải lùi về phía trận pháp. Ở phía sau, truyền tống trận đã mở, bên trong có mấy sứ giả Lôi Tiên Điện vây quanh Chiến Không Liệt; họ chứng kiến cảnh bên ngoài rồi theo trận pháp hóa thành cột sáng bay lên trời biến mất."},{"chuong":753,"tieuDe":"Đại Ân Không Bao Giờ Quên","tomTat":"Vương Lâm dẫn hơn trăm tu sĩ đồng loạt hô nhường đường và tiến về truyền tống trận, tạo khí thế khiến sáu sứ giả Lôi Tiên điện liên tục lùi lại. Một sứ giả hoảng sợ thúc giục mở trận bỏ chạy, ba người khoanh chân vận chuyển trận pháp, ba người còn lại cố ngăn cản. Vương Lâm phá Khóa nguyên, phong thần, đoạt khóa vàng rồi dùng lôi nguyên thần luyện hóa; sau đó hắn phá phòng hộ ba lá cờ nhỏ, định thân và bắt nguyên thần một sứ giả. Các tu sĩ còn lại cũng hợp lực vây giết thêm sứ giả, khiến thế thủ của Lôi Tiên điện tan rã. Ba sứ giả cưỡng ép truyền tống bằng cách phá hủy trận pháp, nhưng khi bốn sứ giả sắp biến mất trong cột sáng, Vương Lâm dùng Trảm La quyết chém tan cột sáng khiến họ bị xé nát. Sau đó các tu sĩ lần lượt rời đi; Thân Công Hổ vì từng chịu ân Lôi Tiên điện nên không ra tay và đổi dung mạo trước khi truyền tống. Trước lúc biến mất, Vương Lâm tự xưng là Hứa Mộc, để toàn bộ tu sĩ được cứu ghi nhớ đại ân này."},{"chuong":754,"tieuDe":"Cuối Ranh Giới","tomTat":"Sau khi cột sáng biến mất, Lôi Tiên Giới tiếp tục sụp đổ: mảnh đất nhỏ cuối cùng bị khe nứt nuốt chửng, chưa tới hai mươi mảnh đại lục còn sót và cả lôi quang thiết liên đều bị băng đen đóng kín. Những tu sĩ chưa kịp rời đi bị gió lạnh đóng băng trong đủ tư thế, pháp bảo đang thi triển cũng đông cứng, khiến thế giới này chỉ còn như một bầu trời sao yếu ớt trong lớp băng chết. Giữa cảnh băng phong, một trường kiếm ảo ảnh mang bóng người trên mũi kiếm lướt qua rồi biến mất, để lại một bí ẩn chưa giải thích. Cùng lúc, hơn trăm tu sĩ sống sót được truyền tống tới đại lục thứ tư La Thiên, trở về gia tộc và kể lại việc Hứa Mộc kháng quái nhân tóc bạc, cứu người, dẫn họ vào truyền tống trận Lôi Tiên điện. Các gia chủ vì e ngại Lôi Tiên điện truy cứu chuyện xông vào cấm địa nên chọn liên hợp, xóa bỏ trọng tâm sự việc và chủ động lan truyền tên Hứa Mộc. Sau đó Vương Lâm xuất hiện ở sâu trong vùng ranh giới phía Tây La Thiên, nơi bóng tối và sương mù dày đặc khiến hắn cảm thấy nguy hiểm. Hắn dùng hai lôi cầu đẩy lui sương mù, đi ba ngày vẫn không thoát ra nên không dám thả thần thức mà chuyển sang dung nhập không gian. Khi vượt qua màn sương và xuất hiện ở nơi tưởng là cuối đường, trước mặt hắn lại là một bức tường thịt đỏ sậm khổng lồ kéo dài không thấy điểm cuối."},{"chuong":755,"tieuDe":"Thượng Tiên","tomTat":"Vương Lâm dung hợp với trời đất để hướng về tinh cầu tu chân của mình nhưng bị một vật thể như bức tường cản lại, rồi phát hiện trước mặt là bức tường thịt khổng lồ đang nhúc nhích. Khi bức tường phun sương đen và các khe hở dần khép lại, hắn quyết định lao vào một khe hở, vượt qua con đường hẹp bên trong để tìm lối ra. Ra khỏi đường hầm, hắn thấy một đại lục lơ lửng giữa không trung và gặp nam tử áo vải có ký hiệu trên mặt, cầm pháp khí kỳ quái. Nam tử bỏ chạy bằng dấu ấn thực vật bảy lá, khiến Vương Lâm nhận ra đây là Tiên Di tộc, rồi bị hắn dùng nguyên lực ép hiện thân và bắt giữ. Hơn trăm người Tiên Di tộc sau đó kéo tới, trong đó lão nhân tóc bạc cung kính gọi Vương Lâm là Thượng tiên và nhận định hắn là Bát phẩm thượng tiên vì hình bộ xương thú trên tay phải. Qua lời lão nhân, Vương Lâm nghi ngờ nhóm người này không biết Tiên giới đã biến mất và vẫn giữ nhận thức cổ xưa về Tiêu Dao tiên vương. Lão nhân xác nhận hình bộ xương thú là Tử Mẫu Đạo Khô của Tiêu Dao tiên vương, suy đoán Vương Lâm là người thân cận của ông, rồi nhắc tới Huyền Âm đỉnh và mời hắn vào đại lục thưởng Linh Tiên quả."},{"chuong":756,"tieuDe":"Tộc Tiên Tuyển","tomTat":"Vương Lâm theo lão nhân tới một bình nguyên rộng lớn trên đại lục, nơi trung tâm có quần thể kiến trúc cổ của tộc Tiên Di/Tiên Tuyển. Nhờ Trừu Hồn thuật và hiểu biết cấm chế, hắn nhận ra bên ngoài khu cư trú có một cấm chế khổng lồ, được lão nhân giải thích là trận pháp do tiên vương năm xưa tự tay bày để chống Vụ thú. Khi tộc nhân xuất hiện, họ đều sợ hãi người ngoài, vì đã quá lâu không gặp người của tiên giới và thường nghi ngờ kẻ lạ là Vụ thú do sương đen biến thành. Lão nhân kể bộ tộc đời đời bảo vệ Huyền Âm đỉnh theo Tiêu Dao tiên vương, nhưng từ ba ngàn năm trước đỉnh cứ trăm năm mở một lần, phun sương đen hóa yêu thú, thậm chí có Vụ thú hóa người giết hại tộc nhân. Vương Lâm muốn tới cấm địa xem Huyền Âm đỉnh thì Tháp Sơn, đại hán có ký hiệu mười ba lá, bước ra phản đối. Tháp Sơn phủ nhận niềm tin vào tiên nhân và tiên dụ, cho rằng bộ tộc bị bỏ mặc trước tai họa nên chỉ có thể tin vào thực lực bản thân. Hắn tuyên bố dù Vương Lâm là tiên nhân thật cũng phải giết tiên rồi tung quyền đánh tới, khiến Vương Lâm nhận ra đối phương là Đại Phù sĩ tu luyện thân thể."},{"chuong":757,"tieuDe":"Vụ Thú","tomTat":"Tháp Sơn dùng thân thể mạnh mẽ và ký hiệu quanh người tấn công Vương Lâm, nhưng Vương Lâm phá lực trói buộc, liên tiếp áp chế và khiến đối thủ bị đẩy lui trước sự chấn động của tộc Tiên Tuyển. Không chịu dừng lại, Tháp Sơn thu ký hiệu về mi tâm tạo thành linh giáp đen do tiên ban thưởng, khiến lão nhân tộc Tiên Tuyển kinh ngạc và khiến Vương Lâm liên tưởng tới áo giáp Tán Ma ở mảnh đất yêu linh. Vương Lâm phun ra một hạt cát hóa thành mảnh đất nhỏ tiên giới rộng trăm trượng, dùng tiên lực và độ cứng của nó trấn áp Tháp Sơn, khiến đối phương không thể phá nổi. Khi mảnh đất nhỏ nện xuống, toàn đại lục rung chuyển, nứt ra và phun sương đen, nhanh chóng ngưng thành khoảng một trăm Vụ thú màu đen trên bầu trời. Tộc nhân tộc Tiên Tuyển lập tức dùng pháp khí dạng vòi ấm để hút diệt Vụ thú trước khi chúng thức tỉnh, nhưng một con mở mắt, chui vào thất khiếu một tộc nhân và khiến người đó nổ tung. Lão nhân vội gọi Tiên trận diệt sát, còn cuối chương một Vụ thú khác mở mắt lao thẳng về phía Vương Lâm, tiếng rít như muốn xuyên thủng tâm thần."},{"chuong":758,"tieuDe":"Huyền Âm Đỉnh","tomTat":"Vương Lâm tiếp tục đối phó đám vụ thú: sau khi dùng lôi cầu đánh tan một con, hắn thi triển Đạo hóa Hoàng Tuyền và thức thứ ba, lực Hoàng Tuyền, hút gần hết vụ thú vào dòng Hoàng Tuyền. Sương mù chưa bị luyện hóa dung hợp thành một vụ thú hình người một mắt, được lão nhân tộc Tiên Tuyển cảnh báo là thứ không pháp thuật nào có thể giết ngay, lại còn có thể chịu đòn và mô phỏng lôi quang của Vương Lâm. Vương Lâm lần lượt dùng lôi cầu, kiếm tiên thi triển Trảm La quyết, Định Thân Thuật và bộ xương thú bắn tia sáng đen khiến sương mù hóa đá, rồi đánh nát hoàn toàn quái vật. Tộc nhân Tiên Tuyển chấn động trước sức mạnh này, Tháp Sơn gọi hắn là tiên nhân, còn lão nhân lẩm bẩm Tử Mẫu đạo khô. Vương Lâm yêu cầu được đưa tới Huyền Âm đỉnh và cho Tháp Sơn đi theo dẫn đường dù lão nhân phản đối. Ba người tới một tế đàn có cửa tím; lão nhân dùng máu mở cửa, để lộ lối vào tối lạnh ẩn giấu tiên khí. Khi chuẩn bị tiến vào, Tháp Sơn ngăn lão nhân và xin tự đưa Vương Lâm xuống Huyền Âm đỉnh vì mình cả đời bảo vệ tế đàn."},{"chuong":759,"tieuDe":"Tiểu Truyền Tống Trận","tomTat":"Tháp Sơn dẫn Vương Lâm xuống sâu dưới cửa vào, qua nhiều nhịp cầu thang lạnh dày tới nơi đặt Huyền Âm đỉnh, một đại đỉnh có hắc khí bị phong ấn và chín sọ người vây quanh. Vương Lâm dùng thần thức thăm dò đỉnh thì bị tiếng nữ nhân đầy sát khí công kích, suýt khiến thần thức tan biến. Tháp Sơn nhân đó chất vấn niềm tin về tiên nhân, kể rằng tộc Tiên Tuyển nhiều đời tin mình được tuyển chọn để bảo vệ Huyền Âm đỉnh, nhưng lại bị bỏ mặc trong thế giới U Minh thú và không thể rời khỏi nơi bị phong ấn. Vương Lâm nói mình không phải tiên nhân, đồng thời cho biết tiên giới đã bị phá hủy từ lâu. Sau khi tiếp tục thử dò xét, hắn dùng lôi cầu đánh vào miệng đỉnh, làm hắc khí tạm dạt ra và phát hiện một tiểu truyền tống trận dưới đáy. Hắc khí lập tức ngưng tụ thành ảo ảnh nữ nhân lao ra truy kích, tiếng rít của nàng gây thương tổn thân thể khiến Vương Lâm thổ huyết và phải kéo Tháp Sơn lui lại. Vương Lâm dùng tinh khí nguyên thần kết thành cấm chế, gọi Côn Cực Tiên và thi triển con mắt thứ ba nhưng vẫn không chặn được hắc khí hoàn toàn. Khi hắc khí đuổi tới cửa ngoài, lão nhân Tiên Tuyển dùng ký hiệu từ mi tâm khép cửa ngăn lại, song bị tiếng kêu phản chấn đến phun máu và kiệt sức."},{"chuong":760,"tieuDe":"Bẩy Cái Ký Hiệu","tomTat":"Ngay khi cánh cửa khép lại, Linh hồn Huyền Âm đỉnh dưới dạng bóng nữ nhân định lao ra, nhưng Vương Lâm dùng tiên bút vẽ ký hiệu sáu nét tỏa kim quang để đánh lui nó. Sau khi lão nhân tộc Tiên Tuyển giải thích lai lịch cái bóng, Vương Lâm cho Tháp Sơn và lão nhân lui ra canh giữ, rồi nhận ra ký hiệu bản mệnh của lão nhân có liên hệ với các ký hiệu trên đầu lâu tộc Tiên Di mà hắn từng thu được. Hắn lấy Xạ Thần xa thứ ba ra, đọc lại di ngôn Viên mỗ về uy lực, ba tài liệu còn thiếu và điều kiện dung hợp bảy ký hiệu phong ấn để nhận chủ. Vương Lâm quyết định tế luyện bảo vật này thành bổn mạng pháp bảo, dù biết pháp bảo đồng tu sẽ khiến tính mạng chủ nhân và bảo vật tương liên, được lợi lớn nhưng cũng chịu rủi ro nặng nề. Hắn thả Văn thú, Lôi oa, triệu Hứa Lập Quốc ra canh giữ phạm vi trăm trượng; Hứa Lập Quốc vừa khoe trung nghĩa vừa tự nhủ phải rèn thêm bản lĩnh nịnh bợ. Sau khi bố trí cấm chế, Vương Lâm để nguyên thần hóa thành Thái Cổ Lôi Long, bay tới Xạ Thần xa và nuốt ký hiệu màu đen đầu tiên, nhưng ký hiệu này ngoan cố chống cự trong quá trình bị chèn ép."},{"chuong":761,"tieuDe":"Bộ Tộc Thấp Hèn","tomTat":"Vương Lâm lấy lôi điện trong nguyên thần lần lượt luyện hóa các ký hiệu trên Xạ Thần Xa, càng về sau càng gian nan, đến ký hiệu thứ năm phải hóa nguyên thần thành Thái Cổ Lôi Long công kích suốt nhiều canh giờ rồi tĩnh dưỡng năm ngày. Trong lúc hắn khôi phục, tộc Tiên Tuyển nhiều lần muốn tiếp cận nhưng bị Văn thú, Lôi Oa và Hứa Lập Quốc ngăn lại; Hứa Lập Quốc còn cố ý diễn vẻ trung nghĩa khiến lão nhân trong tộc cảm phục, dù trong lòng đầy tính toán riêng. Sau khi hấp thu nốt hai ký hiệu cuối, Vương Lâm không chọn cách để Xạ Thần Xa trở thành pháp bảo bản mệnh mà trực tiếp giải phong, khiến hồn thú khổng lồ trong xe hiện ra. Hắn dùng bảy đạo băng quyết liên tiếp đánh tan hồn thú, ép nó từ hung hãn chuyển sang sợ hãi khuất phục, cuối cùng thu nhỏ thành kén rồi hóa thành một con bướm ngũ sắc. Đúng lúc đó, truyền tống trận dưới tế đàn Huyền Âm đỉnh sáng lên, một nam nhân trung niên áo xanh thân ảnh nửa hư ảo bước ra, mang tu vi Dương Thực đỉnh và lạnh lùng gọi tộc Tiên Tuyển là bộ tộc thấp hèn. Tháp Sơn phẫn nộ tấn công nhưng lập tức bị phù văn ấn ký trong chính cơ thể phản khống, ép quỳ xuống thổ huyết, khiến cả tộc nhận ra sự ràng buộc tổ tiên để lại đối với cái gọi là tiên nhân. Nam nhân áo xanh xưng bản tiên, ép toàn bộ tộc Tiên Tuyển quỳ bái, nhưng Vương Lâm vẫn đứng yên đối mặt, còn Tháp Sơn dù từng bị ép quỳ vẫn dốc sức chống lại lần khuất phục thứ hai."},{"chuong":762,"tieuDe":"Cánh Bướm","tomTat":"Sau khi thấy Tháp Sơn bị nô phù ép quỳ mà vẫn bất khuất, Vương Lâm suy đoán Tiên Tuyển Tộc và Tiên Di Tộc đều là nô tộc bị tiên nhân gieo dấu ấn truyền thừa. Nam nhân áo xanh mở tế đàn, thả vụ thú từ sương đen ra thôn phệ tộc nhân Tiên Tuyển Tộc, đồng thời lạnh lùng nói sứ mệnh của họ là nuôi nấng vụ thú và tiếp tục sinh sản con cháu. Trước cảnh lão nhân và hài đồng bị đe dọa, Vương Lâm can thiệp cứu người, dùng mảnh vỡ đại ấn chắn đòn và hỗ trợ Tháp Sơn xử lý vụ thú trong khu nhà. Nam nhân áo xanh dùng ti tộc nô phù ép tộc nhân vây công Vương Lâm, nhưng Vương Lâm kích phát Xạ Thần Xa thứ ba đang hóa thành bướm nhiều màu. Chỉ bằng những lần vỗ cánh, pháp bảo này khiến phân thân nam nhân áo xanh liên tục phun huyết vụ, tiên nguyên bị phong tỏa rồi tiêu tán trước cửa tế đàn. Trong U Minh Thú, bản thể nghi vấn của kẻ này mở mắt kinh hãi vì phân thân bị hủy quá dễ dàng. Vương Lâm thu lại Xạ Thần Xa, nhận định nếu phối hợp nó với Tử Mẫu Đạo Khô thì mình có thể chiến với Khuy Niết. Mười ngày sau, hắn xác nhận đại lục bị phong kín, tin truyền tống trận trong Huyền Âm đỉnh là lối ra, rồi tới bình nguyên phía đông gặp lại Văn Thú và Lôi Oa."},{"chuong":763,"tieuDe":"Cổ Thần Bì Giáp","tomTat":"Vương Lâm tìm một khoảng đất trống trên bình nguyên, nơi hắn đã dọn sạch cỏ và bố trí cấm chế từ trước, rồi kích hoạt trận pháp để che giấu khu vực như một thảo nguyên vô tận. Hắn thả Lôi Oa và Văn Thú tự do hộ pháp, mặc kệ Hứa Lập Quốc, sau đó bắt đầu xử lý các vật phẩm thu được từ Lôi Chi Tiên Giới. Vương Lâm lấy Cổ Thần Bì Giáp ra tế luyện, nhận ra bên trong còn tàn dư thần thức rất có thể thuộc về Tiêu Dao Tử và quyết định hủy diệt mầm khí linh chưa thành hình để pháp bảo thật sự thuộc về mình. Sau nhiều ngày luyện hóa, hắn bức vân vụ màu lam ra khỏi bì giáp, dùng Trảm La quyết chém đứt liên hệ giữa nó và giáp, rồi dùng Tôn Hồn Phiên thôn phệ. Khi thần thức Vương Lâm tràn vào, Cổ Thần Bì Giáp phát ra khí tức tang thương và tự dung nhập vào nguyên thần dạng Thái Cổ Lôi Long, khiến phòng ngự nguyên thần của hắn tăng đến mức đáng sợ. Sau đó Vương Lâm lấy Kim Tỏa cướp từ sứ giả Lôi Tiên Điện, xóa lạc ấn chủ cũ rồi bóp nát pháp bảo, chỉ giữ lại giọt chất lỏng vàng bên trong vì đây là thứ tạo nên năng lực phong ấn thần thông của Kim Tỏa."},{"chuong":764,"tieuDe":"Toái Tiên Ấn, Xuất Thế!","tomTat":"Vương Lâm bóp nát một tiên bảo từng được sứ giả Lôi Tiên Điện coi trọng để lấy giọt chất lỏng màu vàng bên trong, rồi dùng tam nhãn soi xét căn nguyên của nó. Dưới nguyên lực toàn lực vận chuyển, chất lỏng hóa thành kim tuyến giao thoa, để lộ một phù văn phức tạp có năng lực phong ấn. Vương Lâm dùng tiên bút phục khắc phù văn, thử lên Văn Thú và chứng minh nó có thể hóa thành chất lỏng vàng khóa thân thể mục tiêu trong chốc lát. Hắn đặt tên phù văn ấy là Phong văn, suy ra có thể đưa phù văn vào pháp bảo khác để ban thần thông phong ấn. Sau đó Vương Lâm chọn hàng trăm toái phiến đại ấn làm nền, vì chúng là vật tiên giới từng chịu thiên kiếp luyện hóa và một kích của Thanh Thủy Tiên Quân mà không hủy. Qua hơn một tháng, hắn dung nhập hơn sáu mươi vạn phong văn, luyện toái phiến thành tiểu ấn ba tấc và đặt tên là Phong Tiên Ấn. Cuối cùng, Vương Lâm đánh cấm chế che bớt tiên khí cùng lực phong ấn, khiến bảo vật nhìn như một toái tiên ấn bình thường nhưng thực chất là chí bảo mới xuất thế."},{"chuong":765,"tieuDe":"Tháp Sơn, Tiên Vệ","tomTat":"Vương Lâm chỉnh lý chiến lợi phẩm từ Lôi Chi Tiên Giới, nuốt Phong Tiên Ấn vào nguyên thần để dưỡng lôi uy và giải phong ba tiểu kỳ màu tím từng giam nguyên thần sứ giả Lôi Tiên Điện. Nguyên thần này vừa thoát liền muốn bỏ chạy, lại đem tin tức La Thiên thạch ra cầu mạng, nhưng Vương Lâm vẫn dùng Tôn Hồn Phiên thôn phệ và phong ấn lại. Sau đó hắn luyện hóa ba tiểu kỳ thành pháp bảo phòng hộ, xem xét hai chỉ phù chưa rõ công dụng, rồi thận trọng lấy Tàng Phẩm Các ra, xác định đây là thu hoạch lớn nhất nhưng tạm thời chưa nghiên cứu vì nơi ở chưa đủ an toàn. Gần hai tháng sau, Vương Lâm rời nơi bế quan cùng Văn Thú và Lôi Oa, tới quần thể kiến trúc của Tiên Tuyển tộc và thấy toàn tộc đang quỳ quanh Tháp Sơn hấp hối trên đài gỗ. Lão nhân Tiên Tuyển tộc đau xót công khai việc tiên giới đã sụp đổ, chất vấn số phận bị tiên nhân an bài làm nô bộc và thức ăn cho vụ thú; Vương Lâm xác nhận tiên giới đã sụp đổ, khiến ý chí phản kháng của toàn tộc bùng lên. Trước tiếng hô phản kháng, Vương Lâm nói có thể khiến Tháp Sơn không chết với năm phần nắm chắc, nhưng nếu thành công Tháp Sơn sẽ trở thành khôi lỗi không có ý thức, còn khả năng khôi phục phải dựa vào chính hắn."},{"chuong":766,"tieuDe":"Quan Tài Pha Lê","tomTat":"Tháp Sơn đang gần chết tự nguyện chịu Vương Lâm luyện hóa thành tiên vệ, đáp ứng yêu cầu niềm tin kiên định và cam tâm tình nguyện tuyệt đối của thuật. Vương Lâm mang hắn về nơi tế luyện pháp bảo, dùng nguyên thần khí bao thân, lấy Thiên Quỷ từ Tôn Hồn Phiên và Côn Cực Tiên trấn áp nó, cùng tiên ngọc và hơn mười đầu lâu tổ tiên Tiên Di tộc làm phụ trợ. Sau hơn hai tháng, Tháp Sơn trở thành đại hán thân cao hai trượng toàn thân kim quang, chiến lực đạt Dương Thực đỉnh nhưng thần trí tan vỡ tồn tại trong tiên vệ; Vương Lâm tiếc chưa đột phá Khuy Niết và nghi ngờ Thiên Quỷ tăng tỷ lệ thành công. Lão nhân Tiên Tuyển tộc quyết rời nơi cư trú, Vương Lâm thu Lôi Oa và Văn Thú, dùng ấn ký mở cửa tế đàn và tam diện tiểu kỳ màu tím phá âm thanh bén nhọn. Tháp Sơn lao vào thông đạo, chống hư ảnh nữ nhân và tung quyền đánh Huyền Âm đỉnh nứt vỡ rồi sụp đổ. Hắc khí và hư ảnh nữ nhân bị hút vào truyền tống trận, Vương Lâm gọi Hứa Lập Quốc trở về rồi cùng Tháp Sơn truyền tống đi, cả Tiên Tuyển tộc rời khỏi nơi nhiều đời cư trú. Cuối chương chuyển tới hư vô tối đen, nơi có trận pháp đỏ sậm như máu và quan tài pha lê chứa thi thể nam nhân tuấn mỹ như đang ngủ say."},{"chuong":767,"tieuDe":"Cốt","tomTat":"Hắc khí liên tục bị trận pháp hút vào quan tài pha lê, trong khi nam tử áo đen ngồi bên ngoài thủ hộ và tự nhận hiện không đủ sức hủy pháp trận. Cảm ứng có người tới, hắn tách ra năm phân thân từ mi tâm để đi ngăn chặn. Vương Lâm xuất hiện từ lốc xoáy năm màu cùng Hứa Lập Quốc, Tháp Sơn và tộc nhân Tiên Tuyển Tộc, nhanh chóng nhận ra kẻ từng bị mình giết trước đây chỉ là một phân thân. Hắn triệu Tử Mẫu Đạo Khô khiến năm phân thân kinh hãi, dùng Phong Tiên Ấn diệt một phân thân và phong hút nguyên thần, rồi phát hiện bốn phân thân còn lại định dẫn mình rời xa mục tiêu. Khi bốn phân thân quay lại tự bạo cấp Dương Thực, Vương Lâm dựa vào tam diện tiểu kỳ, Hà Đồ Bình Phong, Cổ Thần Bì Giáp, Tử Mẫu Đạo Khô, tiên thuật, Tháp Sơn và Phong Tiên Ấn để lần lượt vượt qua. Sau khi tiêu diệt toàn bộ phân thân, hắn lao theo hướng thần thức đã tìm được tới trận pháp khổng lồ và quan tài pha lê. Gió do Phong Tiên Ấn thổi tung áo bào nam tử áo đen, để lộ ngoài phần đầu thì toàn thân hắn đều là xương cốt."},{"chuong":768,"tieuDe":"Tị Thiên Quan","tomTat":"Vương Lâm đối đầu người áo đen thủ hộ quan tài, nhận ra thân thể đối phương đã tàn khuyết nên để Tháp Sơn đỡ những đoản kiếm hắc quang phóng ra từ mi tâm hắn. Hắn liên tiếp dùng Tử Mẫu Đạo Khô, nguyên thần Thái Cổ Lôi Long và đặc biệt là Phong Tiên Ấn để ép người áo đen phải thi triển Đỉnh Thiên, Thập Long Đỉnh Thiên rồi tự bạo hắc long chống đỡ, khiến kẻ này lần đầu sau vô số năm phải rời khỏi tư thế ngồi thủ hộ. Khi người áo đen định cướp Phong Tiên Ấn, Vương Lâm phá lớp tiên mạc bằng Trảm La Quyết, phối hợp kiếm tiên và Định Thân Thuật chém đứt xương tay phải của hắn. Vương Lâm tiếp tục thi triển Hô Phong, làm người áo đen kinh hãi nhớ lại quá khứ từng bị Tiên đế Bạch Phàm dùng chính thuật này đánh tan thân thể, chỉ nhờ sư tôn Tiêu Dao Tử cứu giữ lại đầu và nguyên thần để canh giữ quan tài. Bị Xạ Thần Xa hóa thành bướm nhiều màu phá vỡ thân thể hư ảo từng phần, người áo đen lộ rõ thân phận Long Đạo Tử và trong tuyệt vọng đã mở Tị Thiên Quan, khiến thân thể thanh niên bên trong tiêu tán. Qua ký ức của Long Đạo Tử, Tị Thiên Quan vốn là tiên vực chi bảo Tiêu Dao Tử dùng để đặt hồn con phàm tục, đồng thời buộc Long Đạo Tử sau khi người ấy tỉnh lại phải nhận làm chủ. Long Đạo Tử chui vào quan tài, được phục hồi thân thể và tu vi tăng vọt đến cảnh giới tiên vương, từ cảm kích chuyển thành oán hận Tiêu Dao Tử vì cho rằng mình bị lừa gạt suốt vô số năm. Nhưng khi hắn lao ra định giết Vương Lâm đoạt bảo, thân thể vừa khôi phục lại bắt đầu tiêu tán giống thanh niên trong quan tài, ngay cả đầu cũng mờ dần như sắp biến mất vào hư vô."},{"chuong":769,"tieuDe":"Hai Sự Kiện Lớn","tomTat":"Long Đạo Tử tuyệt vọng chất vấn Tiêu Dao Tử, cho rằng mình bị lợi dụng và bị bố trí chết trong Tị Thiên Quan, rồi thân thể cùng nguyên thần hoàn toàn tan biến, chỉ còn oán niệm cực mạnh. Vương Lâm dùng Đạo hóa Hoàng Tuyền hút sạch oán khí, thu Tị Thiên Quan và lập tức nghĩ tới Lý Mộ Uyển, từ đó củng cố quyết tâm tới Đông Lâm Tinh tìm Hướng gia. Sau đó hắn cùng Tiên Tuyển tộc rời khỏi thế giới trong U Minh Thú qua trận pháp trong miệng cự thú, nhận ra đây là sinh vật cổ xưa trong ký ức Đồ Ti. Trong thời gian Vương Lâm biến mất, La Thiên Tinh Vực xảy ra hai biến cố lớn: Lôi Tiên Điện phát La Thiên lệnh chuẩn bị tiến quân Liên Minh Tinh Vực và tổ chức Phong Tiên, còn Diêu gia phát Thiên Khung Lệnh truy sát Hứa Mộc. Vương Lâm dẫn Tiên Tuyển tộc vượt sương mù La Thiên Tây Vực nhiều tháng, trải qua huyết chiến với mãnh thú khiến tộc nhân trưởng thành về sát khí, quyết đoán và phối hợp. Cuối cùng họ xông ra khỏi sương mù, nhìn thấy tinh không La Thiên rực rỡ trước mắt."},{"chuong":770,"tieuDe":"Hứa Mộc!","tomTat":"Vương Lâm xác nhận mình đã trở lại La Thiên Tinh Vực, lấy ngọc giản bản đồ do Thân Công Hổ từng giao để định hướng, rồi nói với Tiên Tuyển Tộc rằng họ đã tới vùng dưới Lôi Chi Tiên Giới và được tự do. Lão nhân tiên tổ xin một nơi tạm dung thân vì cả tộc chưa quen La Thiên, nên Vương Lâm nghĩ tới Thanh Linh Tinh và dẫn đoàn tìm tu chân tinh để xác định phương vị. Sau mười ngày, họ gặp Huyền Trần Tinh thuộc La Thiên Tây Vực, nơi Âu Dương Đàn cùng hai lão nhân Âm Hư ra hỏi lai lịch. Âu Dương Đàn bí mật nhận ra Vương Lâm giống hình ảnh Hứa Mộc trong Thiên Khung Lệnh của Diêu gia, ngoài mặt mời nghỉ lại nhưng trong lòng tính báo tin đổi trọng thưởng. Vương Lâm nhận thấy thái độ đối phương quỷ dị, giao ngọc giản ghi vị trí Thanh Linh Tinh cho lão nhân Tiên Tuyển Tộc dẫn tộc đi trước, còn mình dùng bước pháp dung nhập thiên địa quay lại. Âu Dương Đàn bóp nát ngọc giản liên lạc, gọi ra hư ảnh Diêu tộc Thương Khung sứ giả và báo tung tích Hứa Mộc. Khi ba tu sĩ tưởng cơ hội đã nằm trong tay, họ kinh hãi phát hiện Vương Lâm đã xuất hiện phía sau Âu Dương Đàn."},{"chuong":771,"tieuDe":"Hai Nén Hương","tomTat":"Vương Lâm bất ngờ hiện thân từ hư không sau lưng trung niên văn sĩ truy sát mình, đánh sụp thân thể đối phương và bắt lấy nguyên thần. Hai lão nhân Âm Hư còn lại kinh hoàng bỏ chạy nhưng bị Tháp Sơn truy kích, bắt nguyên thần và đem túi trữ vật trở về. Vương Lâm sưu thần ba nguyên thần, biết Diêu gia đang phát lệnh truy sát Hứa Mộc với quy mô rất lớn tại La Thiên Tinh Vực, rồi ném ba nguyên thần vào Tôn Hồn Phiên để làm lương thực cho Hô Phong. Từ ngọc giản và ký ức thu được, hắn phân tích các nguyên nhân có thể khiến Diêu gia nhắm vào mình, gồm Huyết Tổ, cái chết của Diêu gia thiếu gia ở Lôi chi tiên giới và chuyện Tàng Phẩm Các, đồng thời liên tưởng Thiên Khung Lệnh với lệnh truy sát năm xưa tại Tu Ma Hải. Chỉ sau khoảng hai nén hương, hai mươi tám tu sĩ từ bốn hướng đã vây tới, khiến Vương Lâm nhận ra mạng lưới truy sát phản ứng cực nhanh và suy đoán họ là tu sĩ các gia tộc tu chân tinh phụ cận liên hệ với Diêu gia. Hắn quyết định đại khai sát giới, chọn nhóm bên trái yếu nhất để phá vây, dùng Trảm La quyết giết ba tu sĩ Vấn Đỉnh đại viên mãn rồi đuổi sát một tu sĩ Âm Hư đang chuẩn bị nguyên lực thần thông."},{"chuong":772,"tieuDe":"Diêu Trường Không","tomTat":"Vương Lâm tiếp tục phá vòng vây trong tinh không bằng trạng thái nửa thân dung nhập thiên địa, liên tục biến mất khỏi hợp kích rồi hiện sau lưng đối thủ để dùng Trảm La quyết và Tôn Hồn Phiên thu nguyên thần. Lão nhân Dương Thực đỉnh nhận ra cách di chuyển của hắn không phải thuấn di hay Đại Na Di, bèn dùng chuông bạc tạo sóng gợn quấy nhiễu thiên địa, khiến Vương Lâm gọi Tháp Sơn ra kìm chân. Trong lúc phản sát, Vương Lâm dùng Phong Tiên Ấn giết hai tu sĩ và phát hiện kim phù quanh ấn thu nguyên thần, có hai phù văn sáng lên như sống động. Bảy tu sĩ Vấn Đỉnh đại viên mãn bỏ chạy cũng bị hắn vặn vẹo sức mạnh thiên địa ép hiện thân rồi giết sạch; một Âm Hư tu sĩ từ Linh Minh tinh bỏ thân thể cầu xin rút gia tộc khỏi xung đột nên được bỏ qua. Khi tám người còn lại tản ra, Vương Lâm thả Phong Tiên Ấn, Tử Mẫu Đạo Khô và kiếm tiên truy sát, đồng thời cảnh cáo Hứa Lập Quốc sau khi kiếm linh lộ vẻ sợ hãi trước một Âm Hư tu sĩ. Diêu Trường Không xuất hiện trong kiếm quang với tu vi Khuy Niết sơ kỳ, khiến Vương Lâm nhận ra giết đám nhận thưởng không đủ làm Diêu gia đau và quyết định nhắm thẳng tộc nhân Diêu gia. Cuối chương, Vương Lâm giả thế lao về Diêu Trường Không rồi biến mất đúng lúc Tháp Sơn bùng kim quang làm lão nhân Dương Thực đỉnh chói mắt, mở ra thế đảo mục tiêu."},{"chuong":773,"tieuDe":"Tâm Tư Huyết Thần Tử","tomTat":"Vương Lâm cùng Tháp Sơn vừa đánh tan thân thể lão nhân Dương Thực đỉnh, buộc nguyên thần đối phương dùng huyết độn bỏ chạy, thì Diêu Trường Không của Diêu gia đã cưỡi đại kiếm xuất hiện truy sát. Vương Lâm lập tức giành tiên cơ bằng đánh lén, phối hợp Phong Tiên Ấn, Trảm La quyết, kiếm tiên có Hứa Lập Quốc và quyền của Tháp Sơn tạo thành sát cục, nhưng Diêu Trường Không nhờ kim đan tiên nhân do lão tổ ban mà hấp thu toàn bộ công kích, chỉ chật vật chứ không bị thương. Sau đó hai bên liên tiếp đấu thần thông, Diêu Trường Không dùng Hư Băng, Tùy Ảnh Chi Băng, mười chín hồn, Vân Kiếp và Huyết hồn lục chuyển, còn Vương Lâm dựa vào Súc Địa Thành Thốn, Tử Mẫu Đạo Khô, Tôn Hồn Phiên và Hô Phong để chống trả. Khi Diêu Trường Không tế Đế tiên phù, Vương Lâm dù dùng một lá phù tương tự triệt bớt uy lực vẫn bị mảnh phù còn lại dán vào mi tâm, phong ấn nguyên lực toàn thân, rơi vào thế gần như phàm nhân. Trong lúc nguy cấp, Xạ Thần Xa hóa bướm tự vận hành ngăn Diêu Trường Không, còn Vương Lâm chuyển sang đạo niệm Nhân Quả, dùng sự sụp đổ của tiên giới và cái chết của tiên nhân để phá đạo cảnh vinh quang tổ tiên của đối thủ. Đạo tâm Diêu Trường Không tan vỡ, phong ấn trên người Vương Lâm tiêu tán, rồi Xạ Thần Xa hủy diệt thân thể hắn đến cả túi trữ vật cũng không còn dấu vết. Ở từ đường Diêu gia tại La Thiên Đông Vực, Huyết Thần Tử thấy linh bài Diêu Trường Không vỡ nhưng không giận dữ, trái lại thu lấy bạch khí và chờ xem Vương Lâm còn giết được bao nhiêu người Diêu gia. Vương Lâm mang thương thế rời đi, định tìm nơi chữa trị rồi tiếp tục quấy phá Diêu gia, nhưng Diêu Băng Vân nhanh chóng xuất hiện, nhận ra hắn liên tục dùng Súc Địa Thành Thốn và truy đuổi không buông suốt mười ngày."},{"chuong":774,"tieuDe":"Diêu Băng Vân","tomTat":"Diêu Băng Vân truy sát Hứa Mộc vì Thiên Khung Lệnh của Huyết Thần Tử, đồng thời mang chấp niệm phải cứu muội muội. Tin Hứa Mộc diệt hai mươi sáu trong hai mươi tám tu sĩ liên hợp, cộng thêm cái chết của Diêu Trường Đông, khiến La Thiên Tinh Vực chấn động và Diêu gia bắt đầu liên hệ nhiều gia tộc để dựng phòng tuyến phong tỏa tại La Thiên Tây Vực. Vương Lâm dùng dung nhập thiên địa liên tục biến đổi phương vị, dựa vào kinh nghiệm từng dung thân với Viêm Lôi tử để duy trì lâu hơn Diêu Băng Vân, khiến nàng phải hiện thân trước và mất dấu chính xác. Sau đó hắn ẩn trên một tinh cầu hoang phế nơi giao giữa Tây Vực và Bắc Vực, thả Tôn Hồn Phiên, bố trí cấm chế, nuốt bốn nguyên thần Âm Hư và nghiền nát pháp bảo chiến lợi phẩm để tu bổ Tháp Sơn. Diêu Băng Vân dùng tiểu kính lần ra hắn nhưng mặt kính bị sát khí của Vương Lâm phá vỡ. Hai bên chính diện giao thủ: Diêu Băng Vân dùng Băng phá đóng băng tinh không, Vương Lâm phối hợp lôi cầu, Tháp Sơn và Hô Phong thuật phá thế băng, nhưng nàng tiếp tục thi triển Huyết, băng khiến Tháp Sơn phun máu và bị đánh lui về hư ảnh sau lưng Vương Lâm."},{"chuong":775,"tieuDe":"Ma Đạo Tử","tomTat":"Vương Lâm dùng Hô Phong thuật tạo hắc long cản Diêu Băng Vân rồi dung nhập thiên địa rút lui, nhưng nhanh chóng phát hiện La Thiên Tây Vực đã bị Diêu gia cùng nhiều gia tộc phong tỏa. Khi bị thần thức truy tìm làm lộ vị trí, hắn nhận ra nếu chỉ chạy trốn thì sẽ bị cuốn vào thế vây giết ngày càng dày. Vương Lâm quyết định dùng sát phạt để chấn nhiếp, chọn những tu chân tinh vắng cao thủ Âm Hư để giết tu sĩ từ Anh Biến trở lên, đồng thời không hại phàm nhân và người tu vi quá thấp. Trong ba mươi ngày, hơn mười tu chân tinh máu chảy thành sông, nơi nào cũng lưu lại hai chữ Hứa Mộc. Hành động này khiến toàn Tây Vực chấn động và danh hiệu Ma Đạo Tử bắt đầu gắn với Vương Lâm."},{"chuong":776,"tieuDe":"Cửu Tuyệt Tổn Thần Trận!","tomTat":"Sự trả thù của Vương Lâm khiến nhiều gia tộc Tây Vực sợ hãi rút khỏi tuyến phong tỏa, nhưng Diêu Băng Vân vẫn bám sát bằng năng lực dung nhập thiên địa và thôi diễn. Vương Lâm chọn một tu chân tinh hoang, hạ lạc ấn khắp tinh cầu rồi dùng nguyên thần trong Tôn Hồn Phiên bố trí Cửu Tuyệt Tổn Thần Trận, một cấm thuật thuộc truyền thừa của Lý Nguyên. Hắn còn đánh lạc ấn lên nguyên thần Huyết Tổ để giữ làm sát chiêu, sau đó ẩn nấp chờ đội truy sát tới. Diêu Băng Vân cùng tộc nhân Diêu gia và nhiều tu sĩ hợp lực phá hủy tinh cầu, nhưng mảnh vỡ lập tức nối tử lôi, tự bạo liên hoàn và hút nguyên thần người chết. Vương Lâm kích nổ nguyên thần Huyết Tổ, giết nhiều tu sĩ trong phạm vi vạn trượng, rồi bị Diêu Băng Vân dùng Tổn Thần Ấn đánh trọng thương nhưng vẫn thoát. Sau trận này, cái tên Hứa Mộc và danh hiệu Ma Đạo Tử vang khắp La Thiên Tinh Vực, khiến Thanh Thủy ở Lôi Tiên Điện cũng chú ý và tán thưởng."},{"chuong":777,"tieuDe":"Kế Hoạch Lớn","tomTat":"Sau khi sống sót nhờ Du Cổ Thần bì giáp, Vương Lâm vừa bỏ chạy vừa giữ khoảng cách để không cắt đuôi hoàn toàn Diêu Băng Vân và đoàn truy sát. Hắn dẫn truy binh vượt từ La Thiên Tây Vực sang Bắc Vực, khiến một số gia tộc Bắc Vực lo sợ việc đồ tinh lặp lại trên địa bàn của họ và bắt đầu rút lui. Tại khu vực La Vân gần ngũ đại chủ tinh, Vương Lâm dùng thần thức tìm được tinh cầu do Vọng Nguyệt biến thành, một cấm địa khiến tu sĩ Bắc Vực kiêng dè. Hắn tiến vào màn sương đen của Vọng Nguyệt, buộc Diêu Băng Vân và các tu sĩ truy sát phải cân nhắc có nên đuổi theo hay không. Bên trong cơ thể Vọng Nguyệt, Vương Lâm nhớ tới thanh xương năm xưa và đại đỉnh của Tham Lang bị nuốt, rồi quyết định lợi dụng việc chọc giận Vọng Nguyệt để giải quyết truy binh."},{"chuong":778,"tieuDe":"Vọng Nguyệt","tomTat":"Bên ngoài tinh cầu do Vọng Nguyệt biến thành, đoàn tu sĩ truy sát bao vây nhưng nhiều người chần chừ vì đã thấy sự tàn nhẫn của Hứa Mộc. Tộc nhân Diêu gia và Diêu Vân Hải lại khinh thường hung thú, cho rằng điển tịch gia tộc từng ghi nhiều mãnh thú Tiên giới còn lớn hơn bị tiêu diệt, nên Diêu Băng Vân tiên phong tiến vào màn sương đen. Nhiều tu sĩ chìm vào cơ thể Vọng Nguyệt, khiến con thú xuất hiện chấn động nhẹ và làm Vương Lâm nhận ra dấu hiệu thức tỉnh. Vương Lâm quyết định kích thích Vọng Nguyệt tỉnh nhanh hơn, đồng thời tiến về xương đầu của nó. Khi Diêu Vân Hải bị một con Vọng Nguyệt trăm trượng làm phân tâm, Vương Lâm đánh lén phá thân thể, dùng Côn Cực Tiên bắt nguyên thần rồi ném vào Tôn Hồn Phiên. Hắn định tiếp tục ẩn trong cơ thể Vọng Nguyệt để buộc Diêu gia đối đầu hung thú, nhưng cuối chương Diêu Băng Vân dùng băng tinh màu lam chặn đường."},{"chuong":779,"tieuDe":"Sự Hưng Phấn Của Vọng Nguyệt","tomTat":"Diêu Băng Vân đối mặt Vương Lâm trong cơ thể Vọng Nguyệt và tuyên bố muốn giết hắn vì những cuộc tàn sát ở La Thiên Tây Vực. Nàng dùng băng thuật đóng băng không gian, thi triển Băng độn áp sát khiến Vương Lâm phải phun Phong Tiên Ấn ra phòng hộ. Thập Quyết Tổn Thần Ấn của Diêu Băng Vân xuyên qua phòng hộ sau khi bị suy yếu, đánh vào thân thể và nguyên thần Vương Lâm, nhưng hắn vẫn không chết. Nhận thấy không thể trực tiếp chống lại nàng trong môi trường không thể thuấn di, Vương Lâm dùng Trảm La Quyết oanh kích bùn đất để tạo tiếng nổ, lợi dụng tập tính Vọng Nguyệt ghét ồn. Một con Vọng Nguyệt trăm trượng xuất hiện với khí tức cấp Khuy Niết, nhưng lại hưng phấn đuổi theo Vương Lâm thay vì tấn công Diêu Băng Vân. Khi Diêu Băng Vân định vượt qua nó để đánh Vương Lâm, Vọng Nguyệt nổi giận cuốn lấy nàng; nàng dùng viên đan màu lam tạo băng phong diện rộng, nhưng ngay sau đó bốn con Vọng Nguyệt trăm trượng khác chui ra lao thẳng tới nàng."},{"chuong":780,"tieuDe":"Thức Tỉnh","tomTat":"Diêu Băng Vân bị Vương Lâm truy sát trong cơ thể Vọng Nguyệt, phải bóp nát lam đan để phóng ra lực băng phong và dùng Băng độn bỏ chạy. Vương Lâm kịp dùng Định Thân Thuật giữ nàng trong khoảnh khắc, khiến Hô Phong xuyên qua băng tầng đánh trúng và để lại hắc khí khó khu trừ trong cơ thể nàng. Sau đó hắn thu Phong Tiên Ấn, lần theo dấu vết nửa thanh xương Vọng Nguyệt từng bị rút ra để tiến vào vùng giao giữa xương cốt và dây thần kinh, nơi dày đặc tơ đỏ. Vương Lâm liên tục thi triển Trảm La Quyết chém đứt tơ đỏ, khiến Vọng Nguyệt rung chuyển, sương đen ngoài tinh cầu co rút và đất đá sụp đổ. Các tu sĩ Diêu gia cùng nhiều tu sĩ thuộc các gia tộc khác mắc kẹt bên trong hoảng loạn tìm đường thoát nhưng bị xúc tu phong tỏa, có người bị nghiền nát thân thể và nguyên thần bị hấp thu. Diêu Băng Vân sau khi thoát thân nhận ra những xúc tu này giống mãnh thú từng công kích mình, xác nhận tinh cầu là hình thái phóng đại của quái thú đó. Khi Vương Lâm xé đứt một sợi tơ đỏ cực lớn, Vọng Nguyệt rống lên, tinh cầu nứt vỡ và thân thể cự thú khổng lồ chậm rãi thức tỉnh."},{"chuong":781,"tieuDe":"Viêm Lôi Tử Tái Hiện!","tomTat":"Các tu sĩ truy sát Hứa Mộc nhận ra tinh cầu trước mắt thực chất là bản thể Vọng Nguyệt, liền hoảng loạn cho rằng mình bị hắn dẫn tới đây để mượn đao giết người. Vọng Nguyệt bị đánh thức khỏi giấc ngủ, trong cơn phẫn nộ gầm rống làm tinh không nứt vỡ, rồi dùng thân thể khổng lồ và xúc tu tàn sát những tu sĩ không kịp bỏ chạy. Khi cuộc truy sát lan khắp La Thiên Bắc Vực, ngũ đại chủ tinh chỉ mở trận pháp hộ tinh tự thủ, không ai dám ra cứu viện. Vọng Nguyệt tiếp tục phóng ra vô số tiểu Vọng Nguyệt, khiến tộc nhân Diêu gia gần như bị diệt sạch, các gia tộc trợ chiến cũng chết hơn phân nửa. Cách chiến trường mười vạn dặm, Viêm Lôi Tử xuất hiện cùng Hướng mỗ và lão già hồng bào, tiết lộ kế hoạch nhiều năm nhắm vào đầu Nguyệt Thú này. Ông cho rằng tu sĩ La Thiên thiếu sinh tử tôi luyện so với Liên Minh Tinh Vực, nên cần một cuộc huyết tẩy và một trăm lẻ tám tiên sát phạt quyết đoán làm tiên phong. Hứa Mộc được Viêm Lôi Tử và lão già hồng bào chú ý như hạt giống phù hợp, còn Huyết Thần Tử được nhắc tới như người từng dùng bảo bối đổi lấy cơ hội huyết tẩy tộc nhân."},{"chuong":782,"tieuDe":"Khí Tức Bì Giáp","tomTat":"Ba đại năng La Thiên bàn về Hứa Mộc, trong đó Công Tôn nghi ngờ lai lịch Liên Minh Tinh Vực của hắn còn Viêm Lôi Tử đứng ra bảo vệ quyết định trọng dụng. Họ chuyển sang kế hoạch lợi dụng Vọng Nguyệt, chờ thông đạo mở sẽ đuổi nó sang Liên Minh Tinh Vực, rồi dùng phân thân cứu tu sĩ quanh chiến trường và thử uy lực con thú. Lão già họ Hướng dùng đồ án bát giác huyết sắc phong khốn Vọng Nguyệt, nhưng Vọng Nguyệt nổi giận thi triển Cổ Thần chỉ, phá nát phong ấn và đánh tan viêm long, hồng kiếm, hắc ưng của ba phân thân. Trong Lôi Tiên Điện, bản thể ba người tỉnh lại, thừa nhận Nguyệt Thú rất mạnh nhưng vẫn quyết định tập hợp thêm người để triển khai kế hoạch bắt giữ. Ở Từ đường Diêu gia trên Yến Cầu, Huyết Thần Tử thấy hơn mười lệnh bài vỡ vụn, nhận định Hứa Mộc sát phạt quyết đoán rồi phái Diêu Vân đời thứ hai tới La Thiên Bắc Vực giết hắn. Hung danh Ma Đạo Tử Hứa Mộc lan khắp La Thiên Tinh Vực, khiến nhiều tu chân gia tộc e dè không muốn can dự vào ân oán với Diêu gia. Trong cơ thể Vọng Nguyệt, Vương Lâm phát hiện Cổ Thần bì giáp là nguyên nhân hấp dẫn Vọng Nguyệt nhỏ; hắn thu bì giáp lại thì tạm mất dấu, nhưng tiếng gầm chấn nguyên thần buộc hắn phải mặc lại. Khí tức bì giáp khiến vô số Vọng Nguyệt nhỏ từ các khe nứt lao ra, cuối cùng hợp thành vòng vây dày đặc quanh Vương Lâm."},{"chuong":783,"tieuDe":"Bí Mật Của Vọng Nguyệt !","tomTat":"Khi đàn Vọng Nguyệt lao tới, một tiếng gầm trong cơ thể con mẹ khiến chúng tách ra, để một con Vọng Nguyệt vạn trượng xuất hiện và nuốt Vương Lâm vào. Hắn bị đưa tới một lốc xoáy âm hàn được xác định là não bộ của Vọng Nguyệt, nơi con Vọng Nguyệt vạn trượng sinh sống. Khí tức kỳ dị trong đó khiến nguyên lực của Vương Lâm ngừng vận chuyển như phàm nhân, nhưng Cổ Thần bì giáp hút lấy khí tức này và giúp hắn khôi phục. Bên trong không gian hẹp dài, hắn phát hiện vô số xúc tu quấn lấy đại đỉnh của Tham Lang cùng nhiều người đã mất sinh cơ, từ đó suy đoán cư dân Vân Hà Tinh năm xưa có thể đã bị Vọng Nguyệt nuốt làm nguồn sinh mạng. Vương Lâm tránh xúc tu để không kinh động Vọng Nguyệt rồi chui vào đại đỉnh, nơi xúc tu chỉ quấn bên ngoài mà không xâm nhập. Ngay sau đó Diêu Băng Vân cũng bị phun vào, bị xúc tu cuốn lấy hút sức sống và tỉnh lại trong nguy hiểm. Trong đỉnh, Vương Lâm vận chuyển nguyên lực, Tháp Sơn hiện thân hộ pháp, còn hắn tạm thời buông lỏng sau chuỗi biến cố kéo dài từ Lôi Tiên Giới, U Minh thú, La Thiên Tinh vực tới truy sát của Diêu gia và các tu chân gia tộc."},{"chuong":784,"tieuDe":"Đỉnh","tomTat":"Vương Lâm ẩn trong đại đỉnh bên trong cơ thể Vọng Nguyệt, nhận định nơi cực kỳ nguy hiểm này tạm thời lại an toàn vì tu sĩ bên ngoài khó dám truy vào, rồi vận chuyển nguyên lực để chữa thương nguyên thần sau trận với Diêu Băng Vân. Diêu Băng Vân được thuật lại là đã thoát khỏi tinh cầu do Vọng Nguyệt biến thành nhưng lại bị một Vọng Nguyệt vạn trượng nuốt vào, bị xúc tu quấn chặt và hấp thu nguyên lực cùng sức sống. Nàng bình tĩnh thi triển Bế thần thuật, tự phong bế giác quan, khí tức, nguyên thần và ý nghĩ cầu sinh, khiến thân thể như xác chết rồi bị băng phong trong lớp băng dày. Vọng Nguyệt khổng lồ du đãng đến vùng sâu La Thiên Bắc Vực, dừng tại tinh không thưa thớt rồi cuộn thân hóa lại thành tinh cầu tu chân, phun sương đen bao phủ bên ngoài. Khi nguyên thần khôi phục khoảng tám phần, Vương Lâm nghiên cứu đại đỉnh và nhận ra trong đó có khí tức Cổ Thần rất đậm, suy đoán đây là nơi Vọng Nguyệt giữ vật hoặc người liên quan Cổ Thần để hấp thu. Hắn dùng thần thức cố lưu lạc ấn lên đại đỉnh nhưng vẫn không có cảm giác khống chế, sau đó phát hiện phù văn cực khó thấy ở một góc ngoài đỉnh. Trên phù văn ấy còn lạc ấn mang khí tức Tham Lang, khiến Vương Lâm xác định Tham Lang chưa chết và hiểu rằng lạc ấn cũ đang cản mình điều khiển đại đỉnh; dù là kẻ địch, hắn vẫn sinh lòng khâm phục thủ đoạn của Tham Lang."},{"chuong":785,"tieuDe":"Băng Vân","tomTat":"Vương Lâm nhận ra Tham Lang chỉ dựa vào một phù văn ấn lên đại đỉnh để khống chế một phần thần thông, nên quyết định thu thần thức về phía phù văn nhằm xóa lạc ấn cũ. Đúng lúc đó, trong không gian đầy xúc tu và khí âm hàn, một lão già gầy gò bị xúc tu quấn bỗng bùng sinh cơ, thân thể phồng nứt và một cá thể Vọng Nguyệt nhỏ chui ra. Vọng Nguyệt mới sinh nuốt thân lão già cùng khí âm hàn xung quanh, nhanh chóng lớn từ hai trượng thành mười trượng rồi hóa tia chớp xuyên qua lốc xoáy rời đi. Dựa vào trí nhớ Đồ Ti, Vương Lâm suy đoán Vọng Nguyệt đã trải qua biến hóa lớn, có thể dựa vào thân thể tu sĩ hoặc người thường để ngưng tụ sinh mệnh mới. Sau đó hắn dùng thần thức đánh sụp lạc ấn Tham Lang trên phù văn, lưu lạc ấn của mình và thu đại đỉnh về tay, dù vẫn chưa khống chế được toàn bộ uy lực. Vương Lâm thử thần thông Di hình của đại đỉnh, khiến đỉnh biến mất khỏi trong đám xúc tu và xuất hiện ở bên ngoài. Khi đã có thời gian quan sát xung quanh, ánh mắt hắn rơi lên Diêu Băng Vân ở cách đó không xa."},{"chuong":786,"tieuDe":"Phong Ấn Hoàn Mỹ","tomTat":"Trong cơ thể Vọng Nguyệt, Vương Lâm phát hiện Diêu Băng Vân dùng Bế thần thuật tự phong thân thể trong tầng băng, nhờ đó tạm chưa bị Vọng Nguyệt hấp thu dù nguyên lực đã bị chia lìa. Nghĩ đến việc nàng từng truy sát khiến mình suýt mất mạng, hắn quyết định phá băng, phong ấn nàng rồi luyện thành Tiên vệ để trả nhân quả với Diêu gia. Khi lớp băng gần vỡ, Diêu Băng Vân tỉnh lại và mở đạo tâm bi ai, trước người hiện ra hình ảnh thiếu nữ câm gắn với ý cảnh của nàng. Vương Lâm đã đoán trước phản kích nên dùng Trảm La Quyết không nhằm chém nàng, mà kích thích xúc tu Vọng Nguyệt đang quấn nàng, khiến xúc tu co rút, hút nguyên lực, sinh cơ và cả đạo niệm, làm ý cảnh vừa xuất hiện lập tức tan vỡ. Nhân lúc Diêu Băng Vân tuyệt vọng và suy yếu, hắn liên tiếp hạ cấm chế, dùng Côn Cực Tiên trấn nguyên thần, Tôn Hồn Phiên bao kín và Phong Tiên Ấn phủ hơn mười vạn phù văn để hoàn tất phong ấn. Cuối cùng, Vương Lâm dùng đại đỉnh thi triển Di hình, đưa Diêu Băng Vân đã bị phong ấn ra khỏi vị trí cũ, thu nàng vào túi trữ vật như pháp bảo rồi tiếp tục tiến lên trong cơ thể Vọng Nguyệt."},{"chuong":787,"tieuDe":"Kêu Gọi Trong Cơ Thể Vọng Nguyệt","tomTat":"Vương Lâm tiếp tục đi sâu trong cơ thể Vọng Nguyệt, dùng luồng khí trắng từ cái đỉnh để tránh xúc tu quấn tới. Trên đường, hắn thấy vô số người thường và tu sĩ bị xúc tu trói giữ; càng vào sâu, những người này càng có linh tính và sinh cơ rõ hơn, khiến hắn suy đoán Vọng Nguyệt đã bắt đầu hấp thu sinh mạng từ bên ngoài. Khi gần tới chỗ sâu nhất, Vương Lâm nghe một tiếng gọi truyền thẳng vào linh hồn, xuyên qua thân thể và nguyên thần, thậm chí ảnh hưởng tới bản tôn ở Liên minh Tinh vực, nên hắn quyết đoán lao về nơi phát ra rung động. Bên ngoài, Vọng Nguyệt đã thu lại thành tinh cầu tu chân và ngủ say, trong khi người đàn ông trung niên họ Công Tôn, Viêm Lôi Tử và lão già áo đỏ họ Hướng lần lượt tụ tập. Hướng gia đưa Phong thần tứ tử tới dùng Huyết đan lập thế vây quanh Vọng Nguyệt; Công Tôn nói đã mời Thân Công lão tổ và Liệt Vân tử, còn lão già họ Hướng nói đã mời Huyết Thần Tử và Ngũ Thải đạo nhân. Thân Công lão tổ, Ngũ Thải đạo nhân và Liệt Vân tử lần lượt xuất hiện, khiến cuộc bắt Vọng Nguyệt bước vào giai đoạn nhiều lão quái cùng hội tụ."},{"chuong":788,"tieuDe":"Cổ Thần Toái Tinh","tomTat":"Huyết Thần Tử hiện thân bằng huyết quang trước tinh cầu Vọng Nguyệt, khiến các lão quái chú ý, rồi trực tiếp hẹn Viêm Lôi Tử sau khi mở đường thông Liên minh sẽ quyết chiến vì chuyện nguyên thần cháu mình. Ở La Thiên Bắc vực, Lôi Tiên điện gần như dốc toàn lực, để các sứ giả tạo vòng phong tỏa mười vạn dặm và kết giới Lôi vực quanh Vọng Nguyệt, bên ngoài còn có thêm tầng tầng tu sĩ bao vây. Bên trong cơ thể Vọng Nguyệt, Vương Lâm lần theo tiếng gọi trong linh hồn, phát hiện một đứa trẻ Cổ Thần khổng lồ có tám tinh điểm hư ảo bị khoảng trăm xúc tu quấn chặt và hút sinh cơ. Dựa vào truyền thừa Đồ Ti, hắn suy đoán đứa trẻ hoặc là con của bát tinh Cổ Thần, hoặc chính là bát tinh Cổ Thần trưởng thành thoái hóa, đồng thời nghi Vọng Nguyệt đã cắn trả Cổ Thần để có lực lượng này. Đứa trẻ Cổ Thần truyền âm, nhận ra khí tức tộc nhân trong Vương Lâm nhưng cho rằng chưa đủ nồng, yêu cầu đưa người chân chính trong tộc tới nhận truyền thừa cuối cùng; ngay lúc Vương Lâm hỏi thân phận thật, xúc tu đột ngột cuồng bạo hút cạn sinh cơ khiến nhiều kẻ yếu vỡ tan, buộc hắn rút về cái đỉnh tự bảo vệ. Bên ngoài, Vọng Nguyệt thức tỉnh và điều động nhiều Vọng Nguyệt nhỏ, rồi trận chiến giữa bảy cường giả gần đỉnh La Thiên Tinh vực và Vọng Nguyệt chính thức mở ra. Lão già áo đỏ họ Hướng dùng trận pháp bát giác dẫn Thiên địa Lôi Hỏa, Phong thần tứ tử phối hợp Huyết Đan dùng lôi quang đỏ hạn chế nó, còn người đàn ông họ Công Tôn hóa chim ưng khổng lồ liên tục oanh kích. Trước nguy cơ mạnh, Vọng Nguyệt thi triển tiếng rít thần thông có thể khiến tinh không sụp đổ, đẩy cuộc giao chiến lên quy mô cực lớn."},{"chuong":789,"tieuDe":"Phong Ấn Vọng Nguyệt","tomTat":"Các lão quái La Thiên cùng ra tay vây bắt Vọng Nguyệt: Thân Công lão tổ hóa lôi quang thành vạn Lôi Long, Liệt Vân Tử dùng Tâm động Tiên thuật, Ngũ Thải đạo nhân tạo lốc xoáy năm màu, Huyết Thần Tử xâm nhập cơ thể con thú, còn Viêm Lôi Tử điều động mảnh vỡ Tiên giới để phong ấn. Vọng Nguyệt đau đớn phản kích, phun ra nhiều cá thể nhỏ, cùng phát ngôn ngữ Cổ Thần để ngưng tụ vô số Cổ Thần chỉ, rồi bẻ xúc tu hóa thành nhiều Vọng Nguyệt vạn trượng khiến các cao thủ kinh hãi. Bên trong cơ thể Vọng Nguyệt, Vương Lâm thấy đứa trẻ Cổ Thần bị xúc tu cắn nuốt, định cứu nhưng được thanh âm tang thương ngăn lại và nhờ đưa người có thể chịu truyền thừa tới. Đứa trẻ Cổ Thần tự toái tinh, tạo lực xung kích đẩy Vương Lâm về lối ra và đánh trọng thương Huyết Thần Tử, khiến hắn phải nhờ vật yêu dị bản mạng đỡ thay rồi huyết độn bỏ chạy. Bên ngoài, Viêm Lôi Tử mở rộng mảnh vỡ Tiên giới, lão họ Hướng phân tán trận pháp, bốn đồng tử dùng Huyết đan phong tỏa, nhưng Cổ Thần chỉ gần như thực chất phá tan phong tỏa và khiến nhiều người sụp đổ. Năm cao thủ còn lại hợp lực chống Cổ Thần chỉ, cuối cùng làm thần thông này sụp đổ nhưng bản thân đều trọng thương, dư chấn lan mười vạn dặm làm tinh cầu bỏ đi vỡ vụn và vòng vây Lôi Tiên điện bị quét ngã. Trong cơ thể Vọng Nguyệt, đứa trẻ Cổ Thần tiếp tục toái thêm một tinh, tạo truyền tống trận cổ xưa; Vương Lâm trầm mặc nhìn Cổ Thần suy yếu rồi bước vào trận biến mất."},{"chuong":790,"tieuDe":"Trở Lại Thanh Linh Tinh","tomTat":"Sau khi Vương Lâm truyền tống rời đi, truyền tống trận lập tức bị vô số xúc tu từ hư vô quấn lấy, cắn nuốt và sụp đổ. Viêm Lôi Tử nhân lúc nhóm Liệt Vân Tử cản trở Vọng Nguyệt liền thi triển Phong, dẫn động mảnh vỡ Tiên giới bao phủ cự thú, nhưng một nam tử hư ảo bất ngờ bước ra từ tinh không sụp đổ khiến Vọng Nguyệt sợ hãi và nhóm tu sĩ cung kính. Vương Lâm đã xuất hiện ở nơi rất xa chiến trường, suy xét về biến đổi của Vọng Nguyệt và nghi ngờ truyền thừa Cổ Thần trong cơ thể nó có thể là mưu đồ đoạt xá. Hắn trở lại Thanh Linh tinh thuộc La Thiên Bắc vực, được lão già Tiên Tổ cùng người Tiên Tuyển tộc nghênh đón và báo tin Diêu gia từng truy sát mình. Vương Lâm giao Tiên Tuyển tộc an cư, phòng hộ Thanh Linh tinh rồi về động phủ Hoành Vân mở trận pháp bế quan. Trong động phủ, hắn tế luyện đại đỉnh, gọi Tháp Sơn trọng thương ra tự chữa trị, sau đó lấy Diêu Băng Vân đang bị nhiều tầng phong cấm ra. Vương Lâm cân nhắc luyện Diêu Băng Vân thành Tiên vệ, nhưng trước mắt dùng nguyên lực tạo lốc xoáy trong cơ thể nàng để hút lấy nguyên lực, khiến nguyên thần hắn hoàn toàn khôi phục sau một đêm. Hắn nhận ra nếu tiếp tục hấp thu hết nguyên lực của nàng, tu vi sẽ tăng mạnh và chỉ cần cảm ngộ ý cảnh là có thể bước vào Khuy Niết."},{"chuong":791,"tieuDe":"Thôn Phệ","tomTat":"Tin Lôi Tiên điện bắt giữ mãnh thú khổng lồ ở La Thiên Bắc vực khiến toàn La Thiên Tinh vực chấn động, danh vọng Lôi Tiên điện vượt lên trên nhiều gia tộc tu chân truyền thừa thượng cổ. Lôi Tiên điện nhân thế triển khai phong một trăm linh tám tiên, chia bốn khu vực đông tây nam bắc tuyển người mạnh, lập vùng cấm đấu mười vạn dặm quanh Lôi Tiên điện và tuyên bố sẽ mở đường sang Liên minh Tinh vực, đẩy La Thiên vào khí thế chiến tranh. Trong khi đó, Vương Lâm bế quan trong động phủ Hoàng Vân Sơn, hấp thu nguyên lực Khuy Niết trung kỳ của Diêu Băng Vân; chỉ luyện hóa ba phần đã lên tới đỉnh Dương Thực nhưng vẫn chưa thể đột phá Khuy Niết. Hắn nhận ra cửa ải thật sự nằm ở cảm ngộ Thiên đạo và Ý cảnh Nhân quả, bèn rà lại chuỗi nhân quả đời mình từ Thiên Nghịch châu, Tư Đồ Nam, Đằng Liệt, Đằng Hóa Nguyên tới việc diệt Đằng tộc. Từ ký ức về Cổ Yêu Bối La, Thiên Vận Tử và lời Tiên vệ nói Thiên Vận Tử nuốt Tôn Vân, Vương Lâm nghĩ ra phương pháp cắn nuốt ý cảnh và Đạo niệm người khác để biến Nhân quả thành chân thực. Hắn đặt tay lên mi tâm Diêu Băng Vân nhưng dừng lại, vì hiểu đây là lựa chọn Đạo có thể dẫn vào con đường không về. Ba ngày sau, Vương Lâm vẫn chìm trong câu hỏi Đạo là gì, còn nguyên lực trong cơ thể tự hình thành cơn gió lốc vận chuyển điên cuồng."},{"chuong":792,"tieuDe":"Mộng Đạo","tomTat":"Trong lúc Vương Lâm chìm sâu vào tìm Đạo, quanh thân hắn xuất hiện lốc xoáy nguyên lực đen trắng như Âm Dương, còn nguyên thần từ hình thái Thái Cổ Lôi Long dần biến thành hình người giống hệt bản thân. Dị tượng khiến linh khí Thanh Linh tinh nồng đậm bất thường, tu sĩ khắp nơi hướng về phía Hoàng Vân Sơn, nơi động phủ tan thành bụi và chỉ còn Vương Lâm cùng Diêu Băng Vân dưới đồ án Thái Cực đen trắng. Trạng thái này được gọi là Mộng Đạo, khiến Vương Lâm cảm thấy mình hòa làm một với Thanh Linh tinh. Trong dòng cảm ngộ ấy, hắn quan sát cảnh rắn lớn nuốt thú nhỏ nhưng phủ định đó là Đạo, rồi nhìn thấy cô bé áo gấm thả Tiểu Hắc và nhân quả báo ân ngày sau. Cuối cùng, qua chiếc bát vỡ trong một gia đình thôn xóm, hắn cảm nhận Đạo không tròn đầy, có khe hở và có thể tan vỡ; đứa bé trong thôn thoáng thấy bóng người đạp hư không rồi mọi thứ biến mất."},{"chuong":793,"tieuDe":"Ngươi Đã Minh Ngộ?","tomTat":"Trên Thanh Linh tinh, Vương Lâm trong trạng thái như làn gió đi qua nhiều cảnh thế tục để tìm hiểu Nhân quả và Đạo. Hắn chứng kiến nữ tử áo đen báo thù kẻ hại gia đình, đội đưa tang trong mưa và cảnh phụ tử trong hoàng cung tranh đoạt ngôi vị, nhưng mỗi cảnh chỉ làm câu hỏi trong lòng hắn thêm sâu. Khi như hóa thành cả tinh cầu, hắn nhìn thấy sinh lão bệnh tử, tình thân, luyến ái, chia ly, đoàn tụ và thiện ác của chúng sinh mà vẫn không tìm được đáp án Đạo là gì. Linh lực Thanh Linh tinh trở nên nồng đậm, khiến những người thổ nạp bị cuốn vào trạng thái kỳ dị, còn Vương Lâm như phân thành nhiều hóa thân mượn miệng người thường đi hỏi các bậc học thức. Lão Tạ bị câu hỏi ấy ám ảnh, trong mưa đi tới bờ sông và nhìn cá vùng vẫy trong lưới, từ đó ví mình là cá, Đạo là lưới, sông là trời và người kéo lưới là kẻ quản lý vận mệnh tạo hóa. Lời ví von này khiến Vương Lâm chấn động có chút hiểu ra; hắn hiện thân từ cuồng phong, nhìn cá rơi lại xuống sông rồi điểm linh khí trời đất vào thân thể lão Tạ, ban cho lão một lần vận may."},{"chuong":794,"tieuDe":"Thay Đổi","tomTat":"Trong trạng thái mộng đạo, Vương Lâm minh ngộ đạo không phải bản thân trời mà là ý niệm của trời đất, từ hình tượng cá, nước và lưới mà nhận ra quy tắc thiên địa cùng mạch nghịch đạo của người tu luyện. Hắn quy Sinh Tử Luân Hồi và Nhân Quả Chi Cảnh về đạo niệm, rồi hòa hợp với Thanh Linh Tinh, khiến linh lực toàn tinh cầu tăng vọt, linh mạch phun linh khí, núi thường hóa linh sơn và đất đá dần thành linh thạch. Vương Lâm cảm nhận được linh hồn tinh cầu, hiểu rằng tinh cầu cũng có thể có hồn và có thể ngộ đạo, đồng thời nhận ra mình đã có thể rút hồn lực tinh cầu như Tán Ma năm xưa. Dị biến lan khắp Thanh Linh Tinh khiến phàm nhân và tu sĩ chấn động quỳ bái; nhiều tu sĩ Nguyên Anh nhờ linh khí và tỉnh ngộ Ý Cảnh riêng mà bước lên Hóa Thần, phá bỏ hạn chế lâu năm của tinh cầu. Lão già họ Tạ từ kinh hoàng nghi hoặc chuyển sang minh ngộ, không còn coi Vương Lâm là quỷ. Trên Hoành Vân Sơn, lực lượng toàn tinh cầu hội tụ vào cơ thể Vương Lâm khiến hắn tỉnh lại, nhưng hắn nhận ra mình từng suýt bị những ý niệm quỷ dị thay thế thần trí. Cuối chương, lực lượng từ phàm nhân, tu sĩ và cây cỏ Thanh Linh Tinh tiếp tục ngưng tụ vào Vương Lâm, hóa thành sức phản kháng của sinh linh phóng lên như muốn xé toạc bầu trời."},{"chuong":795,"tieuDe":"Đạo Của Diêu Băng Vân","tomTat":"Trên Thanh Linh Tinh, ý cảnh Nhân Quả của Vương Lâm tạo ra đôi cá âm dương trắng đen, hút ý niệm sinh linh toàn tinh cầu và làm thiên địa biến sắc. Tại Lôi Tiên Điện ở tinh vực La Thiên, Thanh Thủy cảm ứng có người ngoài học được Hô Phong, nhớ tới Bạch Phàm và thề tìm ra nguyên nhân Tiên giới tan vỡ cùng nguyên nhân bản thân phát cuồng để báo thù cho sư tôn. Vương Lâm nhờ cảm ngộ đã chạm ngưỡng Khuy Niết nhưng chưa lập tức đột phá vì lo thiên kiếp quỷ dị; hắn phủ định con đường thôn phệ ý cảnh và chọn mượn đạo người khác để kiểm chứng Nhân Quả. Khi điểm chỉ lên mi tâm Diêu Băng Vân, hắn đưa đôi cá âm dương nhập vào cơ thể nàng, còn Nghịch Thiên châu trong mi tâm chậm rãi xoay chuyển hấp thu. Đạo niệm của Diêu Băng Vân mở ra tiếng gọi muội muội, ký ức tuổi thơ của Băng Vân và Mộng Vân, cùng nỗi sợ hãi muốn gặp mẹ. Diêu Vân từng định đưa hai cô bé tới Huyết Thần Tinh nhưng bị lão tổ Diêu Gia ngăn lại; lão tổ tuyên bố hai cô bé từ khi sinh ra đã được định sẵn làm linh hồn pháp bảo. Cuối cùng Diêu Vân bị đánh bật khỏi từ đường, còn Băng Vân và Mộng Vân bị cuốn vào trong, trở thành bi kịch cốt lõi cấu thành đạo của Diêu Băng Vân mà Vương Lâm đang quan sát."},{"chuong":796,"tieuDe":"Lui Một Bước","tomTat":"Diêu Vân đau đớn nói rõ số phận của Diêu Băng Vân và Mộng Vân: hai tỷ muội sinh ra không phải vì tình thân bình thường mà để trở thành linh hồn mới của pháp bảo Diêu Gia. Trong từ đường, lão tổ Diêu Gia triệu ra cổ đăng có ngọn lửa xanh lạnh, giải thích ngọn lửa đã tồn tại từ tiên giới và việc hắn rút khí hồn dung nhập vào tộc nhân đã dẫn đến sự ra đời của hai tỷ muội. Ngọn lửa hóa thành Cổ Yêu khiến Vương Lâm chấn động; khi quái vật lao tới, Băng Vân vì sợ hãi lùi một bước, để Mộng Vân đứng trước và bị nuốt vào cổ đăng. Băng Vân lập tức suy sụp vì hối hận, cầu xin được thay muội muội làm khí linh, nhưng lão tổ cự tuyệt và mang cổ đăng vào khe nứt hư vô. Diêu Vân muốn xông vào cứu hai cháu gái nhưng bị lực lượng từ đường đánh bật. Ảo cảnh tan vỡ trong tiếng kêu thê lương của Diêu Băng Vân, khi nàng thề rằng ai cứu được Mộng Vân thì nàng sẽ đời đời kiếp kiếp làm người hầu, chết cũng không hối hận."},{"chuong":797,"tieuDe":"Nguyên Lực Thay Đổi","tomTat":"Sau khi thần niệm bị công kích, Vương Lâm mượn Ý Cảnh của Diêu Băng Vân để chứng đạo và nhìn thấu đạo tâm của nàng: bề ngoài tu đạo vô tình, nhưng căn nguyên lại là tình cảm dành cho muội muội. Hắn không phá đạo tâm ấy mà giải phong ấn cho Diêu Băng Vân, xem việc nàng truy sát lại giúp mình đột phá là một đoạn nhân quả đã kết. Diêu Băng Vân tỉnh lại, hỏi về luân hồi và lời nói bí ẩn từng nghe trong từ đường Diêu Gia, nhưng khi Vương Lâm thừa nhận chưa thể giúp nàng, nàng thất vọng rời Hoành Vân Sơn. Sau đó Nhân Quả Ý Cảnh của Vương Lâm ngưng thực thành hư ảnh cá âm dương, khiến hắn về mặt Ý Cảnh thật sự tiến vào Đệ Nhị Bộ và chạm ngưỡng Khuy Niết; Nghịch Thiên châu cũng sinh biến hóa âm dương trong nguyên thần. Sự thay đổi nguyên lực làm linh lực toàn Thanh Linh Tinh bị khuấy động và ngưng tụ về Hoành Vân Sơn, khiến Vương Lâm nhận ra nếu tiếp tục tại đây tinh cầu có thể tan vỡ. Khi định rời đi, hắn thấy lão già họ Tạ dùng thân phàm nhân hành hương lên núi nên ở lại quan sát; lão mất nửa tháng bò tới đỉnh, sinh ngộ về người, trời và đạo rồi quỳ xin truyền đạo. Vương Lâm nhận định lão có đạo tâm ổn định nhưng tuổi thọ sắp hết, kinh mạch đã già yếu, nên hỏi lão có hiểu tu đạo không phải chuyện một sớm một chiều hay không."},{"chuong":798,"tieuDe":"Khuy Niết","tomTat":"Tạ Thanh nói rõ căn nguyên mờ mịt mà mình tỉnh ngộ chính là đạo và cầu xin Vương Lâm thu làm đệ tử. Vương Lâm nhìn thấy phía sau lão có vòng luân hồi nên nhận làm đệ tử ký danh, tặng Hoành Vân làm nơi tu luyện và chỉ truyền một phần cảm ngộ qua đôi cá âm dương. Sau đó Vương Lâm tìm Tiên Tuyển Tộc trên Thanh Linh Tinh bằng Trương Chỉ Phù cuối cùng nhưng không có manh mối, rồi tới một tinh cầu hoang mở động phủ để tĩnh tọa, để Tháp Sơn hộ pháp bên ngoài. Trong lúc tu luyện, nguyên lực của hắn phân thành khí đen trắng, Nhân Quả Ý Cảnh được thực chất hóa và dung nhập vào thân thể, trở thành đạo cảnh nhập thể. Vương Lâm rời động phủ, định tới Phá Diệt Tinh ở La Thiên Nam Vực tìm Lý Nguyên học Tâm Cấm Chi Thuật và sẵn sàng mượn Thiên Kiếp nếu có kẻ cản đường. Trên đường, Diêu Vân dùng kính đồng truy tung, phong tỏa hư vô, hỏi hắn có phải Hứa Mộc hay không rồi thu cả vùng tinh không vạn trượng vào trong kính. Bị nhốt trong không gian nóng như hồng lô, Vương Lâm vẫn bình tĩnh vận chuyển khí đen trắng, khiến tu vi tiến thêm nửa bước và chạm tới Khuy Niết."},{"chuong":799,"tieuDe":"Huyết Thần Tử!","tomTat":"Vương Lâm vừa đạt Khuy Niết thì khí tức bùng phát, âm dương song ngư hóa vòng xoáy cuốn tan sương mù và dẫn động kiếp vân đỏ bao phủ vạn trượng. Diêu Vân bị hé lộ từng đạt Tịnh Niết sơ kỳ nhưng tu vi thụt lùi, ký ức trước khi rời Huyết Thần Tinh mơ hồ, lại bị đau đầu và sát ý khống chế; dưới thiên kiếp, Cổ Yêu trong thân thể hắn lộ diện và thôn phệ lôi kiếp. Vương Lâm dùng Trảm La Quyết phá gương đồng thoát ra, dùng âm dương song ngư và nguyên thần Thái Cổ Lôi Long chống lôi kiếp, rồi nhắc Diêu Băng Vân, Diêu Mộng Vân và cảnh cổ đăng nuốt hồn để kích thích Diêu Vân phản kháng. Khi Cổ Yêu quay sang nuốt Vương Lâm, hắn tung Phong Tiên Ấn phóng kim sắc phù văn, triệu Cổ Thần đại đỉnh thi triển hoán vị, khiến Cổ Yêu rơi vào giữa phù văn và thiên lôi rồi trọng thương hóa thành ấn ký. Huyết Thần Tử xuất hiện trong huyết vụ, chụp ấn ký ấn trở lại mi tâm Diêu Vân, dập tắt phản kháng của hắn; cùng lúc Thanh Thủy Tiên Quân ở Lôi Tiên Điện cảm ứng biến cố và biến mất. Sau đó Huyết Thần Tử dùng Ngôn Xuất Pháp Tùy ép Vương Lâm giao vật lấy được trong cơ thể Vọng Nguyệt, làm hắn bị chấn thương dù Cổ Thần đại đỉnh tự hiện bảo vệ. Vương Lâm vừa lui vừa dùng lời nhắc chuyện lấy lớn ép nhỏ, còn Huyết Thần Tử đáp lạnh nhạt rồi hóa hồng quang thành Huyết Yến lao thẳng về phía hắn."},{"chuong":800,"tieuDe":"Huyết Yến","tomTat":"Vương Lâm kinh nghi khi nhận ra Huyết Yến không chỉ thôn phệ thần thông mà còn có thể thi triển lại, nên gọi Xạ Thần Xa thứ ba hóa thành bướm ngũ sắc để kiềm chế nó. Huyết Thần Tử nuốt lời, trực tiếp chặn đường lui của Vương Lâm và dẫn thiên địa nguyên lực vào kiếp vân, khiến lôi kiếp màu đỏ giáng xuống cả hai phía. Trong sát na bị Huyết Thần Tử áp sát, Vương Lâm nhắc tới cổ yêu Bối La, làm lão khựng lại và khiến yêu vật hai sừng màu xanh từ mi tâm hiện ra truy vấn tung tích Bối La. Nhân cơ hội ấy, Vương Lâm dùng Cổ Thần đại đỉnh kéo giãn khoảng cách, thi triển Hô Phong phá một phần thiên lôi và để nguyên thần nuốt ba đạo lôi kiếp. Bướm ngũ sắc cùng Huyết Yến tiếp tục cản bớt thiên lôi cho hắn, còn Vương Lâm dung nhập vào Phong Tiên Ấn để chịu thêm ba đạo thiên lôi, khiến ấn tràn lôi quang và kim sắc phù văn. Huyết Thần Tử sau đó lại tiến tới định chụp đỉnh đầu Vương Lâm để rút hồn sưu thần, còn Vương Lâm tiếp tục giơ tay gọi Hô Phong."},{"chuong":801,"tieuDe":"Ngươi Không Có Tư Cách","tomTat":"Vương Lâm dốc toàn lực thi triển Hô Phong, thúc Phong Tiên Ấn dẫn thiên lôi và dùng kiếm tiên chém ra Trảm La Quyết liên tiếp để chống Huyết Thần Tử, nhưng tất cả đều bị đối phương phá tan. Khi Huyết Thần Tử miệt thị Hô Phong của Tiên đế Bạch Phàm và chuẩn bị ra tay với Vương Lâm, Thanh Thủy hiện thân với sát khí kinh người, làm quy tắc, kiếp vân và không gian quanh chiến trường biến động dữ dội. Trước lời Huyết Thần Tử muốn hắn không can dự ân oán Diêu gia, Thanh Thủy công khai gọi Vương Lâm là sư đệ và khẳng định người học Hô Phong chính là đại truyền nhân của sư tôn hắn. Thanh Thủy thi triển Hô Phong, hóa ra sáu hắc long vạn trượng khiến Huyết Thần Tử phải dùng chín mươi chín Huyết Yến chống đỡ nhưng vẫn bị đẩy lui. Hắn tuyên bố dù Vương Lâm có sai cũng do chính hắn thay sư tôn dạy, Huyết Thần Tử không có tư cách xử trí. Cuối cùng Thanh Thủy thi triển Hoán Vũ, mưa sát khí bao phủ ngàn dặm nhưng quanh Vương Lâm lại ấm áp, giúp nguyên lực đã tiêu hao của hắn chậm rãi khôi phục."},{"chuong":802,"tieuDe":"Phong Thanh Hạc Lệ Thảo Mộc Giai Binh","tomTat":"Trong lúc Thanh Thủy đứng ra ngăn Huyết Thần Tử và thiên kiếp, Vương Lâm dấy lên cảm giác biết ơn xa lạ, nhớ lại những ân nghĩa sâu nặng từng nhận từ Độn Thiên, Tư Đồ Nam, Thiên Vận Tử và Chu Dật. Huyết Thần Tử tuy âm trầm nhưng thực ra đang bị thương nặng sau một kích của Cổ Thần ấu tử, lại kiêng dè uy danh Thanh Thủy được ghi trong điển tịch Diêu gia. Thanh Thủy điều động mưa trong phạm vi ngàn dặm, mỗi giọt đều ẩn chứa thiên địa lực và một tia lực tiên giới, tạo thế sát phạt ép thẳng về phía Huyết Thần Tử. Huyết Thần Tử dùng tiên thuật Phong Thanh triệu lôi phong đối kháng, nhưng Thanh Thủy đáp lại bằng Vũ Phong, khiến mưa hóa tuyết và đóng băng lôi phong. Không dừng lại, Huyết Thần Tử ngưng thiên địa lực thành chín tiên hạc, thi triển Hạc Lệ để phá băng rồi khiến tiên hạc tự bạo sinh ra vô số lông chim. Từ đó hắn phát động Thảo Mộc Giai Binh, biến lông chim thành hàng loạt pháp bảo và binh khí, khiến thần thông lan rộng tới mức đe dọa La Thiên nam vực. Đúng lúc uy thế thần thông đạt đỉnh, kiếp vân hoàn tất co rút và thất thải thiên lôi gồm bảy màu giáng xuống với khí thế hủy diệt."},{"chuong":803,"tieuDe":"Vãi Đậu Thành Binh","tomTat":"Thanh Thủy đứng ra trước Vương Lâm, khinh miệt thần thông của Huyết Thần Tử rồi dùng hồng quang trong mắt nuốt sạch bảy đạo thiên kiếp bảy màu, khiến Cực Cảnh của hắn khôi phục thêm một phần. Sau đó hắn giảng cho Vương Lâm rằng Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh là tam thức thần thông của sư tôn Bạch Phàm, trong đó thức thứ ba khiến hắn phải cảm ngộ khoảng trăm năm. Khi Thanh Thủy thi triển Vãi Đậu Thành Binh, vô số điểm sáng hóa thành hồn phách những tu sĩ và tiên nhân từng bị hắn giết, từ Mạnh Mộc, Khang Nhiễm, Lữ Kiệt cho đến các Tiên Vương, Tiên Quân và cả hư ảnh phân thân thứ nhất của Thanh Sương. Hắn hé lộ bản chất thần thông là tế luyện sát nghiệt, rút hồn kẻ bị giết khỏi luân hồi rồi luyện hóa thành bổn mạng. Huyết Thần Tử kinh hãi trước tiên thuật của Bạch Phàm, dùng Thảo Mộc Chi Công và binh khí lông chim chống đỡ nhưng nhanh chóng bị phá tan, lần đầu lộ vẻ sợ hãi tử vong. Dư ba trận chiến lan khắp Nam Vực La Thiên Tinh Vực, khiến tinh không sụp đổ và đe dọa thành hạo kiếp, còn Diêu Vân ở phía sau bị chấn thương nặng đến mức yêu vật trong cơ thể gần như sụp đổ."},{"chuong":804,"tieuDe":"Bước Thứ Ba","tomTat":"Thanh Thủy tiếp tục truy sát Huyết Thần Tử, buộc Huyết Thần Tử hiến tế Diêu Vân để Cổ Yêu hút sạch huyết nhục và nguyên thần, khiến Diêu Vân tỉnh táo trong khoảnh khắc cuối rồi ngã xuống. Huyết Thần Tử lấy Cổ Đăng ra, để lộ bản thể Yêu Diễm Phệ Thần và khiến yêu khí bao phủ Nam vực La Thiên. Thanh Thủy dùng Cực Cảnh đánh tan Cổ Yêu, nhưng Cổ Yêu nhờ Cổ Đăng tái ngưng tụ và đoạt được một tia Cực Cảnh. Khi Thanh Thủy chuẩn bị cho Vương Lâm xem Sơn Băng, khí tức bước thứ ba xuất hiện, rồi một thân ảnh tinh quang trấn áp Huyết Thần Tử và Cổ Yêu, cảnh cáo Thanh Thủy cùng Cổ Yêu và nghịch chuyển phá hoại trong khu vực. Sau khi chiến cuộc bị cưỡng ép kết thúc, Thanh Thủy xem Vương Lâm có duyên với truyền thừa của sư tôn vì đã học Hô Phong, bảo hắn tranh cơ hội vào tiên trì để ngưng tụ tiên nguyên và trao giọt mưa bông tuyết chứa ba lượt Hoán Vũ phòng thân. Vương Lâm suy tư về bước thứ ba và phương hướng thấy được từ Nghịch Thiên châu, rồi dùng Súc Địa Thành Thốn đi tới chỗ Lý Nguyên. Tại Phá Diệt Tinh, Lý Nguyên ở tổ trạch Lý gia đã suy tàn, nhớ ân tình với Hứa Mộc ở Lôi chi Tiên giới và hứa sẽ truyền Phá Diệt tâm cấm nếu Hứa Mộc tới."},{"chuong":805,"tieuDe":"Mục Tiêu Một Trăm Lẻ Tám Tiên","tomTat":"Vương Lâm xuất hiện tại Phá Diệt Tinh, gặp Lý Nguyên rồi cùng vào từ đường nhà tổ Lý gia để tiến hành truyền thừa Phá Diệt tâm cấm. Vì báo ân, Lý Nguyên không do dự chia nửa Tâm cấm trong cơ thể cho hắn, khiến bản thân mệt mỏi, già nua và tu vi cấm chế suy giảm. Sau chín ngày trong ao nước đen, hắc tuyến truyền thừa lạc ấn vào mi tâm Vương Lâm, giúp hắn dung hợp tri thức Phá Diệt cấm với hiểu biết cấm chế vốn có. Theo chỉ điểm của Lý Nguyên, Vương Lâm gom nước đen, dung nhập tảng đất lấy ở Lôi Tiên giới và dùng nguyên thần rèn luyện thành tâm cấm la bàn. Khi nhắc đến cuộc tranh đoạt một trăm lẻ tám tiên, Lý Nguyên tự biết chưa đủ tu vi nên chọn bế quan đột phá Âm Hư, còn Vương Lâm trao cho hắn ngọc giản ghi Lôi Nguyên Quyết. Sau đó Vương Lâm rời Phá Diệt Tinh, xác định mục tiêu bước vào cuộc tranh hùng một trăm lẻ tám tiên của Lôi Tiên Điện vì các Tiên thuật, lời hứa của nhiều thế lực và tư cách vào Tiên trì."},{"chuong":806,"tieuDe":"Tiến Đến","tomTat":"Hành động phong tiên cùng cuộc tiến công Liên Minh Tinh Vực sắp tới khiến chiến ý toàn La Thiên Tinh Vực sôi sục; Lôi Tiên Điện phái sứ giả tới bốn vùng Đông Tây Nam Bắc để chọn ra một trăm lẻ tám người vào dự cuộc chiến phong hào cuối cùng. Tại Nam vực La Thiên, chiến trường tranh đoạt phong hào được đặt trong phạm vi ngàn dặm bên ngoài Địa Viêm Tinh, với phiến đá xanh cho khán giả, đá đỏ thẫm cho khoảng ba bốn trăm người đủ tư cách và đá trắng cho các lão tổ. Chiến Không Liệt, Thân Công Hổ và Đường Ngôn Phong — được xưng là Nam Kỹ Tam Kiệt — đều có mặt, cả ba đều nghĩ tới chuyện Hứa Mộc bị Diêu gia truy sát và cùng thất vọng vì cho rằng đã đánh giá sai tu vi thật của hắn. Chiến Vân ngồi sau Chiến Không Liệt, nhớ ân cứu mạng của vị tiền bối trong Lôi Tiên Giới. Ba người Lôi Tiên Điện phụ trách tranh đoạt, trong đó lão già áo bào đen được cả hai sứ giả áo xanh lẫn các lão tổ Nam vực cung kính; một trận tranh đoạt kết thúc với việc Lý Diệp được tuyên bố chiến thắng. Trong lúc đó, Vương Lâm dưới thân phận Hứa Mộc hiện thân cách Địa Viêm Tinh hơn mười vạn dặm, nhớ quy tắc lệnh bài tư cách và vòng phong tỏa mười vạn dặm rồi dùng thân pháp biến mất tiến vào."},{"chuong":807,"tieuDe":"Cái Ta Muốn Là Vị Trí Thứ Nhất","tomTat":"Mạnh Lâm, tu sĩ Anh Biến hậu kỳ đang trấn thủ ngoài Địa Viêm Tinh, bực bội vì bỏ lỡ cuộc tranh đoạt phong hào tiên nhân, nhưng chỉ một ánh mắt của Vương Lâm đi ngang đã khiến hắn mất tri giác rồi vô thức nhập định. Vương Lâm không dùng Súc Địa Thành Thốn mà từng bước tiến vào vùng tranh đoạt để lắng tâm và tích lũy chiến ý, bởi mục tiêu của hắn là đoạt vị trí cao trong ba mươi sáu Thiên Cang chứ không chỉ bảy mươi hai Địa sát. Hắn nhớ tới Lý Mộ Uyển, lời nữ tử Hướng gia trong tranh và ước định với Thanh Thủy, từ đó tự ép mình phải thắng để có tư cách khiến Hướng gia coi trọng yêu cầu hồi sinh nàng. Chiến ý của Vương Lâm hóa thành gió lốc với âm dương song ngư, lan khắp tinh không quanh Địa Viêm Tinh, khiến sứ giả Lôi Tiên Điện, lão tổ các gia tộc và đông đảo tu sĩ đều chấn động. Thân Công Hổ nhận ra khí tức Tôn chủ, Chiến Không Liệt bộc phát khí thế Chiến gia, còn Đường Ngôn Phong chủ động lao lên công kích. Vương Lâm hiện thân với tu vi Khuy Niết sơ kỳ, dùng Trảm La Quyết phá trường kiếm đỏ và hoa sen đỏ của Đường Ngôn Phong, khiến đối phương trọng thương, rồi mở con mắt thứ ba đánh lui nhóm tu sĩ phía sau. Sau khi áp đảo toàn trường, hắn dùng thân phận Hứa Mộc tuyên bố phải đứng thứ nhất trong một trăm lẻ tám tư cách Nam Vực La Thiên, khiến mọi người nhớ lại danh tiếng Ma Đạo Tử và thất bại của Diêu gia khi truy sát hắn. Khi lão già họ Đường chất vấn tư cách của Hứa Mộc, Chiến Vân cùng những người từng được cứu khỏi Lôi Tiên Giới bái kiến hắn, rồi các đại diện Trần gia, Triệu gia, Lý gia và Trịnh gia lần lượt đứng ra tiến cử Hứa Mộc tham chiến."},{"chuong":808,"tieuDe":"Đền Ơn","tomTat":"Trong cuộc phong danh hiệu, nhiều tu sĩ từng được Vương Lâm cứu ở Lôi Tiên Giới lần lượt đứng ra tiến cử Hứa Mộc, khiến lão già họ Đường chấn động vì các trưởng bối gia tộc đều không phản bác. Chiến Không Liệt đại diện Chiến gia lên tiếng, Thân Công Hổ cũng kiên quyết ủng hộ, rồi sứ giả áo tím Lôi Tiên Điện xác nhận Hứa Mộc có tư cách. Khi lão già họ Đường định cuốn Đường Ngôn Phong rời đi và lộ sát khí, Vương Lâm kích nổ ám lực đã cài sẵn trong cơ thể Đường Ngôn Phong, giết chết hắn cả thân thể lẫn nguyên thần và cảnh cáo Đường gia đừng trở thành Diêu tộc thứ hai. Lão già họ Đường muốn trả thù nhưng bị sứ giả áo tím ngăn lại với lý do trong thời gian phong danh hiệu không được đánh nhau vì tư thù, buộc Đường gia rút lui. Sứ giả áo tím hỏi Vương Lâm có muốn tranh tư cách đệ nhất nhân La Thiên Tinh Vực hay không, và Vương Lâm xác nhận dứt khoát. Khi sứ giả tìm người khiêu chiến, Chiến Không Liệt bước vào quầng sáng, tuyên bố nếu tâm phục sẽ dâng đạo niệm và tôn Hứa Mộc làm Tôn Chủ. Trước lời khuyên lui của Vương Lâm, Chiến Không Liệt kể lại nguồn gốc chiến ý bất khuất từ Thiên Lôi Tinh, sự đình trệ sau khi đạt Dương Thực, rồi hỏi đạo của mình đúng hay sai."},{"chuong":809,"tieuDe":"Cửu Khúc Thiên Đao","tomTat":"Chiến Không Liệt hỏi Vương Lâm về con đường chiến ý và muốn dâng đạo niệm để đổi chỉ điểm, nhưng Vương Lâm bác bỏ, giảng rằng chiến ý thật sự phải có niềm tin và đạo niệm bất khuất. Sau khi Chiến Không Liệt lui ra cảm ngộ, Nam Cung Hàn xuất hiện với chín thanh đao và chủ động khiêu chiến bằng Cửu Khúc Thiên Đao. Thần thông này được nhận ra là truyền thừa của Nam Cung gia trong tứ đại gia tộc La Thiên, đồng thời hé lộ biến cố mất tích bí ẩn của gia tộc này. Vương Lâm không muốn dây dưa nên thi triển Hô Phong, hóa hắc phong thành hai hắc long nghìn trượng phá nát đao khí. Quần tu chấn động trước uy lực Hô Phong, còn lão già áo tím Lôi Tiên Điện liên hệ Hứa Mộc với Thanh Thủy Tiên Quân. Cuối chương, Nam Cung Hàn phát động Thiên Đao trảm diệt, còn Vương Lâm chìm sâu vào cảm ngộ Hô Phong qua ký ức Thanh Thủy và bức họa Tiên Đế Bạch Phàm."},{"chuong":810,"tieuDe":"Lão Tử Thua Rồi","tomTat":"Vương Lâm điều khiển hắc long nghìn trượng đối kháng Thiên Đao, khiến bốn đao và quầng sáng nghìn dặm cùng tan vỡ, dư chấn lan khắp khu vực ngoài Địa Viêm Tinh. Nam Cung Hàn bị ép rời tảng đá đỏ sẫm nhưng tiếp tục dùng năm thanh đao thi triển Thiên Đao Đồ Ma. Trong lúc đối kháng, Vương Lâm nhớ chữ trên bức họa tầng chín Tàng Phẩm Các, khiến Hô Phong lộ thêm ý hoán vũ, phun âm phong lẫn mưa va chạm với năm Thiên Đao. Sau khi hai bên đều bị thương, Nam Cung Hàn lộ tên và công nhận Vương Lâm là đối thủ hiện tại. Vương Lâm lập tức dùng Súc Địa Thành Thốn áp sát, thi triển chỉ pháp âm dương đánh vào mi tâm đối thủ. Nam Cung Hàn triển khai Cửu Khúc Đao Trận phòng ngự, nhưng Vương Lâm dùng đồ hình Thú Cốt áp chế thương thế rồi tiếp tục biến mất, khiến Nam Cung Hàn không chịu nổi và tuyên bố nhận thua."},{"chuong":811,"tieuDe":"Người Cuối Cùng","tomTat":"Nam Cung Hàn công khai chịu thua vì không đối phó nổi Súc Địa Thành Thốn, khiến Vương Lâm trong thân phận Hứa Mộc trở thành đệ nhất nhân thứ một trăm lẻ tám của Nam Vực. Vương Lâm được sắp xếp tĩnh tu bảy ngày trên Địa Viêm Tinh để chuẩn bị tới Lôi Tiên Điện, trong thời gian đó Thân Công Hổ đến luận đạo và Nam Cung Hàn liên tục quấy hỏi về thần thông dịch chuyển. Để thoát phiền, Vương Lâm thả Hứa Lập Quốc ra, khiến khí hồn này bị Nam Cung Hàn nói chuyện đến gần tan rã rồi phải cầu xin trở về túi trữ vật. Hết thời hạn, lão già áo tím dùng hòn đá đen mở truyền tống trận đặc biệt, đưa nhóm một trăm linh tám người Nam Vực đến Lôi Tiên Điện. Tại đây, Vương Lâm nhận ra cấm chế quanh Lôi Tiên Điện cực kỳ đáng sợ, đủ khiến hắn chết nếu bị vây. Khi các truyền tống trận bốn vực lần lượt sáng lên, phía Đông Vực xuất hiện biến cố: ba sứ giả trở về kinh hãi, rồi một người trong mùi máu tanh tuyên bố đã giết sạch một trăm linh bảy người còn lại."},{"chuong":812,"tieuDe":"Hứa Gia Ở Đông Lâm Tinh","tomTat":"Người cuối cùng từ Đông Vực lộ diện là Hứa Đình, nam tử áo trắng mang sát khí và mùi máu tanh, vừa xuất hiện đã miệt thị đám tu sĩ xung quanh. Vương Lâm nhận ra Hứa Đình có tu vi Khuy Niết Sơ Kỳ nhưng khí tức quỷ dị, hai người lập tức giao phong thần thức qua ánh mắt, khiến chỉ bốn tu sĩ đặc biệt phát hiện được. Người tiếp dẫn Lôi Tiên Điện xuất hiện trên mây đỏ, chất vấn Hứa Đình về việc giết các tu sĩ tư cách khác của Đông Vực; Hứa Đình thừa nhận và tự xưng là người nhập thế của Hứa gia ở Đông Lâm Tinh. Danh tiếng giết chóc của Hứa gia khiến đám tu sĩ kinh sợ, nhiều người nghĩ tới việc tránh đối đầu hắn trong tranh đoạt. Người tiếp dẫn công bố ba ngày sau khai mạc tranh đoạt một trăm lẻ tám danh hiệu rồi hỏi ai là Hứa Mộc; Vương Lâm bình tĩnh nhận thân phận, làm Tây Vực và Bắc Vực chú ý mạnh. Nam tử áo lam từ Tây Vực nổi sát khí vì Tử Phượng nhớ mãi Hứa Mộc, còn Vương Lâm được Điện Chủ Lôi Tiên Điện triệu kiến vào nội điện, trên đường nghe giới thiệu về một nghìn ba trăm bảy mươi hai tòa đại điện mang về từ Lôi Tiên Giới."},{"chuong":813,"tieuDe":"Tây Tử Phượng","tomTat":"Vương Lâm theo lão già Lôi Tiên Điện tiến sâu vào nội điện, nhìn thấy cấm chế lôi điện dày đặc và Lôi Trì nghìn trượng có phân thân Lôi Linh được trấn an bằng Thăng Tiên Quả. Tại đại điện phía đông, Viêm Lôi Tử triệu kiến hắn, nhận ra thân phận Hứa Mộc chính là Vương Lâm và xác nhận tu vi Khuy Niết, rồi hỏi hắn có muốn tham gia cuộc chiến với Liên Minh Tinh Vực hay không. Vương Lâm nhận lời, hỏi lại Lôi Thú nhưng chỉ được hứa trả sau khi mở thông đạo, sau đó nhận lệnh bài truyền tống và bản đồ nơi ở từ Trần San. Ba ngày sau, các thế lực và lão quái tụ hội quanh Lôi Trì để xem trận tranh đoạt một trăm lẻ tám danh hiệu phong tiên; Tây Tử Phượng cũng có mặt, nhìn Vương Lâm với mối si tình chưa dứt khiến lão tổ Tây gia thầm than là nghiệt duyên. Viêm Lôi Tử công bố thể lệ gồm tam quan Thiên Địa Nhân, lục đạo luân hồi và sinh tử sát lục nhất tuyến thiên, đồng thời nói ba mươi sáu Thiên Cang sẽ có cơ hội lưu danh trên Phong Tiên Thạch. Tin này khiến Thanh Thủy, lão tổ Hướng gia và nam tử họ Công Tôn chấn động vì Phong Tiên Thạch gắn với truyền thuyết Viễn Cổ Tiên Vực. Nhân Chi Quan mở màn khi La Tố của Lôi Tiên Điện bước vào Lôi Trì, khinh miệt toàn bộ người dự tranh, bắt một tu sĩ Bắc Vực xuống sân rồi tản thần thức hóa thành cự nhân kim giáp."},{"chuong":814,"tieuDe":"Không Đủ Tư Cách","tomTat":"La Tố mở Nhân Chi Quan bằng người khổng lồ kim giáp đánh thẳng vào nguyên thần tu sĩ dự tuyển; người đầu tiên bị bức nguyên thần rời thân và bị loại, người thứ hai nhờ cố chịu đủ mười nhịp thở mà được tính qua. Qua nhiều lượt khảo nghiệm, chỉ khoảng bốn phần tu sĩ đủ tư cách, trong đó có tu sĩ sáu ngón, đồng tử đầu to và Nam Cung Hàn. Hứa Đình của Hứa gia Đông Lâm Tinh không chờ bị đánh mà chủ động thi triển Xà Thôn, dùng hắc xà nuốt trọn người khổng lồ kim giáp, khiến các lão quái chú ý. Đến lượt Vương Lâm, La Tố vì thù tộc đệ bị Hứa Mộc giết nên cố ý gây khó, dùng bàn tay thần thông chộp tới nhưng bị hồng quang con mắt thứ ba của Vương Lâm phá tan. Vương Lâm tiếp tục dùng cấm chế phong kín người khổng lồ kim giáp trước người, nhưng La Tố phá lệ tăng khảo nghiệm, gọi thêm người khổng lồ và tự thân dùng tu vi Khuy Niết Trung Kỳ đánh ép hắn qua Phong Tiên Ấn. Bị tuyên bố không đủ tư cách, Vương Lâm phẫn nộ không rời đi mà thi triển Hô Phong, Trảm La Quyết, Thú Cốt và Côn Cực Tiên phá thế công của La Tố. Cuối chương, Thanh Thủy chứng kiến khí thế phản kích ấy và khen Vương Lâm đã có dáng vẻ một môn hạ của sư tôn Bạch Phàm."},{"chuong":815,"tieuDe":"Thần Thức Thuật","tomTat":"La Tố dùng thần thức Khuy Niết Trung Kỳ bao phủ nghìn trượng và điều khiển những người khổng lồ mặc kim giáp tấn công Vương Lâm, nhưng Vương Lâm phóng Côn Cực Tiên thành roi trăm trượng phá hủy toàn bộ kim giáp còn lại. Trong phong tỏa thần thức, Vương Lâm dùng Hô Phong tạo hắc long và lốc xoáy, phối hợp Côn Cực Tiên phá vỡ áp lực của La Tố. La Tố thi triển thần thức thuật thành danh, ngưng thần thức thành châm nhọn, thanh xà và gợn sóng chuyên công kích nguyên thần, song phần lớn bị Côn Cực Tiên phá hoặc bị bì giáp Cổ Thần của Vương Lâm chặn lại. Nhận thấy La Tố dao động, Vương Lâm lập tức phản công bằng Phong Tiên Ấn, Định Thân Thuật, Tôn Hồn Phiên và Trảm La Quyết, còn La Tố dùng trống nhỏ cùng lôi hỏa nguyên lực chống đỡ. Khi cuộc chiến trở nên kịch liệt, Viêm Lôi Tử ra tay cưỡng ép tách hai người, khiến cả Vương Lâm và La Tố phun máu. Thanh Thủy thấy Vương Lâm bị thương thì phát động Cực Cảnh, bất chấp Viêm Lôi Tử ngăn cản, đánh nát nguyên thần La Tố và giết hắn tại chỗ. Viêm Lôi Tử phẫn nộ chất vấn, còn Thanh Thủy bình thản đáp rằng vì La Tố làm Hứa Mộc phun máu nên hắn phải lấy mạng La Tố."},{"chuong":816,"tieuDe":"Thanh Thủy Bênh Vực","tomTat":"Thanh Thủy công khai xem Hứa Mộc là sư đệ theo lời dặn của sư tôn Bạch Phàm và giải thích việc giết La Tố như một lần lỡ tay, nhưng thực chất là vì nhìn thấy sát ý nhằm vào Hứa Mộc. Vương Lâm kính cẩn gọi Thanh Thủy là sư huynh, khiến toàn trường chấn động và suy đoán hắn cũng thuộc mạch Tiên Đế Bạch Phàm. Các nhân vật trọng yếu lập tức có phản ứng riêng: Hứa Đình kiêng kị, Tây Tử Phượng vừa mừng vừa buồn, Thân Công Hổ càng cuồng nhiệt sùng kính, còn Nam Cung Hàn muốn thân cận Hứa Mộc hơn. Viêm Lôi Tử vì kiêng dè Thanh Thủy nên bỏ qua cái chết của La Tố, thay người giữ cửa thứ nhất và kết thúc Nhân Chi Quan với 196 người được ở lại. Sau đó hắn kích hoạt quảng trường nghìn trượng thành Lôi Trì, mở Địa Chi Quan và tuyên bố người dự thi phải chịu được mười lăm nhịp thở mới thông qua. Trước khi vào khảo nghiệm, Tây Tử Phượng đỏ mặt trao cho Vương Lâm một ngọc giản màu xanh, khiến lão tổ Tây gia thở dài. Hứa Đình bước vào Lôi Trì đầu tiên, còn Thân Công Hổ cũng tiến vào rất ung dung vì quen tu luyện nơi lôi điện."},{"chuong":817,"tieuDe":"Hài Đồng","tomTat":"Các tu sĩ lần lượt tiến vào Lôi Trì, người tu vi không đủ lập tức bị lôi uy chấn động phải rời khỏi. Vương Lâm nhận ngọc giản phòng thân do Tây Tử Phượng đưa, nhận ra đây là trọng bảo có thể chống lôi uy mạnh rồi cất vào ngực, khiến nàng đỏ mặt còn biểu ca áo lam của nàng sinh địch ý. Viêm Lôi Tử tuyên bố cửa thứ hai bắt đầu, hai sứ giả Lôi Tiên Điện gọi ra trống lớn và dùng tiếng trống để tính thời gian, mỗi tiếng trống lại làm lôi uy trong Lôi Trì tăng mạnh. Khi nhiều tu sĩ phải dùng pháp bảo hoặc thủ đoạn phòng ngự, Vương Lâm để lôi đình nhập thể, nhờ đó khôi phục hao tổn nguyên thần sau trận với La Tố và khiến Hứa Đình kinh hãi quan sát. Từ tiếng trống thứ mười một, lôi điện ngưng tụ thành Lôi Linh trăm trượng giống rắn lại giống rồng, tiếng rít và lôi quang của nó đào thải hàng loạt tu sĩ. Thân Công Hổ, Chiến Không Liệt, tu sĩ sáu ngón và đồng tử đầu to đều gắng chống chịu, trong khi Vương Lâm tiếp tục nhờ lôi lực khôi phục hoàn toàn thương tổn và thanh trừ ẩn họa cũ từ trận với Diêu Băng Vân. Khi Lôi Linh cuốn tới chỗ hắn, Vương Lâm mở mắt nhìn lạnh lùng; uy áp truyền thừa trong ánh mắt đánh vào lôi hồn khiến Lôi Linh kinh hoảng, gần như hồn phi phách tán và phải thối lui."},{"chuong":818,"tieuDe":"Mèo Nào Cắn Mỉu Nào","tomTat":"Vương Lâm nhắm mắt cảm ngộ trong lôi trì, không để ý tới Lôi Linh, nhưng khí tức Thái Cổ Lôi Long trên người hắn khiến Lôi Linh kinh hãi như gặp tổ tông của vạn lôi. Cảnh tượng này làm Hứa Đình, Thân Công Hổ, Chiến Không Liệt và nhiều tu sĩ chấn động, còn Viêm Lôi Tử nhớ lại Hứa Mộc từng suýt tu thành Lôi Linh nên cho rằng trận này khó làm gì được hắn. Bị áp chế trước Vương Lâm, Lôi Linh trút giận lên các tu sĩ khác, đánh vỡ ba mảnh ngọc giản màu xanh của nam tử áo xanh và ép hắn rời khỏi lôi trì. Chiến Không Liệt, Thân Công Hổ, đồng tử đầu to và tu sĩ sáu ngón lần lượt tránh khỏi vùng nguy hiểm, để trong lôi trì chỉ còn Hứa Đình và Vương Lâm. Hứa Đình cố trụ bằng hắc vụ nhưng bị Lôi Linh lao tới làm hắc khí tiêu tán, phải lùi hơn ngàn trượng ra ngoài trong không cam lòng. Sau đó Vương Lâm mở mắt, đi vào trung tâm lôi trì khoanh chân tiếp tục cảm ngộ. Tiếng trống trên trời không ngừng vang lên, kích thích hung tính và tham niệm trong Lôi Linh, khiến nó tin rằng nuốt Vương Lâm sẽ hóa thành Lôi Long. Cuối chương, Lôi Linh gom lôi quang toàn lôi trì, làm lôi trì cuồn cuộn nổi sóng và lao thẳng về phía Vương Lâm."},{"chuong":819,"tieuDe":"Quyền Lực Sử Dụng Sấm Sét","tomTat":"Khi Lôi Linh áp sát, lôi quang ở mi tâm Vương Lâm lóe lên và nguyên thần Thái Cổ Lôi Long lao ra, dùng khí tức tổ tiên khiến Lôi Linh run rẩy. Hai bên cắn nuốt lẫn nhau trong Lôi Trì, ban đầu ngang sức, nhưng Vương Lâm nhờ đặc tính thôn hồn và ý chí quyết liệt đã nuốt nát nửa thân Lôi Linh. Nửa thân còn lại của Lôi Linh kéo lôi điện khổng lồ dưới nền đá xanh bùng phát, làm Lôi Trì nghìn trượng nổ tung như Thiên Kiếp giáng xuống Lôi Tiên Điện, buộc Viêm Lôi Tử ra tay dập cơn lốc lôi đình. Sau khi nuốt nửa Lôi Linh, nguyên thần Vương Lâm phát ra tiếng rít gào đầu tiên của Thái Cổ Lôi Long, khiến lôi đình đang tụ về Lôi Linh đổi hướng triều bái và nghe lệnh hắn. Thanh Thủy bật cười khen ngợi, Viêm Lôi Tử kinh sợ nhưng không dám ngăn vì kiêng dè Thanh Thủy, còn các lão quái và tu sĩ xung quanh đều chấn động trước nguyên thần Thái Cổ Lôi Long. Dưới uy áp hiệu lệnh sấm sét, nửa Lôi Linh còn lại không dám phản kháng và bị Vương Lâm nuốt trọn, khiến mức dung hợp của hắn với Thái Cổ Lôi Long tăng từ khoảng một phần năm lên gần một nửa. Khi nguyên thần trở về mi tâm, toàn bộ lôi đình trong phạm vi nghìn trượng co rút vào Vương Lâm, để lại Lôi Trì hoang tàn không còn chút lôi điện và khiến toàn trường lặng ngắt như lúc La Tố bị giết."},{"chuong":820,"tieuDe":"Thiên Chi Quan","tomTat":"Vương Lâm rời khỏi Lôi Trì đã bị phá sau Địa Chi Quan, toàn thân còn lôi quang khiến những người dự tranh đoạt danh hiệu Tiên kinh sợ lùi lại và bàn luận rằng Hứa Mộc có thể đứng trong nhóm đầu lần này. Các lão quái trên bồ đoàn và hai sứ giả Lôi Tiên Điện đều chuyển sang tán thưởng, còn Viêm Lôi Tử không trách hắn mà xem tổn thất Lôi Trì và phân thân Lôi Linh là đáng giá để đổi lấy một tiểu bối cao thủ cho La Thiên. Viêm Lôi Tử dùng ký hiệu chứa tia bổn nguyên lực phục hồi mặt đá xanh nghìn trượng, khiến Vương Lâm chú ý tới tầng lực lượng huyền diệu này. Sau đó ông tuyên bố mở cửa cuối cùng là Thiên Chi Quan và mời Liệt Vân Tử chủ trì. Liệt Vân Tử lấy Chiến Tự Thiếp của Chiến gia ra, mở cuộn tranh cổ thành bức tranh chỉ có chữ Chiến, rồi loại bớt người yếu và quy định người dự thi phải cảm ngộ mười nhịp thở dưới pháp bảo này. Chiến Không Liệt được gọi lên đầu tiên, thần thức dung nhập chữ Chiến và nhận một tia bổn nguyên cực mỏng nhưng không giữ được đến cuối, song vẫn được tuyên bố đủ tư cách. Qua quan sát, Vương Lâm nhận ra Chiến Tự Thiếp chứa bổn nguyên lực và hiểu rằng điều kiện vượt quan nằm ở việc được chữ Chiến tiếp nhận thần thức."},{"chuong":821,"tieuDe":"Con Mắt Thứ Ba Tiến Hóa","tomTat":"Hứa Đình bước vào khảo nghiệm Chiến Tự Thiếp, nhập định ở nhịp thở thứ năm và được một tia bổn nguyên lực rất mỏng lưu lại trong thân thể, khiến Liệt Vân Tử công nhận tư cách cho hắn xem Chiến Tự Thiếp thứ hai. Vương Lâm nhìn ra cơ duyên ấy cùng sát khí cũ của Hứa Đình nên âm thầm quyết không để người này sống. Khi Vương Lâm tự bước vào khảo nghiệm, hắn chỉ mất một nhịp thở để nhập định, làm Liệt Vân Tử, Chiến Không Liệt và các lão quái chấn động, đồng thời khiến Huyết Thần Tử nổi sát ý nhưng bị Thanh Thủy cảnh cáo. Tia bổn nguyên lực từ Chiến Tự Thiếp lao vào mi tâm Vương Lâm, làm con mắt thứ ba bùng phát hồng quang, bao phủ bức tranh và giúp hắn thấy ảo cảnh lão già áo trắng viết chữ Chiến trong tinh không, chữ ấy hóa thành sáu cuốn tranh. Sau khi tỉnh lại, Vương Lâm nhận ra sức mạnh ở con mắt thứ ba có nguy cơ cắn trả nên dùng Phá Diệt cấm hóa thành ba đạo ấn quyết tạm phong ấn mi tâm. Thiên Chi Quan kết thúc, số người còn lại là một trăm mười hai; Viêm Lôi Tử tuyên bố Nhất Đường Thiên là cửa cuối, dùng tám khúc gỗ phát ánh sáng nhiều màu đưa toàn bộ tu sĩ vào không gian rừng rậm đầy cổ thụ, lá mục, độc trùng và tiếng rống xa."},{"chuong":822,"tieuDe":"Nhất Đường Thiên","tomTat":"Vương Lâm hiện thân trong Nhất Đường Thiên từ cây đại thụ, lập tức thi triển Tâm cấm thuật thu liễm hơi thở, xác nhận ở đây chỉ là phân thân và đây mới là cuộc chiến phong hào thực sự. Hắn thử thi triển Súc Địa Thành Thốn nhưng thất bại vì nơi đây không phải trời đất thực sự. Phát hiện Triệu Dật Đạo vô thức tỏa thần thức khi vừa xuất hiện, bị Hứa Đình hóa làn khói đen nuốt chửng không nhả lại dù mảnh vải. Hứa Đình đối diện Vương Lâm, e ngại đề nghị để cuộc chiến đến cuối cùng, Vương Lâm lạnh lùng bỏ đi, hai bên ngầm phân ranh giới. Vương Lâm cố ý tỏa thần thức dẫn dụ đối thủ, dùng Phong Tiên Ấn lần lượt giết một tu sĩ bỏ chạy và bốn tu sĩ Dương Thực liên thủ, phát hiện ấn có thể phong ấn phân thân thành ký hiệu có linh tính, tổng cộng bảy ký hiệu. Hắn nảy ý tưởng kết hợp Tôn Hồn Phiên và Phong Tiên Ấn, rung động trước khả năng này. Ở một nơi khác, Thân Công Hổ vừa xuất hiện đã bị Đồng tử đầu to truy đuổi, bị thương bỏ chạy rồi bị kiến Thiên Minh kẹp lấy, tình thế nguy kịch."},{"chuong":823,"tieuDe":"Lôi Diệt","tomTat":"Thân Công Hổ bị kiến Thiên Minh của đồng tử đầu to truy sát, phóng lôi cầu nhưng bị kẹp nát do chênh lệch tu vi, lâm vào thế tuyệt vọng. Vương Lâm kịp thời xuất hiện, dùng Phong Tiên ấn phong chặn kiến Thiên Minh cứu Thân Công Hổ rồi truy sát đồng tử đầu to. Đồng tử đầu to muốn rút lui nhưng bất thành, phải dùng kiến Thiên Minh chắn Trảm La quyết và thi triển Tiên thuật Bao La triệu mãnh thú cản đường. Vương Lâm triệu nguyên thần Thái Cổ Lôi Long gầm vang khống chế toàn bộ lôi hệ, khiến chiến trường chấn động — Hứa Đình bị đánh bật khỏi trạng thái khói đen, tu sĩ sáu ngón bị ép lộ thân, Chiến Không Liệt mừng rỡ chạy về phía tiếng rống. Ở Lôi Tiên điện, tám cây cột gỗ chấn động, Viêm Lôi Tử phải ra tay ổn định. Vương Lâm tụ lôi điện phạm vi ngàn dặm rồi thi triển Lôi Diệt, thiêu sạch phân thần đồng tử đầu to không còn xương. Bản thể đồng tử đầu to tại Lôi Tiên điện phun máu tỉnh lại, kinh hãi phát hiện chỉ còn 108 người và suy đoán có bốn kẻ đã vào Nhất Đường Thiên bằng bản thể."},{"chuong":824,"tieuDe":"Con Mắt Thứ Ba","tomTat":"Sau khi thu phân thần đồng tử đầu to, Vương Lâm đưa đan dược cho Thân Công Hổ và biết Thân Công Hổ không mở được túi trữ vật, từ đó suy ra chiến trường có thật giả lẫn lộn, chỉ người có bản thể thật mới dùng được túi trữ vật. Hắn bay khắp chiến trường, gặp tu sĩ thì kiểm tra túi trữ vật trước, không mở được thì giết, còn dùng kim phù chiếm phân thần người tự tuyệt. Hứa Đình hóa thành sương đen cắn nuốt các tu sĩ trong khu vực của mình. Về đêm, Nam Cung Hàn lộ mình là bản thể thật xui xẻo lọt vào và ẩn nấp, còn tu sĩ sáu ngón chờ cơ hội sau cuộc đấu hai kẻ mạnh nhất. Vương Lâm chủ động tìm Hứa Đình để đoạt một tia bản nguyên; Hứa Đình dùng bóng ma, Xà thôn và Sơn lâm công kích, Vương Lâm dùng Hô Phong chống lại rồi mở phong ấn thứ ba trên mi tâm, khiến con mắt thứ ba phóng ánh sáng hồng làm tan rã ngọn núi đen và đánh trúng Hứa Đình, đẩy hắn vào trạng thái nguy hiểm cực độ."},{"chuong":825,"tieuDe":"Phong Tiên","tomTat":"Hứa Đình bị ánh sáng màu hồng từ mi tâm Vương Lâm giữ chặt, thân thể và tu vi lần lượt thoái hóa cho đến khi cả phân thần cùng chút bản nguyên đều tan biến. Vương Lâm sau đó suy kiệt và phong ấn lực lượng nơi mi tâm, nhưng Chu Hành Đạo lại nhân cơ hội đánh lén để giết Hứa Mộc nổi danh La Thiên. Vương Lâm dùng lôi đình phá thế công, ngưng lôi thành chỉ kiếm đánh tan máu thịt và nguyên thần Chu Hành Đạo, rồi ký hiệu vàng hút phân thần đối phương về Phong Tiên ấn. Nam Cung Hàn kinh hãi thừa nhận không muốn giao chiến, Thân Công Hổ cũng bị chấn động trước ánh sáng màu hồng, sau đó ba người được ánh sáng nhiều màu đưa khỏi khảo nghiệm. Vương Lâm và Nam Cung Hàn trở lại tảng đá ngàn trượng, nơi một trăm lẻ tám tu sĩ đã thức tỉnh, gồm cả Hứa Đình và Chu Hành Đạo với vẻ thù hận. Viêm Lôi Tử chính thức mở nghi lễ Phong Tiên của Lôi Tiên điện trước toàn La Thiên, tạo dị tượng tiên khí, tiên hạc và mây lành, khiến các lão tổ, lão quái và sứ giả đều đứng dậy cung kính. Hình ảnh Phong Tiên được truyền qua đá truyền âm tới các tinh cầu và đội quân bốn hướng, đồng thời trở thành màn tổng động viên cho quyết chiến với Liên Minh. Cuối chương, Viêm Lôi Tử công bố cơ cấu chính, phó Lôi Tiên, Thiên Cương tiên và Địa Sát tiên rồi gọi Hứa Mộc tiến lên nhận lệnh."},{"chuong":826,"tieuDe":"Uyển Nhi","tomTat":"Viêm Lôi Tử chủ trì nghi thức Phong Tiên, phong Hứa Mộc làm Chính phẩm Lôi tiên tiên phong số một của La Thiên tinh vực và ban Thiên Hổ kỳ, phong Hứa Đình làm phó phẩm Lôi tiên cùng một trăm lẻ tám vị tiên khác. Hình ảnh Vương Lâm lan khắp La Thiên, khiến Tạ Thanh Tòng, Diêu Băng Vân, nữ tu Nhiễm Vân tinh và Tham Lang lần lượt phản ứng mạnh. Viêm Lôi Tử triệu Thăng Tiên trì cho các tiên vị lựa chọn giữa tu tiên thượng cổ và tu đạo: Hứa Đình dứt khoát bỏ ý cảnh bước vào để tăng thực lực, trong khi Vương Lâm, Nam Cung Hàn, Thân Công Hổ, Chiến Không Liệt và hơn mười người từ chối. Phong Tiên thạch xuất hiện để khắc danh, Hứa Đình bị hấp thu nửa nguyên thần, Vương Lâm cố ý rút nguyên thần và chỉ lưu tên Ma Đạo Tử. Viêm Lôi Tử công bố phần thưởng cuối cùng cho ba mươi tám tiên vị; Vương Lâm xin cứu một Nguyên Anh tàn phá đang ngủ say rồi mở quả cầu phong ấn lộ ra Nguyên Anh Lý Mộ Uyển, khiến Tây Tử Phượng đau lòng rơi lệ và Thanh Thủy buồn bã nhớ quá khứ, còn lão Hướng nghiêm mặt hỏi nàng đã ngủ say bao lâu."},{"chuong":827,"tieuDe":"Ta Đồng Ý","tomTat":"Vương Lâm trình Nguyên Anh Lý Mộ Uyển cho lão nhân họ Hướng chẩn đoán, được cho biết nàng đã ở bờ tử vong, tuổi thọ đã hết, lão nhân chỉ có thể đưa vào luân hồi chứ không đủ sức cứu. Vương Lâm phun máu, rơi lệ, thề cướp nàng trở về từ tay trời. Lão nhân họ Hướng tiết lộ phương pháp cuối cùng: thần thông Thất Tịch Thuật do tiên tổ bế quan Hướng gia tại Đông Lâm tinh thi triển, chuyển đổi sinh cơ giữa hai người nhưng Vương Lâm sẽ mất chín phần tuổi thọ và chỉ có chút hy vọng thành công. Vương Lâm không do dự tuyên bố đồng ý trước mặt toàn bộ tu sĩ tinh vực La Thiên. Thanh Thủy chủ động xin đi cùng tới Đông Lâm tinh bảo vệ. Hứa Đình và Nam Cung Hàn cùng xin vào Tàng Tiên các của Lôi Tiên điện học tiên thuật, Phong Tiên chính thức chấm dứt. Viêm Lôi Tử tuyên bố đại chiến sắp bắt đầu, thi triển thần thông triệu hơn mười mảnh đại lục nhỏ tiên giới tạo dòng xoáy cực mạnh phá bức tường không gian mở thông đạo tới Liên Minh, mười một lão quái cùng Huyết Thần Tử dung nhập thần thông hỗ trợ."},{"chuong":828,"tieuDe":"Bức Tường Không Gian Mở Ra","tomTat":"Dòng xoáy trên bầu trời Lôi Tiên Điện đạt cực hạn, Viêm Lôi Tử dùng Lôi giới lực gọi Lôi thú từ mười mảnh đại lục nhỏ nhập vào dòng xoáy, rồi các lão quái La Thiên lần lượt ra tay phá mở hư không. Ông tiếp tục hiến tinh huyết nguyên thần, dùng linh hồn mười mảnh đại lục bị phong ấn và tia Cực do Thanh Thủy đưa ra để xé bức tường không gian, khiến khe hở nối sang tinh vực Liên Minh hiện ra. Khi khe vừa mở đã muốn khép lại, Viêm Lôi Tử hy sinh các mảnh đại lục chống vào miệng khe, nhưng một cánh tay khổng lồ từ phía bên kia vươn ra bóp nát chúng; Vương Lâm nhận ra cánh tay ấy không mang khí tức Cổ Thần. Cái bóng thần bí từng ngăn Thanh Thủy và Huyết Thần Tử xuất hiện, dùng lực lượng bản nguyên ở đầu ngón tay làm cánh tay biến mất, rồi đối đáp với thanh âm cảnh cáo về quy tắc tiên vực viễn cổ. Khi đường sang Liên Minh đã mở, Viêm Lôi Tử tuyên bố cuộc chiến La Thiên – Liên Minh bắt đầu, ra lệnh bốn đại quân trong ba ngày chiếm ba tinh cầu tu chân làm căn cứ, đồng thời mở truyền tống đại trận toàn tinh vực để đưa thêm tu sĩ tới chiến trường. Sau khi chính, phó Lôi Tiên cùng một trăm lẻ tám vị tiên lao qua khe, Viêm Lôi Tử tự mình bước vào tinh vực Liên Minh và gọi tên Trọng Huyền Tử với cừu hận. Ở phía Tây tinh vực Liên Minh, khe ngàn trượng mở ra đúng lúc một đại quân tu sĩ Liên Minh đang trên đường tới tinh cầu được chỉ định để kiến tạo quốc gia tu chân."},{"chuong":829,"tieuDe":"Đông Lâm Tinh","tomTat":"Biến cố ở khe nứt khiến tu sĩ Liên Minh lập tức tản ra rút về Huyền Đình tinh, nhưng trong lúc tháo chạy vẫn có kẻ giả yếu để phản sát tu sĩ La Thiên truy kích. Hướng Vân Đông gọi Hứa Mộc rời khỏi nhóm tiên phong, nhận định hắn sẽ không mạo hiểm tiến vào Liên Minh tinh vực đầu tiên, còn Vương Lâm cũng tự thấy cuộc chiến hai tinh vực cần hết sức thận trọng. Thanh Thủy đi theo Vương Lâm, trong khi Mạnh Vân Tử do dự rồi quay nhìn vào khe nứt. Hướng Vân Đông dẫn hai người rời Lôi Tiên điện tới phía Đông La Thiên, dùng ngọc giản đỏ tìm Đông Lâm tinh, một tinh cầu thần bí có vị trí di chuyển và cấm chế cực mạnh. Ông kích hoạt một tinh cầu tu chân nhỏ quanh Đông Lâm tinh thành truyền tống trận, đưa cả ba vào trong rồi bay thẳng tới cấm địa phía Tây thay vì về gia tộc. Tại vùng đất đầy tử khí, mộ phần và thi thể, Vương Lâm cảm nhận vô số hồn phách, cho rằng nơi này thậm chí vượt xa thời mạnh nhất của Tôn hồn phiên. Hướng Vân Đông cung kính cầu kiến tổ tiên Hướng gia, trình bày chuyện chiến tranh La Thiên — Liên Minh và xin thi triển Thất Tịch Thuật cho Hứa Mộc. Tổ tiên Hướng gia dùng thần thức quét Vương Lâm nhưng không nhìn thấu hoàn toàn vì lực lượng bản nguyên từ con mắt thứ ba, sau đó mở khe nứt và cho Vương Lâm một mình xuống gặp."},{"chuong":830,"tieuDe":"Sinh Cơ","tomTat":"Thanh Thủy cảnh cáo các dòng họ trên Đông Lâm tinh rằng nếu Vương Lâm bị hại thì máu sẽ chảy thành sông, rồi Vương Lâm cảm tạ ông và Hướng Vân Đông trước khi một mình xuống cái khe tử khí. Càng xuống sâu, tử khí càng nồng đặc, nhưng nhờ từng tu Sinh Tử Luân Hồi, Hoàng Tuyền Thăng Khiếu Quyết và vận chuyển Âm Dương song ngư, hắn tạm chống chịu để đi tới thông đạo tối và biển đầu người. Ở nơi đặt quan tài của tổ tiên Hướng gia, lão đồng ý thi triển Thất Tịch thuật nhưng yêu cầu một nửa sinh cơ của Vương Lâm, khiến hắn nhanh chóng già đi dưới ánh sáng từ vô số đầu lâu. Vương Lâm lấy quả cầu chứa nguyên anh Lý Mộ Uyển ra, nhưng tổ tiên Hướng gia cuốn nó vào trung tâm gió lốc, làm hắn nổi giận mở con mắt thứ ba phá tử khí và lao theo. Tổ tiên Hướng gia phá cấm chế quanh nguyên anh, nhận ra nàng đã mất hết sinh cơ và nói hiện chỉ nắm chắc ba phần. Vương Lâm không chống cự, để tử khí rút sinh cơ của mình truyền vào nguyên anh Lý Mộ Uyển, khiến hắn già yếu đến mức cảm nhận Thiên Đạo Luân Hồi kêu gọi. Đến ngày thứ ba, sinh cơ của Vương Lâm cạn, Thất Tịch thuật dừng lại dù cần duy trì bảy ngày, và tổ tiên Hướng gia hỏi hắn còn thứ gì có thể tăng sinh cơ hay không."},{"chuong":831,"tieuDe":"Món Quà Của Thanh Thủy","tomTat":"Nguyên anh Lý Mộ Uyển lại mất sinh cơ và bắt đầu tiêu tán, Vương Lâm liền tự nguyện để nàng tiếp tục hút sinh cơ của mình, khiến phân thân nhanh chóng già nua và cảm nhận rõ hơn lời kêu gọi của thiên đạo. Vì sinh cơ phân thân không đủ, bổn tôn Cổ Thần của hắn trong tinh vực Liên Minh cũng truyền sinh cơ qua phương pháp đặc biệt, giúp nguyên anh Lý Mộ Uyển sau bốn ngày trở nên rõ ràng và tử khí biến mất. Đến ngày thứ năm, sinh cơ của Vương Lâm đạt cực hạn, tổ tiên Hướng gia kết luận vẫn không thể làm sống lại Nguyên Anh, rồi dùng tử khí đẩy Vương Lâm và Lý Mộ Uyển ra khỏi thông đạo. Vương Lâm lập tức dùng cấm chế làm chậm phần sức sống còn lại của nguyên anh, cất nàng vào túi trữ vật và rời đi cùng Thanh Thủy, trong khi Hướng Văn Đông thừa nhận mình có tính kế nhưng cho rằng giao dịch đã xong. Trên đường trong tinh không, Vương Lâm hỏi Thanh Thủy về Tị Thiên quan; Thanh Thủy nhận ra tiên khí đậm đặc và lực lượng giống quy tắc, đoán vật này dùng chữa thương nhưng không biết cách sử dụng. Thanh Thủy sau đó xem Vương Lâm là đã vượt khảo nghiệm, truyền thừa Hoán Vũ và Tát đậu thành binh, để lại một đạo tiên nguyên lực hóa thành hạt tiên khí trong nguyên thần hắn. Vì xúc động trước việc Vương Lâm hao hết sinh cơ vì người yêu, Thanh Thủy nhớ lại bi kịch của mình và truyền thêm thần thông thôn phệ, đồng thời cảnh báo thuật này có tác hại rất lớn, không được tùy tiện sử dụng."},{"chuong":832,"tieuDe":"Tư Đồ Nam Xuất Quan","tomTat":"Thanh Thủy nhận thấy sức sống của Vương Lâm tổn thất quá nặng nên dùng ký hiệu màu đỏ ấn vào ngực hắn, chỉ giúp che giấu và bảo vệ phần tổn thương chứ không thật sự khôi phục. Trước khi rời đi, Thanh Thủy nhắc rằng phương pháp khôi phục Cực Cảnh liên quan Thiên Kiếp và cảnh báo Vương Lâm nếu chưa vào Toái Niết thì không được dựa vào Cực Cảnh. Vương Lâm tìm một tu chân tinh bỏ hoang, lập động phủ tạm, để Tháp Sơn hộ pháp rồi mở quả cầu cấm chế phong ấn Nguyên Anh Lý Mộ Uyển. Hắn thử đưa nàng vào hạt châu Thiên Nghịch nhưng sức sống vẫn tiêu tán, nên lấy Tị Thiên Quan ra và nhờ chút sinh cơ còn lại của nàng để ngưng tụ lại thân thể có hơi thở. Ba ngày sau, Vương Lâm mang Lý Mộ Uyển rời đi, tiến thẳng đến Lôi Tiên Điện và nói rằng họ về nhà. Cùng lúc, đạo quân La Thiên Tinh Vực xâm nhập phía tây Liên Minh Tinh Vực trong nửa tháng, nhưng Tu Chân Liên Minh không phản kích rõ ràng khiến Viêm Lôi Tử và các lão quái La Thiên nghi ngờ. Những tu sĩ Liên Minh còn lại tuy ít hơn nhưng kinh nghiệm chiến đấu cực kỳ phong phú, pháp bảo xảo quyệt, gây tổn thất và chấn động cho tu sĩ La Thiên. Ở một tinh cầu hoang dã phía tây Liên Minh Tinh Vực, một nam tử áo rách lao ra sau thời gian bế quan, tự xưng đã đạt Tịnh Niết sơ kỳ và muốn tới Phượng Loan Tinh trả thù."},{"chuong":833,"tieuDe":"Chu Tước Tinh","tomTat":"Vương Lâm trở lại Liên Minh Tinh Vực, nhớ lại khi rời đi còn là Vấn Đỉnh còn nay đã đạt Khuy Niết, đồng thời khơi lại ân oán cũ với Thiên Vận Tử và Lăng Thiên Hầu. Hắn nhận định chiến tranh giữa La Thiên và Liên Minh vô cùng thâm sâu nên chọn quan vọng, không dễ để bản thân bị cuốn vào chiến cục, đồng thời cảm ứng được phương vị bản tôn. Vì từng tiêu hao phần lớn sức sống để đổi lấy Thất Tịch thuật cứu Lý Mộ Uyển, hắn tìm một tinh cầu hoang dã đầy sinh cơ, để Tháp Sơn hộ pháp rồi dùng Tịch Diệt Chỉ hút sinh mệnh lực trong phạm vi ngàn dặm. Cùng lúc đó, trên Chu Tước Tinh đang bán hoang phế, Bạch Tuyết dẫn tu sĩ tuần tra trong không khí chiến loạn và cảnh báo nơi này quá gần tu sĩ Viêm Ly La Thiên Tinh Vực. Một đội mấy trăm tu sĩ La Thiên do đồng tử đầu to dẫn đầu áp sát Chu Tước Tinh, xem nơi này chỉ ngang Lục cấp tu chân quốc và không đặt vào mắt. Bạch Tuyết cùng tu sĩ Chu Tước lập tức rút vào tinh cầu, còn một nam tử trung niên Vấn Đỉnh đại viên mãn bước ra xin đồng tử đầu to cho hai huynh đệ mình giải quyết Chu Tước Tinh."},{"chuong":834,"tieuDe":"Pho Tượng Vương Lâm","tomTat":"Đồng tử đầu to xem thường Chu Tước Tinh và ra lệnh cho hai huynh đệ La Thiên trong một nén hương giết sạch toàn bộ tu sĩ trên tinh cầu. Trên Chu Tước Sơn, Chu Vũ Thái lấy thân phận Chu Tước Tử do Vương Lâm nhường lại để tuyên thệ cùng tồn vong với quê nhà, trong khi Bạch Tuyết, Hoàng Long chân nhân, hai tu sĩ Vấn Đỉnh già cả và nhiều tu sĩ bản thổ chuẩn bị nghênh chiến. Vân Tước Tử cũng xuất quan, tập hợp Tiên Di Tộc, còn Tôn Thái già yếu ở Vân Thiên Tông vẫn gượng đứng trước nguy cơ diệt tinh. Khi hai huynh đệ La Thiên dùng thần thức quét qua Chu Tước Tinh, họ phát hiện pho tượng Vương Lâm tại Vân Thiên Tông và nhận ra đó chính là Ma Đạo Tử Hứa Mộc nổi danh ở La Thiên. Uy danh Hứa Mộc, thân phận Chính phẩm Lôi Tiên và quan hệ với Thanh Thủy Tiên Quân khiến hai tu sĩ Vấn Đỉnh đại viên mãn mất sạch sát khí, không dám tra hỏi mà lập tức bỏ chạy. Sự rút lui bất ngờ làm toàn bộ tu sĩ Chu Tước Tinh kinh ngạc, còn Vân Tước Tử dùng thần thức tập trung vào pho tượng Vương Lâm để tìm nguyên nhân."},{"chuong":835,"tieuDe":"Trở Về","tomTat":"Hai tu sĩ La Thiên rút khỏi Chu Tước Tinh sau khi thấy pho tượng Vương Lâm, khiến Vân Tước Tử, Chu Vũ Thái và Tôn Thái đều nhận ra có điều bất thường. Trên tinh cầu hoang dã, Vương Lâm dùng Tịch Diệt Chỉ hút sinh cơ trong phạm vi vạn dặm để khôi phục dung mạo, nhận ra mặt trái của cách làm này rồi mang Tháp Sơn trở về Chu Tước Tinh. Đồng tử đầu to tự mình tiến vào tinh cầu, dùng thần thức Khuy Niết sơ kỳ trấn áp toàn bộ Chu Tước Tinh, khiến núi sụp, sông cuộn, tu sĩ và phàm nhân đều bị thương tổn hoặc hôn mê. Chu Vũ Thái kích phát huyết mạch Thanh Long còn Vân Tước Tử dùng phù văn chống đỡ, nhưng cả hai vẫn bị tiên thuật và thần thức của đồng tử đầu to áp chế. Khi phát hiện pho tượng Vương Lâm tại Vân Thiên Tông, đồng tử đầu to nhận ra đó là Hứa Mộc, người từng giết hắn ở Nhất Tuyến Thiên, và suy đoán Hứa Mộc thực ra thuộc Liên Minh Tinh Vực. Đúng lúc hắn định phá tượng, giọng Vương Lâm vang lên khiến hắn kinh hoàng dùng Huyết độn bỏ chạy. Vương Lâm xuất hiện trước pho tượng, được Thiết Nham, Vân Tước Tử, Chu Vũ Thái và tu sĩ Chu Tước Tinh nhận ra, rồi dùng thân pháp dung nhập thiên địa đuổi kịp đồng tử đầu to và đánh trọng thương hắn bằng Âm Dương song ngư. Trận chiến tiếp tục khi đồng tử đầu to phản kích bằng Thiên Linh Võng và lốc xoáy tiên khí, còn Vương Lâm áp sát rồi hợp hơn mười đạo Trảm La Quyết chém thẳng vào gió lốc."},{"chuong":836,"tieuDe":"Đồng Tử Đầu To","tomTat":"Đồng tử đầu to bị Vương Lâm áp sát thì hoảng sợ, ngoài mặt cầu hòa nhưng trong lòng muốn chạy về đại bản doanh La Thiên Tinh Vực tại Liên Minh Tinh Vực để tố cáo thân phận Hứa Mộc. Vương Lâm nhìn thấu ý đồ ấy, gọi hư ảnh Cổ Thần Đỉnh và thi triển Hoán vị, đổi chỗ hai người ngay khi đồng tử đầu to sắp thoát khỏi tầng cương phong. Bị chặn đường, đồng tử đầu to tuyệt vọng nhưng không cam chịu, thi triển Tiên Ma thuật, Cân Động, để phù văn âm trầm nhập thể và dồn tinh hoa huyết nhục lên đầu. Vương Lâm không lập tức dùng đại thần thông giết hắn vì đối thủ còn hữu dụng, lại mang thân phận Tam Thập Lục Thiên Cương Tiên, nếu giết trước mặt tu sĩ La Thiên sẽ gây hậu quả chính trị. Chương đồng thời hé lộ quá khứ đồng tử đầu to từng bị gia tộc ruồng bỏ, sau này trở về với tu vi cao, bí mật hành hạ tộc nhân rồi bộc phát Khuy Niết giết Lão Tổ gia tộc. Cuối chương, Cân Động hóa thành cây côn thịt rồi vỡ ra thành vô số sợi tơ mảnh, mang tiên khí và ma khí kết thành lưới trùm tới Vương Lâm."},{"chuong":837,"tieuDe":"Tôi Tớ","tomTat":"Vương Lâm mở màn bằng Phong Tiên Ấn, tạo hơn mười vạn kim phù phong bế thân thể đồng tử đầu to. Khi đối phương gào thét phá phù văn, hắn dùng Súc Địa Thành Thốn áp sát, dung hợp đạo niệm và nguyên lực thành một chỉ Âm Dương đánh trọng thương mi tâm. Đồng tử đầu to phun máu chứa tiên khí phản kích, nhưng Định Thân thuật của Vương Lâm được tiên nguyên từ Tiên đậu tăng cường nên định trụ cả máu lẫn người. Mấy trăm tu sĩ La Thiên phát hiện bất thường lao xuống Chu Tước Tinh, song Vương Lâm tung Thiên Hổ Kỳ đại biểu thân phận Chính phẩm Lôi Tiên và ra lệnh họ lui ra ngoài thủ hộ. Sau đó, hắn ngưng tụ lôi cầu từ lôi vân trên tinh không, khiến đồng tử đầu to nhớ lại nỗi sợ lôi quang và xin tha. Vương Lâm tuyên bố cần một tên tôi tớ, rồi dùng tiên nguyên thi triển Hoàng Ấn Quyết từ mạch pháp thuật phong ấn trong ngọc giản Tiên Đế Thanh Lân để ấn vào mi tâm đồng tử đầu to. Từ khoảnh khắc ấy, hắn cảm thấy chỉ cần một ý niệm là có thể khiến đối phương tử vong, đồng thời nhận ra Phong Canh thuật này khác với Tiên vệ."},{"chuong":838,"tieuDe":"Về Nhà","tomTat":"Chương mở bằng sự phân biệt giữa Tiên vệ khôi lỗi thuật của Tiên Đế Thanh Lâm và Phong Ấn thần thông: một bên mô phỏng Cổ Thần, luyện thân thể để tạo khôi lỗi khó phản bội, còn một bên chỉ là thủ đoạn khống chế tôi tớ có thể bị phá giải theo thời gian. Vương Lâm dùng Phong Ấn thần thông khống chế đồng tử đầu to, khiến đối phương tỉnh lại rồi cung kính nhận hắn làm chủ nhân, sau đó sai hắn an bài nhóm tu sĩ La Thiên và giữ lại bên cạnh. Trở về Chu Tước Tinh, Vương Lâm chìm trong nỗi phiền muộn của người rời quê mấy trăm năm, tránh gặp Chu Vũ Thái và Vân Tước Tử bằng một đạo thần niệm nói muốn yên tĩnh. Chu Vũ Thái và Vân Tước Tử đều chấn động trước khí thế hiện tại của Vương Lâm, đồng thời hiểu tâm trạng của hắn nên cùng phong tỏa tin tức hắn đã trở về. Nhiều ngày sau, Vương Lâm cùng Tháp Sơn và đồng tử đầu to đi trên quan đạo cũ, nhìn phong cảnh vừa quen vừa lạ như một lão nhân tang thương trở lại nơi chôn nhau cắt rốn. Cuối đường, quê cũ của hắn đã biến thành Hoàng Tổ Thành phồn hoa, khiến ký ức về cha mẹ, cây hoè, tảng đá và Tứ thúc càng trở nên xa xôi. Sau khi lặng lẽ đi vào thành và đứng trước cửa hàng ngọc khí ở vị trí kỷ niệm cũ, Vương Lâm xuất hiện trong tổ trạch nơi có mộ phần và linh bài hậu nhân lập. Hắn quỳ trước linh bài cha mẹ, rơi lệ gọi cha mẹ và nói Thiết Trụ đã trở về, còn đồng tử đầu to bên cạnh cũng bị cảnh ấy gợi lên cảm xúc thân tình và ký ức thơ ấu."},{"chuong":839,"tieuDe":"Cảm Ơn Các Ngươi","tomTat":"Vương Lâm trở lại căn nhà cũ tại Hoàng Tổ thành dưới ánh trăng, nhìn lại sân viện và nhớ về cha mẹ cùng thời thơ ấu khi còn được gọi là Thiết Trụ. Hắn để Tháp Sơn và Đồng tử đầu to chờ bên ngoài, một mình ngồi trong nhà cảm thụ hơi thở gia đình, quên đi tu chân giới và trải qua một lần gột rửa thân tâm trong hồi ức. Bên ngoài, Tháp Sơn lặng lẽ đứng canh, còn Đồng tử đầu to cũng bị ký ức đau đớn thời thơ ấu kéo về nhưng cảm thấy mọi chuyện đã phai nhạt hơn. Khi ba người không ẩn hình, binh lính và mười tu sĩ thủ hộ kéo tới vây quanh, cho rằng họ xâm nhập nhà tổ hoàng tộc. Vương Lâm hỏi về phần mộ cha mẹ, dùng uy áp khiến lão già Hóa Thần phải trả lời rằng nơi này là nhà tổ hoàng tộc và từng là chỗ ở của lão tổ Chu Tước tinh. Sau đó một lão già Anh Biến của Huyền Đạo Tông xuất hiện, kể rằng các môn phái Chu Tước Tinh nhiều đời luân phiên thủ hộ nơi này, còn Vương Lâm nhận ra lão là một trong mười người từng nhận Linh Loại ở Triệu quốc năm xưa. Cảm động trước sự thủ hộ ấy, Vương Lâm nói lời cảm ơn và ban tinh quang/nhiệt lưu cho toàn bộ tu sĩ cùng binh lính. Trước khi rời đi, hắn nhắc lại chuyện Linh Loại khiến lão già Anh Biến nhận ra thân phận Vương gia lão tổ của hắn, làm những người vừa vây hắn chấn động."},{"chuong":840,"tieuDe":"Đại Vương Triều","tomTat":"Vương Lâm trở về Chu Tước tinh và suy ra sự cung kính của tu sĩ nơi đây bắt nguồn từ Chu Vũ Thái, người vừa báo ân năm xưa vừa mượn uy danh hắn để củng cố địa vị Chu Tước Tử. Chu Vũ Thái đã nâng đỡ hậu nhân Vương gia và những môn phái Vương Lâm lưu lại ở Triệu quốc, khiến Triệu quốc mạnh lên và danh hiệu người bảo hộ Chu Tước tinh của Vương Lâm lan rộng. Vương Lâm cùng Tháp Sơn và Đồng tử đầu to tới đô thành Đại Vương triều, nơi huyết mạch Vương gia tập trung nhất, nhưng hắn không tìm thấy Vương Trác. Bề ngoài đô thành cực kỳ phồn thịnh và xa hoa, song Vương Lâm nhìn ra phúc trạch bị làm nhơ nhuốc, oán khí bao phủ nhiều nơi trên Chu Tước tinh, đặc biệt Tây Bắc đầy tử thi và phía trên đô thành oán khí đã hóa thành ma hỏa. Trên phố, hoàng tử thứ mười sáu phóng ngựa với tùy tùng, võ lâm nhân sĩ và hai tu sĩ Trúc Cơ mở đường, phía sau kéo lê một nam tử bị xích khiến dân chúng chỉ dám thì thầm. Qua lời dân, Vương Lâm biết triều đình từng vì lời quốc sư về hung tinh Tây Bắc mà giết hơn mười vạn bình dân, khiến sắc mặt hắn âm trầm. Sau khi xác nhận hoàng tử mang huyết mạch Vương gia, Vương Lâm sai Tháp Sơn bắt người này tới trước mặt mình. Hoàng tử bị ném xuống đất vẫn lấy thân phận Vương gia đe dọa, trên mặt hiện hắc khí hóa rắn, trong khi thuộc hạ và hai tu sĩ Trúc Cơ kéo tới cứu giá."},{"chuong":841,"tieuDe":"Nổi Giận","tomTat":"Trong đô thành Đại Vương triều, Tháp Sơn ném hoàng tử Vương gia xuống đất và dễ dàng đánh tan kiếm quang của hai đệ tử Vân Thiên Tông, khiến đám võ lâm xông tới cũng bị thương mà không giết ai. Gã hoàng tử lấy thân phận Vương gia uy hiếp, nhưng bị Vương Lâm dùng thân phàm nhân tát bay, từ đó lộ ra hắc xà oán linh trong cơ thể và cho thấy hồn phách hắn đã bị oán khí thôn phệ. Vương Lâm nổi giận vì có kẻ lấy người Vương gia chăn nuôi oán linh, nghiền nát hắc xà thành ký hiệu màu đen rồi để ký hiệu tự dẫn đường về phía hoàng thành. Trên đường, tu sĩ các phái Chu Tước tinh kéo tới công kích bằng pháp bảo nhưng bị Vương Lâm vung tay áo đẩy bay mấy vạn dặm, còn binh lính cản đường chỉ bị hắn đưa ra xa. Trong hoàng cung, bệ hạ Đại Vương triều phẫn nộ, lão đạo đầu bạc nhận định kẻ xâm nhập có tu vi rất cao, và quốc sư sai ba đệ tử bao phủ hắc khí ra xử lý. Vương Lâm nhìn ra ba đệ tử này chỉ có tu vi Anh Biến nhưng nhờ oán linh mà uy lực gần Vấn Đỉnh sơ kỳ, trong cơ thể không có huyết mạch Vương gia mà chỉ có oán khí, nên lần lượt dùng song chỉ, chưởng lực và lôi trong ánh mắt diệt sạch. Sau đó hắn tiến thẳng vào hoàng cung, khiến các tu sĩ trong điện dù đầy sát khí vẫn e ngại không dám ra tay."},{"chuong":842,"tieuDe":"Thi Âm Tông","tomTat":"Vương Lâm áp xuống hoàng cung Vương gia và phát hiện nhiều hậu nhân Vương gia bị hắc khí ở mi tâm khống chế, trong khi kẻ mặc long bào ngồi giữa đại điện lại không giống tộc nhân Vương gia. Nam tử mặc long bào ra lệnh cho tám lão cung phụng giết Vương Lâm, nhưng Vương Lâm dùng khí đen trắng phá hắc khí, khiến họ tỉnh lại và nhận ra lão tổ. Hắc khí hợp thành mãng xà oán linh lao tới nhưng bị Tháp Sơn đánh nổ, còn nam tử không mặc áo ẩn dưới đất bị Vương Lâm ép hiện thân và vạch tội dùng hậu nhân Vương gia chăn nuôi oán linh. Vương Lâm giả truy kích nam tử này để đánh lạc hướng nữ tử Phượng Loan tinh, rồi dịch chuyển vào đại điện, dùng lôi ý liên tục phá phượng linh hộ thân của nàng. Nữ tử tự xưng là một trong thất phượng của Phượng Loan tinh nhưng vẫn bị đánh nổ thân thể, nguyên thần bị Vương Lâm sưu thần rồi diệt sát. Cái chết của nàng khiến hơn nửa tộc nhân Vương gia hiện diện phun máu tử vong, số còn lại thoát hắc khí và quỳ xuống nhận lỗi. Vương Lâm vạch ra nam tử mặc long bào không phải người Vương gia, cảm tạ các tu sĩ từng chiếu cố gia tộc, rồi từ ký ức nữ tử xác định Phượng Loan tinh và Thi Âm Tông là mục tiêu báo thù tiếp theo."},{"chuong":843,"tieuDe":"Phong Tảo Tàn Diệp","tomTat":"Vương Lâm đọc ký ức nữ tử Phượng Loan tinh và xác nhận nàng vừa là một trong thất phượng vừa là người Thi Âm Tông. Từ đó hắn biết Thi Âm Tông cài người gần như khắp các thành trì Đại Vương triều để thu gom oán khí, chăn nuôi oán khí và oán linh, nên quyết định tiêu diệt toàn bộ căn cơ của tông này trên Chu Tước tinh. Đồng tử đầu to dẫn tù binh trở về, nhận lệnh giết người đó rồi lấy nguyên thần giao cho Vương Lâm. Vương Lâm tới Kim thành rồi lần lượt quét qua Mộc, Thủy, Hỏa, Thổ, dùng thần thức Khuy Niết và tiếng hừ lạnh diệt các vị trí Thi Âm Tông ẩn nấp, sau đó bao phủ toàn bộ Đại Vương triều khiến đệ tử Thi Âm Tông bỏ chạy đều bị đánh nát. Khi tra tiếp ký ức, hắn phát hiện phần mật lệnh từ tổng bộ Thi Âm Tông tại tinh vực Liên Minh đã bị xóa bởi kẻ có thần thông cao hơn, đồng thời xác định tổng bộ mới trên Chu Tước tinh đặt tại Thi Âm Tông Triệu quốc. Vương Lâm dẫn Tháp Sơn và Đồng tử đầu to tới bình nguyên đầm lầy, Tháp Sơn một quyền phá tan cấm chế và làm lộ mật đạo. Bước vào nơi này, Vương Lâm nhớ lại những lần từng tới Thi Âm Tông năm xưa, dùng thần thức phong tỏa toàn bộ khu vực và nổi giận khi biết hậu nhân Vương gia bị dùng để nuôi dưỡng oán linh."},{"chuong":844,"tieuDe":"Lôi Cát","tomTat":"Vương Lâm tiến vào tổng bộ Thi Âm Tông trên Chu Tước Tinh, dùng thần thức Khuy Niết phong tỏa đường lui và khiến tu sĩ bỏ chạy lần lượt nổ tung. Một thi khôi Vấn Đỉnh đánh lén bằng kiếm quang nhưng bị hắn phá tan rồi đá một cước hóa thành tro, để lộ thoáng chốc tỉnh táo của kẻ từng bị luyện thành thi khôi. Hắn phá tám truyền tống trận mà đệ tử Thi Âm Tông dùng để đào thoát, khiến không ai chạy khỏi tổng bộ. Đi sâu theo ký ức tới nơi từng tu luyện Hoàng Tuyền bí quyết, Vương Lâm phát hiện quan tài khổng lồ giam người Cự Ma Tộc tên Lôi Cát. Sau khi phá cấm chế quan tài, hắn biết Thi Âm Tông bắt thân thể Cự Ma Tộc để đoạt xá trong trạng thái vẫn giữ Thiên Phú Thần Thông, còn cây xanh tím ký sinh trên Lôi Cát dùng để hút sức sống và chuẩn bị thân thể cho phó điện chủ. Vương Lâm kéo cây xanh tím ra, dùng Phong Tiên Ấn, lôi lực và Thú Cốt đánh nát nó, khiến nguyên thần phó điện chủ Oán Điện Lưu Thanh Vân hiện thân. Lưu Thanh Vân tự xưng thân phận và muốn giảng hòa khi thấy Vương Lâm có Đồng tử đầu to cùng Tháp Sơn bên cạnh, nhưng Vương Lâm nhận ra nguyên thần này là Khuy Niết do Tịnh Niết suy yếu biến thành. Cuối chương, Vương Lâm tiếp tục truy kích vì muốn dùng nguyên thần Lưu Thanh Vân giúp thân thể Tháp Sơn đạt tới Khuy Niết."},{"chuong":845,"tieuDe":"Phó Điện Chủ Của Oán Điện","tomTat":"Vương Lâm cùng đồng tử đầu to và Tháp Sơn bao vây Lưu Thanh Vân — phó điện chủ Oán Điện thuộc Thi Âm Tông, kẻ chỉ còn nguyên thần đang tìm cách đoạt xá tại Chu Tước Tinh. Lưu Thanh Vân giả vờ cầu hòa dâng nguyên thần Khuy Niết tu sĩ, rồi bất ngờ dùng Viêm Linh Hỏa Thi hạng 12 bảng kỳ thi dị thể cho tự bạo ám toán, nhưng Vương Lâm đã sớm triển khai Cổ Thần Cự Đỉnh chắn nổ hoàn toàn. Lưu Thanh Vân tuyệt vọng chọn tự bạo nguyên thần, bị Vương Lâm dùng Tiên thuật Định Thân tăng cường bởi tiên nguyên khống chế, bắt sống đưa ra xa phong ấn. Đồng tử đầu to chứng kiến toàn bộ, hoàn toàn tâm phục Vương Lâm. Sau trận chiến, Vương Lâm chính thức thu phục Lôi Cát làm vật cưỡi, lấy máu chứa khí tức Cổ Thần để tế luyện thần thông. Chuyển cảnh đến Chu Tước Thánh Tinh phía đông Liên Minh Tinh Vực, ba lão già trên pho tượng Chu Tước nhận tin La Thiên đã chiếm sáu phần địa giới phía tây, 108 vị Tiên mới phong do Phó Phẩm Lôi Tiên Hứa Đình dẫn đầu, còn Chính Phẩm Lôi Tiên Hứa Mộc vẫn bặt vô âm tín."},{"chuong":846,"tieuDe":"Giải Quyết Nhân Quả","tomTat":"Vương Lâm trở lại Chu Tước Tinh, vào từ đường hoàng thành Đại Vương Triều viếng bài vị hậu nhân Vương gia, nhìn thấy bài vị Vương Trác và Vương Ngọc đều đã qua đời, lòng chỉ còn tang thương. Hắn dặn dò hậu nhân tự lo liệu cơ nghiệp rồi rời đi, đến Vân Thiên Tông gặp Thiết Nham đang tu vi thoái hóa vì trăm năm trước hy sinh tuổi thọ giúp Chu Như đạt Anh Biến, liền dùng tiên ngọc khôi phục tu vi cho Thiết Nham và tặng chín thanh trường kiếm. Trên đường đi, Vương Lâm bắt gặp Hoàng Long chưởng môn cưỡi rết nghìn chân, cảm thấy quái dị nhưng không hành động. Sau khi ngộ sâu ý cảnh nhân quả, hắn tản thần thức bao phủ toàn Chu Tước Tinh, lần lượt tìm đến hậu nhân Trương Hổ tặng tài nguyên, gặp lại Dương Hùng và Chu Tử Hồng tặng tiên ngọc đan dược, gặp Sất Hổ tặng tiên ngọc cùng bình máu Lôi Cát là máu tổ tiên Cự Ma Tộc. Tại Tu Ma Hải, hắn mở Tị Thiên Quan cho Lý Kỳ Khánh nhìn thi thể em gái Lý Mộ Uyển lần cuối, rồi vỗ tay giết chết Xích Huyết Lão Tổ là kẻ năm xưa truy sát Lý Mộ Uyển, nhưng Lý Kỳ Khánh lạnh lùng rời đi không muốn dính dáng. Cuối cùng Vương Lâm bay đến tinh không rút bảy đạo tinh hồn từ các tinh cầu hoang bơm vào lòng đất Chu Tước Tinh, linh mạch toàn diện hồi phục, tiếng phượng kêu vang khắp nơi, lấy đó giải quyết nhân quả với Chu Vũ Thái."},{"chuong":847,"tieuDe":"Tìm Bí Mật Của Tiên Di Tộc","tomTat":"Vương Lâm đưa tinh hồn cuối cùng vào lòng đất Chu Tước Tinh, giúp linh lực toàn tinh cầu hồi phục đạt đỉnh và nhiều tu sĩ bậc thấp nhân đó đột phá; Chu Vũ Thái đứng trên Chu Tước Sơn thầm cảm tạ, còn một lão đạo có tướng mạo giống hệt Hoàng Long năm xưa thì suy ngẫm về lựa chọn tương lai của hắn trong trận chiến với La Thiên Tinh Vực. Nhân quả với Chu Tước Tinh đã trọn, Vương Lâm quyết đến hố sâu vùng đất Tiên Di Tộc trước khi rời đi, mang theo nỗi lo tiên nguyên do Thanh Thủy tặng sắp cạn và mối nghi ngờ về lá bùa phong ấn của Diêu gia còn sót trên thân. Tại đó hắn gặp lại Vân Tước Tử, người tiết lộ cấu trúc mười chín tầng của Tiên Di Tộc, rằng tầng mười tám chứa bổn nguyên lực và tầng mười chín chỉ đệ nhất tổ tiên Chiến Hồn từng đặt chân. Nhờ tu vi Khuy Niết, Vương Lâm dễ dàng xuống đến tầng mười sáu, rồi sai Đồng tử đầu to thi triển tiên thuật toàn lực kết hợp lôi đình, Thú Cốt và một quyền của Tháp Sơn để phá vỡ phong ấn, mở Truyền Tống Trận dẫn xuống tầng mười bảy. Ở nơi khác, Sát Vực Giới thuộc Tu Chân Liên Minh phát lệnh cho Hồn Sát Nhị Thị truy sát và lấy đầu Chính Phẩm Lôi Tiên Hứa Mộc của La Thiên Tinh Vực. Tầng mười bảy tối đen ngập tử khí với thi hài tiên nhân treo trên xích sắt khiến Đồng tử đầu to bị áp chế đến phun máu và được Vương Lâm kịp cứu, trong khi Vân Tước Tử lại cảm nhận khí tức Tiên Di Tộc khiến dấu ấn đen trên thân co rút và bắt đầu thoái hóa."},{"chuong":848,"tieuDe":"Hình Phạt Tiên Nhân","tomTat":"Vương Lâm cùng Vân Tước Tử, Đồng tử đầu to và Tháp Sơn tiến vào tầng thứ mười bảy tối đen, nơi có sức mạnh vô hình đè ép khiến tiên đậu vận chuyển chậm chạp. Họ phát hiện hơn một trăm thi hài tiên nhân bị xích sắt xuyên thấu khóa treo, nguyên thần bị giam cầm chịu tử khí ăn mòn đến chết. Một thây khô tỉnh dậy tấn công Đồng tử đầu to, khiến tiên nguyên của hắn vừa vận chuyển liền tràn ra tiêu tan gần hết. Vương Lâm dùng nguyên lực đẩy lui thây khô, Tháp Sơn tung quyền với ký hiệu khiến thi hài lộ vẻ cung kính lui lại. Vân Tước Tử nhận ra đây là Hình Đường do tổ tiên Tiên Di Tộc lập nên để hành hình tiên nhân, thể hiện hận ý nồng đậm. Toàn bộ thây khô tỉnh dậy lao đến, Vương Lâm thi triển Hô Phong triệu hắc phong cùng hai hắc long quét phá và nhận ra phong ấn ký hiệu giống Diêu gia. Khi điểm vỡ thi hài bằng song chỉ chứa lôi uy, hắn phát hiện tiên nguyên khí dung hợp vào tiên đậu bổ sung tiên nguyên — mấu chốt để nghiên cứu Hoán Vũ và Tát Đậu Thành Binh, rồi tự mình đơn độc chiến đấu hấp thu tiên nguyên."},{"chuong":849,"tieuDe":"Hoàng Long Tiến Đến","tomTat":"Vương Lâm đối diện đám thây khô tiên nhân ở tầng thứ mười bảy hố sâu Tiên Di Tộc, nhận thấy chúng ngu dại dễ giết nhưng hắn có ý tưởng lớn hơn là tu luyện Tát Đậu Thành Binh. Hắn hồi tưởng hai thuật được Thanh Thủy truyền thừa là Hoán Vũ và Tát Đậu Thành Binh, cùng nguồn gốc Huyền Không Binh Giới của Bạch Phàm và Họa Địa Vi Lao của Thanh Thủy, rồi quyết định dùng đạo Hoàng Tuyền Sinh Tử Luân Hồi của mình tạo luân hồi riêng. Vương Lâm thi triển Luân Hồi Hoàng Tuyền và phóng nguyên thần Thái Cổ Lôi Long triệu tập lôi đình từ mấy vạn dặm quanh Chu Tước Tinh, khiến toàn tinh cầu chấn động như ngày tận thế. Lôi đình phá hủy tầng mười bảy, tiêu diệt toàn bộ thây khô, khiến tiên đậu trong cơ thể hắn lớn gấp mấy lần và rút hàng trăm hồn phách tiên nhân dung nhập Hoàng Tuyền. Tầng mười bảy sụp đổ, mở ra thông đạo xuống tầng mười tám. Vân Tước Tử kinh hãi nhận ra mình xem nhẹ Vương Lâm, đồng tử đầu to run rẩy nhớ lại lần bị giết, Lôi Cát cảm thấy vinh dự khi làm vật cưỡi. Tu sĩ sáu ngón dẫn đội La Thiên nhầm lôi đình là của Hứa Mộc nên đổi hướng tránh, còn lão đạo giống Hoàng Long trên Chu Tước Tinh lập tức biến mất và cấm không cho đi vào tầng mười tám."},{"chuong":850,"tieuDe":"Danh Sách Chu Tước","tomTat":"Tại tầng thứ mười bảy Tiên Di Tộc trên Chu Tước Tinh, khi Tháp Sơn định đi vào tầng mười tám thì một thanh âm uy nghiêm vang lên cấm tiến, luồng đại lực đẩy lui cả nhóm khiến Tháp Sơn phun máu, Lôi Cát trống rỗng đầu óc, Vân Tước Tử bị bắn tung, riêng Vương Lâm vận nguyên lực đứng vững. Một lão đạo tiên phong đạo cốt rất giống Hoàng Long bước ra, phong kín thông đạo tầng mười tám, vung tay áo đưa bốn người ra ngoài chỉ giữ Vương Lâm lại. Lão đạo gọi thẳng Vương Lâm là Chính Phẩm Lôi Tiên Hứa Mộc của La Thiên Tinh Vực, Vương Lâm phủ nhận nhưng khẳng định Hằng Nhạc Phái là môn phái đầu tiên và Chu Tước Tinh là quê hương. Lão đạo xác nhận hắn là đệ tử một đời của Chu Tước trong Tứ Thánh Tông, đồng thời tuyên bố trận chiến La Thiên là của Tu Chân Liên Minh không liên quan Tứ Thánh Tông. Lão đạo cảnh cáo nếu người Tiên Di Tộc lấy được bổn nguyên tầng mười tám sẽ gây kiếp nạn cho cả Liên Minh Tinh Vực, rồi đưa Vương Lâm vào phòng bí mật cảm ngộ bổn nguyên lực. Khi Vương Lâm tiếp xúc ngọn lửa, hai mắt hiện mặt trời mặt trăng, nhân quả đạo niệm và âm dương song ngư trừ tạp niệm, hắn nhìn thấy ảo cảnh đại chiến cổ xưa giữa tiên nhân cưỡi mây dùng ký hiệu phong ấn thiên địa và Tiên Di Tộc đứng trên lá bùa vàng. Lão đạo đánh giá cao và thì thào có thể cho Vương Lâm vào danh sách Chu Tước sau khi xem xét."},{"chuong":851,"tieuDe":"Bỏ Đi","tomTat":"Vương Lâm hoàn thành cảm ngộ bản nguyên Phù tộc, chứng kiến cảnh tượng Kim Diệp Phù Sĩ bị bóng người trong hắc quang kéo ngọn lửa bản nguyên và một đốm lửa in vào mi tâm khiến hắn tỉnh lại. Lão đạo sĩ giải thích quả cầu lửa là khảo nghiệm bắt buộc của đệ tử nội môn Chu Tước, hút lực lượng rồi tiễn Vương Lâm đi, sau đó lẩm bẩm quyết mở tầng cuối cùng liên quan Phù tộc. Vương Lâm phân tích lão đạo sĩ là Chu Tước của Tứ Thánh Tông tu vi ngang hoặc hơn Viêm Lôi Tử rồi quyết định rời Chu Tước Tinh, triệu tập đám Tháp Sơn. Lôi Cát tình nguyện hóa thân khổng lồ làm vật cưỡi, cả đoàn phóng đi trong tinh không, còn Chu Vũ Thái, Lý Kỳ Khánh và Thiết Nham cảm nhận việc Vương Lâm rời đi. Trên đường, Vu Phi thuộc Sát Thị của Sát Vực Giới Tu Chân Liên Minh xuất hiện tuyên bố đến lấy đầu Hứa Mộc, phóng bảy huyết kiếm hóa phân thân giao chiến với Đồng Tử Đầu To và Tháp Sơn. Vương Lâm triệu lôi quang mấy vạn dặm rồi phóng nguyên thần Thái Cổ Lôi Long nén sấm sét sánh ngang Thiên Kiếp, phá vỡ ba mươi lăm phi kiếm và năm phân thân của Vu Phi. Vu Phi vẫn bình tĩnh, khen Vương Lâm xứng chính phẩm Lôi Tiên rồi lấy ra một vật từ túi trữ vật."},{"chuong":852,"tieuDe":"Cho Ngươi Một Kỳ Tích","tomTat":"Vu Phi lấy ra Lôi Thụ Tàn Chi, bảo vật của Sát Vực Giới, ném ra khiến toàn bộ sấm sét Vương Lâm khống chế bị hút vào cành cây, năm thanh phi kiếm rút lui, và tự tin tuyên bố Khuy Niết sơ kỳ của Vương Lâm chẳng đáng gì. Vương Lâm bình thản nói sẽ cho hắn thấy một kỳ tích rồi biến mất, khiến Vu Phi bùng nguyên lực mà không tìm ra tung tích. Cảnh chuyển về Nguyệt Tông trên một tu chân tinh xa xôi trong Liên Minh Tinh Vực, nơi bản tôn Vương Lâm ẩn thân làm tạp vụ phòng luyện đan; cô gái Tống Oánh thường đến hấp thu hàn khí (thật ra là linh khí rời rạc khi Cổ Thần thôn phệ linh khí) và dần sinh tình cảm đơn phương, may túi linh thảo định tặng nhưng chưa kịp nói thì bản tôn bay thẳng lên trời. Bản tôn ra ngoài tinh cầu, phân thân và bản tôn dung hợp sau mấy trăm năm tách biệt, Cổ Thần và Luyện Khí Sĩ ngưng tụ khiến mắt trái hàm nhật mắt phải ẩn nguyệt, tóc tím đậm, khí tức khổng lồ bùng nổ chấn động cả tu chân quốc cấp sáu. Vương Lâm lại tuyên bố cho Vu Phi thấy kỳ tích rồi thi triển thần thông Súc Địa Thành Thốn biến mất. Vu Phi kinh ngạc nhận ra loại thần thông cực hiếm này không hề được đề cập trong tư liệu về Hứa Mộc mà hắn đoạt được."},{"chuong":853,"tieuDe":"Hợp Thể Cực Mạnh","tomTat":"Vu Phi tản nguyên lực tìm kiếm nhưng xác nhận Hứa Mộc (phân thân Vương Lâm) đã chạy thoát nên phẫn nộ đổ sát khí lên Đồng tử đầu to, điều khiển năm phi kiếm đỏ thẫm cùng phân thân dồn ép hắn. Khi Đầu To tuyệt vọng định tự bạo nguyên thần liều mạng, Vương Lâm bản tôn đã hợp thể với Hứa Mộc từ hư vô bước ra, ném Đầu To khỏi hiểm cảnh và tuyên bố kỳ tích của mình. Vương Lâm tung một quyền đánh vỡ tinh không cùng sáu thanh phi kiếm, diệt liên tiếp hai phân thân Khuy Niết sơ kỳ của Vu Phi. Nhục thân sau hợp thể cứng đến mức bốn phi kiếm còn lại đâm vào chỉ phát ra tiếng va chạm kim loại, bị đánh văng mà không gây thương tổn. Sau đó Vương Lâm gầm lên tiếng rống Cổ Thần mang khí tức tang thương khai thiên lập địa, hóa cơn lốc khổng lồ chấn nhiếp toàn trường. Vu Phi (Khuy Niết trung kỳ) bị chấn động tâm thần, nguyên lực mất kiểm soát, lần đầu tiên sinh ra cảm giác sợ hãi từ linh hồn, còn Đầu To cảm thấy mình chỉ như con kiến. Lôi Cái run rẩy quỳ gối phục tùng như kẻ hầu gặp chủ nhân, vừa hoảng sợ vừa cảm thấy thân thiết, gợi ý mối liên hệ huyết mạch với Cổ Thần."},{"chuong":854,"tieuDe":"Sát Vực Giới","tomTat":"Vương Lâm liên tục tiêu diệt cả bảy phân thân của Vu Phi chỉ trong vài lần hít thở, dùng tiếng gầm Cổ Thần và chỉ kiếm kết hợp sấm sét cùng đôi cá âm dương. Vu Phi hoảng sợ trước sức mạnh thân thể khó tin của Vương Lâm nên dùng Huyết Độn phun máu bỏ chạy, nhưng bị chặn lại. Vu Phi tung bản mệnh pháp bảo hoá đại kiếm hồng sắc, huyễn hoá Yêu Mãng trăm trượng và ném hết pháp bảo trong túi trữ vật, song Vương Lâm hợp thể phân thân với bản tôn hoá người khổng lồ vài chục trượng đập vỡ tất cả. Vương Lâm triệu Hoàng Tuyền thu linh hồn con mãng xà rồi phá huỷ toàn bộ pháp bảo còn lại. Bị bức đến đường cùng, Vu Phi vặn đứt cánh tay trái tạo cổng vòng xoáy chạy về Sát Vực Giới, cảnh cáo rằng Trung Hồn Sát Nhị còn một người nữa có thần thông Hồn Thị. Vương Lâm triệu Cổ Thần Đỉnh, dùng Di hình kéo vòng xoáy lại và một chỉ xuyên vào truy kích. Vòng xoáy hiện ra tại Sát Vực Giới, thu hút sự chú ý của toàn bộ tu sĩ nơi đây."},{"chuong":855,"tieuDe":"Hỏi Tội","tomTat":"Vu Phi vừa thoát vòng xoáy trở về Sát Vực Giới thì bị Vương Lâm xuyên hai ngón tay qua vòng xoáy đặt lên hậu tâm, cơ thể nổ tan hình thần câu diệt, nguyên thần cũng không thoát. Túi trữ vật Vu Phi vỡ, Vương Lâm mạo hiểm chụp được nửa Thiên Địa Lôi Thụ Tàn Chi ngay trước mặt lão già tóc đỏ, còn lão chỉ chộp được nửa kia rồi ra lệnh truy sát Hứa Mộc. Vương Lâm trở về lưng Lôi Cát, lệnh tìm tinh cầu hoang dã bế quan; trên đường các tu sĩ La Thiên hâm mộ Lôi Tiên, còn Hứa Đình ngầm châm dầu cho tin đồn Hứa Mộc phản bội. Đến tinh cầu hoang dã, Vương Lâm bố trí Phá Diệt Tâm Cấm và bắt đầu cảm ngộ tiên thuật Hoán Vũ từ truyền thừa Thanh Thủy, triệu mây đen mưa lớn. Viêm Lôi Tử cùng trưởng lão hình pháp Lôi Tiên Điện đến hỏi tội việc thất tung, Vương Lâm bình tĩnh trình nửa Lôi Thụ Tàn Chi làm chứng nên được Viêm Lôi Tử tán thưởng và hẹn một tháng sau theo viện quân thẳng tiến Liên Minh bắc bộ. Sau khi rời đi, Viêm Lôi Tử nhận ra mi tâm Vương Lâm có bốn cỗ lực lượng, cỗ yếu nhất là ấn ký Chu Tước, và vì nhớ ân xưa nên quyết định bỏ qua không truy cứu."},{"chuong":856,"tieuDe":"Hoán Vũ","tomTat":"Trên đỉnh núi giữa trời mưa, đồng tử đầu to hồi tưởng tuổi thơ bi thương khi bị gia tộc đuổi đi trong đêm mưa, nay cảm thấy ấm áp bên Vương Lâm — người đã cứu hắn khỏi tự bạo. Lôi Cát cũng cảm ngộ thần thông thiên phú và nhớ lại quá khứ mang Cự Ma Tộc rời Cự Ma Tinh tới Chu Tước Tinh, được Dạ Vô Ưu khoản đãi cấp đất, từng cầm chiến phủ giết vào Tiên Di Tộc báo ân. Lôi Cát tự nhận tâm cơ sâu, kiên định đi theo Vương Lâm vì tin có ngày trở về Cự Ma Tinh báo thù, nhất là sau khi tiếng rống Cổ Thần khiến ý chí truyền thừa tổ tiên trỗi dậy. Vương Lâm thiền định trong mưa, ban đầu thất bại khi dung nhập thần thức vào nước mưa. Nhờ nhớ lại cảm ngộ về sinh tử của mưa, hắn chuyển hướng đưa thần thức lên tầng mây, phát hiện thiên địa nguyên khí va chạm tạo mưa. Cuối cùng hắn tự tay ngưng tụ hơi nước thành mây và tạo mưa nhân tạo, trong mơ hồ chạm tới bên cạnh một tia quy tắc — bước tiến then chốt trong Khuy Niết kỳ."},{"chuong":857,"tieuDe":"Đồ La Kế Hoạch","tomTat":"Vương Lâm đứng trên đỉnh núi, nước mưa cách thân ba tấc tự hóa hơi nước tạo mây mù bên ngoài thân thể — biểu hiện chạm tới quy tắc chứ không phải thần thông nguyên lực thông thường. Hắn cảm thán Tiên Đế Bạch Phàm là thần nhân, vì Hoán Vũ thuật do Thanh Thủy truyền thừa khi minh ngộ sẽ tự nhiên chạm tới quy tắc. Hồi tưởng cảnh Tư Đồ Nam năm xưa từ hạt châu Thiên Nghịch ra hét tan mưa, hắn ngộ ra Tư Đồ Nam đã nắm giữ quy tắc và hạt châu Thiên Nghịch chứa quy tắc bộ phận thủy. Hắn vung tay hét Tan khiến tầng mây sụp đổ, vạn dặm trời quang, rồi triệu hắc long tạo mây mưa tùy tâm — Hoán Vũ thuật minh ngộ hoàn toàn, khiến Đồng tử đầu to và Lôi Cát càng kính sợ tâm phục, còn Tháp Sơn nhắm mắt đả tọa. Ở biên giới tây-bắc Liên Minh Tinh Vực, tu sĩ sáu ngón dẫn đội tiên phong La Thiên bị vô số thân ảnh hư ảo chiếm xác; kẻ chiếm xác tuyên bố kế hoạch Đồ La của Huyền Điện nhằm tiêu diệt toàn bộ tàn dư và cho biết tứ tôn đã xuất động Hắc Sát Ma Tôn cùng Đạo Nguyên Thiên Tôn. Cuối cùng Vương Lâm chuyển sang cảm ngộ Tát Đậu Thành Binh — đại thần thông dương danh Tiên Giới năm đó."},{"chuong":858,"tieuDe":"Mười Tám Tầng Địa Ngục","tomTat":"Vương Lâm bắt đầu thi triển Tát Đậu Thành Binh theo truyền thừa của Thanh Thủy. Hắn kích hoạt tiên nguyên chi tinh trong cơ thể, tạo lốc xoáy tiên khí lớn mấy trượng, rồi nguyên thần Thái Cổ Lôi Long xông vào lốc xoáy sống lại toàn bộ ký ức giết chóc cả đời — từ thiếu niên bị Dẫn Lực Thuật giết ở Hằng Nhạc Phái cho tới nội đấu tranh đoạt phong hào trong Lôi Tiên Điện — hồn phách từng người bị giết lần lượt dung nhập nguyên thần. Đồng tử đầu to quan sát bên cạnh, thầm kinh ngạc vì Vương Lâm sở hữu tiên nguyên đồng thời với ý cảnh mà không cần qua Thăng Tiên Trì. Sau khi tỉnh, tiên nguyên chi tinh đã hao tổn gần sáu phần. Bước thứ hai, Vương Lâm triệu Hoàng Tuyền uốn thành vòng tròn oán khí, phun Phong Tiên Ấn dung hợp cùng hơn mười vạn phù văn kim sắc, tạo ra Luân Hồi Giới Mười Tám Tầng Địa Ngục — thế giới riêng của mình cho Tát Đậu Thành Binh. Phong Tiên Ấn biến đen sẫm chia mười tám tầng, uy áp bao phủ cả tinh cầu hoang dã. Tầng 15 trở xuống trống không, tầng thứ mười bốn chỉ có duy nhất hồn phách Huyết Tổ bị sương máu bao phủ, oán hận ngập trời."},{"chuong":859,"tieuDe":"Cái Giá Lớn Của Liên Minh","tomTat":"Trên tinh cầu riêng, Vương Lâm hoàn thiện Phong Tiên Ấn mười tám tầng địa ngục: tầng mười ba chứa hơn trăm hồn phách tiên nhân Tiên Di Tộc, tộc nhân Diêu gia và tu sĩ Dương Thực trở lên bị hắn giết, nhờ tiên thuật Tát Đậu Thành Binh rút hồn phách từ luân hồi. Hắn rung Tôn Hồn Phiên đổ toàn bộ hồn phách vào bảo ấn khiến oán khí bao phủ tinh cầu, nhưng giữ lại phiên vì là vật Độn Thiên tặng, đồng thời giữ hai nguyên thần Khuy Niết sơ kỳ để khôi phục tu vi. Vương Lâm thu nhỏ mười tám tầng địa ngục nuốt vào bụng rồi dẫn đám Lôi Cát rời đi. Đại quân La Thiên đã chiếm toàn bộ liên minh tây bộ, nhận ra nơi này quỷ dị vì không có tu chân quốc cấp bảy nào, song theo hiệu lệnh Lôi Tiên Điện vẫn phát động tấn công bắc bộ do Viêm Lôi Tử chỉ huy. Viêm Lôi Tử cảm nhận nguy cơ sâu và bấm toán bị huyết quang che phủ, nhưng vẫn quyết tiến vì tin La Thiên đã chuẩn bị hậu thủ. Khi đại quân tiến vào bắc bộ, Tu Chân Liên Minh kích hoạt tự hủy toàn bộ tu chân tinh tây bộ, tạo gió lốc hủy diệt quét mấy vạn dặm khiến vô số tu sĩ La Thiên hình thần câu diệt — cái giá khổng lồ Liên Minh chủ động trả để chôn vùi kẻ địch."},{"chuong":860,"tieuDe":"La Thiên Phản Kích","tomTat":"Tu Chân Liên Minh thực hiện kế hoạch Đồ La, hy sinh toàn bộ tu chân tinh liên minh tây bộ tạo gió lốc hủy diệt giết vô số tu sĩ La Thiên và hình thành hàng rào khe nứt tinh không ngăn cách thông đạo. Viêm Lôi Tử giữ bình tĩnh phản kích, triệu hoán Thập Bát La Phù — mười tám huyết cầu mười trượng — đè ép tâm thần tu sĩ liên minh khiến họ mất sức chiến đấu. Hắc Sát Ma Tôn xuất trận định hủy huyết cầu nhưng bị Huyết Thần Tử ngăn cản. Trên vạn tu sĩ La Thiên đẩy Tham Thiên Cự Mộc — cây gỗ viễn cổ vạn trượng — phá tan hàng rào khe nứt xông vào liên minh tây bộ, lão tổ Hướng gia cùng nam tử họ Công Tôn truy kích Đạo Nguyên Thiên Tôn. Vọng Nguyệt xuất hiện từ thông đạo La Thiên, phát cuồng tấn công tu sĩ liên minh, tiếng rống bức lộ thân ảnh Đạo Nguyên Thiên Tôn — một trong tứ tôn — khiến Liên Minh Tinh Vực rơi vào thế yếu. Vương Lâm cùng Lôi Cát, Đồng tử đầu to, Tháp Sơn di chuyển qua chiến trường, thể hiện khí tức Tịnh Niết mờ nhạt nhờ minh ngộ Thiên Nghịch — khe nứt tinh không tự vòng tránh hắn. Cuối chương Vương Lâm phát hiện ở xa một nữ tử mặc y phục tím đang bị tu sĩ liên minh truy đuổi, nhận ra đó là người quen."},{"chuong":861,"tieuDe":"Chu Thiên","tomTat":"Tây Tử Phượng bị thương nặng và bị tu sĩ Liên Minh truy đuổi, Vương Lâm xuất hiện kịp thời, chỉ quát hai chữ \"Lui ra\" kết hợp quy tắc mới ngộ với cảnh giới Ngôn Xuất Pháp Tùy đã khiến đám tu sĩ nổ tung. Tu sĩ sáu ngón Chu Thiên ở cảnh giới Khuy Niết trung kỳ xuất hiện giao chiến, lần lượt dùng Vạn Hồn Nuốt Thần, Hồn Sát và đoạt xá nhưng đều thất bại trước Trảm La quyết đã tăng uy lực nhờ quy tắc, giáp da Cổ Thần bảo hộ nguyên thần, và nguyên thần Thái Cổ Lôi Long nuốt một phần hồn phách hắn. Vương Lâm lần đầu thi triển Tát Đậu Thành Binh, triệu hồi toàn bộ hồn phách trong mười tám tầng địa ngục bao gồm tu sĩ Khuy Niết, hơn trăm tiên nhân và Huyết Tổ Tinh Niết, tạo thành đạo quân oán hồn bao vây bắt trọn Chu Thiên rồi giam vào tầng mười ba. Sau trận chiến, Vương Lâm dùng Thiên Hổ kỳ thả Phi Thiên hổ làm tín hiệu tập hợp tu sĩ La Thiên đang phân tán, hình thành đội hình lớn nhất khu vực phía Tây, danh vọng tăng vọt nhằm tính toán lập công trạng để Viêm Lôi Tử sẵn lòng giúp đỡ khi gặp Thiên Vận Tử hoặc Thác Sâm. Cuối chương, một cự mộc vạn trượng lao tới kèm theo Vọng Nguyệt với thân thể khổng lồ như tinh cầu tu chân, Vương Lâm nhìn thấy liền chấn động toàn thân mà sự chấn động đó đến từ giáp da Cổ Thần trong người hắn."},{"chuong":862,"tieuDe":"Ngọc Giản Màu Xanh","tomTat":"Bổn tôn Cổ Thần trong Vương Lâm chấn động khi thấy xúc tua Vọng Nguyệt, dấu sao trên mi tâm ẩn hiện rồi bị kìm nén. Hắn hồi tưởng lại năm xưa ẩn thân trong Vọng Nguyệt thoát truy sát Diêu gia, suy đoán người bí ẩn từng gặp hai lần chính là kẻ đã biến Vọng Nguyệt thành pháp bảo đưa tới Liên Minh. Cự mộc tiến gần, trên cây gần trăm cường giả do Mạnh Vân Tử và Thân Công lão tổ đứng đầu, trong đó có ba cường giả Khuy Niết hậu kỳ bí ẩn mà Vương Lâm không thể nhận ra tu vi. Vương Lâm dùng kỹ thuật tĩnh-động bộc phát nguyên lực kèm quy tắc, thong dong bước lên cự mộc không chút chật vật, trở thành người thứ tư làm được điều này, khiến ba cường giả coi trọng. Vọng Nguyệt nhận ra Vương Lâm, nhớ hai lần bị trêu chọc nên nổi giận tung xúc tua tấn công lên cự mộc. Mạnh Vân Tử mở khe không gian lấy ngọc giản màu xanh ném về phía Vọng Nguyệt, ngọc giản nổ tung phát ra ngôn ngữ Cổ Thần khiến chỉ mình Vương Lâm hiểu được ý nghĩa và biến sắc chấn động."},{"chuong":863,"tieuDe":"Cực Hiền Thiên","tomTat":"Nội dung câu nói bằng ngôn ngữ Cổ Thần được giải nghĩa: hứa cho Vọng Nguyệt thân thể mới sau khi phá tinh vực Vũ hạ giới, đổi lại Vọng Nguyệt giúp thoát vây. Vọng Nguyệt tỉnh táo trở lại, lao lên mở đường, dùng xúc tua hút khô tu sĩ Liên Minh. Mạnh Vân Tử hẹn Vương Lâm sau trận chiến xem vài tấm hình chữ Chiến còn lại. Thân Công lão tổ thu lại đạo niệm Thân Công Hổ từ Vương Lâm. Tại khu vực phía Bắc Liên Minh, Hắc Sắt ma tôn đã hủy diệt phía Tây và đang giao chiến Huyết Thần Tử, Vân Long yêu tôn lộ diện tự xưng tôn giả mới Liên Minh bị ba lão tổ chặn lại. Viêm Lôi Tử dùng mười tám La Phù nghịch chuyển càn khôn, ép Cực Hiền Thiên ra khỏi khe nứt tinh không, hai bên đối đầu lửa-băng, Cực Hiền Thiên phá nổ một La Phù bằng âm thanh nguyên lực. Mấy vạn tu sĩ hai bên loạn chiến, máu huyết bị La Phù hút. Vương Lâm đứng trên cây nhìn Vọng Nguyệt, thầm nhận ra đó là ấu tử Cổ Thần."},{"chuong":864,"tieuDe":"Đầu Danh Trạng","tomTat":"Tại chiến trường phía Bắc Liên Minh, Viêm Lôi Tử đại chiến Cực Hiền Thiên. Cực Hiền Thiên thi triển Quy tắc băng hàn phong tỏa Viêm Lôi Tử trong tảng băng vạn trượng, nhưng Viêm Lôi Tử bất ngờ bộc lộ tu vi thật — ẩn giấu từ đầu, bùng phát từ Toái Niết hậu kỳ tăng lên vô hạn, đã đột phá. Lão phá băng, dùng Tiên giới luân chuyển kết hợp biển lửa vây khốn Cực Hiền Thiên. Vọng Nguyệt từ tinh không lao tới, tiếng rít rung chuyển trời đất khiến Hắc Sát ma tôn, Vân Long yêu tôn và Huyết Thần Tử đều lui lại. Cây khổng lồ theo sát Vọng Nguyệt đánh vỡ mảnh tiên giới, phá 6 tầng Lam ý của Cực Hiền Thiên, lửa Viêm Lôi Tử phá thêm 3 tầng, Thân Công lão tổ và Mạnh Vân Tử từ trên cây lao ra cùng đánh. Cực Hiền Thiên buộc phải kích nổ 4 tầng Lam ý còn lại để thoát vây, phun máu bị thương nặng, thề báo thù rồi xé không gian định bỏ chạy. Vương Lâm đứng trên cây khổng lồ, cắn răng điểm tay quát Định nhắm Cực Hiền Thiên — chương kết thúc tại đây."},{"chuong":865,"tieuDe":"Công Lớn","tomTat":"Vương Lâm thi triển thuật định thân bằng nguyên lực tạo sợi tơ quấn chậm Cực Hiền Thiên đúng lúc hắn định chui vào vết nứt không gian thoát thân. Viêm Lôi Tử nhân cơ hội vỗ đánh bật Cực Hiền Thiên ra, Vọng Nguyệt lập tức nuốt chửng — một trong tứ tôn xếp hạng thứ chín Liên Minh bị tiêu diệt. Vương Lâm bị phản chấn phun máu nhưng chủ ý quát lên trước mặt mọi người để đoạt đầu danh trạng công thần, tạo lá chắn bảo vệ từ La Thiên cho tương lai. Viêm Lôi Tử truyền nguyên lực khổng lồ chữa thương cho Vương Lâm, khiến tu vi gần đạt đỉnh phong Khuy Niết sơ kỳ, đồng thời hứa trả Lôi thú và tặng bảo vật phòng thân. Viện quân Liên Minh tu chân ập đến với trăm ngọn tháp ngàn trượng, bốn tinh cầu do tộc Cự Ma khiêng, cùng nữ nhân váy lam chỉ huy và cường giả bí ẩn Vũ Đông Thiện. Vũ Đông Thiện cuồng ngạo thách đấu Viêm Lôi Tử, hai bên chìm vào đám mây đen giao chiến. Nữ nhân váy lam ra lệnh trăm tháp lao vào giam cầm Vọng Nguyệt, phe La Thiên thoáng nhìn ở thế yếu hơn. Vương Lâm lui sau cái cây, bất chợt cảm nhận ánh mắt dữ dằn phức tạp của nữ nhân váy lam đang nhìn mình."},{"chuong":866,"tieuDe":"Bách Vạn Thú Huyết Tỏa Thiên Thần","tomTat":"Liên Minh tu chân triển khai một trong mười trận pháp lớn — Bách Vạn Thú Huyết Tỏa Thiên Thần — dùng trăm ngọn tháp hóa bụi đen bao quanh Vọng Nguyệt, đồng thời giết sạch hơn trăm vạn yêu thú trên gần trăm tinh cầu tu chân để hấp thu máu huyết hồn phách truyền tới bụi đen phong ấn Vọng Nguyệt. Nữ nhân áo lam chỉ huy phía Liên Minh hô Phong kích hoạt phong ấn, hơn vạn tu sĩ Liên Minh nhảy xuống giao chiến với La Thiên. Mạnh Vân Tử và Thân Công lão tổ được giao quyền chỉ huy tạm thời hậu viện La Thiên: Mạnh Vân Tử ra lệnh 72 Địa Sát tiên xông trận, Thân Công lão tổ dẫn 36 Thiên Cương tiên đi phá phong ấn Vọng Nguyệt. Mạnh Vân Tử ngồi trên cây khổng lồ xuất nguyên thần kèm ba chữ Chiến, lần lượt kích hoạt hai huyết cầu La Phù triệu hồi huyết nhân — huyết nhân thứ nhất khiến Hắc Sát ma tôn chật vật phải lui, huyết nhân thứ hai lao về phía phong ấn Vọng Nguyệt. Vương Lâm được gọi là Hứa Mộc, chỉ định làm hộ pháp cho Mạnh Vân Tử cùng ba người khác. Liên Minh phản công bằng cách sai tộc nhân Cự Ma cao ngàn trượng khiêng tinh cầu lao tới 15 La Phù còn lại, Mạnh Vân Tử quát gọi La Hồng và Chu Hành Thiên đi bảo vệ La Phù."},{"chuong":867,"tieuDe":"Cự Ma Ngàn Trượng Nổ Tung","tomTat":"Đại chiến tiếp diễn quanh La Phù và Cự Mộc. Mạnh Vân Tử điểm chữ Thiếp và chữ Chiến trên huyết cầu La Phù, triệu hoán hai huyết nhân nghênh chiến phe Liên Minh. Gã khổng lồ tộc Cự Ma tu vi Dương Thực đỉnh phong lao về phía Cự Mộc định tự bạo, Vương Lâm chủ động nghênh chiến, dùng lực Cổ Thần đánh nổ tung tay phải và hơn nửa thân gã, rồi thi triển Thuật Hô Phong hấp thu ngọn lửa sinh mệnh giảm uy lực tự bạo, sau đó giả vờ bị thương che giấu thực lực. Lão nhân trên tinh cầu tu chân phe Liên Minh thi triển Tu tinh dao động phóng làn sóng hồng tàn sát tu sĩ La Thiên, đe dọa cả Cự Mộc. Mạnh Vân Tử quát Hứa Mộc và Tử Yên tản ra, bản thân kết ấn quyết dung nhập nguyên thần vào Cự Mộc biến mất. Vương Lâm rời cây giết tu sĩ Liên Minh đánh lén, gặp lại Hứa Đình và đề nghị cùng nhắm giết nữ nhân váy lam chỉ huy Liên Minh."},{"chuong":868,"tieuDe":"Chàng Không Nhận Ra Thiếp","tomTat":"Vương Lâm và Hứa Đình cùng lao về phía nữ nhân váy lam đang chủ trì trận đại chiến phía Liên Minh. Hứa Đình nhận ra nữ nhân có thân phận đặc biệt, bên cạnh chắc chắn có cường giả bảo vệ nên chủ động lui lại xem Vương Lâm tự xông vào chết. Khi gợn sóng đỏ hủy diệt từ tinh cầu tu chân sắp đến, Vương Lâm triệu cự đỉnh dùng thần thông Hoán Vị đổi chỗ với Hứa Đình, đẩy hắn bất ngờ đối diện gợn sóng. Hứa Đình triển khai trăm lớp phòng hộ tiên thuật Hứa gia, bóp nát trăm ngọc giản, lấy vô số pháp bảo nhưng tất cả đều bị phá hủy, phải phun máu thi triển Huyết Độn mới thoát, tiêu hao phần lớn tiên nguyên và mất gần hết pháp bảo. Vương Lâm cười lớn cắt lời Hứa Đình, tuyên bố trước mặt mọi người rằng hắn chủ động giúp làm yếu gợn sóng, khiến Hứa Đình uất hận rút lui. Vương Lâm xuyên qua gợn sóng bằng kiếm chỉ Âm Dương song ngư, triệu gió lốc đen với hai rồng đen tấn công nữ nhân. Nữ nhân bình tĩnh, trong lòng thầm than nhận ra Vương Lâm nhưng hắn không nhận ra nàng, rồi gỡ một đóa hoa từ pháp bảo bông sen tám cánh trên tay phải vất ra, cánh hoa phóng to hơn mười trượng tạo uy áp kinh hoàng đè Vương Lâm khiến không gian sụp đổ, thân thể hắn bị sức ép chực đẩy vào khe nứt."},{"chuong":869,"tieuDe":"Ngũ Hành Kim Thi","tomTat":"Nữ tử Thủy La dùng đài hoa sen bảy cánh phát uy áp áp chế Vương Lâm, hai con hắc long của hắn bị phá tan. Vương Lâm lần đầu tự thân thi triển thức thứ hai Tiên thuật Bạch Phàm — Hoán Vũ, tạo lốc xoáy trăm trượng với hơn vạn hạt mưa chứa thiên địa nguyên lực, phá tan cánh hoa sen. Hắn kiềm chế lôi ý, cố tình làm bộ chiến đấu hết sức dưới danh nghĩa Hứa Mộc rồi rút lui. Huyết Thần Tử cùng Huyết nhân La Phù đánh không lại Hắc Sát Ma Tôn, thối lui. Thủy La triệu hoán Hài Ngục Giới, giải phóng 18 khối Luyện Thi — trong đó 15 khối thường ở Khuy Niết hậu kỳ, 2 khối bạc ở Tịnh Niết sơ kỳ, và 1 khối Ngũ hành linh thể mặc long bào — đảo ngược thế trận cho Liên Minh. Vương Lâm nhìn Luyện Thi ngũ hành linh thể liền nhớ tới Hồng Điệp. Hắn tính toán đục nước béo cò, cố ý tiếp cận hắc xác Vọng Nguyệt đang bị phong ấn, dung nhập khí tức Cổ Thần vào bên trong. Vọng Nguyệt bản năng cảm nhận, phát cuồng gầm lên, xuất ra Cổ Thần Chỉ, hắc xác nổ tung, Cổ Thần Chỉ thô ráp vươn ra ngoài."},{"chuong":870,"tieuDe":"Của Vương Lâm Ta!","tomTat":"Vọng Nguyệt phá huỷ hoàn toàn hắc xác phong ấn bên ngoài, lần đầu thi triển thần thông Cổ Thần Chỉ tại Liên Minh Bắc Vực với uy lực gần đạt tiếng rống Cổ Thần. Cổ Thần Chỉ tiêu diệt Luyện Thi đang truy kích Vương Lâm rồi quét tiến về phía Hắc Sát Ma Tôn. Hắc Sát Ma Tôn thi triển nhiều thần thông phòng ngự: hắc hạc hoá thụ nghìn trượng, bức tượng gỗ hình người hoá năm đoá hoa đen ôm trói Cổ Thần Chỉ, nhưng vẫn không ngăn nổi. Vương Lâm đứng xa quan sát, coi đại chiến là cơ hội mở rộng kiến thức về thực lực Tịnh Niết và Toái Niết kỳ, đồng thời cảm nhận cự mộc che trời ẩn chứa bí ẩn. Vọng Nguyệt gầm rống khiến Cổ Thần Chỉ tự bạo, phá nát tinh không ngàn dặm, hơn mười Luyện Thi bị huỷ, Hắc Sát Ma Tôn trọng thương bỏ chạy. Nữ Ngân Thi xinh đẹp bị văng về phía Vương Lâm, hắn tuyên bố muốn đoạt lấy nữ thi và nửa bức tượng gỗ bị tổn hại."},{"chuong":871,"tieuDe":"Liên Minh Trưởng Lão Đoàn","tomTat":"Sau khi Cổ Thần Chỉ tự bạo, Vương Lâm lùi về phía nữ thi Ngân Thi, quan sát ba tu sĩ lần lượt bị nữ thi hấp thu máu huyết mà chết. Hắn dùng Cổ Thần Đỉnh hoán đổi vị trí với tu sĩ La Thiên, dùng thần thông Định khống chế tu sĩ Liên Minh mặc mãng bào, rồi kết hợp tiên lực và Cổ Thần lực biến ảo Âm Dương song ngư ấn vào mi tâm nữ thi phá cơ chế hấp thu, thành công đoạt nữ thi. Vương Lâm đá trọng thương tu sĩ Liên Minh, phong ấn nữ thi thu vào túi trữ vật rồi lao về phía tinh không sụp đổ. Trong khi đó Vọng Nguyệt điên cuồng chém giết, Huyết Thần Tử cùng Huyết nhân La Phù hỗ trợ, Viêm Lôi Tử đấu với Võ Đông Thiện kinh thiên động địa. Thuỷ La bình tĩnh chủ trì chiến trường phía Liên Minh, triệu mời Huyền Bảo thượng nhân — Đại Trưởng lão Địa Huyền Điện, thành viên Liên Minh Trưởng Lão Đoàn — xuất hiện. Tiếng cười của Huyền Bảo khiến pháp bảo khắp nơi run rẩy, Hắc Sát Ma Tôn và Vân Long Yêu Tôn đều lui lại. Chương tiết lộ cơ cấu Tu Chân Liên Minh gồm Lưỡng Điện Tứ Tôn Bát Phương, và Trưởng Lão Đoàn là tổ chức tối cao; Thiên Vận Tử cũng là thành viên nhưng sau biến cố địa vị xuống dốc. Huyền Bảo không coi ai trong chiến trường ra gì, duy nhìn Vọng Nguyệt thì đồng tử co rụt, lộ ý cười thâm thuý."},{"chuong":872,"tieuDe":"Thứ Không Niết!","tomTat":"Huyền Bảo thượng nhân mở khe hư không triệu ra bốn Tiên vệ kim phẩm vây Vọng Nguyệt bốn phương, rồi thả chín hắc Hồ Điệp tạo lưới hắc tuyến bao quanh. Huyết Thần Tử dùng huyết hải công kích nhưng không cản nổi Tiên vệ. Vương Lâm nhận ra khí tức Tiên vệ giống Tháp Sơn và Hồ Điệp giống biến thể Xạ Thần xa, chấn động trước thủ đoạn của Huyền Bảo. Lợi dụng hỗn loạn, Vương Lâm dùng lực dung hợp pháp thuật và Cổ Thần lực cùng Cổ Thần Đỉnh hoán đổi vị trí để đoạt nửa bức tượng gỗ mà Hắc Sát Ma Tôn để lại. Thần Long của Đại La Kiếm Tông dùng kiếm khí Lăng Thiên Hầu tranh bảo, bị Vương Lâm dùng Phong Tiên Ấn mười tám tầng địa ngục chặn lại rồi nhắc chuyện năm xưa khiến Thần Long kinh hãi nhận ra. Cuối chương, Huyền Bảo dẫn xuất Thứ Không Niết Tiễn — mũi tên xanh khổng lồ có vết máu xám đen — khiến tu sĩ mấy vạn dặm chấn động, cả Huyết Thần Tử và Viêm Lôi Tử đều biến sắc."},{"chuong":873,"tieuDe":"Cổ Thần Khí","tomTat":"Vọng Nguyệt gầm rít dùng ngôn ngữ Cổ Thần khiến tinh không sụp đổ, đồng thời phun ra hơn mấy trăm ngàn Vọng Nguyệt nhỏ tràn ngập chiến trường gây thương vong lớn cho tu sĩ cả hai phe. Huyền Bảo thượng nhân triển khai trọng bảo Tu Chân Liên Minh — Thứ Không Niết Tiễn, mũi tên lớn ba mươi trượng hai lần phá hủy Cổ Thần Chỉ do Vọng Nguyệt ngưng tụ, sau đó tiêu tan lộ ra bản thể chân chính là mũi tên nhỏ ba tấc vết máu đỏ tươi. Mũi tên nhỏ đâm trúng mắt Vọng Nguyệt, khiến nó trọng thương lần đầu trong vô số năm tháng. Vương Lâm nhân lúc Cổ Thần lực nồng đậm tràn ngập tinh không, mừng rỡ hấp thu Cổ Thần khí — thân thể Cổ Thần nhảy vọt cường đại, Cổ Thần chi tinh Tam tinh rưỡi hư ảo có xu thế ngưng tụ thành thực chất. Huyền Bảo thượng nhân bộc lộ dã tâm muốn thu Vọng Nguyệt luyện thành Thứ Không Niết Cực, dung hợp với Thứ Không Niết Tiễn cửu phẩm nâng lên bát phẩm để chống lại Trọng Huyền Tử trong Trưởng lão Đoàn. Vọng Nguyệt phẫn nộ cực điểm, tự bạo một trong bảy Cổ Thần toái tinh giải phóng lực lượng tuyệt cường bức mũi tên ra khỏi thân, nhưng đau đớn kịch liệt khiến nó mất lý trí chỉ còn ý niệm giết. Viêm Lôi Tử lạnh lùng tiết lộ mưu đồ thực sự của tiền bối phía La Thiên: đưa Nguyệt Thú đến Liên Minh là để nó càng tức giận, càng trọng thương thì phá hoại càng lớn, càng cường đại."},{"chuong":874,"tieuDe":"Thanh Thuỷ Tới","tomTat":"Vọng Nguyệt rống giận dữ, ngưng vô số xúc tu vạn trượng thành Cổ Thần Tí — cánh tay Cổ Thần — một quyền huỷ tan Thứ Không Niết Tiễn, pháp bảo duy nhất của Huyền Bảo thượng nhân. Đúng khoảnh khắc pháp bảo bị huỷ, Thanh Thuỷ áo trắng bước ra từ tinh không với Cực Cảnh lâm thế, phóng tia chớp đỏ đâm Huyền Bảo, tự xưng bản quân của Lôi Giới. Thanh Thuỷ triệu bảy hắc long, Hô Phong Hoán Vũ vây đánh, nhưng Huyền Bảo thi triển Cửu Điệp quy nhất — chín con Hồ Điệp dung hợp thành Hồ Điệp bốn màu, rồi bóc cánh thi triển Quy tắc Thứ Không xoá mọi thần thông và cướp luôn Hô Phong Hoán Vũ thành của mình. Thân phận Huyền Bảo bị lộ: Tiên nhân Vũ chi Tiên giới, sư đệ Thiên Bảo thượng nhân. Thanh Thuỷ đáp trả bằng Tát Đậu Thành Binh hoá hơn ngàn binh lính hư ảnh khiến Huyền Bảo chua xót. Huyền Bảo thi triển pháp bảo lực triệu mọi pháp bảo và túi trữ vật trong mấy vạn dặm, sóng gợn tràn khắp, mọi pháp bảo kể cả của tu sĩ đã chết đều bay về phía lão. Vương Lâm bị cuốn mất túi trữ vật, mở con mắt thứ ba ở mi tâm phóng hồng quang, dùng bổn nguyên đối kháng lực kỳ dị giữ được túi, sắc mặt tái nhợt; đồng thời thầm ghi nhớ thật kỹ thủ ấn chế Hồ Điệp bốn màu của Huyền Bảo."},{"chuong":875,"tieuDe":"Tiến Nhập Nguyệt Khẩu","tomTat":"Huyền Bảo thượng nhân bị ba phía vây đánh — Thanh Thủy dùng Tát Đậu Thành Binh, Vọng Nguyệt dùng Cổ Thần Tí, Viêm Lôi Tử dùng Tiên Giới Toái Phiến — thi triển Pháp lực Không Niết chống trả nhưng thân thể tan nát, nguyên thần thoát ra với kim y bảo hộ rồi kim y cũng vỡ. Nữ tử Thủy La dùng ấn quyết Giải phong giải phóng Kim Thi, khiến Kim Thi hóa thành kim long chân chính có huyết nhục, kích hoạt chỉ phù Độc hỏa cuốn nguyên thần Huyền Bảo định bỏ chạy. Từ bên trong cây cự mộc che trời, Nhất Mộc Tử — Cửu trưởng lão La Thiên — bước ra, dùng hư ảnh cự mộc ngăn kim long. Vọng Nguyệt phẫn nộ mất lý trí, dùng Cổ Thần Tí nắm kim long cùng nguyên thần Huyền Bảo nuốt vào miệng rồi chui vào lốc xoáy hư không biến mất. Thanh Thủy, Võ Đông Thiện, Nhất Mộc Tử lần lượt lao vào miệng Vọng Nguyệt đuổi theo. Vương Lâm chờ đúng thời cơ, nương lôi quang đạp lên thân Vọng Nguyệt chui vào bên trong. Viêm Lôi Tử quyết định ở lại chủ trì đại chiến, ném cho Vương Lâm một mảnh Tiên Giới Toái Phiến nhỏ để bảo hộ và định vị, bên trong chứa khí tức Lôi Thú. Thủy La nhìn Vương Lâm với ánh mắt phức tạp, lẩm bẩm tự hỏi lần sau gặp lại chàng có nhận ra mình rồi hư ảo biến mất."},{"chuong":876,"tieuDe":"Lôi Thú Uất Ức","tomTat":"Chiến trường Liên Minh Bắc Bộ trở thành tử địa sau trận đại chiến, cả hai bên La Thiên và Tu Chân Liên Minh tạm đình chiến. Hoàng Long chân nhân xuất hiện quan sát chiến trường, nhận định Tu Chân Liên Minh thực tế thua và trận chiến do Viêm Lôi Tử dựng lên. Hắn tiết lộ Tứ Thánh Tông đã nhẫn nhịn tích tụ lực lượng rất lâu chờ bùng nổ, coi Vương Lâm là con cờ bí mật trong phe La Thiên vì đã đặt ấn ký trên người hắn mà Viêm Lôi Tử không nhìn ra. Vọng Nguyệt tiến vào Hư Vô giới — không gian hắc ám vô biên do tinh không toái liệt tạo thành, phong ấn mọi nguyên lực. Vương Lâm ở bên trong cơ thể Vọng Nguyệt, dùng Tiên Giới Toái Phiến triệu hồi Lôi Thú ra. Lôi Thú bộ dáng thảm hại với thiết liên, chỉ phù, thiết hoàn trên người, gặp lại Vương Lâm hai mắt đẫm lệ bộc phát nỗi ủy khuất nhiều năm. Hứa Lập Quốc được gọi ra từ Kiếm Tiên, dùng tài ăn nói đặc biệt an ủi thành công Lôi Thú, khiến nó vui vẻ cho ngồi trên lưng, vẻ cao ngạo cuồng vọng năm xưa đã tan thành mây khói."},{"chuong":877,"tieuDe":"Ngư Ông","tomTat":"Vương Lâm cảm khái nhìn Lôi Thú đã mất phong tư năm xưa rồi thu nó vào túi trữ vật, đồng thời từ chối lời xin tự do của Hứa Lập Quốc và thu luôn hắn vào. Di chuyển nhanh trong cơ thể Vọng Nguyệt nhờ các tiểu Vọng Nguyệt đã tan nát, Vương Lâm phát hiện nguyên lực trong người bị lực vô hình phong ấn dần, tương tự chỉ phù Tiên Di Tộc, và linh lực trên xương cốt Vọng Nguyệt cũng biến mất hoàn toàn. Tuy nhiên lực lượng thân thể Cổ Thần không bị ảnh hưởng, tạo ưu thế lớn. Phía trước động khẩu dẫn tới nơi Cổ Thần ấu tử, Võ Đông Thiện và Nhất Mộc Tử đang giao chiến, trong khi Huyền Bảo thượng nhân đối phó Thanh Thủy ở nơi khác. Nhất Mộc Tử thi triển thần thông Nhất mộc nhất giới tạo lục khí phong ấn Võ Đông Thiện rồi lao vào động khẩu, Võ Đông Thiện phá phong ấn trong ba tức rồi mỉm cười bước vào theo. Vương Lâm quyết định áp dụng kế ngư ông đắc lợi, dựa vào ưu thế Cổ Thần lực miễn phong ấn để chờ các cường giả tiêu hao nguyên lực, phóng đoản kiếm dung nhập thần thức thăm dò và cho phi kiếm lao thẳng vào lốc xoáy nơi Cổ Thần ấu tử."},{"chuong":878,"tieuDe":"Hoạ Địa Vi Lao","tomTat":"Trong thân thể Vọng Nguyệt, Vương Lâm nhận ra cần vừa tăng tiêu hao của các lão quái vừa chừa đường lui cho bản thân, nên lấy hơn mười thanh phi kiếm thu được từ trận chiến trước, nén nguyên lực rồi phóng tới các điểm mẫn cảm của Vọng Nguyệt. Hắn dùng thần thức bám lên phi kiếm dò lốc xoáy nhưng bị dư ba nguyên lực đánh sụp phi kiếm, thần thức tiêu tán hơn phân nửa, sau đó vẫn điều khiển phi kiếm khác vượt qua lốc xoáy vào thông đạo. Tại đây, hắn thấy Thanh Thuỷ đang giao chiến với kim long, Huyền Bảo thượng nhân suy yếu bị xúc tu hấp thu tiên nguyên lực, Nhất Mộc Tử bị Võ Đông Thiện truy đuổi, còn Cổ Thần ấu tử ở cuối vách thịt dường như đã bị phong kín. Kim long dùng Tàn kim ngưng vảy thành kim lân kiếm đối đầu Thanh Thuỷ, khiến thông đạo nổ tung, vách thịt nứt ra và máu lục trào xuống. Khi Vọng Nguyệt dị biến, Thanh Thuỷ mở Sát lục giới, còn kim long vận dụng năm tấm chỉ phù thi triển Ngũ hành nghịch chuyển để ngăn cách thông đạo thành một mảnh thiên địa. Thanh Thuỷ tiếp tục dùng tiên thuật tự sáng tạo Hoạ địa vi lao, lấy sát lục làm nền và lao ngục quy tắc làm phong ấn, vây khốn cả Ngũ hành nghịch chuyển rồi rút nguyên thần Huyền Bảo khỏi vòng bảo hộ của kim long. Đúng lúc hắn định lui, một cánh tay đỏ máu mang sát khí và khí tức Vọng Nguyệt từ khe hở lao ra, đánh Thanh Thuỷ phun máu và cướp lại Huyền Bảo thượng nhân. Vì Huyền Bảo là hy vọng duy nhất để Thanh Thuỷ biết chuyện Tiên giới năm xưa, việc bị cướp ngay trước mắt khiến cơn giận của hắn bộc phát."},{"chuong":879,"tieuDe":"Cổ Thần Khôi Lỗi Thuật","tomTat":"Thanh Thuỷ điên cuồng công kích cánh tay Vọng Nguyệt bằng sợi tơ mảnh và Cực Cảnh, hy sinh mắt phải (bạo khai hoá huyết nhục) để buộc cánh tay buông lỏng nguyên thần Huyền Bảo thượng nhân, rồi dùng Hô Phong bát long quét nguyên thần Huyền Bảo bay đi và phong ấn khiến hắn hôn mê. Vương Lâm phối hợp ăn ý: chui qua lốc xoáy nắm nguyên thần Huyền Bảo ném vào túi trữ vật, mở con mắt thứ ba phóng bổn nguyên lực khiến kim long khiếp sợ dừng lại khoảnh khắc rồi bỏ chạy trong cơ thể Vọng Nguyệt. Vương Lâm kích nổ hơn mười thanh phi kiếm cài sẵn tại các điểm mẫn cảm trong cơ thể Vọng Nguyệt, gây đau đớn kinh hoàng buộc Vọng Nguyệt phun tất cả ra Hư Vô: kim long, Vương Lâm, Thanh Thuỷ, Nhất Mộc Tử, Võ Đông Thiện. Tại Hư Vô giới, nguyên lực và tiên nguyên của mọi người cấp tốc tiêu tan, chỉ Cổ Thần lực trong cơ thể Vương Lâm hoàn toàn không bị ảnh hưởng. Vọng Nguyệt sau đó mắt hiện lốc xoáy phun ra Cực Hiền Thiên. Vương Lâm nhờ thân thể Cổ Thần nhận ra Cực Hiền Thiên đã dung hợp Cổ Thần nhất tinh, trở thành tồn tại phi tiên phi tu phi thần — đây là Cổ Thần Khôi Lỗi Thuật, thần thông chỉ Cổ Thần trưởng thành mới thi triển, nhất tinh đến từ bát tinh Cổ Thần."},{"chuong":880,"tieuDe":"Lực Lượng Truyền Thừa","tomTat":"Cực Hiền Thiên phát huy tốc độ vượt xa thuấn di, lần lượt đánh bại kim long, Võ Đông Thiện, Nhất Mộc Tử và Thanh Thủy trong chớp mắt nhờ cơ thể không có nguyên lực nên không chịu phong ấn Hư Vô. Vương Lâm dựa vào Cổ Thần thân thể đánh quyền bức lui Cực Hiền Thiên hai bước, là người duy nhất đối kháng được nhục thân hắn. Kim long quay sang tấn công Vương Lâm bằng ngũ hành khí nhưng bị Vương Lâm dùng nguyên thần Huyền Bảo thượng nhân uy hiếp buộc dừng tay. Vương Lâm phối hợp Thanh Thủy, nhận phân nửa tiên nguyên còn lại của sư huynh, lần đầu tiên chân chính phát huy uy lực Định Thân Thuật, định trụ Cực Hiền Thiên trong hư vô. Tam đại lão quái đồng thời ra tay: Nhất Mộc Tử biến cự mộc thành mộc kiếm đâm xuyên đỉnh đầu bạo khai, Võ Đông Thiện phun nguyên thần tinh khí hóa bọt khí ngũ quang bạo khai, kim long dung hợp ngũ hành lực thành hư ảnh vương miện ấn xuống thiên linh. Ba đòn đồng thời khiến thân thể Cực Hiền Thiên sụp đổ tan nát. Ngay khi Cực Hiền Thiên bị diệt, Vương Lâm mắt lộ tham quang, triệu Cổ Thần Đỉnh tới, cắn lưỡi phun máu rồi há mồm hút lấy viên tử tinh to bằng nắm tay chứa Cổ Thần lực từ huyết nhục — chính là lực lượng truyền thừa."},{"chuong":881,"tieuDe":"Vương Tộc Cổ Thần","tomTat":"Vương Lâm hút viên tử tinh về phía mình trong lúc Vọng Nguyệt rống lên phóng khí tức Cổ Thần, còn Nhất Mộc Tử và Võ Đông Thiện cùng lao tới tranh đoạt nhưng đã cạn nguyên lực. Hắn nuốt Cổ Thần nhất tinh, thân thể bành trướng dữ dội và Cổ Thần chi tinh trên mi tâm từ Tam tinh rưỡi thăng thành Tứ tinh chân chính của vương tộc Cổ Thần kế thừa Đồ Ti. Sau đó Vương Lâm áp sát Kim Thi, dùng một quyền Tứ tinh Cổ Thần lần lượt chấn nát Độc hoả, Cống thuỷ, Tàn kim, Hình mộc, Táng thổ và đánh Kim Thi thổ huyết. Kim Thi phản kích bằng Ngũ hành lực rồi định bóp nát mộc bài mở thông đạo bỏ trốn, nhưng Vương Lâm lấy Long Tôn ngũ hành quan ra khiến hư ảnh nữ tử trong vương miện hiện thân và thu hắn vào trong. Sau khi thu Kim Thi, nữ tử hư ảnh nhìn Vương Lâm như muốn nói gì nhưng không phát ra thanh âm rồi biến mất. Vương Lâm quay sang Vọng Nguyệt, dùng ngôn ngữ Cổ Thần phát lời khiêu chiến thành niên; Ngũ tinh Cổ Thần bên trong Vọng Nguyệt chấp nhận, bước ra và bành trướng thân hình tới hơn ba trăm trượng như thiên thần."},{"chuong":882,"tieuDe":"Pháp Khí Của Vương Tộc","tomTat":"Nhất Mộc Tử nhận ra Hứa Mộc chính là Cổ Thần nhưng vẫn không quên nhiệm vụ được giao, lập tức lao vào miệng Vọng Nguyệt trước khi nó khép lại. Võ Đông Thiện cũng nhớ tới ghi chép về Nguyệt Hoa trong cơ thể Vọng Nguyệt, tin rằng có thể luyện thành pháp bảo Thứ Không Niết Cấp nên cắn răng phóng theo, còn Thanh Thủy đứng ngoài quan sát. Ngũ Tinh Cổ Thần tự xưng là La Trần và giao chiến với Vương Lâm, hai bên dùng bàn tay Cổ Thần, quyền thuật và thần thông huyễn hóa đối công dữ dội. La Trần tuy có cảnh giới cao hơn nhưng đã suy yếu nặng, lại bị việc đồng hóa lâu năm với Vọng Nguyệt khiến tâm trí rối loạn giữa truyền thừa và thôn phệ. Vương Lâm nhớ tới Diệt Thần Mâu của Đồ Ti, dùng lực Tứ Tinh huyễn hóa pháp khí vương tộc Cổ Thần, làm Tuyệt Nguyên Đại Trận hiện nguyên hình. Nhìn thấy Diệt Thần Mâu, La Trần xác nhận truyền thừa của Vương Lâm đến từ Đồ Ti và thái độ trở nên nhu hòa hơn. Vương Lâm tiếp tục tự xưng là Cổ Thần Vương Lâm, thi triển Diệt Thần Ấn phối hợp với Diệt Thần Mâu tạo cơn lốc trong hư vô. Cuối chương, trên mảng lưới Tuyệt Nguyên Đại Trận xuất hiện hai luồng u quang lạnh lùng nhìn vào trận chiến, kèm tiếng nói bí ẩn nhắc tới Vọng Nguyệt và Cổ Thần."},{"chuong":883,"tieuDe":"Nghịch Thiên Châu Chấn Động","tomTat":"Luồng u quang bí ẩn xuất hiện rồi biến mất, Thanh Thủy cảm nhận được nỗi sợ hãi tột cùng nhưng không nhìn rõ, mơ hồ thấy quen mà không nhớ. Nghịch Thiên châu bên trong nguyên thần Vương Lâm đột nhiên tự vận chuyển kịch liệt, phóng lực lượng kỳ diệu khiến mắt hắn hiện lam quang, nhờ đó nhìn thấy hai luồng u quang mà cả La Trần lẫn Thanh Thủy đều không thấy. Giao đấu tiếp diễn, La Trần phóng xương nhọn Cổ Thần, Vương Lâm dùng Diệt Thần Mâu niệm tiếng Cổ Thần thi triển Phản Cổ Tá Tổ triệu hoán vòng xoáy khổng lồ hấp thu tấn công, La Trần kích động tán thưởng đây là truyền thừa vương tộc. La Trần thi triển Thuật Thú Linh triệu hoán voi khổng lồ đen kịt, bị nắm đấm da xanh từ Phản Cổ Tá Tổ đánh gãy một ngà, Vương Lâm phun máu lui sau. Vọng Nguyệt gầm lên quấy nhiễu La Trần bằng ý chí khiến hắn đau khổ chấn động. Mạng lưới quanh Vọng Nguyệt rạn nứt, khe hở khổng lồ mở ra, ba người nhìn thấy ba hình ảnh hoàn toàn khác nhau: Thanh Thủy thốt Sư Tôn, Vương Lâm thốt Thác Sâm muốn bỏ chạy, La Trần thốt Tiên tổ ngây người. Khí bảy màu từ khe nứt bao bọc Vọng Nguyệt rồi kéo vào trong, Nhất Mộc Tử và Vũ Đông Thiện bên trong cơ thể Vọng Nguyệt cũng bị ảnh hưởng. Khe nứt phun thêm sương mù bảy màu hóa ba luồng khí phóng thẳng đến Vương Lâm, La Trần và Thanh Thủy."},{"chuong":884,"tieuDe":"Thiên Đạo?","tomTat":"La Trần cảm nhận nỗi đau đớn của Vọng Nguyệt qua đồng hóa, lần lượt tự bạo ba tinh điểm Cổ Thần trên mi tâm, cơ thể phóng đại từ 300 lên hơn 1000 trượng, gần đạt sức mạnh đỉnh phong xưa, xé toạc khe nứt ép kẻ bí ẩn lộ diện. Thanh niên mi tâm có dấu ấn trăng lưỡi liềm xuất hiện từ khe nứt, tự xưng có thể coi là thiên đạo, dùng Chín trăm chín mươi chín Thôn Trận và Khai Thiên Trận của Phong Giới đối kháng nhưng không địch nổi. Sư tôn của thanh niên — lão già tóc bạc — bước ra, kích hoạt Linh Khai Thiên Phủ triệu tập tinh điểm từ nghìn vạn dặm ngưng tụ thành chiến phủ trăm trượng mang khí hồng hoang, đánh bại đồng thời Vương Lâm, Thanh Thủy và La Trần. La Trần nhận ra Khai Thiên Phủ là thánh vật tộc Cổ Thần, hét cho Vương Lâm biết truyền thừa của hắn cũng có thứ này. Vọng Nguyệt bị bàn tay tinh quang nắm kéo hoàn toàn vào mạng lưới. La Trần trong khoảnh khắc cuối cùng tự móc hai Cổ Thần Tinh còn lại trên mi tâm ném tặng Vương Lâm làm lễ vật trưởng thành theo tục Cổ Thần, rồi bị bắt ném vào mạng lưới, thốt lời bi thương chơi chữ Cổ Thần thành Cô Thần — Thần cô độc."},{"chuong":885,"tieuDe":"Nghịch Thiên Châu Lại Tái Hiện","tomTat":"Tiếng bi thương của La Trần vang vào tai Vương Lâm, khiến hắn đồng cảm với số phận một Cổ Thần từng nghịch thiên nhưng bị Vọng Nguyệt đồng hóa, rơi từ Bát Tinh đỉnh phong xuống trạng thái ấu tử. Hai Cổ Thần Tinh phóng tới, được Vương Lâm chụp lấy và dung nhập, làm lực lượng Cổ Thần bùng phát, thân thể hắn phình lớn tới ba trăm trượng và đánh lui bàn tay tinh quang. Thanh Thủy nhìn cảnh hai người già trẻ trong mảng lưới thì sinh phản ứng kỳ dị, như có ký ức bị che giấu bắt đầu mở ra. Bên ngoài mảng lưới, lão già tộc Nguyệt Phệ nhận ra Vương Lâm là Ngũ Tinh Vương Tộc Cổ Thần đang thức tỉnh, nổi lòng tham muốn thôn phệ để giành vị trí trong Trường Tôn Hội. Lão thi triển Nguyệt Tiên Thôn Thần bằng dấu ấn trăng lưỡi liềm, hóa thành vầng trăng nuốt lấy Vương Lâm, nhưng Nghịch Thiên Châu trong cơ thể hắn tự động vận chuyển và phá tan thần thông. Hạt châu tỏa hai luồng khí đen trắng truy kích lão già, vô hiệu hóa thuấn di và dung nhập thiên địa, rồi kéo dấu ấn trăng lưỡi liềm gãy đôi khỏi mi tâm lão khiến lão đau đớn thê lương."},{"chuong":886,"tieuDe":"Bí Ẩn","tomTat":"Lão già Nguyệt Phệ tộc cầu xin Phong Giới Chi Tôn nhưng vẫn bị Nghịch Thiên Châu rút dấu ấn trăng lưỡi liềm, mi tâm phụt máu và gục xuống, khiến thanh niên đi cùng hoảng sợ ôm lão lui nhanh. Vòng xoáy đen trắng tiêu tán, Nghịch Thiên Châu bay về trước Vương Lâm rồi dung nhập vào tay phải và nguyên thần của hắn, trong khi Vọng Nguyệt cùng La Trần bị mảnh lưới ngăn cách và biến mất vĩnh viễn trong hư vô. Thanh Thủy kể cho Vương Lâm bí sử Viễn Cổ Tiên Vực, nguồn gốc Tứ Đại Tiên Giới Phong Vũ Lôi Điện, thân phận Luyện Khí Sĩ và bi kịch năm xưa của chính mình. Hắn nói Tứ Đại Tiên Giới từng đại chiến vì một hạt châu bí ẩn, rồi bị một cố nhân mang lệnh Viễn Cổ Tiên Vực dựng hàng rào chia cắt. Sau đại chiến, Phù Văn Tộc từ hư vô dưới tinh không xuất hiện, dùng thần thông quỷ dị trên dấu ấn giống pháp bảo và bị tiên nhân đánh tan, khiến Vương Lâm liên hệ tới Tiên Di Tộc cùng Nguyệt Phệ tộc Thái Cổ Tiên Tộc. Thanh Thủy ngày càng suy kiệt vì tiên nguyên bị phong ấn, dặn Vương Lâm giữ nguyên thần Huyền Bảo, rồi được Vương Lâm đỡ đi theo mảnh vỡ Tiên Giới dẫn đường. Cuối cùng họ tới một vòng xoáy kim quang có tòa tế đàn và nhiều tu sĩ niệm chú, nơi Viêm Lôi Tử mỉm cười đón trở về. Bản tôn Vương Lâm lúc này thu nhỏ về hình người, mi tâm có năm Tinh Điểm Cổ Thần, đạt lực lượng Ngũ Tinh Cổ Thần và bước vào hàng cường giả."},{"chuong":887,"tieuDe":"Mục Đồng Tay Chỉ Hạnh Hoa Thôn","tomTat":"Bốn ngày sau khi Vương Lâm và Thanh Thủy được Viêm Lôi Tử mở đường rời cõi hư vô, Vương Lâm một mình phi hành trong tinh không bằng thân thể, không dùng Tinh La Bàn hay pháp bảo. Hắn hồi tưởng các biến cố trong hư vô, từ La Trần, Phong Giới, Tiên Giới cho tới bí mật Nghịch Thiên Châu từng gây chiến trên Tứ Đại Tiên Giới. Thanh Thủy tái xuất với sát khí và mùi máu tanh, cho biết đã giết một bộ phận tu sĩ Sát Vực Giới đang truy sát Hứa Mộc. Vương Lâm giao nguyên thần Huyền Bảo cho Thanh Thủy lấy ký ức, khiến nguyên thần này mất hết linh trí, rồi hai người hẹn mười ngày sau cùng tới Sát Vực Giới Tu Chân Liên Minh lấy một vật. Sau đó Vương Lâm dung nhập thiên địa tới Ám Nguyệt Tinh ở phía bắc Liên Minh Tinh Vực, tìm Thiên Sơn và thôn phàm nhân dưới núi. Trong cảnh hạnh hoa nở, một tiểu đồng chăn trâu chỉ cho hắn biết nơi phía trước là Hạnh Hoa Thôn. Vương Lâm tới khu mộ sau thôn, lấy bình ngọc chứa tro cốt Tôn Thái ra và hoàn thành lời hứa đưa cố nhân về quê, khép lại ân oán cũ."}];
